window.SNOWPRO_QUESTION_BANK = {"generatedFrom": "01_資格/Snowflake/SnowPro_Core/問題", "examCount": 6, "questionCount": 742, "exams": [{"slug": "01_practice_exam", "title": "SnowPro Core 01_practice_exam", "sourcePath": "01_資格/Snowflake/SnowPro_Core/問題/01_practice_exam.md", "metadata": ["問題数: 121問"], "questionCount": 121, "questions": [{"order": 1, "title": "次のうち、ユーザーがサードパーティのデータセットを検索・利用できる場所はどれですか？", "multiSelect": false, "stemHtml": "<p>次のうち、ユーザーがサードパーティのデータセットを検索・利用できる場所はどれですか？</p>", "options": [{"key": "A", "label": "Sharing Centre"}, {"key": "B", "label": "Snowflake Marketplace"}, {"key": "C", "label": "Secure Data Sharing"}, {"key": "D", "label": "Partner Hub"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Snowflake Marketplace</strong></p><p>Snowflake Marketplaceは、さまざまな組織が公開しているサードパーティのデータセットを検索・利用するための場所です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 2, "title": "Snowparkがサポートしている言語はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowparkがサポートしている言語はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Scala"}, {"key": "B", "label": "Java"}, {"key": "C", "label": "Python"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>Java / Scala / Python</strong></p><p>Java、Scala、Pythonはすべて Snowpark でサポートされています。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 3, "title": "以下のリソースモニターの設定を確認してください。", "multiSelect": true, "stemHtml": "<p>以下のリソースモニターの設定を確認してください。</p>", "options": [{"key": "A", "label": "Warehouse 1"}, {"key": "B", "label": "Warehouse 4"}, {"key": "C", "label": "Warehouse 3"}, {"key": "D", "label": "Warehouse 2"}, {"key": "E", "label": "Warehouse 5"}], "correctAnswers": ["A", "E"], "explanationHtml": "<p>✅ <strong>Warehouse 1 / Warehouse 5</strong></p><p>リソースモニターは、定義されたクォータに対して単一または複数の仮想ウェアハウスのクレジット使用量を追跡・管理できます。アカウントレベルのリソースモニターは、すべての仮想ウェアハウスのクレジット使用量を合算して追跡します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 4, "title": "クエリ処理層に関する正しい説明はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>クエリ処理層に関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "クエリ処理層はクエリプランの最適化を担当する。"}, {"key": "B", "label": "クエリ処理層は複数のコンピュートクラスター（仮想ウェアハウス）を同時に実行できる。"}, {"key": "C", "label": "クエリ処理層はクエリプランの生成を担当する。"}, {"key": "D", "label": "クエリ処理層はクエリの実行を担当する。"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>複数の仮想ウェアハウスの同時実行 / クエリ実行</strong></p><p>クエリ処理層は、保存されたデータに対してクエリやデータ処理ジョブを実行するコンピュート層です。Snowflakeのコンピュートエンジンは「仮想ウェアハウス」と呼ばれ、同時に複数稼働させることができます。クエリプランの生成と最適化はクラウドサービス層が担います。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 5, "title": "数ギガバイトのテーブルから外部ステージにデータをアンロードする際、エクスポートされるファイルにつ...", "multiSelect": true, "stemHtml": "<p>数ギガバイトのテーブルから外部ステージにデータをアンロードする際、エクスポートされるファイルについて正しいものはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "エクスポートされるファイルは圧縮される。"}, {"key": "B", "label": "各エクスポートファイルのサイズは16MBである。"}, {"key": "C", "label": "エクスポートされるファイルは圧縮されない。"}, {"key": "D", "label": "データは単一の大きなファイルにエクスポートされる。"}, {"key": "E", "label": "データは複数のファイルにエクスポートされる。"}], "correctAnswers": ["A", "B", "E"], "explanationHtml": "<p>✅ <strong>圧縮される / 16MB / 複数ファイル</strong></p><p>Snowflakeからデータをアンロードすると、デフォルトでgzip圧縮が適用されます（変更・無効化も可能）。並列処理を活用するため、デフォルトでは複数ファイルに分割されます（<code>SINGLE=TRUE</code> で単一ファイル化も可能）。各出力ファイルのデフォルトサイズは16MBですが、<code>MAX_FILE_SIZE</code> パラメータで変更できます（クラウドストレージへのエクスポート時の最大サイズは5GB）。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 6, "title": "マテリアライズドビューに関する正しい説明はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューに関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "ユーザーには見えないSnowflakeサービスが、バックグラウンドでマテリアライズドビューを自動的にメンテナンスする。"}, {"key": "B", "label": "マテリアライズドビューはクエリパフォーマンスを向上させるために使用され、クエリ結果を事前計算して物理的に保存する。"}, {"key": "C", "label": "マテリアライズドビューは事前計算済みの回答を提供し、一部のクエリを高速化できる。"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>すべて正しい</strong></p><p>マテリアライズドビューは、SELECTクエリに基づいてデータを事前計算するビューです。クエリ結果は物理的に保存され、同様のクエリのパフォーマンスを向上させます。基となるテーブルが更新されると、マテリアライズドビューは自動的に更新（バックグラウンドで透過的に処理）されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 7, "title": "あるビジネスユーザーが複雑なクエリを実行しようとしています。別のユーザーが24時間以内に同一クエ...", "multiSelect": false, "stemHtml": "<p>あるビジネスユーザーが複雑なクエリを実行しようとしています。別のユーザーが24時間以内に同一クエリを実行しており、クエリ対象のデータは変更されていません。このクエリはどのように実行される可能性が高いですか？</p>", "options": [{"key": "A", "label": "Snowflakeはメタデータキャッシュからクエリ結果を返す。"}, {"key": "B", "label": "以前に実行されたクエリであるため、Snowflakeはクエリ結果キャッシュを使用してクエリを処理する。"}, {"key": "C", "label": "Snowflakeはクエリを再実行し、基となるテーブルをスキャンして結果を再計算する。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>クエリ結果キャッシュを使用する</strong></p><p>Snowflakeはクエリを実行すると、その結果を一定期間キャッシュします（クエリ結果キャッシュ）。以前に実行されたクエリと同一かつ対象データに変更がない場合、このキャッシュが使用されます。結果キャッシュは24時間有効で、再利用されるたびに24時間延長され、最大31日間保持されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 8, "title": "コンシューマーにシェアが付与され、コンシューマーがシェアからデータベースを作成した後、シェアに新...", "multiSelect": false, "stemHtml": "<p>コンシューマーにシェアが付与され、コンシューマーがシェアからデータベースを作成した後、シェアに新しいオブジェクトが追加された場合、何が起こりますか？</p>", "options": [{"key": "A", "label": "コンシューマーは付与されたシェアオブジェクトからデータベースを再作成する必要がある。"}, {"key": "B", "label": "一度作成されてコンシューマーに付与されたシェアにオブジェクトを追加することはできない。"}, {"key": "C", "label": "新しいオブジェクトはコンシューマーにすぐにアクセス可能になる。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>新しいオブジェクトはすぐにアクセス可能になる</strong></p><p>データプロバイダーがシェアに新しいオブジェクトを追加すると、コンシューマーは追加された瞬間からそのオブジェクトにアクセスできるようになります。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 9, "title": "次のうち、クローンできないオブジェクトはどれですか？", "multiSelect": false, "stemHtml": "<p>次のうち、クローンできないオブジェクトはどれですか？</p>", "options": [{"key": "A", "label": "データベース"}, {"key": "B", "label": "名前付き内部ステージ（Named Internal Stage）"}, {"key": "C", "label": "外部ステージ"}, {"key": "D", "label": "スキーマ"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>名前付き内部ステージ</strong></p><p>名前付き内部ステージはクローンできません。データベースやスキーマをクローンしても、名前付き内部ステージを参照するSnowpipeはクローンされません。なお、名前付き外部ステージはクローン可能です。テーブルステージはテーブルと紐付いているためテーブルのクローン時に自動クローンされます。データベース、スキーマ、テーブルなどはクローン可能です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローン", "originalCorrect": null, "reviewPoint": ""}}, {"order": 10, "title": "Snowflakeが準拠しているセキュリティ標準はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeが準拠しているセキュリティ標準はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "PCI-DSS"}, {"key": "B", "label": "FedRAMP"}, {"key": "C", "label": "IRAP – Protected"}, {"key": "D", "label": "HIPAA"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>PCI-DSS / FedRAMP / IRAP – Protected / HIPAA</strong></p><p>Snowflakeは以下のセキュリティ・金融標準に準拠しています：IRAP Protected、ITAR、FedRAMP Moderate、GxP、SOC 1 Type II、SOC 2 Type II、PCI-DSS、HITRUST / HIPAA、ISO/IEC 27001</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 11, "title": "大規模なテーブルは _________ のマイクロパーティションを持つことができます。", "multiSelect": false, "stemHtml": "<p>大規模なテーブルは _________ のマイクロパーティションを持つことができます。</p>", "options": [{"key": "A", "label": "数十個"}, {"key": "B", "label": "数百個"}, {"key": "C", "label": "数百万〜数億個"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>数百万〜数億個</strong></p><p>テーブルのマイクロパーティション数は主にデータ量に依存します。非常に大規模なテーブルでは、マイクロパーティション数が数百万から数億に達することがあります。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 12, "title": "True/False: Snowflakeベースのデータウェアハウスは、クラウドストレージを基盤...", "multiSelect": false, "stemHtml": "<p>True/False: Snowflakeベースのデータウェアハウスは、クラウドストレージを基盤として使用しているため、ストレージ容量は実質的に無制限です。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>Snowflakeは Amazon S3 や Azure Blob Storage などのクラウドベースのストレージを使用しているため、利用可能なスペースは実質的に無制限です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 13, "title": "Snowflakeのストレージ階層を正しく表しているものはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeのストレージ階層を正しく表しているものはどれですか？</p>", "options": [{"key": "A", "label": "Schema→Account→Database→Table"}, {"key": "B", "label": "Account→Database→Schema→Table"}, {"key": "C", "label": "Account→Table→Database→Schema"}, {"key": "D", "label": "Database→Account→Schema→Table"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Account→Database→Schema→Table</strong></p><p>Snowflakeでは最上位レベルがアカウントで、その下にデータベース、その下にスキーマ、スキーマの中にテーブル・ビュー・ファイルフォーマット・シーケンス・UDF・ストアドプロシージャなどのオブジェクトが含まれます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflakeのカタログとオブジェクト", "originalCorrect": null, "reviewPoint": ""}}, {"order": 14, "title": "Snowpipeを通じてロードされたデータについて、過去365日間のデータロード履歴を確認できる...", "multiSelect": true, "stemHtml": "<p>Snowpipeを通じてロードされたデータについて、過去365日間のデータロード履歴を確認できるビューはどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "ACCOUNT_USAGE.COPY_HISTORY"}, {"key": "B", "label": "ACCOUNT_USAGE.LOAD_HISTORY"}, {"key": "C", "label": "ACCOUNT_USAGE.PIPE_USAGE_HISTORY"}, {"key": "D", "label": "INFORMATION_SCHEMA.QUERY_HISTORY"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>COPY_HISTORY / PIPE_USAGE_HISTORY</strong></p><p>ACCOUNT_USAGEスキーマの <code>COPY_HISTORY</code> ビューと <code>PIPE_USAGE_HISTORY</code> ビューが、Snowpipeを通じたデータロードの履歴を提供します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 15, "title": "Snowflake UDFは、データの返し方に基づいて大きく2種類に分類されます。それはどれです...", "multiSelect": true, "stemHtml": "<p>Snowflake UDFは、データの返し方に基づいて大きく2種類に分類されます。それはどれですか？</p>", "options": [{"key": "A", "label": "Interpreted UDFs"}, {"key": "B", "label": "Table UDFs（テーブルUDF）"}, {"key": "C", "label": "Scalar UDFs（スカラーUDF）"}, {"key": "D", "label": "Compiled UDFs"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>Scalar UDFs / Table UDFs</strong></p><p>スカラーUDFは入力行ごとに1行（1つの値）を返します。テーブルUDF（UDTF）は、入力に対してゼロ行以上・複数列の結果を返すことができます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 16, "title": "True/False: Snowflakeの顧客は、テーブルのデータ保存形式をコントロールできま...", "multiSelect": false, "stemHtml": "<p>True/False: Snowflakeの顧客は、テーブルのデータ保存形式をコントロールできます。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>SnowflakeはAWS S3、Azure Blob Storage、Google Cloud Storageなどのクラウドオブジェクトストレージ上で独自フォーマットでデータを保存します。ユーザーは実際のファイルを見たり、データの保存方法を直接確認したり、ファイルにアクセスしたりすることはできません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 17, "title": "Snowflakeの保存データ（Data at rest）の暗号化に関する正しい説明はどれですか...", "multiSelect": true, "stemHtml": "<p>Snowflakeの保存データ（Data at rest）の暗号化に関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Snowflakeは暗号化に使用するキーを30日ごとにローテーションする。"}, {"key": "B", "label": "SnowflakeはAES 128ビット暗号化を使用する。"}, {"key": "C", "label": "Snowflakeは1年後に暗号化データの再暗号化（リキーイング）を行う。"}, {"key": "D", "label": "SnowflakeはデフォルトでSnowflakeが暗号化キーを管理する。"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>30日ごとのキーローテーション / 1年後のリキーイング / Snowflakeによるキー管理</strong></p><p>デフォルトでは、Snowflakeが暗号化キーを自動管理します。キーは30日ごとにローテーションされ、年次の再暗号化プロセスにより新しいキーでデータを再暗号化します。Snowflakeは保存データの暗号化に <strong>AES 256ビット</strong>を使用します（128ビットではありません）。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 18, "title": "クエリプロファイルの結果として、大規模テーブルのクラスタリングが不十分であることを示す指標はどれ...", "multiSelect": true, "stemHtml": "<p>クエリプロファイルの結果として、大規模テーブルのクラスタリングが不十分であることを示す指標はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "結果ノードが多くの行を返している。"}, {"key": "B", "label": "JoinFilterノードが多数ある。"}, {"key": "C", "label": "「Partitions Scanned（スキャンされたパーティション数）」の値が大きい。"}, {"key": "D", "label": "「Partitions Total（全パーティション数）」と「Partitions Scanned」の値が等しい。"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>Partitions Scannedが大きい / Partitions Totalと等しい</strong></p><p>パーティションプルーニングが機能している場合、スキャンされたパーティション数は全体より大幅に少なくなります。両者が等しければ、テーブル全体がスキャンされており、プルーニングが発生していないことを意味します。クラスタリングキーの見直しが必要です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 19, "title": "検索最適化サービス（Search Optimization Service）は、どのタイプのクエ...", "multiSelect": false, "stemHtml": "<p>検索最適化サービス（Search Optimization Service）は、どのタイプのクエリのパフォーマンス向上に使用できますか？</p>", "options": [{"key": "A", "label": "選択的ポイントルックアップクエリ"}, {"key": "B", "label": "1TB超のテーブルに対するすべてのクエリ"}, {"key": "C", "label": "テーブルの列のサブセットにアクセスするクエリ"}, {"key": "D", "label": "すべての列とすべての行にアクセスするクエリ"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>選択的ポイントルックアップクエリ</strong></p><p>検索最適化サービスは以下のクエリパフォーマンスを向上させます：</p><ul><li>ポイントルックアップクエリ（高選択性フィルターで少数の行を返すもの）</li><li>部分一致・正規表現検索（LIKE、ILIKE、RLIKE）</li><li>VARIANT・OBJECT・ARRAY列のフィールドへのクエリ</li><li>特定のジオスペーシャル関数を使用するクエリ</li></ul><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 20, "title": "Snowflakeアカウント間でのデータベースのフェイルオーバーとフェイルバックをサポートし、ビ...", "multiSelect": true, "stemHtml": "<p>Snowflakeアカウント間でのデータベースのフェイルオーバーとフェイルバックをサポートし、ビジネス継続性と災害復旧を提供するSnowflakeエディションはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Business Critical"}, {"key": "B", "label": "Enterprise"}, {"key": "C", "label": "Standard"}, {"key": "D", "label": "Virtual Private Snowflake（VPS）"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>Business Critical / Virtual Private Snowflake</strong></p><p>データベースのフェイルオーバーとフェイルバックは、Business CriticalエディションとVirtual Private Snowflake（VPS）エディションで提供されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 21, "title": "新しいリソースモニターを作成できるのは誰ですか？", "multiSelect": false, "stemHtml": "<p>新しいリソースモニターを作成できるのは誰ですか？</p>", "options": [{"key": "A", "label": "アカウント管理者（ACCOUNTADMINロールを持つユーザー）"}, {"key": "B", "label": "システムの任意のユーザー"}, {"key": "C", "label": "システム管理者（SYSADMINロールを持つユーザー）"}, {"key": "D", "label": "リソースモニターに対してMONITORおよびMODIFY権限を持つユーザー"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>ACCOUNTADMINロールを持つユーザー</strong></p><p>権限の観点から、新しいリソースモニターを作成できるのはアカウント管理者（ACCOUNTADMINロールを持つユーザー）のみです。ただし、アカウント管理者は既存のリソースモニターに権限を付与することで、他のユーザーがリソースモニターの設定を確認・変更できるようにすることができます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 22, "title": "仮想ウェアハウスのパフォーマンスを最適化するために使用すべき戦略はどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>仮想ウェアハウスのパフォーマンスを最適化するために使用すべき戦略はどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "MAX_CONCURRENCY_LEVELを高い数値に設定する。"}, {"key": "B", "label": "仮想ウェアハウスのサイズを増やす。"}, {"key": "C", "label": "仮想ウェアハウスを停止する。"}, {"key": "D", "label": "キューイングを減らす。"}, {"key": "E", "label": "メモリスピリングパラメータをTrueに設定する。"}, {"key": "F", "label": "ローカルディスクキャッシュのサイズを増やす。"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>ウェアハウスサイズの増加 / キューイングの削減</strong></p><p>仮想ウェアハウスのパフォーマンス改善に適用できる戦略：①キューイングの削減、②メモリスピルの解消、③ウェアハウスサイズの増加、④クエリアクセラレーションの試用、⑤ウェアハウスキャッシュの最適化、⑥同時実行クエリ数の制限</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 23, "title": "Snowflakeの課金に関する正しい説明はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeの課金に関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Snowflakeの課金は実際に使用したストレージ量に基づく。"}, {"key": "B", "label": "Snowflakeの課金は実行されたクエリ数に基づく。"}, {"key": "C", "label": "Snowflakeの課金はクエリで処理されたデータ量に基づく。"}, {"key": "D", "label": "仮想ウェアハウスが停止中の場合、コストは発生しない。"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>実際の使用ストレージ / 停止中のウェアハウスはコスト不発生</strong></p><p>再開（アクティブ）状態の仮想ウェアハウスはコストに寄与しますが、クエリを実行していなくても再開中であればコストが発生します。Snowflakeはデータベーステーブル内のデータ、内部ステージのファイル、タイムトラベル履歴、フェイルセーフストレージの保存量に対して課金します。クエリが処理したデータ量への課金はありません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "コストと価格", "originalCorrect": null, "reviewPoint": ""}}, {"order": 24, "title": "True or False: Snowsight（Snowflakeのウェブユーザーインターフェ...", "multiSelect": false, "stemHtml": "<p>True or False: Snowsight（Snowflakeのウェブユーザーインターフェース）では、一度に1つのクエリしか実行できません。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>Snowsightでは複数のワークシートを同時に開くことができ、それぞれ異なるクエリを持てます。ワークシートが非アクティブでもクエリは実行し続けるため、複数のクエリを同時に実行できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 25, "title": "ある仮想ウェアハウスが起動し、45秒間使用された後に停止されました。顧客は何秒分の料金を請求され...", "multiSelect": false, "stemHtml": "<p>ある仮想ウェアハウスが起動し、45秒間使用された後に停止されました。顧客は何秒分の料金を請求されますか？</p>", "options": [{"key": "A", "label": "315秒"}, {"key": "B", "label": "45秒"}, {"key": "C", "label": "60秒"}, {"key": "D", "label": "3600秒"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>60秒</strong></p><p>Snowflakeのクレジットは1秒単位で課金されますが、<strong>最低60秒分の課金</strong>が適用されます。つまり、最初の1分以内に起動・停止した場合でも、最低60秒分のクレジット使用量が請求されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 26, "title": "動的データマスキング（Dynamic Data Masking）はSnowflakeにおいてどの...", "multiSelect": false, "stemHtml": "<p>動的データマスキング（Dynamic Data Masking）はSnowflakeにおいてどのようなセキュリティを提供しますか？</p>", "options": [{"key": "A", "label": "データベースレベルのセキュリティ"}, {"key": "B", "label": "行レベルのセキュリティ"}, {"key": "C", "label": "列レベルのセキュリティ"}, {"key": "D", "label": "オブジェクトセキュリティ"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>列レベルのセキュリティ</strong></p><p>Snowflakeは列に適用できるマスキングポリシーをサポートし、列レベルのセキュリティを提供します。列レベルのセキュリティは、動的データマスキングまたは外部トークン化によって実現されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 27, "title": "同時実行と需要の変化に応じて、クラスターを自動的に追加・削除できる仮想ウェアハウスの種類はどれで...", "multiSelect": false, "stemHtml": "<p>同時実行と需要の変化に応じて、クラスターを自動的に追加・削除できる仮想ウェアハウスの種類はどれですか？</p>", "options": [{"key": "A", "label": "非仮想ウェアハウス"}, {"key": "B", "label": "X-Largeサイズの仮想ウェアハウス"}, {"key": "C", "label": "マルチクラスター仮想ウェアハウス"}, {"key": "D", "label": "停止中の仮想ウェアハウス"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>マルチクラスター仮想ウェアハウス</strong></p><p>マルチクラスター仮想ウェアハウスは、同時実行ユーザー数が単一ウェアハウスの処理能力を超えた場合に使用します。同時実行ワークロードが最大に達するとクエリがキューに入りますが、マルチクラスターではクラスターを追加することでこれに対応します。需要が減少すると余分なクラスターが削除されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "エラスティックコンピュート", "originalCorrect": null, "reviewPoint": ""}}, {"order": 28, "title": "マイクロパーティション、データベース、テーブルに関するメタデータを管理するSnowflakeの層...", "multiSelect": false, "stemHtml": "<p>マイクロパーティション、データベース、テーブルに関するメタデータを管理するSnowflakeの層はどれですか？</p>", "options": [{"key": "A", "label": "クラウドサービス層"}, {"key": "B", "label": "データベースストレージ層"}, {"key": "C", "label": "クライアントツール"}, {"key": "D", "label": "クエリ処理層"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>クラウドサービス層</strong></p><p>クラウドサービス層は、データの保存方法、マイクロパーティション情報、データベース・テーブルのメタデータ、ユーザー・ロール・セキュリティ情報など、さまざまなメタデータを管理します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 29, "title": "ストアドプロシージャを作成するのに適切なシナリオはどれですか？", "multiSelect": false, "stemHtml": "<p>ストアドプロシージャを作成するのに適切なシナリオはどれですか？</p>", "options": [{"key": "A", "label": "文字列列を数値列に変換する。"}, {"key": "B", "label": "動的に組み立てられた1つ以上のSQLステートメントを実行する。"}, {"key": "C", "label": "2つの入力値の最大値を計算する。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>動的に組み立てられたSQLステートメントの実行</strong></p><p>ストアドプロシージャは、新しいユーザーの作成・ロールの付与・プライベートデータベースの作成など、繰り返し行われる管理作業の自動化に適しています。これらの手順をストアドプロシージャにまとめ、必要な際に呼び出すことができます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 30, "title": "True or False: リーダーアカウントを使用して、Snowflakeを使用していないユ...", "multiSelect": false, "stemHtml": "<p>True or False: リーダーアカウントを使用して、Snowflakeを使用していないユーザーや組織とデータを共有できます。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>Snowflakeを使用していないユーザーや組織とデータを共有するには、リーダーアカウントを作成します。このリーダーアカウントはデータプロバイダーが共有目的のためだけに作成します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 31, "title": "クエリパフォーマンス向上のためにデータクラスタリングを利用できるSnowflakeエディションは...", "multiSelect": true, "stemHtml": "<p>クエリパフォーマンス向上のためにデータクラスタリングを利用できるSnowflakeエディションはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Enterprise"}, {"key": "B", "label": "Virtual Private Snowflake"}, {"key": "C", "label": "Business Critical"}, {"key": "D", "label": "Standard"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>すべてのエディション</strong></p><p>データクラスタリングはすべてのSnowflakeエディションでサポートされています。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 32, "title": "Snowflake Marketplaceをサポートしていないエディションはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflake Marketplaceをサポートしていないエディションはどれですか？</p>", "options": [{"key": "A", "label": "Standard"}, {"key": "B", "label": "Business Critical"}, {"key": "C", "label": "VPS（Virtual Private Snowflake）"}, {"key": "D", "label": "Enterprise"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>VPS（Virtual Private Snowflake）</strong></p><p>VPS以外のすべてのSnowflakeアカウントでSnowflake Marketplaceを使用できます。VPSアカウントは独立したメタデータとコンピュートを持つため、Snowflakeの共通クラウドサービス・メタデータ上に構築されたMarketplaceを使用できません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 33, "title": "Snowflakeが提供しているドライバーはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeが提供しているドライバーはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Snowflake用ODBCドライバー"}, {"key": "B", "label": "PHP PDOドライバー"}, {"key": "C", "label": "Go言語用Snowflakeドライバー"}, {"key": "D", "label": "Snowflake用JDBCドライバー"}, {"key": "E", "label": "Snowflake用.NETドライバー"}], "correctAnswers": ["A", "B", "C", "D", "E"], "explanationHtml": "<p>✅ <strong>すべて正しい</strong></p><p>Snowflakeは以下のドライバー・コネクターを提供しています：Python/Spark/Kafka用コネクター、JDBCドライバー、ODBCドライバー、.NETドライバー、Goドライバー、Node.jsドライバー、PHP PDOドライバー</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 34, "title": "セキュアUDFは通常のUDFとどのように異なりますか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>セキュアUDFは通常のUDFとどのように異なりますか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "セキュアUDFは特定のSQL最適化を使用しない。"}, {"key": "B", "label": "セキュアUDFは、承認されていないユーザーがUDFの定義を見られないようにする。"}, {"key": "C", "label": "セキュアUDFは管理者のみが実行できる。"}, {"key": "D", "label": "セキュアUDFはマシン語で記述され、Snowflakeのコードにコンパイルされる。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>SQL最適化を使用しない / 定義の非表示</strong></p><p>特定のSQL UDF最適化により、非表示にすべきデータに間接的にアクセスできる場合があります。セキュアUDFはこれらの最適化を使用せず、ユーザーが間接的にもデータにアクセスできないようにします。また、UDFを所有するロールを付与されたユーザーのみがセキュアUDFの定義を確認できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 35, "title": "現在のセッションで実行された2番目に新しいクエリのクエリIDを取得するにはどうすればよいですか？", "multiSelect": false, "stemHtml": "<p>現在のセッションで実行された2番目に新しいクエリのクエリIDを取得するにはどうすればよいですか？</p>", "options": [{"key": "A", "label": "`SELECT LAST_QUERY_ID(2);`"}, {"key": "B", "label": "`SELECT LAST_QUERY_ID(1);`"}, {"key": "C", "label": "`SELECT LAST_QUERY_ID(-2);`"}, {"key": "D", "label": "`SELECT LAST_QUERY_ID(-1);`"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong><code>SELECT LAST_QUERY_ID(-2);</code></strong></p><p><code>LAST_QUERY_ID</code> 関数は現在のセッション内で指定されたクエリのIDを返します。負の値を使用すると最近のクエリから数えます：-1 = 最新クエリ、-2 = 2番目に新しいクエリ。正の値は最初からのクエリを示します：1 = 最初のクエリ、2 = 2番目のクエリ。デフォルトは -1 です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "一般", "originalCorrect": null, "reviewPoint": ""}}, {"order": 36, "title": "INFORMATION SCHEMAで提供される使用データの保持期間はどれくらいですか？", "multiSelect": false, "stemHtml": "<p>INFORMATION SCHEMAで提供される使用データの保持期間はどれくらいですか？</p>", "options": [{"key": "A", "label": "7日〜6ヶ月"}, {"key": "B", "label": "365日"}, {"key": "C", "label": "128日"}, {"key": "D", "label": "永久"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>7日〜6ヶ月</strong></p><p>INFORMATION_SCHEMAのビューのデータ保持期間は短く、通常14日ですが、特定のビューで7日、使用履歴ビューで最大6ヶ月となります。直近の情報確認に適しています（ACCOUNT_USAGEは最大365日）。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 37, "title": "以下の図のうち、最もクラスタリングが良好なテーブルを示しているものはどれですか？", "multiSelect": false, "stemHtml": "<p>以下の図のうち、最もクラスタリングが良好なテーブルを示しているものはどれですか？</p>", "options": [{"key": "A", "label": "3"}, {"key": "B", "label": "4"}, {"key": "C", "label": "1"}, {"key": "D", "label": "2"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>1</strong></p><p>クラスタリング深度（Clustering Depth）は、特定の列についてマイクロパーティションが重複する平均深度を示します。値が1に近いほど（または1であるほど）テーブルのクラスタリングが良好です。値が大きいほどクラスタリングが不十分です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 38, "title": "ディレクトリテーブルに関する正しい説明はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>ディレクトリテーブルに関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "ディレクトリテーブルには直接権限を割り当てることができない。"}, {"key": "B", "label": "ディレクトリテーブルには権限を割り当てることができる。"}, {"key": "C", "label": "ディレクトリテーブルは独立したオブジェクトではない。"}, {"key": "D", "label": "ディレクトリテーブルは独立したオブジェクトである。"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>直接権限割り当て不可 / 独立したオブジェクトではない</strong></p><p>ディレクトリテーブルは独立したデータベースオブジェクトではなく、ステージに付随する暗黙的なオブジェクトです。ステージ作成時、またはその後で有効化できます。独立したオブジェクトではないため、権限を直接付与することはできません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 39, "title": "新しく作成されたオブジェクトはどのロールが所有しますか？", "multiSelect": false, "stemHtml": "<p>新しく作成されたオブジェクトはどのロールが所有しますか？</p>", "options": [{"key": "A", "label": "ACCOUNTADMIN"}, {"key": "B", "label": "オブジェクト作成時に使用していたロール"}, {"key": "C", "label": "SYSADMIN"}, {"key": "D", "label": "PUBLIC"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>オブジェクト作成時に使用していたロール</strong></p><p>Snowflakeは任意アクセス制御（DAC）をサポートしており、オブジェクトを作成したロールがそのオブジェクトを所有し、他のロールへのアクセス提供もそのロールが行えます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 40, "title": "True or False: データをプロバイダーとして共有し、コンシューマーとして消費するため...", "multiSelect": false, "stemHtml": "<p>True or False: データをプロバイダーとして共有し、コンシューマーとして消費するためには、2つのSnowflakeアカウントが必要です（共有用と消費用で別々に）。</p>", "options": [{"key": "A", "label": "False（誤り）"}, {"key": "B", "label": "True（正しい）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>同じSnowflakeアカウントがデータプロバイダーとしてデータを共有しながら、データコンシューマーとしてデータを消費することができます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 41, "title": "ユーザーとグループメンバーシップの自動プロビジョニングのためにSnowflakeがサポートしてい...", "multiSelect": false, "stemHtml": "<p>ユーザーとグループメンバーシップの自動プロビジョニングのためにSnowflakeがサポートしているものはどれですか？</p>", "options": [{"key": "A", "label": "ABAC"}, {"key": "B", "label": "DAC"}, {"key": "C", "label": "RBAC"}, {"key": "D", "label": "SCIM"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>SCIM</strong></p><p>SnowflakeはSCIM 2.0をサポートし、OktaおよびAzure Active Directoryと互換性があります。SCIMは、アイデンティティプロバイダーの情報に基づいてユーザーの自動プロビジョニングとロールの同期を提供するオープン標準です。アイデンティティプロバイダーで新しいユーザーが作成されると、SCIMはSnowflake内でそのユーザーを自動的にプロビジョニングします。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 42, "title": "Snowflakeがクエリ実行時に不要なパーティションを排除できる最適化技術の名称は何ですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeがクエリ実行時に不要なパーティションを排除できる最適化技術の名称は何ですか？</p>", "options": [{"key": "A", "label": "パーティションプルーニング（Partition pruning）"}, {"key": "B", "label": "述語最適化（Predicate optimization）"}, {"key": "C", "label": "WHERE句最適化"}, {"key": "D", "label": "必要なデータのみ取得（RNDO）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>パーティションプルーニング</strong></p><p>Snowflakeはデータをマイクロパーティションと呼ばれる小さな単位で保存します。各列について、どのマイクロパーティションにどの範囲のデータが格納されているかのメタデータを保持しており、クエリ実行時に不要なマイクロパーティションを排除（プルーニング）することでパフォーマンスを向上させます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 43, "title": "あなたは大規模な小売組織のデータモデラーで、「Transactions」テーブルにトランザクショ...", "multiSelect": false, "stemHtml": "<p>あなたは大規模な小売組織のデータモデラーで、「Transactions」テーブルにトランザクションデータを保存しています。毎日の売上レポートはこのテーブルを使用しています。テーブルのデータは元々500GBでしたが、現在5TBに増加し、日次レポートのパフォーマンスが低下しています。最も効率的でコスト効果の高い最適化方法はどれですか？</p>", "options": [{"key": "A", "label": "Transactionsテーブルをトランザクション日付列でクラスタリングする。"}, {"key": "B", "label": "年ごとにテーブルを分割（例：Transactions_2017、Transactions_2018）し、データを挿入してレポートを最新年のテーブルに向ける。"}, {"key": "C", "label": "日次レポートを実行する仮想ウェアハウスのサイズを増やす。"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>トランザクション日付列でのクラスタリング</strong></p><p>テーブルを特定の列でクラスタリングすることで、クエリ処理から不要なパーティションを除外できます。日次レポートは1日分のデータにアクセスするため、日付列でのクラスタリングが最も効率的です。これにより不要なマイクロパーティションのスキャンを大幅に削減できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 44, "title": "Snowflakeはどこにステージされたデータをロードできますか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeはどこにステージされたデータをロードできますか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Oracle Cloud Storage"}, {"key": "B", "label": "Azure Blob Storage"}, {"key": "C", "label": "AWS S3"}, {"key": "D", "label": "Google Cloud Storage"}, {"key": "E", "label": "VMWare Storage"}, {"key": "F", "label": "内部ステージ（Internal Stage）"}], "correctAnswers": ["B", "C", "D", "F"], "explanationHtml": "<p>✅ <strong>Azure Blob Storage / AWS S3 / Google Cloud Storage / 内部ステージ</strong></p><p>Snowflakeは内部ステージと外部ステージからのロードをサポートします。外部ステージはAWS S3、Azure Blob、Google Cloud Storageを使用できます。データは通常まずSnowflakeのステージに配置され、その後COPYコマンドでテーブルにロードされます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 45, "title": "管理者がCustomerテーブルをProspectsテーブルにクローンしました。その後、Cust...", "multiSelect": true, "stemHtml": "<p>管理者がCustomerテーブルをProspectsテーブルにクローンしました。その後、Customerテーブルに新しいデータをロードします。Prospectsテーブルはどうなりますか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "クローン操作のソースになったテーブルへのデータロードは失敗する。"}, {"key": "B", "label": "新しいデータはCustomerテーブルとそのクローンであるProspectsテーブルの両方にロードされる。"}, {"key": "C", "label": "新しいデータはCustomerテーブルのみに正常にロードされる。"}, {"key": "D", "label": "新しいデータはProspectsテーブルには表示されない。"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>Customerテーブルのみにロード / Prospectsには反映されない</strong></p><p>ソースとクローンのオブジェクトは独立しており、一方のデータを変更しても他方には影響しません。たとえば、ソーステーブルを削除しても、クローンされたテーブルには影響しません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローン", "originalCorrect": null, "reviewPoint": ""}}, {"order": 46, "title": "True or False: 仮想ウェアハウスが処理できる量よりも多くのクエリが送信されると、ク...", "multiSelect": false, "stemHtml": "<p>True or False: 仮想ウェアハウスが処理できる量よりも多くのクエリが送信されると、クエリはキューに入れられます。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>ウェアハウスにクエリが送信されると、ウェアハウスは各クエリに必要なリソースを割り当てて実行を開始します。すべてのクエリを実行するのに十分なリソースがない場合、Snowflakeはリソースが再び利用可能になるまで余分なクエリをキューに入れます。この問題を解決するためにマルチクラスター仮想ウェアハウスが用意されています。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 47, "title": "ディレクトリテーブルに関する正しい説明はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>ディレクトリテーブルに関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "ディレクトリテーブルでストリームを使用するには、ステージオブジェクトにストリームを作成する必要がある。"}, {"key": "B", "label": "ストリームはディレクトリテーブルで使用できない。"}, {"key": "C", "label": "ストリームはディレクトリテーブルで使用できる。"}, {"key": "D", "label": "ディレクトリテーブルでストリームを使用するには、ディレクトリテーブルオブジェクトにストリームを作成する必要がある。"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>ストリームは使用可能 / ステージオブジェクトに作成</strong></p><p>ストリームをディレクトリテーブルと併用することで、追加・削除・変更されたファイルを追跡できます。ストリームはステージオブジェクト上に作成する必要があります。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 48, "title": "ACCOUNT_USAGEスキーマの `DATABASE_STORAGE_USAGE_HISTO...", "multiSelect": true, "stemHtml": "<p>ACCOUNT_USAGEスキーマの <code>DATABASE_STORAGE_USAGE_HISTORY</code> ビューに関する正しい説明はどれですか？（4つ選択）</p>", "options": [{"key": "A", "label": "このビューは削除されたデータベースの情報を表示しない。"}, {"key": "B", "label": "このビューはすべてのデータベース（削除済みを含む）の情報を表示する。"}, {"key": "C", "label": "このビューにはリアルタイムの情報が含まれる。"}, {"key": "D", "label": "このビューはタイムトラベルストレージを含むデータベースストレージ使用バイト数を表示する。"}, {"key": "E", "label": "このビューはフェイルセーフストレージのバイト数を表示する。"}, {"key": "F", "label": "このビューは過去365日間の情報を含む。"}], "correctAnswers": ["B", "D", "E", "F"], "explanationHtml": "<p>✅ <strong>削除済み含む / タイムトラベル込みのストレージ / フェイルセーフ / 365日</strong></p><p><code>DATABASE_STORAGE_USAGE_HISTORY</code> ビューは、タイムトラベル内のデータを含む各データベースのストレージ使用量と、フェイルセーフストレージのバイト数を個別に表示します。ACCOUNT_USAGEの他のビューと同様に過去365日分のデータを表示し、最大3時間の遅延があります（リアルタイムではありません）。削除済みオブジェクトの情報も含まれます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 49, "title": "True or False: IPアドレスがネットワークポリシーのブロックリストと許可リストの両...", "multiSelect": false, "stemHtml": "<p>True or False: IPアドレスがネットワークポリシーのブロックリストと許可リストの両方に含まれている場合、Snowflakeはブロックリストを先に適用します。</p>", "options": [{"key": "A", "label": "False（誤り）"}, {"key": "B", "label": "True（正しい）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>許可リストとブロックリストの両方にIPアドレスが含まれている場合、Snowflakeはブロックリストを先に適用し、次に許可リストを適用します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 50, "title": "新しいSnowflakeアカウントを作成するためにSnowflakeユーザーに付与する必要がある...", "multiSelect": false, "stemHtml": "<p>新しいSnowflakeアカウントを作成するためにSnowflakeユーザーに付与する必要があるロールはどれですか？</p>", "options": [{"key": "A", "label": "SECURITYADMIN"}, {"key": "B", "label": "ACCOUNTADMIN"}, {"key": "C", "label": "ORGADMIN"}, {"key": "D", "label": "SYSADMIN"}, {"key": "E", "label": "GLOBALADMIN"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>ORGADMIN</strong></p><p>ORGADMINロールは、すべてのアカウントのリスト表示や新しいアカウントの作成など、組織固有のタスクを実行します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 51, "title": "Snowflakeは新しいソフトウェアをどのくらいの頻度でリリースしますか？", "multiSelect": false, "stemHtml": "<p>Snowflakeは新しいソフトウェアをどのくらいの頻度でリリースしますか？</p>", "options": [{"key": "A", "label": "毎週（Weekly）"}, {"key": "B", "label": "毎日（Daily）"}, {"key": "C", "label": "毎年（Yearly）"}, {"key": "D", "label": "隔週（Fortnightly）"}, {"key": "E", "label": "毎月（Monthly）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>毎週（Weekly）</strong></p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "一般", "originalCorrect": null, "reviewPoint": ""}}, {"order": 52, "title": "クエリ結果キャッシュはどのレベルで無効化できますか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>クエリ結果キャッシュはどのレベルで無効化できますか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "アカウント（Account）"}, {"key": "B", "label": "セッション（Session）"}, {"key": "C", "label": "ユーザー（User）"}, {"key": "D", "label": "テーブル（Table）"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>アカウント / セッション / ユーザー</strong></p><p>クエリ結果キャッシュはデフォルトで有効ですが、<code>USE_CACHED_RESULT</code> パラメータを使用して、セッション・ユーザー・アカウントレベルで無効化できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 53, "title": "外部関数（External Function）のリモートサービスとして使用できるものはどれですか...", "multiSelect": true, "stemHtml": "<p>外部関数（External Function）のリモートサービスとして使用できるものはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "EC2インスタンス上で動作するNode.js"}, {"key": "B", "label": "Microsoft Azure Function"}, {"key": "C", "label": "AWS Lambda Function"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>Node.js on EC2 / Azure Function / AWS Lambda</strong></p><p>これらはすべて外部関数の実装方法として有効な例です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 54, "title": "True or False: ACCOUNT_USAGEビューには削除されたオブジェクトの情報が...", "multiSelect": false, "stemHtml": "<p>True or False: ACCOUNT_USAGEビューには削除されたオブジェクトの情報が含まれています。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>ACCOUNT_USAGEビューにはドロップされたオブジェクトの情報が含まれ、多くのビューにはドロップされたオブジェクトの情報を示す <code>DELETED</code> 列があります。一方、INFORMATION_SCHEMAにはドロップされたオブジェクトは含まれません。また、ACCOUNT_USAGEビューには、同名で再作成されたオブジェクトを区別するためのID列も含まれます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 55, "title": "True or False: クラスタリングキーを定義する際は、カーディナリティが非常に高い列を...", "multiSelect": false, "stemHtml": "<p>True or False: クラスタリングキーを定義する際は、カーディナリティが非常に高い列を選択すべきです。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>クラスタリングキーの列は、効果的なパーティションプルーニングを可能にするほど十分に高いカーディナリティを持ちながら、Snowflakeがデータを効率的にマイクロパーティションにグループ化できる程度に低いカーディナリティであることが重要です。カーディナリティが低すぎる列（例：性別）はプルーニングが最小限になります。カーディナリティが高すぎる列（例：顧客ID）はパーティション維持のオーバーヘッドが大きくなります。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 56, "title": "タイムトラベルとフェイルセーフストレージに関する正しい説明はどれですか？（該当するものをすべて選...", "multiSelect": true, "stemHtml": "<p>タイムトラベルとフェイルセーフストレージに関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "一時テーブルの最大タイムトラベル期間は7日間である。"}, {"key": "B", "label": "一時テーブル（Transient Table）の最大タイムトラベル期間は1日間である。"}, {"key": "C", "label": "一時テーブルには7日間のフェイルセーフストレージがある。"}, {"key": "D", "label": "一時テーブルにはフェイルセーフストレージがない。"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>Transientテーブルのタイムトラベルは最大1日 / フェイルセーフなし</strong></p><p>TransientテーブルとTemporaryテーブルにはフェイルセーフ機能がなく（フェイルセーフ期間 = 0日）、タイムトラベルの最大期間は1日です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 57, "title": "True or False: 大規模テーブルのクラスタリングキーを定義する際は、WHERE句で頻...", "multiSelect": false, "stemHtml": "<p>True or False: 大規模テーブルのクラスタリングキーを定義する際は、WHERE句で頻繁に使用される列を選択することを検討すべきです。</p>", "options": [{"key": "A", "label": "False（誤り）"}, {"key": "B", "label": "True（正しい）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>クラスタリングキーの候補列は、WHERE句や選択的フィルターで頻繁に使用される列が最初の候補です。また、結合に使用される列も候補として考えられます。適切なカーディナリティを持つ列を選択することで、効果的なパーティションプルーニングが可能になります。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 58, "title": "True/False: 作成されたマイクロパーティションは不変（イミュータブル）であり、変更でき...", "multiSelect": false, "stemHtml": "<p>True/False: 作成されたマイクロパーティションは不変（イミュータブル）であり、変更できません。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>Snowflakeのパーティションは不変（イミュータブル）であり、作成後に変更することはできません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "マイクロパーティション", "originalCorrect": null, "reviewPoint": ""}}, {"order": 59, "title": "クエリプロファイルに表示される「Bytes spilled to remote storage（...", "multiSelect": false, "stemHtml": "<p>クエリプロファイルに表示される「Bytes spilled to remote storage（リモートストレージへのバイトスピル）」の正しい説明はどれですか？</p>", "options": [{"key": "A", "label": "「Bytes spilled to remote storage」は、仮想ウェアハウスのメモリにも一時ストレージにも収まりきらず、一時クラウドストレージにスピルされたデータ量を示す。"}, {"key": "B", "label": "「Bytes spilled to remote storage」はネットワーク障害を示す。"}, {"key": "C", "label": "「Bytes spilled to remote storage」はオンプレミスシステムからファイルがロードされていることを示す。"}, {"key": "D", "label": "「Bytes spilled to remote storage」はPUTコマンドでアップロードされたデータ量を示す。"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>メモリ・一時ストレージ不足によりリモートクラウドストレージにスピルされたデータ量</strong></p><p>Snowflakeは操作をメモリに収めることができない場合、ウェアハウスのローカルディスクにデータを保存します（「Bytes spilled to local storage」）。ローカルディスクも満杯になると、リモートクラウドストレージにスピルします（「Bytes spilled to remote storage」）。リモートストレージへのスピルはローカルよりさらに遅く、クエリパフォーマンスを大幅に低下させます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 60, "title": "フェイルセーフは、タイムトラベルの保持期間が終了した後に履歴データにアクセスするための代替手段と...", "multiSelect": false, "stemHtml": "<p>フェイルセーフは、タイムトラベルの保持期間が終了した後に履歴データにアクセスするための代替手段として、Snowflakeユーザーが利用できます。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>タイムトラベル期間が終了した後、フェイルセーフはさらに7日間データを保存します。フェイルセーフはデータ損失に対する追加の安全策ですが、Snowflakeサポートチームのみがフェイルセーフストレージからデータを復元できます。エンドユーザーが履歴データにアクセスするためのものではなく、Snowflakeサポートによる誤ったデータ損失からの回復のためのものです。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 61, "title": "True or False: 異なるリージョンにSnowflakeインスタンスを作成するには、各...", "multiSelect": false, "stemHtml": "<p>True or False: 異なるリージョンにSnowflakeインスタンスを作成するには、各リージョンで別々のSnowflakeアカウントを維持する必要があります。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>各Snowflakeアカウントは特定のSnowflakeリージョンでホストされています。複数のリージョンでSnowflakeを使用するには、各リージョンに少なくとも1つのSnowflakeアカウントを維持する必要があります。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 62, "title": "Snowflakeステージにある非構造化データを、ユーザーやアプリケーションがダウンロードできる...", "multiSelect": false, "stemHtml": "<p>Snowflakeステージにある非構造化データを、ユーザーやアプリケーションがダウンロードできるようにするファイル関数はどれですか？</p>", "options": [{"key": "A", "label": "GET_PRESIGNED_URL"}, {"key": "B", "label": "GET_DATA_FROM_STAGE"}, {"key": "C", "label": "BUILD_SCOPED_FILE_URL"}, {"key": "D", "label": "BUILD_STAGE_FILE_URL"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>GET_PRESIGNED_URL</strong></p><p>プリサインドURLは、Webブラウザを使用してファイルにアクセスするためのシンプルなHTTPS URLです。プリサインドアクセストークンを使用して生成されます。ユーザーは認証なしでプリサインドURLを介して一時的にファイルにアクセスできます。有効期限は設定可能です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 63, "title": "検索最適化（Search Optimization）がサポートしていないものはどれですか？（3つ...", "multiSelect": true, "stemHtml": "<p>検索最適化（Search Optimization）がサポートしていないものはどれですか？（3つ選択）</p>", "options": [{"key": "A", "label": "日付列（Date Columns）"}, {"key": "B", "label": "外部テーブル（External Tables）"}, {"key": "C", "label": "テーブル列へのキャスト（Cast on table columns）"}, {"key": "D", "label": "整数列（Integer Columns）"}, {"key": "E", "label": "マテリアライズドビュー（Materialized Views）"}], "correctAnswers": ["B", "C", "E"], "explanationHtml": "<p>✅ <strong>外部テーブル / テーブル列へのキャスト / マテリアライズドビュー</strong></p><p>検索最適化がサポートしないもの：外部テーブル、マテリアライズドビュー、COLLATEが指定された列、列の連結、分析式、テーブル列へのキャスト（固定小数点数から文字列へのキャストを除く）</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 64, "title": "外部テーブルに関する正しい説明はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>外部テーブルに関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "外部テーブルは外部ステージのみをサポートする。"}, {"key": "B", "label": "外部テーブルのデータは顧客が管理するクラウドストレージに保存される。"}, {"key": "C", "label": "外部テーブルは内部ステージをサポートする。"}, {"key": "D", "label": "外部テーブルはTransientテーブルの別名である。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>外部ステージのみ / 顧客管理のクラウドストレージ</strong></p><p>外部テーブルはメタデータ定義であり、テーブル自体にはデータが含まれません。テーブルのメタデータには列定義、外部ステージ名、ファイルフォーマットが含まれます。外部ステージはAWS S3、Azure Blob Storageなどのクラウドストレージを参照します。外部テーブルは外部ステージのみを参照でき、内部ステージは使用できません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 65, "title": "SnowflakeのデータベースはTeradata、Greenplum、Hadoopなどで使用さ...", "multiSelect": false, "stemHtml": "<p>SnowflakeのデータベースはTeradata、Greenplum、Hadoopなどで使用される大規模並列共有なし（Massively Parallel Shared Nothing）アーキテクチャに基づいています。</p>", "options": [{"key": "A", "label": "いいえ（No）"}, {"key": "B", "label": "はい（Yes）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>いいえ（No）</strong></p><p>Snowflakeは、共有ディスクアーキテクチャと共有なしアーキテクチャの両方の優れた特性を組み合わせた新しいハイブリッドアーキテクチャを実装しています。Snowflakeは共有ディスクアーキテクチャと同様にデータを共有して保存しますが、それぞれ独自のメモリと処理能力を持つ複数のコンピュートエンジンの使用も可能にします。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 66, "title": "True or False: INFORMATION_SCHEMAで提供される関数を使用して、ア...", "multiSelect": false, "stemHtml": "<p>True or False: INFORMATION_SCHEMAで提供される関数を使用して、アカウントレベルの情報を表示できます。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>INFORMATION_SCHEMAは、親データベース内のオブジェクトのデータを提供するとともに、ロール、ウェアハウス、データベースなどのアカウントレベルのオブジェクトに関するデータも提供します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 67, "title": "Snowflakeのシェアに追加できるコンシューマーアカウントは1つだけです。", "multiSelect": false, "stemHtml": "<p>Snowflakeのシェアに追加できるコンシューマーアカウントは1つだけです。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>Snowflakeのシェアには、ゼロ、1つ、または複数のコンシューマーを追加できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 68, "title": "コストの節約を目的としたスケーリングポリシーはどれですか？", "multiSelect": false, "stemHtml": "<p>コストの節約を目的としたスケーリングポリシーはどれですか？</p>", "options": [{"key": "A", "label": "Fast"}, {"key": "B", "label": "Economy（エコノミー）"}, {"key": "C", "label": "Standard"}, {"key": "D", "label": "Efficient"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Economy（エコノミー）</strong></p><p>Economyスケーリングポリシーは、パフォーマンスやユーザーエクスペリエンスよりもクレジットの節約を優先します。キューイングが検出されてもすぐに追加ウェアハウスを起動せず、追加基準を適用して判断します。Standardポリシーはキューイングを検出するとほぼ即座に追加ウェアハウスを起動し、キューイングの防止・最小化を目指します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 69, "title": "True or False: データをアンロードする際、各エクスポートファイルは16MBで、この...", "multiSelect": false, "stemHtml": "<p>True or False: データをアンロードする際、各エクスポートファイルは16MBで、この設定は変更できません。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>各出力ファイルのデフォルトサイズは16MBですが、<code>MAX_FILE_SIZE</code> パラメータで変更できます。クラウドストレージへのエクスポート時のファイルあたりの最大サイズは5GBです。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 70, "title": "外部テーブルに関する正しい説明はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>外部テーブルに関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "外部テーブルは通常のテーブルと同様にクエリを実行できる。"}, {"key": "B", "label": "外部テーブルは他のテーブルとJOINできる。"}, {"key": "C", "label": "外部テーブルはクエリを実行できない。"}, {"key": "D", "label": "外部テーブルは他のテーブルとJOINできない。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>通常テーブルと同様にクエリ可 / JOIN可</strong></p><p>外部テーブルを使用すると、データをSnowflakeにロードすることなく外部データを標準テーブルと同様にクエリできます。外部テーブルは他のテーブルとJOINでき、ビューも作成できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 71, "title": "True or False: SnowpipeのCOPYコマンドは、通常のCOPYコマンドと同じ...", "multiSelect": false, "stemHtml": "<p>True or False: SnowpipeのCOPYコマンドは、通常のCOPYコマンドと同じ変換をサポートしています。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>SnowpipeはCOPYコマンドをその定義に使用しており、COPYコマンドで利用可能な同じ変換をサポートできます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 72, "title": "Snowflakeのデータ統合パートナーはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeのデータ統合パートナーはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "AbInitio"}, {"key": "B", "label": "IBM DataStage"}, {"key": "C", "label": "Informatica"}, {"key": "D", "label": "Talend"}, {"key": "E", "label": "Matillion"}], "correctAnswers": ["A", "B", "C", "D", "E"], "explanationHtml": "<p>✅ <strong>すべて正しい</strong></p><p>これらはすべてSnowflakeのデータ統合パートナーです。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パートナー", "originalCorrect": null, "reviewPoint": ""}}, {"order": 73, "title": "Snowsightインターフェースのクエリ履歴ページで、クエリが表示される期間はどれくらいですか...", "multiSelect": false, "stemHtml": "<p>Snowsightインターフェースのクエリ履歴ページで、クエリが表示される期間はどれくらいですか？</p>", "options": [{"key": "A", "label": "14日間"}, {"key": "B", "label": "28日間"}, {"key": "C", "label": "3ヶ月"}, {"key": "D", "label": "60分"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>14日間</strong></p><p>クエリ履歴ページでは、過去14日間に実行されたクエリの履歴を表示できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 74, "title": "多要素認証（MFA）を有効にできるものはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>多要素認証（MFA）を有効にできるものはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "SnowSQL"}, {"key": "B", "label": "Snowpipe"}, {"key": "C", "label": "Snowflake WebUI（ウェブインターフェース）"}, {"key": "D", "label": "JDBC"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>SnowSQL / WebUI / JDBC</strong></p><p>MFAはデフォルトですべてのSnowflakeアカウントで有効であり、すべてのエディションで利用できます。ウェブインターフェース、SnowSQL、各種コネクター・ドライバーなどすべてのSnowflakeクライアントツールがMFAをサポートします。SnowpipeはSnowflake管理のサーバーレスサービスであり、ユーザーがログインするものではないためMFAは不要です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 75, "title": "ストアドプロシージャが返せる結果の種類はどれですか？", "multiSelect": true, "stemHtml": "<p>ストアドプロシージャが返せる結果の種類はどれですか？</p>", "options": [{"key": "A", "label": "表形式データ（Tabular Data）"}, {"key": "B", "label": "実行可能ファイル（Exe files）"}, {"key": "C", "label": "単一の値（Single Value）"}, {"key": "D", "label": "バイナリ実行可能ファイル（Binary Executables）"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>表形式データ / 単一の値</strong></p><p>ストアドプロシージャは単一の値または表形式データを返すことができます（ただし、値の返却は必須ではありません）。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 76, "title": "システム管理者が新しい仮想ウェアハウスの初期サイズを決定するための最良の方法はどれですか？", "multiSelect": false, "stemHtml": "<p>システム管理者が新しい仮想ウェアハウスの初期サイズを決定するための最良の方法はどれですか？</p>", "options": [{"key": "A", "label": "パフォーマンスを確保するためにX-Largeを選択する。"}, {"key": "B", "label": "コストを節約するためにX-Smallを選択する。"}, {"key": "C", "label": "様々な種類のクエリとウェアハウスサイズを試して、クエリのニーズとワークロードに最適な組み合わせを見つける。"}, {"key": "D", "label": "Snowflakeに連絡して、組織に適したサイズを決めてもらう。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>様々なクエリとサイズの組み合わせを試して最適な選択を見つける</strong></p><p>特定のクエリ要件とワークロードに対して最適な組み合わせを決定するために、X-Large、Large、Mediumなどのウェアハウスサイズとクエリのセットを使って実験することが推奨されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 77, "title": "ACCOUNTADMINロールに関する正しい説明はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>ACCOUNTADMINロールに関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "ACCOUNTADMINロールを持つユーザーはリソースモニターを作成・管理できる。"}, {"key": "B", "label": "ACCOUNTADMINロールを持つユーザーは課金情報を見ることができない。"}, {"key": "C", "label": "ACCOUNTADMINロールはフルアクセス権を持つ最も強力なアカウントである。"}, {"key": "D", "label": "ACCOUNTADMINロールを持つユーザーは新しいリーダーアカウントを作成できない。"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>リソースモニターの作成・管理可 / フルアクセス権を持つ最強ロール</strong></p><p>ACCOUNTADMINはフルアクセス権を持つアカウント管理者ロールです。最も強力なロールであるため、このロールへのアクセスは厳格に管理する必要があります。SECURITYADMINとSYSADMINロールを包含しており、両者の権限をすべて持ちます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 78, "title": "True/False: 複数の仮想ウェアハウスを作成した場合、それらはメモリとCPUリソースを共...", "multiSelect": false, "stemHtml": "<p>True/False: 複数の仮想ウェアハウスを作成した場合、それらはメモリとCPUリソースを共有します。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>Snowflakeは共有ディスクアーキテクチャのようにデータを共有して保存しますが、それぞれ独自のメモリと処理能力を持つ複数のコンピュートエンジンの使用を可能にします。仮想ウェアハウスは互いに独立していますが、同じ共有データにアクセスして処理します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 79, "title": "コンシューマーアカウントのユーザーがシェアからデータベースを作成できる権限はどれですか？（2つ選...", "multiSelect": true, "stemHtml": "<p>コンシューマーアカウントのユーザーがシェアからデータベースを作成できる権限はどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "IMPORT SHARE権限"}, {"key": "B", "label": "ACCOUNTADMINロール"}, {"key": "C", "label": "SYSADMINロール"}, {"key": "D", "label": "SECURITY ADMINロール"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>IMPORT SHARE権限 / ACCOUNTADMINロール</strong></p><p>コンシューマーアカウントのユーザーが、ACCOUNTADMINロールまたはIMPORT SHARE権限を持っている場合、シェアからデータベースを作成できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 80, "title": "COPYコマンドでサポートされていない変換はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>COPYコマンドでサポートされていない変換はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "GROUP BY"}, {"key": "B", "label": "JOIN"}, {"key": "C", "label": "SUM"}, {"key": "D", "label": "列の切り捨て（Truncate columns）"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>GROUP BY / JOIN / SUM</strong></p><p>COPYコマンドを使用してデータをロードする際、列の順序変更・列の省略・データ型のキャスト・値の切り捨てなどのシンプルな変換が可能です。ただし、JOIN、フィルター、集計、FLATTENの使用などの複雑な変換はサポートされていません。これらはデータがテーブルにロードされた後にのみ実行できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 81, "title": "True or False: ステージからテーブルにすでにロードされたファイルは、クローンされた...", "multiSelect": false, "stemHtml": "<p>True or False: ステージからテーブルにすでにロードされたファイルは、クローンされたテーブルに再度ロードできます。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>クローンはソーステーブルのロードメタデータをコピーしないため、クローンされたテーブルのロードメタデータは空になります。したがって、ソーステーブルにロード済みのファイルをクローンされたテーブルに再度ロードできます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 82, "title": "タイムトラベルをサポートするSnowflakeエディションはどれですか？（該当するものをすべて選...", "multiSelect": true, "stemHtml": "<p>タイムトラベルをサポートするSnowflakeエディションはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Business Critical"}, {"key": "B", "label": "Enterprise"}, {"key": "C", "label": "Standard"}, {"key": "D", "label": "Virtual Private Snowflake"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>すべてのエディション</strong></p><p>タイムトラベルはすべてのSnowflakeエディションでサポートされています。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 83, "title": "Snowflake Marketplaceを閲覧するために必要な最低Snowflakeエディショ...", "multiSelect": false, "stemHtml": "<p>Snowflake Marketplaceを閲覧するために必要な最低Snowflakeエディションはどれですか？</p>", "options": [{"key": "A", "label": "Snowflakeエディションは不要（Marketplaceのリストは誰でも閲覧可）"}, {"key": "B", "label": "Business Critical"}, {"key": "C", "label": "Enterprise"}, {"key": "D", "label": "Virtual Private Snowflake"}, {"key": "E", "label": "Standard"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>Snowflakeエディションは不要</strong></p><p>Snowflake Marketplaceは非Snowflakeユーザーでも閲覧できますが、データを利用するにはSnowflakeエディションへの登録が必要です。なお、VPSはData Marketplaceをサポートしていません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 84, "title": "マイクロパーティションに関する正しい説明はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>マイクロパーティションに関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "マイクロパーティションは新しいデータが到着した順にテーブルに作成・追加される。"}, {"key": "B", "label": "列の値はマイクロパーティション間でオーバーラップする可能性がある。"}, {"key": "C", "label": "Snowflakeは各マイクロパーティション内の列を行ストレージ形式で保存する。"}, {"key": "D", "label": "列の値はマイクロパーティション間でオーバーラップすることはない。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>データ到着順に作成 / 値のオーバーラップあり</strong></p><p>マイクロパーティションは不変であるため、新しいデータや変更されたデータは新しいマイクロパーティションに追加する必要があります。同様の値が同じ物理パーティションに存在しない場合があります。Snowflakeでは他のデータベースとは異なり、異なるマイクロパーティション間で値がオーバーラップすることがあります。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 85, "title": "以下のクエリプロファイルを正しく説明しているものはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>以下のクエリプロファイルを正しく説明しているものはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "このクエリプロファイルは、以前のクエリで生成された結果が再利用されたことを示している。"}, {"key": "B", "label": "このクエリプロファイルは、このクエリでアクティブな仮想ウェアハウスが不要であったことを示している。"}, {"key": "C", "label": "このクエリプロファイルは仮想ウェアハウスキャッシュが使用されたことを示している。"}, {"key": "D", "label": "このクエリプロファイルはメタデータキャッシュが使用されたことを示している。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>以前のクエリ結果の再利用 / ウェアハウス不要</strong></p><p>クエリ結果キャッシュが使用された場合、以前に実行されたクエリの結果が再利用されます。この場合、コンピュートリソース（アクティブな仮想ウェアハウス）は不要です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 86, "title": "Snowsightのユーザープロファイルで設定できるものはどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>Snowsightのユーザープロファイルで設定できるものはどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "デフォルトロール（Default Role）"}, {"key": "B", "label": "デフォルトスキーマ（Default schema）"}, {"key": "C", "label": "デフォルトウェアハウス（Default Warehouse）"}, {"key": "D", "label": "デフォルトデータベース（Default database）"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>デフォルトロール / デフォルトウェアハウス</strong></p><p>Snowsightのプロファイルダイアログを使用して、MFAへの登録、通知設定、メールアドレスの設定、デフォルトロールとデフォルトウェアハウスの設定が可能です。名前、パスワード、言語なども設定できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 87, "title": "Snowflakeがクエリ結果キャッシュを再利用するために満たすべき条件はどれですか？（該当する...", "multiSelect": true, "stemHtml": "<p>Snowflakeがクエリ結果キャッシュを再利用するために満たすべき条件はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "クエリ結果に寄与する基礎データが変更されていない。"}, {"key": "B", "label": "クエリがユーザー定義または外部関数を使用していない。"}, {"key": "C", "label": "テーブルのマイクロパーティションが再クラスタリングや統合によって変更されていない。"}, {"key": "D", "label": "クエリがランタイム関数を使用していない。"}, {"key": "E", "label": "新しいクエリが以前のクエリと一致する。"}], "correctAnswers": ["A", "B", "C", "D", "E"], "explanationHtml": "<p>✅ <strong>すべて正しい</strong></p><p>Snowflakeがクエリ結果キャッシュを使用する条件：①新しいクエリが以前のクエリと一致する、②クエリ結果に寄与するデータが変更されていない、③テーブルのマイクロパーティションがクラスタリングや統合によって変更されていない、④ユーザー定義・外部・ランタイム関数を使用していない。なお、<code>CURRENT_DATE</code> 関数を使用するクエリはクエリ結果キャッシュの対象になります。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 88, "title": "SYSADMINロールに関する正しい説明はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>SYSADMINロールに関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "SYSADMINロールを持つユーザーは新しいユーザーを作成できる。"}, {"key": "B", "label": "SYSADMINロールを持つユーザーは新しいデータベースを作成できる。"}, {"key": "C", "label": "SYSADMINロールを持つユーザーは新しい仮想ウェアハウスを作成できる。"}, {"key": "D", "label": "SYSADMINロールを持つユーザーは新しいロールを作成できる。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>データベース作成可 / 仮想ウェアハウス作成可</strong></p><p>SYSADMINロールはデータベース、テーブル、ビュー、仮想ウェアハウスなど、ほとんどのSnowflakeオブジェクトを作成・管理できます。ただし、新しいユーザーやロールを作成する権限は持っていません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 89, "title": "True/False: Snowflakeアーキテクチャでは、コンピュートとストレージを独立して...", "multiSelect": false, "stemHtml": "<p>True/False: Snowflakeアーキテクチャでは、コンピュートとストレージを独立してスケーリングできます。</p>", "options": [{"key": "A", "label": "False（誤り）"}, {"key": "B", "label": "True（正しい）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>Snowflakeは共有ディスクアーキテクチャのようにデータを共有して保存しますが、それぞれ独自のメモリと処理能力を持つ複数のコンピュートエンジンの使用も可能にします。このアーキテクチャにより、コンピュートとストレージを独立してスケーリングできます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 90, "title": "True or False: ACCOUNT_USAGEスキーマのビューのデータは最大3時間の遅...", "multiSelect": false, "stemHtml": "<p>True or False: ACCOUNT_USAGEスキーマのビューのデータは最大3時間の遅延が生じる可能性があります。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>ACCOUNT_USAGEスキーマのビューはアカウントレベルの使用メトリクスとメタデータ情報を提供しますが、リアルタイムではなく、ビューによって45分から3時間程度のラグがあります。データは最大365日間保持されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 91, "title": "True/False: TransientテーブルのタイムトラベルのRetention期間が終了...", "multiSelect": false, "stemHtml": "<p>True/False: TransientテーブルのタイムトラベルのRetention期間が終了すると、そのテーブルの履歴データをSnowflakeサポートでも回復できません。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True（正しい）</strong></p><p>TransientテーブルとTemporaryテーブルにはフェイルセーフ機能がなく（フェイルセーフ = 0日）、タイムトラベルの最大期間は1日です。これらのテーブルのタイムトラベル期間が終了すると、履歴データを回復する方法はありません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ保護", "originalCorrect": null, "reviewPoint": ""}}, {"order": 92, "title": "Snowflakeが自動的に提供するデータ保護機能はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeが自動的に提供するデータ保護機能はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "増分バックアップ（Incremental Backups）"}, {"key": "B", "label": "フェイルセーフ（Fail-Safe）"}, {"key": "C", "label": "テープバックアップ（Tape Backups）"}, {"key": "D", "label": "タイムトラベル（Time Travel）"}, {"key": "E", "label": "オンプレミスへのバックアップ（Backups to on-premises）"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>フェイルセーフ / タイムトラベル</strong></p><p>Snowflakeはタイムトラベルとフェイルセーフを提供します。タイムトラベルはテーブルに保存された過去のデータへのアクセス・取得・回復を可能にします（1〜90日）。フェイルセーフストレージはタイムトラベル期間終了後さらに7日間データを保持します。フェイルセーフからのデータ回復はSnowflakeサポートのみが実施できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローン", "originalCorrect": null, "reviewPoint": ""}}, {"order": 93, "title": "Snowpipeを正しく説明しているものはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowpipeを正しく説明しているものはどれですか？</p>", "options": [{"key": "A", "label": "Snowpipeはバックアップと回復に使用される。"}, {"key": "B", "label": "Snowpipeは大量のデータをバッチ方式でロードするために使用される。"}, {"key": "C", "label": "Snowpipeは頻繁・継続的に届く少量のデータをロードするために使用される。"}, {"key": "D", "label": "Snowpipeは通信のためのセキュアパイプを提供するセキュリティメカニズムである。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>頻繁・継続的な少量データのロード</strong></p><p>Snowflakeはサーバーレスサービスであるマイクロバッチ方式のSnowpipeを使用して継続的なデータロードを可能にします。Snowpipeはトランザクションやイベントなどの継続的なデータストリームをステージ到着後数分以内にロードします。Snowpipeはサーバーレスで独自のコンピュート能力を持ち、仮想ウェアハウスに依存せず、コストも仮想ウェアハウスとは別に課金されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 94, "title": "専用メタデータストアをサポートする最低Snowflakeエディションはどれですか？", "multiSelect": false, "stemHtml": "<p>専用メタデータストアをサポートする最低Snowflakeエディションはどれですか？</p>", "options": [{"key": "A", "label": "Enterprise"}, {"key": "B", "label": "Virtual Private Snowflake"}, {"key": "C", "label": "Business Critical"}, {"key": "D", "label": "Standard"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Virtual Private Snowflake</strong></p><p>VPSエディションは他の顧客からの分離を提供するために設計されており、各インスタンスが独自のメタデータストアとコンピュートリソースを持ちます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 95, "title": "データ処理パイプラインの一部として、中間テーブルに一時的にデータを保存する必要があります。パイプ...", "multiSelect": false, "stemHtml": "<p>データ処理パイプラインの一部として、中間テーブルに一時的にデータを保存する必要があります。パイプラインの最初のプロセスは中間テーブルの既存データをすべて削除し、新しいデータをロードします。その後、パイプラインの複数の独立したプロセスがこのデータを使用します。ストレージコストを最小化するには、どのタイプのテーブルを作成しますか？</p>", "options": [{"key": "A", "label": "Temporary（一時テーブル）"}, {"key": "B", "label": "Permanent（永続テーブル）"}, {"key": "C", "label": "Transient（トランジェントテーブル）"}, {"key": "D", "label": "External（外部テーブル）"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Transientテーブル</strong></p><p>要件に基づくと、Transientテーブルが最適な選択です。Transientテーブルはフェイルセーフストレージを持たず、タイムトラベルは最大1日のみです。このシナリオでは毎日データが削除・再ロードされるため、Transientテーブルが最適です。また、複数のセッションやプロセスからアクセスできるため、独立したプロセスがデータを共有できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ保護", "originalCorrect": null, "reviewPoint": ""}}, {"order": 96, "title": "シェア内のデータへのアクセスを制御し、有料顧客のみに特定のデータを許可するために使用できるシステ...", "multiSelect": false, "stemHtml": "<p>シェア内のデータへのアクセスを制御し、有料顧客のみに特定のデータを許可するために使用できるシステム関数はどれですか？</p>", "options": [{"key": "A", "label": "SYSTEM$DISABLE_BEHAVIOR_CHANGE_BUNDLE"}, {"key": "B", "label": "SYSTEM$IS_LISTING_PURCHASED"}, {"key": "C", "label": "SYSTEM$ALLOWLIST"}, {"key": "D", "label": "SYSTEM$BLOCK_INTERNAL_STAGES_PUBLIC_ACCESS"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>SYSTEM$IS_LISTING_PURCHASED</strong></p><p><code>SYSTEM$IS_LISTING_PURCHASED</code> システム関数は、有料顧客とトライアル顧客に対して、どのデータを表示するかを制御するために使用できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 97, "title": "以下の構造のテーブルに、以下のJSONデータがすでにロードされているとします。", "multiSelect": false, "stemHtml": "<p>以下の構造のテーブルに、以下のJSONデータがすでにロードされているとします。</p>", "options": [{"key": "A", "label": "VARIANTに格納されているため、このデータにアクセスする方法はない。"}, {"key": "B", "label": "`SELECT extract(date_extracted from json_data) FROM my_json_table;`"}, {"key": "C", "label": "`SELECT json_data:date_extracted FROM my_json_table;`"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong><code>SELECT json_data:date_extracted FROM my_json_table;</code></strong></p><p>SnowflakeでVARIANT列に保存されたJSONデータにアクセスするには、コロン（<code>:</code>）を使用したパス記法を使用します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 98, "title": "True/False: Snowflakeアカウントのフェイルセーフを完全に無効化することは可能...", "multiSelect": false, "stemHtml": "<p>True/False: Snowflakeアカウントのフェイルセーフを完全に無効化することは可能です。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>タイムトラベル期間が終了すると、Snowflakeはさらに7日間データをフェイルセーフとして保持します。このフェイルセーフは無効化や設定変更はできません。ただし、TransientまたはTemporaryテーブルを使用することで、フェイルセーフ期間が0日のテーブルを作成することは可能です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 99, "title": "複数の異なるデータベース内のテーブルからデータを共有する必要があります。共有プロセスを簡素化する...", "multiSelect": false, "stemHtml": "<p>複数の異なるデータベース内のテーブルからデータを共有する必要があります。共有プロセスを簡素化するための推奨アプローチはどれですか？</p>", "options": [{"key": "A", "label": "データベースごとに1つのシェアを作成する。"}, {"key": "B", "label": "複数のデータベースのデータを統合するセキュアビューを単一データベースに作成し、そのデータベースを共有する。"}, {"key": "C", "label": "別々のデータベースからテーブルをクローンして新しいデータベースに作成し、そのデータベースを共有する。"}, {"key": "D", "label": "様々なテーブルのすべてのデータを新しいデータベースの新しいテーブルにコピーし、そのデータベースを共有する。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>セキュアビューを作成して単一データベースを共有する</strong></p><p>複数の異なるデータベースのデータを共有する必要がある場合、単一のデータベース内にセキュアビューを作成し、そのデータベースを共有することをSnowflakeは推奨しています。1つのシェアに複数のデータベースを追加できないためです。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 100, "title": "`FLIGHTS_STAGE` という名前の外部ステージがあるとします。以下のコマンドのうち、同...", "multiSelect": true, "stemHtml": "<p><code>FLIGHTS_STAGE</code> という名前の外部ステージがあるとします。以下のコマンドのうち、同じ列セットを結果として出力するものはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "`LIST @FLIGHTS_STAGE;`"}, {"key": "B", "label": "`SELECT * FROM DIRECTORY(@FLIGHTS_STAGE) WHERE SIZE > 1000;`"}, {"key": "C", "label": "`SELECT * FROM DIRECTORY(@FLIGHTS_STAGE);`"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>2つのDIRECTORYクエリ</strong></p><p>ディレクトリテーブルをクエリした結果の列と、ステージをリストした結果の列は異なります。DIRECTORYクエリ同士（<code>WHERE</code>句の有無にかかわらず）は同じ列構造を持ちます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 101, "title": "True or False: テーブルがクローンされた後、ソーステーブルのデータを更新すると、ク...", "multiSelect": false, "stemHtml": "<p>True or False: テーブルがクローンされた後、ソーステーブルのデータを更新すると、クローンされたテーブルのデータも自動的に更新されます。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>クラウドサービス層のマイクロパーティションとメタデータにより、クローンされたテーブルのメタデータが既存のマイクロパーティションを参照するため、ゼロコピークローニングが高速・効率的に行われます。ソースとクローンのオブジェクトは独立しており、一方を変更しても他方には影響しません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローン", "originalCorrect": null, "reviewPoint": ""}}, {"order": 102, "title": "あなたは大手小売業者のデータベース管理者です。5TB超のデータを含むイベントテーブルがあり、クラ...", "multiSelect": false, "stemHtml": "<p>あなたは大手小売業者のデータベース管理者です。5TB超のデータを含むイベントテーブルがあり、クラスタリングキーが定義されていません。<code>event_date</code> 列にクラスタリングキーを追加するための最良の方法はどれですか？</p>", "options": [{"key": "A", "label": "ALTERステートメントを使用してクラスタリングキーを追加する：`ALTER TABLE events CLUSTER BY (Event_date);`"}, {"key": "B", "label": "同じ構造の新しいテーブル `events_2` をクラスタリングキーとともに作成し、データを挿入後に元テーブルをドロップして名前変更する。"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>ALTERステートメントの使用</strong></p><p>既存のテーブルにクラスタリングキーを追加する最も簡単な方法は、ALTERステートメントでCLUSTER BY句を使用することです。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 103, "title": "True or False: ACCOUNTADMINはSnowflakeシステム内のすべてのユ...", "multiSelect": false, "stemHtml": "<p>True or False: ACCOUNTADMINはSnowflakeシステム内のすべてのユーザーが実行したクエリの結果を確認できます。</p>", "options": [{"key": "A", "label": "False（誤り）"}, {"key": "B", "label": "True（正しい）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>自分自身が実行したクエリの結果のみを確認できます。管理者として別のユーザーが実行したクエリを閲覧する権限がある場合でも、クエリの詳細は表示されますが、データプライバシーの観点から実際のクエリ結果は表示されません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 104, "title": "マテリアライズドビューを正しく説明しているものはどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューを正しく説明しているものはどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "マテリアライズドビューはデータ共有を有効にするために作成される。"}, {"key": "B", "label": "マテリアライズドビューは特定のクエリのパフォーマンスを向上させるために作成される。"}, {"key": "C", "label": "マテリアライズドビューのリフレッシュは自動的に行われる。"}, {"key": "D", "label": "マテリアライズドビューはすべてのクエリのパフォーマンスを向上させるために作成される。"}, {"key": "E", "label": "マテリアライズドビューは手動でリフレッシュする必要がある。"}, {"key": "F", "label": "マテリアライズドビューのクエリは基となるテーブルよりも通常遅い。"}, {"key": "G", "label": "マテリアライズドビューの定義には複数のテーブルとJOINを含めることができる。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>特定クエリのパフォーマンス向上 / 自動リフレッシュ</strong></p><p>マテリアライズドビューはSELECTクエリに基づいてデータを事前計算するビューです。結果は事前計算されて物理的に保存され、同様のクエリのパフォーマンスを向上させます。基となるテーブルが更新されると自動的にリフレッシュされます（バックグラウンドで透過的に処理）。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 105, "title": "PUTコマンドを使用してSnowflake内部ステージにデータをアップロードする際のデータ暗号化...", "multiSelect": true, "stemHtml": "<p>PUTコマンドを使用してSnowflake内部ステージにデータをアップロードする際のデータ暗号化に関する正しい説明はどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "データはSnowflake内部ステージに暗号化された状態で保存される。"}, {"key": "B", "label": "データはクライアントマシンで自動的に暗号化されてからSnowflake内部ステージに転送される。"}, {"key": "C", "label": "PUTコマンドは暗号化をサポートしていない。"}, {"key": "D", "label": "Snowflakeの内部ステージは暗号化をサポートしていない。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>クライアント側で暗号化 / 内部ステージに暗号化保存</strong></p><p>データはクライアントマシンで自動的に暗号化されてからSnowflake内部ステージに転送されます。内部ステージに配置されると、暗号化された状態で保存されます。これはSnowflakeが管理するエンドツーエンド暗号化の一部です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 106, "title": "Snowflakeに接続するために使用されるコマンドラインツールはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeに接続するために使用されるコマンドラインツールはどれですか？</p>", "options": [{"key": "A", "label": "Snowmobile"}, {"key": "B", "label": "Snowsight"}, {"key": "C", "label": "Snowpipe"}, {"key": "D", "label": "SnowSQL"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>SnowSQL</strong></p><p>コマンドラインクライアント（CLI）はSnowSQLとも呼ばれ、コマンドラインインターフェースを介してSnowflakeインスタンスに接続する方法です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 107, "title": "Snowflakeはカスタムロールを事前定義された ____________ ロールに割り当てる...", "multiSelect": false, "stemHtml": "<p>Snowflakeはカスタムロールを事前定義された ____________ ロールに割り当てることを推奨しています。</p>", "options": [{"key": "A", "label": "ORGADMIN"}, {"key": "B", "label": "ACCOUNTADMIN"}, {"key": "C", "label": "USERADMIN"}, {"key": "D", "label": "SYSADMIN"}, {"key": "E", "label": "SECURITYADMIN"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>SYSADMIN</strong></p><p>Snowflakeは、カスタムロールの階層を確立し、最上位のカスタムロールを事前定義のシステムロールであるSYSADMINに付与することを推奨しています。SYSADMINはシステム内のすべてのセキュアオブジェクトの所有者として機能し、これらのオブジェクトを管理できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 108, "title": "True or False: Snowflakeはすべてのお客様に同時に新しいソフトウェアバージ...", "multiSelect": false, "stemHtml": "<p>True or False: Snowflakeはすべてのお客様に同時に新しいソフトウェアバージョンを適用します。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>Snowflakeは新しいバージョンをすべてのアカウントに即座にデプロイするのではなく、段階的にロールアウトします。1日目（早期アクセス）：早期アクセスを選択したEnterprise以上のアカウントにデプロイ。1〜2日目（通常アクセス）：Standardエディションのすべてのアカウントにデプロイ。2日目（最終）：残りのEnterprise以上のすべてのアカウントにデプロイ。段階的リリース戦略により、ソフトウェアの問題を早期に特定・対処できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント", "originalCorrect": null, "reviewPoint": ""}}, {"order": 109, "title": "Snowflakeの組み込みロールに関する正しい説明はどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeの組み込みロールに関する正しい説明はどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "USERADMINはユーザーとロールの管理専用である。"}, {"key": "B", "label": "USERADMINロールはユーザーとロールの管理をすべての権限付与の管理から分離する。"}, {"key": "C", "label": "USERADMINはSYSADMINのすべての権限を継承する。"}, {"key": "D", "label": "USERADMINはすべての新規ユーザーに自動的に付与される。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>ユーザー・ロール管理専用 / 権限付与の管理から分離</strong></p><p>USERADMINはユーザーとロールの管理のみを専門とするロールで、CREATE USERとCREATE ROLEの権限を持ちます。権限の管理（GRANT操作）はSECURITYADMINロールの役割です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 110, "title": "Snowflakeにおける「OPERATE」タスク権限はロールに何を許可しますか？", "multiSelect": false, "stemHtml": "<p>Snowflakeにおける「OPERATE」タスク権限はロールに何を許可しますか？</p>", "options": [{"key": "A", "label": "OPERATEタスク権限を持つロールはタスクを再開または停止できる。"}, {"key": "B", "label": "OPERATEタスク権限を持つロールはワークロードの需要に基づいてタスク実行を優先化または優先度を下げることができる。"}, {"key": "C", "label": "OPERATEタスク権限を持つロールはタスク定義を変更・更新できる。"}, {"key": "D", "label": "OPERATEタスク権限を持つロールはタスクのステータスと実行履歴を表示できる。"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>タスクの再開または停止</strong></p><p>OPERATEタスク権限により、ロールはタスクを停止または再開することができます。タスク実行の優先度設定にはSnowflakeは対応していません。タスク定義の変更にはMODIFYまたはCREATE TASK権限が必要です。タスクのステータスと実行履歴の表示にはMONITOR権限が必要です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タスク", "originalCorrect": null, "reviewPoint": ""}}, {"order": 111, "title": "仮想ウェアハウスが2つのクエリを実行中に、より小さいサイズにリサイズされました。このリサイズ操作...", "multiSelect": false, "stemHtml": "<p>仮想ウェアハウスが2つのクエリを実行中に、より小さいサイズにリサイズされました。このリサイズ操作を最もよく説明しているものはどれですか？</p>", "options": [{"key": "A", "label": "クエリが停止され、仮想ウェアハウスは即座に小さいサイズにリサイズされる。"}, {"key": "B", "label": "仮想ウェアハウスがリサイズされる間、クエリは一時停止される。"}, {"key": "C", "label": "クエリ実行中は仮想ウェアハウスをリサイズできないため、リサイズ操作は失敗する。"}, {"key": "D", "label": "リサイズ操作は成功するが、アクティブなクエリが終了した後にノードの削除が行われる。"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>リサイズ成功、ノード削除はアクティブクエリ終了後</strong></p><p>クエリ実行中でも仮想ウェアハウスをいつでもリサイズできます。小さいサイズにリサイズする際、そのノード上のすべてのアクティブなクエリが完了した後にのみノードの削除が行われます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 112, "title": "データコンシューマーがデータプロバイダーによって共有されたシェアオブジェクトから読み取り専用デー...", "multiSelect": false, "stemHtml": "<p>データコンシューマーがデータプロバイダーによって共有されたシェアオブジェクトから読み取り専用データベースを作成しています。データプロバイダーがシェアにオブジェクトを追加した場合、何が起こりますか？</p>", "options": [{"key": "A", "label": "コンシューマーが読み取り専用データベースを作成した後、シェアへのオブジェクト追加はできない。"}, {"key": "B", "label": "データコンシューマーは追加されたオブジェクトを読み取り専用データベースに反映させるために `ALTER SHARE <シェア名> REFRESH` を実行する必要がある。"}, {"key": "C", "label": "データコンシューマーは新しいオブジェクトをすぐに確認・消費できる。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>すぐにアクセス可能</strong></p><p>データプロバイダーがシェアに追加したすべての新しいオブジェクトは、コンシューマーにすぐにアクセス可能になります。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 113, "title": "Snowflakeのキャッシュメカニズムはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeのキャッシュメカニズムはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "メモリキャッシュ（Memory Caching）"}, {"key": "B", "label": "クエリ結果キャッシュ（Query Result Caching）"}, {"key": "C", "label": "インデックスキャッシュ（Index Caching）"}, {"key": "D", "label": "メタデータキャッシュ（Metadata Caching）"}, {"key": "E", "label": "ウェアハウスキャッシュ（Warehouse Caching）"}], "correctAnswers": ["B", "D", "E"], "explanationHtml": "<p>✅ <strong>クエリ結果キャッシュ / メタデータキャッシュ / ウェアハウスキャッシュ</strong></p><p>メタデータキャッシュ：テーブルの行数など、メタデータから直接処理できるクエリに使用。クエリ結果キャッシュ：すでに実行されたクエリに対して使用。ウェアハウスキャッシュ：仮想ウェアハウスインスタンス内で、すでに実行されたクエリに基づくキャッシュ。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 114, "title": "Snowflakeのキーペア認証に関する正しい説明はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeのキーペア認証に関する正しい説明はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "キーペア認証は秘密キーと1つまたは2つの公開キーで構成される。"}, {"key": "B", "label": "キーペア認証はシンプルなユーザー名/パスワード認証の代替手段である。"}, {"key": "C", "label": "キーペア認証はユーザーにパスワードの提供を要求する。"}, {"key": "D", "label": "キーペア認証はシングルサインオン（SSO）を可能にする。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>秘密キー+1〜2つの公開キー / ユーザー名/パスワードの代替</strong></p><p>Snowflakeは標準的なユーザー名/パスワードログインに加えてキーペア認証をサポートしています。公開キーをユーザーに割り当て、秘密キーを認証に使用します。ユーザーは最大2つの公開キーを持つことができ、任意の時点でローテーション可能です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 115, "title": "ドロップ後にUNDROPコマンドを使用して回復できるオブジェクトタイプはどれですか？（該当するも...", "multiSelect": true, "stemHtml": "<p>ドロップ後にUNDROPコマンドを使用して回復できるオブジェクトタイプはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "スキーマ（Schema）"}, {"key": "B", "label": "データベース（Database）"}, {"key": "C", "label": "テーブル（Table）"}, {"key": "D", "label": "ロール（Role）"}, {"key": "E", "label": "ユーザー（User）"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>スキーマ / データベース / テーブル</strong></p><p>UNDROP機能はテーブル、スキーマ、データベースに適用されます。データベース全体やスキーマとその子オブジェクトを復元できます。ロールとユーザーはUNDROPの対象外です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 116, "title": "クローンされたテーブルに対して実行できる操作はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>クローンされたテーブルに対して実行できる操作はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "DELETE"}, {"key": "B", "label": "SELECT"}, {"key": "C", "label": "CLONE"}, {"key": "D", "label": "DROP"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>DELETE / SELECT / CLONE / DROP すべて可</strong></p><p>クローンされたテーブルは通常のテーブルと同様なので、これらすべての操作が実行できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローン", "originalCorrect": null, "reviewPoint": ""}}, {"order": 117, "title": "デフォルトでData Exchangeシェアを管理できるロールはどれですか？", "multiSelect": false, "stemHtml": "<p>デフォルトでData Exchangeシェアを管理できるロールはどれですか？</p>", "options": [{"key": "A", "label": "ACCOUNTADMIN"}, {"key": "B", "label": "SECURITYADMIN"}, {"key": "C", "label": "USERADMIN"}, {"key": "D", "label": "SYSADMIN"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>ACCOUNTADMIN</strong></p><p>デフォルトでは、ACCOUNTADMINロールのみがシェアを作成・管理する権限を持ちます。必要に応じて、他のロールにこの権限を付与することもできます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 118, "title": "このコースの練習問題が実際の認定試験の問題と同一でない理由はなぜですか？", "multiSelect": false, "stemHtml": "<p>このコースの練習問題が実際の認定試験の問題と同一でない理由はなぜですか？</p>", "options": [{"key": "A", "label": "受験生が正確な問題と答えを暗記できるようにするため。"}, {"key": "B", "label": "特定の問題を丸暗記するのではなく、概念の知識と理解をテストするため。"}, {"key": "C", "label": "コース作成者が実際の試験問題を知らないため。"}, {"key": "D", "label": "受験生を無関係なトピックで困惑させるため。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>概念の知識と理解のテスト</strong></p><p>このコースは、認定試験に必要な概念とトピックを深く理解するために設計されています。練習問題は特定の問題の答えを暗記するためではなく、知識を強化し、概念を習得して自信を持って試験問題に対応できるよう設計されています。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "", "originalCorrect": null, "reviewPoint": ""}}, {"order": 119, "title": "DMLコマンド（INSERT、UPDATE、DELETEなど）によってテーブルに行われた変更を監...", "multiSelect": false, "stemHtml": "<p>DMLコマンド（INSERT、UPDATE、DELETEなど）によってテーブルに行われた変更を監視するために、Snowflakeが提供するデータベースオブジェクトの種類はどれですか？</p>", "options": [{"key": "A", "label": "ストアドプロシージャ（Stored Procedure）"}, {"key": "B", "label": "Snowpipe"}, {"key": "C", "label": "タスク（Task）"}, {"key": "D", "label": "ストリーム（Stream）"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>ストリーム（Stream）</strong></p><p>Snowflakeストリームは、INSERT（新規追加）、UPDATE（更新）、DELETE（削除）などのテーブルへの変更を追跡します。最後のオフセット以降に変更されたデータのみをクエリ・処理することができます。</p><p>❌ <strong>他の選択肢が誤りである理由:</strong></p><ul><li><strong>ストアドプロシージャ</strong>: 複雑な操作や手続き型ロジックの実行に使用します。</li><li><strong>Snowpipe</strong>: 継続的なリアルタイムデータ取り込みを容易にします。</li><li><strong>タスク</strong>: 時間ベースの自動化プロセスで、SQL文の実行やストアドプロシージャの呼び出しに使用します。</li></ul><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ストリーム", "originalCorrect": null, "reviewPoint": ""}}, {"order": 120, "title": "仮想ウェアハウスをより大きなサイズにスケールアップするのに適したシナリオはどれですか？", "multiSelect": false, "stemHtml": "<p>仮想ウェアハウスをより大きなサイズにスケールアップするのに適したシナリオはどれですか？</p>", "options": [{"key": "A", "label": "多くの同時実行ユーザーがいるシステム。"}, {"key": "B", "label": "多くの同時実行クエリがあるシステム。"}, {"key": "C", "label": "複雑なクエリが実行されており、より早く完了する必要がある。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>複雑なクエリを高速化する場合</strong></p><p>一般的に、ウェアハウスサイズを増やすと、CPUを多く使用するクエリの速度が向上します。一方、多くの同時実行ユーザーやクエリに対処するには、スケールアップではなくマルチクラスター仮想ウェアハウス（スケールアウト）が有効です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 121, "title": "True or False: Snowflakeは半構造化データのロードをサポートしていません。", "multiSelect": false, "stemHtml": "<p>True or False: Snowflakeは半構造化データのロードをサポートしていません。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False（誤り）</strong></p><p>Snowflakeは半構造化データのロードと処理をサポートしています。SnowflakeはVARIANTデータ型を提供しており、あらゆるデータを格納でき、半構造化データの入力とクエリに適しています。JSONデータをVARIANT列にロードすると、SQLを使用してJSONデータを読み取り・操作することができます。</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}]}, {"slug": "02_practice_exam", "title": "SnowPro Core 02_practice_exam", "sourcePath": "01_資格/Snowflake/SnowPro_Core/問題/02_practice_exam.md", "metadata": ["問題数: 118問"], "questionCount": 118, "questions": [{"order": 1, "title": "仮想ウェアハウスが起動してから35秒後に停止しました。Snowflakeクレジットの計算に使われ...", "multiSelect": false, "stemHtml": "<p>仮想ウェアハウスが起動してから35秒後に停止しました。Snowflakeクレジットの計算に使われる時間はどれですか？</p>", "options": [{"key": "A", "label": "クエリが実行された場合は35秒、実行されていない場合は0秒"}, {"key": "B", "label": "60秒"}, {"key": "C", "label": "35秒"}, {"key": "D", "label": "0秒"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>60秒</strong></p><p>Snowflakeのクレジットは秒単位で請求されますが、最低60秒の請求が適用されます。仮想ウェアハウスが最初の60秒以内にプロビジョン、再開、一時停止、または削除された場合でも、最低60秒のクレジット使用量が適用されます。クエリを実行しているかどうかは関係なく、仮想ウェアハウスが稼働中であればクレジットを消費します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 2, "title": "マルチクラスター仮想ウェアハウスが仮想ウェアハウスを動的に起動・停止するのは、どのスケーリングモ...", "multiSelect": false, "stemHtml": "<p>マルチクラスター仮想ウェアハウスが仮想ウェアハウスを動的に起動・停止するのは、どのスケーリングモードですか？</p>", "options": [{"key": "A", "label": "Auto Scale"}, {"key": "B", "label": "Scale Fast"}, {"key": "C", "label": "Scale on Demand"}, {"key": "D", "label": "Maximized"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>Auto Scale</strong></p><p>オートスケーリングモードは、マルチの最小クラスター数と最大ウェアハウス数に異なる値を設定することで有効になります。これにより、Snowflakeはワークロードのニーズに基づいてウェアハウスを動的に起動・停止します。オートスケーリングモードを使用するマルチクラスター仮想ウェアハウスが起動すると、アクティブな仮想ウェアハウスの数は最小ウェアハウス数と等しくなります。Snowflakeは必要に応じて最大ウェアハウス数までウェアハウスを追加で起動します。需要が低下するにつれて、Snowflakeは仮想ウェアハウスをシャットダウンし、最小ウェアハウス数まで減らします。https://docs.snowflake.com/en/user-guide/warehouses-multicluster#maximized-vs-auto-scale</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 3, "title": "SnowflakeデータベースはMySQLやPostgresなどのRDBMSで使用される従来の共...", "multiSelect": false, "stemHtml": "<p>SnowflakeデータベースはMySQLやPostgresなどのRDBMSで使用される従来の共有ディスクアーキテクチャに基づいています。</p>", "options": [{"key": "A", "label": "いいえ"}, {"key": "B", "label": "はい"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>いいえ</strong></p><p>Snowflakeは、共有ディスクと共有なしアーキテクチャの両方の優れた機能を組み合わせた新しいハイブリッドアーキテクチャを実装しています。Snowflakeは共有ディスクアーキテクチャと同様にデータを保存します（データは共有されます）。しかし、それぞれが独自のメモリと処理能力を持つ複数のコンピューティングエンジンの使用も可能にしています。https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 4, "title": "SnowSQLは以下のどのオペレーティングシステムで利用できますか？", "multiSelect": true, "stemHtml": "<p>SnowSQLは以下のどのオペレーティングシステムで利用できますか？</p>", "options": [{"key": "A", "label": "Windows"}, {"key": "B", "label": "Linux"}, {"key": "C", "label": "Android"}, {"key": "D", "label": "macOS"}], "correctAnswers": ["A", "B", "D"], "explanationHtml": "<p>✅ <strong>Windows / Linux / macOS</strong></p><p>SnowSQLはコマンドラインからSnowflakeに接続し、SnowflakeインスタンスでSQLクエリを実行します。SnowSQLはLinux、Windows、Mac OSで利用できます。https://docs.snowflake.com/en/user-guide/snowsql</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 5, "title": "マテリアライズドビューの作成が有効なシナリオはどれですか？該当するものをすべて選択してください。", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューの作成が有効なシナリオはどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "異なるビジネスユーザーが同じテーブルにアクセスする頻繁かつ類似した複雑なクエリを実行する。"}, {"key": "B", "label": "外部テーブルのデータのサブセットにアクセスするクエリの高速化が必要な場合。"}, {"key": "C", "label": "ロールに基づいてユーザーごとに異なる行を返す要件がある。"}, {"key": "D", "label": "データ取り込みプロセスの高速化要件がある。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>類似した複雑なクエリの頻繁な実行 / 外部テーブルのクエリ高速化</strong></p><p>クエリまたはその軽微なバリエーションが頻繁に実行される場合、マテリアライズドビューが役立ちます。</p><p>実行されるクエリが複雑で時間とリソースを消費する場合、マテリアライズドビューは結果を事前計算し、処理を高速化できます。</p><p>マテリアライズドビューは外部テーブルに対して作成することでパフォーマンスを向上させることができます。これらのマテリアライズドビューは手動または通知システムを通じてリフレッシュする必要があります。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 6, "title": "Snowflakeのクラウドサービス層は次のうちどれを提供しますか？", "multiSelect": false, "stemHtml": "<p>Snowflakeのクラウドサービス層は次のうちどれを提供しますか？</p>", "options": [{"key": "A", "label": "メタデータ管理"}, {"key": "B", "label": "データストレージ"}, {"key": "C", "label": "クエリ実行"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>メタデータ管理</strong></p><p>クラウドサービス層には、データの保存方法、マイクロパーティションに関する情報、システム内のデータベースとテーブルのメタデータ、ユーザー、ロール、セキュリティなど、さまざまなメタデータが含まれ、管理されています。クエリの実行はクエリ処理層（クラウドサービスではない）で行われます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 7, "title": "認証なしでファイルへのアクセスを可能にするURLタイプはどれですか？", "multiSelect": false, "stemHtml": "<p>認証なしでファイルへのアクセスを可能にするURLタイプはどれですか？</p>", "options": [{"key": "A", "label": "スコープURL"}, {"key": "B", "label": "事前署名済みURL"}, {"key": "C", "label": "ファイルURL"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>事前署名済みURL</strong></p><p>事前署名済みURLは、Webブラウザを使用してファイルにアクセスするためのシンプルなHTTPS URLです。事前署名済みURLは事前署名済みアクセストークンを使用して生成されます。ユーザーは認証なしで事前署名済みURLを介してファイルに一時的にアクセスできます。事前署名済みURLの有効期限は設定可能で、必要な期間に設定できます。</p><p>https://docs.snowflake.com/en/user-guide/unstructured-intro#types-of-urls-available-to-access-files</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 8, "title": "正誤問題：SnowflakeはSCIM 2.0をサポートし、OktaおよびAzure Activ...", "multiSelect": false, "stemHtml": "<p>正誤問題：SnowflakeはSCIM 2.0をサポートし、OktaおよびAzure Active Directoryと互換性があります。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>SnowflakeはSCIM 2.0をサポートし、OktaおよびAzure Active Directoryと互換性があります。SCIMはオープンスタンダードであり、IDプロバイダー情報に基づいた自動ユーザープロビジョニングとロール同期を提供します。IDプロバイダーで新しいユーザーが作成されると、SCIMは自動的にSnowflakeでそのユーザーをプロビジョニングします。さらに、SCIMはIDプロバイダーで定義されたグループをSnowflakeのロールと同期できます。https://docs.snowflake.com/en/user-guide/scim</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 9, "title": "SNOWFLAKE_SAMPLE_DATA.TPCH_SF1スキーマのCUSTOMERテーブルを...", "multiSelect": true, "stemHtml": "<p>SNOWFLAKE_SAMPLE_DATA.TPCH_SF1スキーマのCUSTOMERテーブルを考えてください。次のクエリのうち、アクティブな仮想ウェアハウスを必要としないものはどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "`USE SNOWFLAKE_SAMPLE_DATA.TPCH_SF1;`"}, {"key": "B", "label": "`SHOW TABLES LIKE '%CUSTOMER%';`"}, {"key": "C", "label": "`SELECT * FROM SNOWFLAKE_SAMPLE_DATA.TPCH_SF1.CUSTOMER`"}, {"key": "D", "label": "`SELECT C_MKTSEGMENT,SUM(C_ACCTBAL) FROM SNOWFLAKE_SAMPLE_DATA.TPCH_SF1.CUSTOMER GROUP BY C_MKTSEGMENT;`"}, {"key": "E", "label": "`DESCRIBE TABLE SNOWFLAKE_SAMPLE_DATA.TPCH_SF1.CUSTOMER;`"}, {"key": "F", "label": "`SELECT COUNT(*) FROM SNOWFLAKE_SAMPLE_DATA.TPCH_SF1.CUSTOMER;`"}], "correctAnswers": ["A", "E", "F"], "explanationHtml": "<p>✅ <strong>USE文 / DESCRIBE TABLE / SELECT COUNT(*)</strong></p><p>統計情報は各テーブル、マイクロパーティション、および列のクラウドサービス層のメタデータキャッシュに保持されます。クエリが単純に行数をカウントするだけであれば、メタデータキャッシュが結果を返せます。</p><p>同様に、クラウドサービス層はテーブル定義（DESCRIBEなど）やスキーマ内のテーブルリスト（SHOW TABLES LIKEなど）を提供できます。</p><p>メタデータキャッシュやクラウドサービスの操作にはアクティブな仮想ウェアハウスは必要ありません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 10, "title": "マルチクラスター仮想ウェアハウスをサポートする最低のSnowflakeエディションはどれですか？", "multiSelect": false, "stemHtml": "<p>マルチクラスター仮想ウェアハウスをサポートする最低のSnowflakeエディションはどれですか？</p>", "options": [{"key": "A", "label": "Standard"}, {"key": "B", "label": "Enterprise"}, {"key": "C", "label": "Virtual Private Snowflake"}, {"key": "D", "label": "Business Critical"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Enterprise</strong></p><p>Enterpriseエディションには、Standardエディションでは提供されない追加機能がいくつかあります。マルチクラスター仮想ウェアハウス、列レベルのマスキング、行アクセスポリシー、マテリアライズドビュー、検索最適化などが含まれます。https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 11, "title": "MAX_DATA_EXTENSION_TIME_IN_DAYSパラメーターはストリームのどの側面...", "multiSelect": false, "stemHtml": "<p>MAX_DATA_EXTENSION_TIME_IN_DAYSパラメーターはストリームのどの側面を制御しますか？</p>", "options": [{"key": "A", "label": "Snowflakeがフェイルセーフストレージにデータを保持する最大日数。"}, {"key": "B", "label": "ストリームが古くなるのを防ぐために、Snowflakeがテーブルのデータ保持期間を延長できる最大日数。"}, {"key": "C", "label": "クエリ結果キャッシュに結果が保持される最大期間。"}, {"key": "D", "label": "Snowflakeがトランジェントテーブルにデータを保持する最大日数。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>ストリームが古くなるのを防ぐためのテーブルデータ保持期間の最大延長日数</strong></p><p>Snowflakeがストリームを古くなるのを防ぐためにテーブルデータ保持期間を延長できる最大日数。Snowflakeエディションに関係なく、ストリームが消費されておらず、ストリームのオフセットよりもDATA_RETENTION_TIME_IN_DAYS設定が14日未満の場合、Snowflakeはソーステーブルの設定を一時的に延長します。データ保持のストレージコストやコンプライアンスを削減するには、MAX_DATA_EXTENSION_TIME_IN_DAYSパラメーターでこの自動延長時間を制限します。<br>詳細は以下のリンクを参照してください：https://docs.snowflake.com/en/user-guide/streams-intro#data-retention-period-and-staleness および https://docs.snowflake.com/en/sql-reference/parameters#max-data-extension-time-in-days</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ストリーム", "originalCorrect": null, "reviewPoint": ""}}, {"order": 12, "title": "検索最適化によってパフォーマンスが向上するクエリの種類はどれですか？2つ選択してください。", "multiSelect": true, "stemHtml": "<p>検索最適化によってパフォーマンスが向上するクエリの種類はどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "ウィンドウ関数を使用するクエリ"}, {"key": "B", "label": "IN述語を使用するクエリ"}, {"key": "C", "label": "テーブル全体を読み取るクエリ"}, {"key": "D", "label": "等価述語を使用するクエリ"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>IN述語を使用するクエリ / 等価述語を使用するクエリ</strong></p><p>検索最適化サービスは、等価述語またはIN述語を使用した高度に選択的なフィルターを使用して、1行または数行のみを返すポイントルックアップクエリのパフォーマンスを向上させるために使用できます。</p><p>https://docs.snowflake.com/en/user-guide/search-optimization-service#understanding-the-search-optimization-service</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 13, "title": "正誤問題：特定のデータベース、スキーマ、またはテーブルに対してフェイルセーフを無効にすることがで...", "multiSelect": false, "stemHtml": "<p>正誤問題：特定のデータベース、スキーマ、またはテーブルに対してフェイルセーフを無効にすることができます。</p>", "options": [{"key": "A", "label": "誤り"}, {"key": "B", "label": "正しい"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>誤り</strong></p><p>タイムトラベル期間が終了すると、Snowflakeはさらなる保護としてデータをさらに7日間保持します。このフェイルセーフは無効化または設定変更ができません。Snowflakeアカウント、データベース、スキーマ、またはテーブルに対して変更することはできません。ただし、フェイルセーフストレージが0日のトランジェントまたは一時テーブルを使用することができます。https://docs.snowflake.com/en/user-guide/data-failsafe https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 14, "title": "次のどのシナリオで仮想ウェアハウスのスケールアップが良い選択肢ですか？", "multiSelect": false, "stemHtml": "<p>次のどのシナリオで仮想ウェアハウスのスケールアップが良い選択肢ですか？</p>", "options": [{"key": "A", "label": "クエリが外部テーブルにアクセスしている。"}, {"key": "B", "label": "現在の仮想ウェアハウスが処理できる以上のアクティブな同時クエリがある。"}, {"key": "C", "label": "クエリが5つ以上のテーブルにアクセスしている。"}, {"key": "D", "label": "仮想ウェアハウスが複雑なクエリを実行し、大量のデータを処理している。"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>複雑なクエリの実行と大量データの処理</strong></p><p>クエリの複雑さと望ましいパフォーマンスに基づいて、仮想ウェアハウスをスケールアップまたはダウンできます。一般的に、仮想ウェアハウスのサイズを大きくすることで、CPUを多用するクエリのクエリ速度が向上します。一方、多数の同時ユーザーやクエリに対処する場合、スケールアップは効果的ではありません。マルチクラスター仮想ウェアハウス（スケールアウト）は、同時ユーザーとクエリの増加に対応します。https://docs.snowflake.com/en/user-guide/warehouses-considerations</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 15, "title": "データベースがクローンされると、どのオブジェクトが対応するソースの権限を継承しますか？該当するも...", "multiSelect": true, "stemHtml": "<p>データベースがクローンされると、どのオブジェクトが対応するソースの権限を継承しますか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "クローンされたデータベース自体。"}, {"key": "B", "label": "データベース内に含まれるスキーマ。"}, {"key": "C", "label": "データベース内に含まれるテーブル。"}, {"key": "D", "label": "データベース内に含まれるビュー。"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>スキーマ / テーブル / ビュー</strong></p><p>クローンされたオブジェクトはソースオブジェクトから権限を継承しません。例えば、クローンされたテーブルはソーステーブルから権限を継承しません。ただし、データベースまたはスキーマがクローンされる場合、権限は子オブジェクトに継承されます。https://docs.snowflake.com/en/user-guide/object-clone#access-control-privileges-for-cloned-objects</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 16, "title": "クエリ結果キャッシュは、次のどの条件が真でない限り24時間後にパージされますか？", "multiSelect": false, "stemHtml": "<p>クエリ結果キャッシュは、次のどの条件が真でない限り24時間後にパージされますか？</p>", "options": [{"key": "A", "label": "24時間以内に別のクエリが実行されてクエリ結果キャッシュが再利用される。"}, {"key": "B", "label": "クエリ結果キャッシュパージパラメーターの値が24以外の数値に設定されている。"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>24時間以内に別のクエリがキャッシュを再利用する</strong></p><p>クエリのクエリ結果キャッシュの初期有効期間は24時間です。新しいクエリが24時間以内に以前生成されたキャッシュを再利用しない場合、キャッシュはパージされます。新しいクエリが結果キャッシュを使用すると、クエリ結果キャッシュの有効期間がさらに24時間リセットされます。再利用されてからさらに24時間有効になります。この最初のクエリ結果キャッシュの延長は、クエリ結果キャッシュが最初に生成された時点から最大31日間継続できます。31日後、クエリのクエリ結果キャッシュは完全にパージされます。https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 17, "title": "半構造化データを構造化データ（テーブルなど）に処理する際、列をデータ型にキャストする正しい方法は...", "multiSelect": false, "stemHtml": "<p>半構造化データを構造化データ（テーブルなど）に処理する際、列をデータ型にキャストする正しい方法はどれですか？</p>", "options": [{"key": "A", "label": "`SELECT col1:CustomerName::String`"}, {"key": "B", "label": "`SELECT col1 AS CustomerName WITH DATATYPE AS String`"}, {"key": "C", "label": "`SELECT CAST(col1:CustomerName AS String)`"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong><code>SELECT col1:CustomerName::String</code></strong></p><p><code>&lt;json_column_name&gt;:&lt;intended_column_name&gt;:&lt;datatype&gt;</code> がVARIANT列の半構造化データを処理する際の正しいキャスト方法です。</p><p>したがって「SELECT col1:CustomerName::String」が正解です。</p><p>https://docs.snowflake.com/en/user-guide/semistructured-considerations#casting-key-values</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 18, "title": "Snowflakeのストレージコストに貢献するものはどれですか？該当するものをすべて選択してくだ...", "multiSelect": true, "stemHtml": "<p>Snowflakeのストレージコストに貢献するものはどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "メタデータ"}, {"key": "B", "label": "パーマネントテーブルストレージ"}, {"key": "C", "label": "キャッシュ結果"}, {"key": "D", "label": "タイムトラベルストレージ"}, {"key": "E", "label": "フェイルセーフストレージ"}], "correctAnswers": ["B", "D", "E"], "explanationHtml": "<p>✅ <strong>パーマネントテーブルストレージ / タイムトラベルストレージ / フェイルセーフストレージ</strong></p><p>パーマネントテーブルに保存されたデータはストレージコストに計上されます。</p><p>一時テーブルとトランジェントテーブルに保存されたデータも、削除またはデータがクリアされるまでストレージコストに貢献します。</p><p>フェイルセーフストレージおよびタイムトラベルストレージ内のデータもストレージコストに貢献します。</p><p>ただし、トランジェントおよび一時テーブルはフェイルセーフストレージコストには貢献せず、タイムトラベルコストは最大1日分のみです。</p><p>キャッシングはストレージコストの決定には考慮されません。</p><p>クエリ結果キャッシュとメタデータキャッシュはクラウドサービス層の一部です。</p><p>ウェアハウスキャッシュ（ローカルディスクキャッシュ）は仮想ウェアハウスの一部であり、ストレージコストには貢献しません。</p><p>https://docs.snowflake.com/en/user-guide/cost-understanding-overall</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "コストと価格", "originalCorrect": null, "reviewPoint": ""}}, {"order": 19, "title": "正誤問題：Snowflakeは、異なるデータベースの複数のテーブルからデータを共有するためにセキ...", "multiSelect": false, "stemHtml": "<p>正誤問題：Snowflakeは、異なるデータベースの複数のテーブルからデータを共有するためにセキュアビューを作成することを推奨しています。</p>", "options": [{"key": "A", "label": "誤り"}, {"key": "B", "label": "正しい"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>異なるデータベースの多くのテーブルからデータを共有する必要がある場合、セキュアビューを作成できます。1つの共有に複数のデータベースを追加できないため、Snowflakeは1つのデータベースにセキュアビューを作成することを推奨しています。https://docs.snowflake.com/en/user-guide/data-sharing-mutiple-db</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 20, "title": "完了したクエリのクエリプロファイルの以下のスニペットを考えてください。強調表示された統計を正確に...", "multiSelect": true, "stemHtml": "<p>完了したクエリのクエリプロファイルの以下のスニペットを考えてください。強調表示された統計を正確に説明するものはどれですか？</p>", "options": [{"key": "A", "label": "クエリプロファイルは非効果的なパーティションプルーニングを示している。"}, {"key": "B", "label": "クエリプロファイルは使用されている仮想ウェアハウスがクエリに対して小さすぎることを示している。"}, {"key": "C", "label": "クエリプロファイルは仮想ウェアハウスキャッシュが使用されたことを示している。"}, {"key": "D", "label": "クエリプロファイルは効果的なパーティションプルーニングを示している。"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>仮想ウェアハウスが小さすぎる / ウェアハウスキャッシュが使用された / 効果的なパーティションプルーニング</strong></p><p>パーティションプルーニングは、スキャンされたパーティション数が合計パーティション数よりもはるかに少ない場合に発生します。Snowflakeは操作をメモリに収められない場合、ウェアハウスのローカルディスクおよびリモートクラウドストレージにデータを保存します。データのスピリングは追加のIO操作が必要であり、ディスクアクセスはメモリアクセスよりも遅いため、クエリの速度が低下します。https://docs.snowflake.com/en/user-guide/ui-query-profile</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 21, "title": "新しいSnowflakeアカウントを作成する際に選択できるものはどれですか？2つ選択してください...", "multiSelect": true, "stemHtml": "<p>新しいSnowflakeアカウントを作成する際に選択できるものはどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "支払い情報"}, {"key": "B", "label": "Snowflakeエディション"}, {"key": "C", "label": "組織名"}, {"key": "D", "label": "アカウントロケーターURL"}, {"key": "E", "label": "リージョン"}, {"key": "F", "label": "アカウントロケーター"}], "correctAnswers": ["B", "E"], "explanationHtml": "<p>✅ <strong>Snowflakeエディション / リージョン</strong></p><p>CREATE ACCOUNT文を使用すると、アカウント名、Snowflakeエディション、リージョン（クラウドプラットフォーム情報を含む）、リージョングループ、管理アカウントの詳細（名前、パスワード、メールなど）を指定できます。</p><p>https://docs.snowflake.com/en/sql-reference/sql/create-account</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 22, "title": "SHAREを作成するために必要な最低ロールはどれですか？", "multiSelect": false, "stemHtml": "<p>SHAREを作成するために必要な最低ロールはどれですか？</p>", "options": [{"key": "A", "label": "SYSADMIN"}, {"key": "B", "label": "SECURITYADMIN"}, {"key": "C", "label": "ACCOUNTADMIN"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>ACCOUNTADMIN</strong></p><p>デフォルトでは、共有の管理はアカウントレベルのアクティビティであるため、共有の作成と管理に必要な権限を持つロールはACCOUNTADMINのみです。あるいは、ACCOUNTADMINロールを使用して、他のロールに共有管理の権限を付与することもできます。https://docs.snowflake.com/en/user-guide/data-sharing-gs</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 23, "title": "正誤問題：大きなテーブルのクラスタリングキーを定義する際、結合ステートメントで頻繁に使用される列...", "multiSelect": false, "stemHtml": "<p>正誤問題：大きなテーブルのクラスタリングキーを定義する際、結合ステートメントで頻繁に使用される列を使用することを検討してください。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>クラスタリングキーを定義する際、最初の候補となるクラスタリング列はWHERE句や他の選択的フィルターで頻繁に使用される列です。さらに、結合に使用される列も検討できます。また、列のカーディナリティ（異なる値の数）も重要です。効果的なパーティションプルーニングを可能にするほど高いカーディナリティを持ちながら、Snowflakeがデータをマイクロパーティションに効率的にグループ化できるほど低いカーディナリティを持つ列を選択することが重要です。異なる値が少なすぎる列（例：性別）はパーティションプルーニングがほとんど行われません。一方、異なる値が多すぎる列（例：顧客ID）はパーティションのメンテナンスに過剰なオーバーヘッドをもたらします。マルチ列クラスターキーを作成する際は、クラスタリングの効果が低下しないよう、最低カーディナリティから高いカーディナリティの順に列を並べてください。https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 24, "title": "SnowflakeのタイムトラベルについてTrue（正しい）のものはどれですか？該当するものをす...", "multiSelect": true, "stemHtml": "<p>SnowflakeのタイムトラベルについてTrue（正しい）のものはどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "Undropはドロップされたテーブル、スキーマ、データベースの復元を可能にします。"}, {"key": "B", "label": "Undropは外部ステージのデータを回復するために使用できます。"}, {"key": "C", "label": "Undropはのは Snowflakeアカウントをリセットするために使用できます。"}, {"key": "D", "label": "テーブル、スキーマ、データベースはすぐに物理的に削除されるのではなく、削除済みとしてマークされます。"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>Undropによる復元 / 論理削除のみ</strong></p><p>Undropはドロップされたテーブル、スキーマ、データベースの復元を可能にします。Snowflakeでテーブル、スキーマ、またはデータベースがドロップされると、システムからすぐに削除されず、タイムトラベル中に回復可能です。テーブルがドロップされると、テーブルはドロップ済みとして表示されていても、データはクラウドストレージに保持されます。Snowflakeは単にテーブルの状態を非削除に設定することでundropします。したがって、undropはテーブル、スキーマ、データベースに適用できます。https://docs.snowflake.com/en/user-guide/data-time-travel#restoring-objects</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 25, "title": "管理者として、1 TBを超えるサイズのすべてのテーブルを検索してリスト化する必要があります。また...", "multiSelect": false, "stemHtml": "<p>管理者として、1 TBを超えるサイズのすべてのテーブルを検索してリスト化する必要があります。また、先月作成・削除されたテーブルも含める必要があります。次のどのオプションを使用すべきですか？</p>", "options": [{"key": "A", "label": "大量のデータがロードされたテーブルを特定するためにCOPYコマンドのログを確認する。"}, {"key": "B", "label": "INFORMATION_SCHEMAスキーマのテーブル関数を使用する。"}, {"key": "C", "label": "Snowsightを使用してこの情報を表示する。"}, {"key": "D", "label": "ACCOUNT_USAGEスキーマのビューにクエリを実行する。"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>ACCOUNT_USAGEスキーマのビュー</strong></p><p>ACCOUNT_USAGEビューにはドロップされたすべてのオブジェクトの情報が含まれています。これらのビューの多くには、ドロップされたオブジェクトの情報を示すDELETED列が含まれています。INFORMATION_SCHEMAにはドロップされたオブジェクトが含まれていません。https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 26, "title": "正誤問題：共有データベースのコンシューマーは、共有データベースに新しいテーブルやビューを追加でき...", "multiSelect": false, "stemHtml": "<p>正誤問題：共有データベースのコンシューマーは、共有データベースに新しいテーブルやビューを追加できます。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>誤り</strong></p><p>共有オブジェクトはコンシューマーにとって読み取り専用であり、コンシューマーが変更することはできません。共有で作成されたデータベースには、データプロバイダーが追加したテーブルやその他のオブジェクトが含まれていますが、コンシューマーはオブジェクトを追加できません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 27, "title": "正誤問題：Snowflakeは顧客が設定しない限り、保存中のすべてのデータを暗号化されていない状...", "multiSelect": false, "stemHtml": "<p>正誤問題：Snowflakeは顧客が設定しない限り、保存中のすべてのデータを暗号化されていない状態で保存します。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>誤り</strong></p><p>Snowflakeでは、保存中のすべてのデータはAES 256ビット暗号化を使用して暗号化されています。https://docs.snowflake.com/en/user-guide/security-encryption-manage</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 28, "title": "セキュアUDFのみで満たせる要件はどれですか？該当するものをすべて選択してください。", "multiSelect": true, "stemHtml": "<p>セキュアUDFのみで満たせる要件はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "結果セットから行のサブセットを制限することでデータを保護する要件がある。"}, {"key": "B", "label": "複雑なSQLを簡略化して、ユーザーが同じロジックを繰り返しコーディングしなくて済むようにする要件がある。"}, {"key": "C", "label": "結果セットから一部のテーブル列を制限することでデータを保護する要件がある。"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>行の制限 / 列の制限</strong></p><p>SQL UDFは、ユーザーに返される行や列を制限するビューなど、データを保護する目的の場合はセキュアとして作成する必要があります。https://docs.snowflake.com/en/developer-guide/secure-udf-procedure</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 29, "title": "次の図のうち、最もよくクラスター化されたテーブルを表すものはどれですか？", "multiSelect": false, "stemHtml": "<p>次の図のうち、最もよくクラスター化されたテーブルを表すものはどれですか？</p>", "options": [{"key": "A", "label": "4"}, {"key": "B", "label": "3"}, {"key": "C", "label": "2"}, {"key": "D", "label": "1"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>4</strong></p><p>データが入力されたテーブルの場合、クラスタリング深度は特定の列に対して重複するマイクロパーティションの平均深度です。クラスタリング深度は1（よくクラスター化されたテーブル）から始まり、より大きな数値になることがあります。平均深度が小さいほど、指定された列のデータのクラスタリングが優れています。https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions#label-clustering-depth</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 30, "title": "正誤問題：クローン操作中、データは新しいマイクロパーティションに物理的にコピーされます。", "multiSelect": false, "stemHtml": "<p>正誤問題：クローン操作中、データは新しいマイクロパーティションに物理的にコピーされます。</p>", "options": [{"key": "A", "label": "誤り"}, {"key": "B", "label": "正しい"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>誤り</strong></p><p>Snowflakeのゼロコピークローン機能により、ユーザーはデータを物理的にコピーせずにテーブル、スキーマ、データベースのクローンを作成できます。クローニングには追加のストレージスペースは必要なく、クローニングはデータを物理的に複製しないため、データの物理コピーよりもはるかに高速です。マイクロパーティションとメタデータにより、クローンされたテーブルのメタデータが既存のマイクロパーティションを参照するため、迅速かつ効率的なゼロコピークローニングが可能になります。https://docs.snowflake.com/en/user-guide/tables-storage-considerations#label-cloning-tables</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 31, "title": "ディレクトリテーブルに関する正しい説明はどれですか？該当するものをすべて選択してください。", "multiSelect": true, "stemHtml": "<p>ディレクトリテーブルに関する正しい説明はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "ディレクトリテーブルはVARIANT列にCSVデータを保存する。"}, {"key": "B", "label": "ディレクトリテーブルはStageオブジェクトにステージングされたファイルのカタログを提供する。"}, {"key": "C", "label": "ディレクトリテーブルにはクラスタリングキーを定義できる。"}, {"key": "D", "label": "ディレクトリテーブルにクエリを実行して、Stage内の各ファイルのファイルURLを取得できる。"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>ステージのファイルカタログ / ファイルURLの取得</strong></p><p>ディレクトリテーブルは、内部または外部ステージで利用可能なファイルのカタログを保存・提示します。ステージに関連付けられたディレクトリテーブルにクエリを実行すると、ステージオブジェクトのファイルにアクセスするために使用できるファイルURLのリストを取得できます。クエリはステージ内の各ファイルへのSnowflakeがホストするファイルURLを返します。ディレクトリテーブルはその他のメタデータも提供します。</p><p>ディレクトリテーブルはデータを物理的に保存しないため、クラスタリングができる通常のテーブルのようには機能しません。</p><p>https://docs.snowflake.com/en/user-guide/data-load-dirtables</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 32, "title": "正誤問題：COPYコマンドを使用してデータをエクスポートする場合、エクスポートされたファイルは自...", "multiSelect": false, "stemHtml": "<p>正誤問題：COPYコマンドを使用してデータをエクスポートする場合、エクスポートされたファイルは自動的に圧縮されます。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>Snowflakeからデータをアンロードする際、デフォルトでgzip圧縮を使用して自動的に圧縮されます。これはデフォルトの動作ですが、代替の圧縮方法を指定したり、圧縮を完全にオフにしたりすることもできます。アンロードプロセスは、Snowflakeの並列処理を活用するために自動的に複数のファイルにエクスポートします。ただし、必要に応じてSINGLEパラメーターをtrueに設定して、1つのファイルにエクスポートすることもできます。各出力ファイルのデフォルトサイズは16MBですが、MAX_FILE_SIZEパラメーターで変更できます。クラウドストレージにデータをエクスポートする場合、1ファイルあたりの最大許容サイズは5GBです。https://docs.snowflake.com/en/user-guide/data-unload-considerations#unloading-to-a-single-file</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 33, "title": "完了したクエリのクエリプロファイルの以下のスニペットを考えてください。強調表示された統計を正確に...", "multiSelect": true, "stemHtml": "<p>完了したクエリのクエリプロファイルの以下のスニペットを考えてください。強調表示された統計を正確に説明するものはどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "クエリプロファイルは非効果的なパーティションプルーニングを示している。"}, {"key": "B", "label": "クエリプロファイルはクエリ結果キャッシュが使用されたことを示している。"}, {"key": "C", "label": "クエリプロファイルはメタデータキャッシュが使用されたことを示している。"}, {"key": "D", "label": "クエリプロファイルはクエリが仮想ウェアハウスのメモリに収まりきらないほど大きいことを示している。"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>非効果的なパーティションプルーニング / メモリに収まりきらないクエリ</strong></p><p>Snowflakeは操作をメモリに収められない場合、ウェアハウスのローカルディスクにデータを保存します。データのスピリングは追加のIO操作が必要であり、ディスクアクセスはメモリアクセスよりも遅いため、クエリの速度が低下します。「Bytes spilled to local storage」はローカルスピリングを示します。ローカルディスクがいっぱいになると、Snowflakeはリモートクラウドストレージにデータをスピルします。これはローカルディスクよりもさらに遅いストレージのため、この操作はさらに遅くなります。クエリプロファイルの「Bytes spilled to remote storage」はリモートスピリングを示します。スキャンされたパーティション数がパーティション合計と等しい場合、クエリはテーブル全体をスキャンしたことを示します。したがって、パーティションプルーニングは発生しておらず、クラスタリングキーを改善する必要があります。https://docs.snowflake.com/en/user-guide/ui-query-profile#queries-too-large-to-fit-in-memory</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 34, "title": "仮想ウェアハウスのクエリキューイングを減らすのに役立つものはどれですか？2つ選択してください。", "multiSelect": true, "stemHtml": "<p>仮想ウェアハウスのクエリキューイングを減らすのに役立つものはどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "すでにマルチクラスター仮想ウェアハウスを使用している場合、クラスターの最大数を増やす。"}, {"key": "B", "label": "仮想ウェアハウスをマルチクラスター仮想ウェアハウスに変更する。"}, {"key": "C", "label": "自動再開を有効にする。"}, {"key": "D", "label": "メモリをクリアするためにウェアハウスを頻繁に停止する。"}, {"key": "E", "label": "仮想ウェアハウスのサイズを大きくする。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>マルチクラスターに変更 / 最大クラスター数を増やす</strong></p><p>キューイングはさまざまな方法で減らすことができます。</p><p>1) 標準の仮想ウェアハウスを使用している場合、追加の仮想ウェアハウスを作成してクエリワークロードを分散することを検討してください。</p><p>2) 標準の仮想ウェアハウスをマルチクラスター仮想ウェアハウスに変換する。</p><p>3) すでにマルチクラスター仮想ウェアハウスを使用している場合、最大クラスターサイズを増やす。</p><p>https://docs.snowflake.com/en/user-guide/performance-query-warehouse-queue#options-for-reducing-queues</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 35, "title": "自動クラスタリングサービスはSnowflakeのどのアクティビティを担当していますか？", "multiSelect": false, "stemHtml": "<p>自動クラスタリングサービスはSnowflakeのどのアクティビティを担当していますか？</p>", "options": [{"key": "A", "label": "共有データの同期管理。"}, {"key": "B", "label": "仮想ウェアハウスクラスターの起動と停止。"}, {"key": "C", "label": "クラスタリングキーに従ってマイクロパーティション内のデータを再分散する。"}, {"key": "D", "label": "マルチクラスター仮想ウェアハウスの管理。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>クラスタリングキーに従ったマイクロパーティションのデータ再分散</strong></p><p>クラスタリングキーが定義されたテーブルの場合、Snowflakeサービスである自動クラスタリングが必要に応じて再クラスタリングを管理し、クラスタリングキーに従ってデータを分散します。Snowflakeは内部的にクラスター化されたテーブルとリソース要件を自動クラスタリングで維持します。自動クラスタリングは再クラスタリングから利益を得るマイクロパーティションのみを調整します。https://docs.snowflake.com/en/user-guide/tables-auto-reclustering</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 36, "title": "クエリプロファイルの統計ボックスに表示される情報はどれですか？2つ選択してください。", "multiSelect": true, "stemHtml": "<p>クエリプロファイルの統計ボックスに表示される情報はどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "ローカルディスクキャッシュから読み取ったデータの割合"}, {"key": "B", "label": "パーティションプルーニング"}, {"key": "C", "label": "オペレーターツリー"}, {"key": "D", "label": "最もコストのかかるノード"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>ローカルディスクキャッシュの割合 / パーティションプルーニング</strong></p><p>詳細は以下のリンクを参照してください。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile#statistics</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 37, "title": "INFORMATION_SCHEMAスキーマのビューを通じてアクセスできる履歴データは何日分です...", "multiSelect": false, "stemHtml": "<p>INFORMATION_SCHEMAスキーマのビューを通じてアクセスできる履歴データは何日分ですか？</p>", "options": [{"key": "A", "label": "1日"}, {"key": "B", "label": "365日"}, {"key": "C", "label": "7日"}, {"key": "D", "label": "7日〜6ヶ月"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>7日〜6ヶ月</strong></p><p>INFORMATION_SCHEMAビューのデータは短期間しか保持されません。INFORMATION SCHEMAの一般的なデータ保持期間は14日ですが、特定のビューでは7日、使用履歴ビューでは最大6ヶ月になることがあります。したがって、これらのビューの保持期間はビューによって7日から最大6ヶ月の範囲です。一般的に、INFORMATION SCHEMAのビューはより最近の情報を検索するために使用できます。https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 38, "title": "正誤問題：マイクロパーティション内のデータは圧縮して保存されます。", "multiSelect": false, "stemHtml": "<p>正誤問題：マイクロパーティション内のデータは圧縮して保存されます。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>Snowflakeテーブルのデータは自動的にマイクロパーティションと呼ばれるパーティションに整理されます。各マイクロパーティションには一般的に50MBから500MBの非圧縮データが含まれています。ただし、Snowflakeのデータは常に圧縮されて保存されるため、保存サイズはより小さくなります。各マイクロパーティション内では、データは列形式で保存されます。https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "マイクロパーティション", "originalCorrect": null, "reviewPoint": ""}}, {"order": 39, "title": "ストアドプロシージャがプロシージャを呼び出した人の権限で実行される条件はどれですか？", "multiSelect": false, "stemHtml": "<p>ストアドプロシージャがプロシージャを呼び出した人の権限で実行される条件はどれですか？</p>", "options": [{"key": "A", "label": "ストアドプロシージャの定義に1つのSQL文しかない。"}, {"key": "B", "label": "ストアドプロシージャがオーナーの権限で実行されるように設定されている。"}, {"key": "C", "label": "ストアドプロシージャが呼び出し元の権限で実行されるように設定されている。"}, {"key": "D", "label": "ストアドプロシージャがDML操作を実行しない。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>呼び出し元の権限で実行するよう設定されている</strong></p><p>ストアドプロシージャは呼び出し元の権限またはオーナーの権限のいずれかで呼び出せます。呼び出し元の権限で実行するように設定されたストアドプロシージャは、呼び出しユーザーの権限で実行されます。オーナーの権限で実行するように設定されたストアドプロシージャは、ストアドプロシージャを作成・所有するロールの権限で実行されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 40, "title": "キーペア認証メカニズムはどれで構成されていますか？1つ選択してください。", "multiSelect": false, "stemHtml": "<p>キーペア認証メカニズムはどれで構成されていますか？1つ選択してください。</p>", "options": [{"key": "A", "label": "ペアリングされたBluetoothデバイスを通じて提供される第2の認証要素。"}, {"key": "B", "label": "モバイルアプリを通じて提供される第2の認証要素。"}, {"key": "C", "label": "ユーザーに割り当てられた公開鍵と認証に使用される秘密鍵のペア。"}, {"key": "D", "label": "90秒ごとにコードを提供する物理的なキー。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>公開鍵と秘密鍵のペア</strong></p><p>Snowflakeは標準のユーザー名/パスワードログインに加えてキーペア認証をサポートすることで、セキュリティの追加層を提供します。このアプローチは秘密鍵と公開鍵で構成されており、公開鍵はユーザーに割り当てられ、秘密鍵は認証に使用されます。ユーザーは認証中に公開鍵を提供します。ユーザーは最大2つの公開鍵を持つことができ、いつでもローテーションできます。キーペア認証はすべてのSnowSQL、Snowflakeドライバー、コネクターでサポートされています。すべてのSnowflakeエディションでキーペア認証がサポートされています。https://docs.snowflake.com/en/user-guide/key-pair-auth</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 41, "title": "正誤問題：Snowflakeはさまざまな言語やフレームワーク用のコネクターとドライバーを提供して...", "multiSelect": false, "stemHtml": "<p>正誤問題：Snowflakeはさまざまな言語やフレームワーク用のコネクターとドライバーを提供しています。</p>", "options": [{"key": "A", "label": "誤り"}, {"key": "B", "label": "正しい"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>Snowflakeにはさまざまなドライバーとコネクターがあり、Snowflakeインスタンスへの接続に使用できます。WebインターフェースやSnowSQLコマンドラインインターフェースなどSnowflakeが製作したクライアントツール、および異なる言語やフレームワークがSnowflakeに接続できるドライバーとコネクターが含まれています。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 42, "title": "ACCOUNTADMINロールはロール階層の最上位にあるため、SYSADMINおよびSECURI...", "multiSelect": false, "stemHtml": "<p>ACCOUNTADMINロールはロール階層の最上位にあるため、SYSADMINおよびSECURITYADMINロールが提供する権限は自動的にACCOUNTADMINロールに含まれています。</p>", "options": [{"key": "A", "label": "誤り"}, {"key": "B", "label": "正しい"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>ACCOUNTADMINはSnowflakeアカウントで最も強力なロールです。ロール階層と権限の継承により、ACCOUNTADMINはSECURITYADMINとUSERADMINが持つすべての権限を継承します。https://docs.snowflake.com/en/user-guide/security-access-control-overview#system-defined-roles</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 43, "title": "正誤問題：仮想ウェアハウスキャッシュまたはローカルディスクキャッシュは仮想ウェアハウスに固有であ...", "multiSelect": false, "stemHtml": "<p>正誤問題：仮想ウェアハウスキャッシュまたはローカルディスクキャッシュは仮想ウェアハウスに固有であり、他の仮想ウェアハウスと共有することはできません。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>仮想ウェアハウスはテーブルからデータにアクセスするたびに、そのデータをローカルにキャッシュします。このデータキャッシュは、後続のクエリがクラウドストレージのテーブルから読み取る代わりにキャッシュ内のデータを再利用できる場合、パフォーマンスを向上させることができます。ウェアハウスキャッシュは仮想ウェアハウスにローカルであり、他の仮想ウェアハウスとは共有できません。https://docs.snowflake.com/en/user-guide/warehouses-considerations#how-does-warehouse-caching-impact-queries</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 44, "title": "INFORMATION_SCHEMAを使用すると、ロール、ウェアハウス、データベースなどのアカウ...", "multiSelect": false, "stemHtml": "<p>INFORMATION_SCHEMAを使用すると、ロール、ウェアハウス、データベースなどのアカウントレベルのオブジェクトに関する情報を表示できます。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>INFORMATION_SCHEMAはINFORMATION_SCHEMAの親データベース内のオブジェクトに関するデータを提供します。また、ロール、ウェアハウス、データベースなどのアカウントレベルのオブジェクトに関するデータも提供します。https://docs.snowflake.com/en/sql-reference/info-schema#information-schema-views-and-table-functions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 45, "title": "COPYコマンドを通じてロードされたデータの過去365日間のロード履歴を表示するために使用できる...", "multiSelect": true, "stemHtml": "<p>COPYコマンドを通じてロードされたデータの過去365日間のロード履歴を表示するために使用できるビューはどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "ACCOUNT_USAGE.LOAD_HISTORY"}, {"key": "B", "label": "ACCOUNT_USAGE.PIPE_USAGE_HISTORY"}, {"key": "C", "label": "ACCOUNT_USAGE.COPY_HISTORY"}, {"key": "D", "label": "INFORMATION_SCHEMA.QUERY_HISTORY"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>ACCOUNT_USAGE.LOAD_HISTORY / ACCOUNT_USAGE.COPY_HISTORY</strong></p><p>ACCOUNT_USAGEスキーマのCOPY_HISTORYビューとLOAD_HISTORYビューは、COPYコマンドを通じて実行されたデータロードの履歴を提供します。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage/load_history</p><p>https://docs.snowflake.com/en/sql-reference/account-usage/copy_history</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 46, "title": "データのロードと変換において、Snowflakeが推奨するアプローチはどれですか？", "multiSelect": false, "stemHtml": "<p>データのロードと変換において、Snowflakeが推奨するアプローチはどれですか？</p>", "options": [{"key": "A", "label": "ELT（抽出、ロード、変換）"}, {"key": "B", "label": "ETL（抽出、変換、ロード）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>ELT（抽出、ロード、変換）</strong></p><p>ELTアプローチはSnowflakeの処理能力を活用して、データがロードされた後に変換を行います。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 47, "title": "Snowflakeのエンタープライズエディションを使用しています。パーマネントテーブルから重要な...", "multiSelect": false, "stemHtml": "<p>Snowflakeのエンタープライズエディションを使用しています。パーマネントテーブルから重要なデータを誤って削除してしまいました。削除から92日が経過し、今になって間違いに気づきました。データを回復するための最善の対応策は何ですか？</p>", "options": [{"key": "A", "label": "ソースファイルからデータを再ロードする。"}, {"key": "B", "label": "SQLとタイムトラベル拡張を使用してデータを自分で取得する。"}, {"key": "C", "label": "手動バックアップから新しいテーブルにデータを復元する。"}, {"key": "D", "label": "Snowflakeサポートチームに連絡してデータの取得を依頼する。"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>Snowflakeサポートチームに連絡する</strong></p><p>テーブルが90日間のタイムトラベルを持つと仮定すると、最も簡単な解決策はSnowflakeサポートに連絡することです。Snowflakeサポートはフェイルセーフストレージからデータを回復できます。データがフェイルセーフストレージにある場合、Snowflakeサポートのみがデータの取得を支援できます。手動バックアップからの復元やソースファイルからの再ロードは煩雑なプロセスであり、フェイルセーフストレージにもデータがない場合（つまり、97日以上経過し（90日のタイムトラベルと7日のフェイルセーフ）、タイムトラベルとフェイルセーフの両方からデータが削除されている場合）にのみ行うべきです。https://docs.snowflake.com/en/user-guide/data-failsafe</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 48, "title": "Snowflakeアーキテクチャの一部である3つの主要な層を選択してください。", "multiSelect": true, "stemHtml": "<p>Snowflakeアーキテクチャの一部である3つの主要な層を選択してください。</p>", "options": [{"key": "A", "label": "Azure VM"}, {"key": "B", "label": "クラウドサービス"}, {"key": "C", "label": "クエリ処理"}, {"key": "D", "label": "Dockerコンテナ"}, {"key": "E", "label": "データベースストレージ"}], "correctAnswers": ["B", "C", "E"], "explanationHtml": "<p>✅ <strong>クラウドサービス / クエリ処理 / データベースストレージ</strong></p><p>Snowflakeアーキテクチャには3つの明確な層があります：データベースストレージ - AWS、Azure、またはGoogle Cloud上の安価なクラウドストレージ / クエリ処理 - 主に仮想ウェアハウスで構成 / クラウドサービス - 全体の動作の「頭脳」 https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 49, "title": "アカウント管理者として、Snowflakeのデータ統合パートナーの1つでトライアルアカウントを作...", "multiSelect": false, "stemHtml": "<p>アカウント管理者として、Snowflakeのデータ統合パートナーの1つでトライアルアカウントを作成するよう求められました。このトライアルアカウントを作成するには何をすべきですか？</p>", "options": [{"key": "A", "label": "パートナーにサポートチケットを提出する。"}, {"key": "B", "label": "Snowflakeにサポートチケットを提出する。"}, {"key": "C", "label": "Partner Connectを使用してトライアルを開始する。"}, {"key": "D", "label": "パートナーのウェブサイトにアクセスしてトライアルアカウントをダウンロード・インストールする。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Partner Connectを使用する</strong></p><p>Partner Connectを使用すると、Snowflakeのビジネスパートナーの一部でトライアルアカウントを簡単に設定し、Snowflakeにリンクできます。この機能により、さまざまなサードパーティのツールやサービスのテストが簡単になります。</p><p>https://docs.snowflake.com/en/user-guide/ecosystem-partner-connect</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パートナー", "originalCorrect": null, "reviewPoint": ""}}, {"order": 50, "title": "ダイレクトデータ共有を通じて共有できるオブジェクトはどれですか？", "multiSelect": true, "stemHtml": "<p>ダイレクトデータ共有を通じて共有できるオブジェクトはどれですか？</p>", "options": [{"key": "A", "label": "ユーザー"}, {"key": "B", "label": "セキュアマテリアライズドビュー"}, {"key": "C", "label": "テーブル"}, {"key": "D", "label": "アカウント"}, {"key": "E", "label": "セキュアビュー"}], "correctAnswers": ["B", "C", "E"], "explanationHtml": "<p>✅ <strong>セキュアマテリアライズドビュー / テーブル / セキュアビュー</strong></p><p>ダイレクトデータ共有では以下の種類のオブジェクトを共有できます：テーブル、外部テーブル、セキュアビュー、セキュアマテリアライズドビュー、セキュアUDF。https://docs.snowflake.com/en/user-guide/data-sharing-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 51, "title": "Snowflakeの検索最適化を正しく説明する文はどれですか？該当するものをすべて選択してくださ...", "multiSelect": true, "stemHtml": "<p>Snowflakeの検索最適化を正しく説明する文はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "検索最適化サービスはマテリアライズドビュー機能に似ている。"}, {"key": "B", "label": "Snowflakeの検索最適化サービスは一般的なデータベースのセカンダリインデックスの概念に似ている。"}, {"key": "C", "label": "検索最適化サービスは、フィルタリングのために多くの述語を使用する一部のルックアップおよび分析クエリのパフォーマンスを大幅に向上させることができる。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>セカンダリインデックスに類似 / ルックアップ・分析クエリのパフォーマンス向上</strong></p><p>検索最適化サービスは、フィルタリングのために多くの述語を使用する一部のルックアップおよび分析クエリのパフォーマンスを大幅に向上させることができます。検索最適化サービスは、ポイントルックアップを高速化するために最適化された検索アクセスパスとして永続的なデータ構造を使用します。テーブルに対して検索最適化を有効にすると、メンテナンスサービスが検索アクセスパスを作成し、ルックアップに必要なデータを入力します。テーブルのサイズによっては、検索最適化データの入力にある程度の時間がかかる場合があります。検索最適化サービスはこの更新をバックグラウンドで実行するため、テーブル上の他のアクションを妨げません。https://docs.snowflake.com/en/user-guide/search-optimization-service</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 52, "title": "セッションが閉じられても存在し続けるテーブルタイプはどれですか？該当するものをすべて選択してくだ...", "multiSelect": true, "stemHtml": "<p>セッションが閉じられても存在し続けるテーブルタイプはどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "一時テーブル（Temporary）"}, {"key": "B", "label": "デュアルストレージ"}, {"key": "C", "label": "トランジェントテーブル（Transient）"}, {"key": "D", "label": "パーマネントテーブル（Permanent）"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>トランジェントテーブル / パーマネントテーブル</strong></p><p>パーマネントテーブルはセッションに関係なく存在し、セッションが閉じられても削除されません。トランジェントテーブルはセッションが閉じられてもドロップされないため、異なるセッションからアクセスできます。一時テーブルはセッションに対してローカルであり、セッションが閉じられるとすぐにドロップされます。https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ保護", "originalCorrect": null, "reviewPoint": ""}}, {"order": 53, "title": "Snowflakeで仮想ウェアハウスをスケールダウンするとはどういう意味ですか？該当するものをす...", "multiSelect": true, "stemHtml": "<p>Snowflakeで仮想ウェアハウスをスケールダウンするとはどういう意味ですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "仮想ウェアハウスをスケールダウンすると、ノードのプロビジョニングが解除されます。"}, {"key": "B", "label": "スケールダウンとは、より複雑なワークロードに対応するために仮想ウェアハウスのサイズを大きくすることを意味します。"}, {"key": "C", "label": "通常、仮想ウェアハウスはクエリの複雑さが低下した際にスケールダウンされます。"}, {"key": "D", "label": "スケールダウンとは、仮想ウェアハウスをより小さなサイズにリサイズすることを意味します。"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>ノードのプロビジョニング解除 / クエリ複雑さ低下への対応 / 小さいサイズへのリサイズ</strong></p><p>仮想ウェアハウスのスケールダウンは通常、クエリの複雑さが軽減され、より小さな仮想ウェアハウスでも効率的かつ時間通りにクエリを実行できる場合に行われます。より小さな仮想ウェアハウスが効率的かつ高速にクエリを実行できるときに大きな仮想ウェアハウスを維持することはリソースと費用の無駄です。そのような場合、仮想ウェアハウスのスケールダウンが選択肢となります。スケールダウン時はノードが仮想ウェアハウスから削除されます。ノードはクエリの実行が終了した後にのみ削除されます。https://docs.snowflake.com/en/user-guide/warehouses-considerations#scaling-up-vs-scaling-out</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 54, "title": "仮想ウェアハウスのコンピュートコストはどれに基づいて決まりますか？該当するものをすべて選択してく...", "multiSelect": true, "stemHtml": "<p>仮想ウェアハウスのコンピュートコストはどれに基づいて決まりますか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "仮想ウェアハウスが実行されていた期間。"}, {"key": "B", "label": "仮想ウェアハウスのサイズ。"}, {"key": "C", "label": "仮想ウェアハウスがサービスしたユーザー数。"}, {"key": "D", "label": "仮想ウェアハウスが実行したクエリ数。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>実行期間 / ウェアハウスのサイズ</strong></p><p>再開（アクティブ）状態の仮想ウェアハウスはコストに貢献します。発生するコストは仮想ウェアハウスのサイズに正比例します。例えば、同じ時間実行された場合、より大きな仮想ウェアハウスはより小さな仮想ウェアハウスよりもコストが高くなります。クエリ数とユーザー数は仮想ウェアハウスのコストには影響しません（ただし、マルチクラスター仮想ウェアハウスの場合、ユーザー/クエリの同時実行数が高くなると追加の仮想ウェアハウスが起動され、コストが増加する可能性があります）。https://docs.snowflake.com/en/user-guide/cost-understanding-compute</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "コストと価格", "originalCorrect": null, "reviewPoint": ""}}, {"order": 55, "title": "USERADMINロールについて正しい説明はどれですか？該当するものをすべて選択してください。", "multiSelect": true, "stemHtml": "<p>USERADMINロールについて正しい説明はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "USERADMINロールを持つユーザーは新しいロールを作成できます。"}, {"key": "B", "label": "USERADMINロールを持つユーザーは新しいユーザーを作成できます。"}, {"key": "C", "label": "USERADMINロールを持つユーザーはアカウント全体を管理できます。"}, {"key": "D", "label": "USERADMINロールを持つユーザーはオブジェクトの権限を管理できます。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>新しいロールの作成 / 新しいユーザーの作成</strong></p><p>USERADMINロールを使用すると、組織のUSERSとROLESを作成できます。USERADMINロールはオブジェクトの権限の管理やアカウントの管理を許可していません。https://docs.snowflake.com/en/user-guide/security-access-control-overview#system-defined-roles</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 56, "title": "次のうち、Snowflakeのビジネスインテリジェンスパートナーはどれですか？該当するものをすべ...", "multiSelect": true, "stemHtml": "<p>次のうち、Snowflakeのビジネスインテリジェンスパートナーはどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "PowerBI"}, {"key": "B", "label": "MicroStrategy"}, {"key": "C", "label": "Tableau"}, {"key": "D", "label": "Looker"}, {"key": "E", "label": "Oracle"}], "correctAnswers": ["A", "B", "C", "D", "E"], "explanationHtml": "<p>✅ <strong>PowerBI / MicroStrategy / Tableau / Looker / Oracle</strong></p><p>これらはすべてSnowflakeのビジネスインテリジェンスパートナーです。詳細は https://docs.Snowflake.com/en/user-guide/ecosystem.html を参照してください。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パートナー", "originalCorrect": null, "reviewPoint": ""}}, {"order": 57, "title": "Snowflakeアカウント間（組織内）のデータベースレプリケーションをサポートする最低のSno...", "multiSelect": false, "stemHtml": "<p>Snowflakeアカウント間（組織内）のデータベースレプリケーションをサポートする最低のSnowflakeエディションはどれですか？</p>", "options": [{"key": "A", "label": "Virtual Private Snowflake"}, {"key": "B", "label": "Standard"}, {"key": "C", "label": "Enterprise"}, {"key": "D", "label": "Business Critical"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>データベースレプリケーションはすべてのSnowflakeエディションでサポートされているため、それをサポートする最低エディションはStandardエディションです。https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 58, "title": "週次リリースサイクル中、リリースの初日に更新される可能性があるアカウントはどれですか？", "multiSelect": true, "stemHtml": "<p>週次リリースサイクル中、リリースの初日に更新される可能性があるアカウントはどれですか？</p>", "options": [{"key": "A", "label": "すべてのBusiness Criticalエディションのアカウント"}, {"key": "B", "label": "早期アクセスに選択したEnterpriseエディションのアカウントのみ"}, {"key": "C", "label": "すべてのEnterpriseエディションのアカウント"}, {"key": "D", "label": "Standardエディションのアカウント"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>早期アクセスのEnterpriseエディション / Standardエディション</strong></p><p>Snowflakeは新バージョンをすべてのSnowflakeアカウントに即座にデプロイするのではなく、段階的な方法で時間をかけてカスタマーアカウントを新しいリリースに移行します。1日目（早期アクセス）：早期アクセスを選択したEnterpriseエディション（またはそれ以上）のアカウントにデプロイされます。早期アクセスへのEnterpriseエディション（またはそれ以上）のアカウント登録は、Snowflakeサポートに連絡することで行えます。1日目または2日目（通常アクセス）：Standardエディションのすべてのsnowflakeアカウントへのデプロイ。2日目（最終）：残りのすべてのEnterpriseエディション（またはそれ以上）のアカウントがデプロイされます。早期アクセスデプロイと最終デプロイの間には最低24時間必要です。この段階的リリース戦略により、Snowflakeは早期アクセス中に発見されたソフトウェア問題を特定して対処できます。https://docs.snowflake.com/en/user-guide/intro-releases</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント", "originalCorrect": null, "reviewPoint": ""}}, {"order": 59, "title": "ストアドプロシージャが提供する機能はどれですか？", "multiSelect": true, "stemHtml": "<p>ストアドプロシージャが提供する機能はどれですか？</p>", "options": [{"key": "A", "label": "ループ"}, {"key": "B", "label": "仮想ウェアハウスの内部メモリへのアクセス"}, {"key": "C", "label": "SQL文の実行"}, {"key": "D", "label": "クラウドサービス層のクエリ"}, {"key": "E", "label": "条件ロジック"}], "correctAnswers": ["A", "C", "E"], "explanationHtml": "<p>✅ <strong>ループ / SQL文の実行 / 条件ロジック</strong></p><p>ストアドプロシージャを使用すると、SQLが通常提供しないif-elseロジック、ループ、その他の機能を使用できます。ストアドプロシージャを使用して、動的なSQL文をその場で組み立てて実行することもできます。https://docs.snowflake.com/en/sql-reference/stored-procedures-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 60, "title": "マテリアライズドビューが役立つシナリオはどれですか？該当するものをすべて選択してください。", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューが役立つシナリオはどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "クエリが各実行で無視できるほど少ないコンピュートクレジットを消費する。"}, {"key": "B", "label": "クエリが各実行で大量のコンピュートクレジットを消費する。"}, {"key": "C", "label": "クエリのコストが非常に低い。"}, {"key": "D", "label": "クエリが処理するデータはあまり変更されない。"}, {"key": "E", "label": "ベーステーブルのデータが頻繁に更新される。"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>大量のクレジット消費 / データの変更が少ない</strong></p><p>クエリまたはその軽微なバリエーションが頻繁に実行される場合、マテリアライズドビューが役立ちます。</p><p>実行されるクエリが複雑で時間とリソースを消費する場合、マテリアライズドビューは結果を事前計算し、処理を高速化できます。</p><p>クエリ結果が一貫しており、頻繁に変更されない場合、クエリの基礎となるデータはあまり頻繁に変更されないことを示しています。もしデータが頻繁に変更されるなら、マテリアライズドビューを最新の状態に保つために必要なリソースとコンピュートがビューの提供するメリットを上回ってしまいます。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 61, "title": "外部テーブルについて正しい説明はどれですか？該当するものをすべて選択してください。", "multiSelect": true, "stemHtml": "<p>外部テーブルについて正しい説明はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "外部テーブルはビューをサポートしない。"}, {"key": "B", "label": "外部テーブルは他のSnowflakeテーブルと結合できない。"}, {"key": "C", "label": "外部テーブルを使用すると、最初にSnowflakeにロードすることなくクラウドストレージのデータをクエリできます。"}, {"key": "D", "label": "外部テーブルの上にビューを作成できます。"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>ロードなしでクラウドストレージのデータをクエリ / ビューの作成が可能</strong></p><p>Snowflakeは外部クラウドストレージに保存されたデータを持つテーブルの作成を許可する外部テーブルと呼ばれる代替アプローチをテーブルに提供しています。外部テーブルはデータをSnowflakeにロードする必要をなくします。外部テーブルの場合、テーブルの定義はSnowflakeメタデータに保存され、テーブル構造、ファイルの場所、ファイル名、その他の属性で構成されています。ただし、テーブルのデータはSnowflakeの外部に保存されます。外部テーブル機能を使用すると、外部データを標準テーブルのようにクエリできます。例えば、外部テーブルは他のテーブルと結合でき、それらを使用してビューを作成することもできます。https://docs.snowflake.com/en/user-guide/tables-external-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 62, "title": "マイクロパーティションは値の範囲で重複できますか？", "multiSelect": false, "stemHtml": "<p>マイクロパーティションは値の範囲で重複できますか？</p>", "options": [{"key": "A", "label": "いいえ"}, {"key": "B", "label": "はい"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>はい</strong></p><p>マイクロパーティションは不変であり、データの変更や新しいデータは新しいマイクロパーティションを必要とするため、類似した値が同じ物理パーティションに存在する保証はなく、パーティションの値も重複する可能性があります。https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 63, "title": "Snowflakeの次のWebベースのインターフェースはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeの次のWebベースのインターフェースはどれですか？</p>", "options": [{"key": "A", "label": "Snowpipe"}, {"key": "B", "label": "SnowSQL"}, {"key": "C", "label": "SnowCD"}, {"key": "D", "label": "Snowsight"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>Snowsight</strong></p><p>Snowsightは新しい技術を使用した近代的で軽量なWebインターフェースであり、Snowflakeインスタンスと対話するための主要な方法です。https://docs.snowflake.com/en/user-guide/snowsql</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 64, "title": "正誤問題：Snowflake Marketplaceを使用すると、顧客はさまざまな組織が提供する...", "multiSelect": false, "stemHtml": "<p>正誤問題：Snowflake Marketplaceを使用すると、顧客はさまざまな組織が提供する公開されているサードパーティのデータセットを検索して利用できます。</p>", "options": [{"key": "A", "label": "誤り"}, {"key": "B", "label": "正しい"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>Snowflake Marketplaceは、データセットを購入・販売できるオンラインマーケットプレイスです。Snowflake Marketplaceを通じて、会社外のデータをSnowflakeインスタンスにインポートし、データの充実に活用できます。https://other-docs.snowflake.com/en/collaboration/collaboration-marketplace-about.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 65, "title": "Snowflakeシステム管理者が、それぞれ1GBのサイズの8つのファイルをロードするための新し...", "multiSelect": true, "stemHtml": "<p>Snowflakeシステム管理者が、それぞれ1GBのサイズの8つのファイルをロードするための新しい仮想ウェアハウスを作成しています。仮想ウェアハウスは毎日のデータロード専用です。どのように設定すべきですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "組織に適切なサイズを判断するためにSnowflakeに連絡する。"}, {"key": "B", "label": "マルチクラスター仮想ウェアハウスを作成する。"}, {"key": "C", "label": "仮想ウェアハウスのサイズとしてX-SmallまたはSmallを選択する。"}, {"key": "D", "label": "仮想ウェアハウスを自動停止・自動再開するように設定する。"}, {"key": "E", "label": "仮想ウェアハウスのサイズとして5X-Largeを選択する。"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>X-SmallまたはSmallのサイズ / 自動停止・自動再開の設定</strong></p><p>大量のファイルを並列でロードしない限り、より大きな仮想ウェアハウスのサイズは何のメリットも提供しません。SmallまたはX-Small仮想ウェアハウスは、小規模で低頻度のファイルロードには十分です。</p><p>このシナリオでは自動停止と自動再開を設定することが有用です。データロードが完了した後にクレジットを節約できます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-considerations-plan</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 66, "title": "正誤問題：新しいユーザーが作成されると、ユーザーは自動的に多要素認証（MFA）に登録されます。", "multiSelect": false, "stemHtml": "<p>正誤問題：新しいユーザーが作成されると、ユーザーは自動的に多要素認証（MFA）に登録されます。</p>", "options": [{"key": "A", "label": "誤り"}, {"key": "B", "label": "正しい"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>誤り</strong></p><p>多要素認証（MFA）はすべてのSnowflakeアカウントでデフォルトで有効になっており、すべてのSnowflakeユーザーはSnowflakeウェブインターフェースを通じてMFAに自分で登録できます。多要素認証はすべてのアカウントおよびすべてのユーザーに対して有効ですが、新しいユーザーは自動的にMFAに登録されません。代わりに、ユーザー自身がMFA登録プロセスを開始して完了する必要があります。https://docs.snowflake.com/en/user-guide/security-mfa</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 67, "title": "外部テーブルを作成するために必要な最低のSnowflakeエディションはどれですか？", "multiSelect": false, "stemHtml": "<p>外部テーブルを作成するために必要な最低のSnowflakeエディションはどれですか？</p>", "options": [{"key": "A", "label": "Virtual Private Snowflake"}, {"key": "B", "label": "Business Critical"}, {"key": "C", "label": "Standard"}, {"key": "D", "label": "Enterprise"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>すべてのSnowflakeエディションで外部テーブルがサポートされているため、サポートする最低エディションはStandardエディションです。https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 68, "title": "クエリを処理する際、Snowflakeが使用する可能性のあるキャッシュの種類はどれですか？該当す...", "multiSelect": true, "stemHtml": "<p>クエリを処理する際、Snowflakeが使用する可能性のあるキャッシュの種類はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "ウェアハウスキャッシュ"}, {"key": "B", "label": "クラウドキャッシュ"}, {"key": "C", "label": "メモリキャッシュ"}, {"key": "D", "label": "クエリ結果キャッシュ"}, {"key": "E", "label": "メタデータキャッシュ"}], "correctAnswers": ["A", "D", "E"], "explanationHtml": "<p>✅ <strong>ウェアハウスキャッシュ / クエリ結果キャッシュ / メタデータキャッシュ</strong></p><p>クエリパフォーマンスを向上させるために、Snowflakeはさまざまなキャッシング技術を採用しています。新しいクエリが実行のために送信されると、Snowflakeはメタデータキャッシュまたはクエリ結果キャッシュを使用してすぐにクエリ結果を提供できます。各仮想ウェアハウスには独自のキャッシュがあり、クエリを実行しながら時間をかけてクラウドストレージからローカルSSDストレージに関連するマイクロパーティションを移動することで構築されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 69, "title": "正誤問題：SnowflakeはTLS 1.2を使用してすべてのデータのエンドツーエンドの転送中暗...", "multiSelect": false, "stemHtml": "<p>正誤問題：SnowflakeはTLS 1.2を使用してすべてのデータのエンドツーエンドの転送中暗号化を行っています。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>SnowflakeはTransport Layer Security（TLS）1.2を使用してすべての転送中のデータを暗号化します。これはSnowflake Webインターフェース、JDBC、ODBC、Pythonコネクターを通じたものを含む、すべてのSnowflake接続に適用されます。https://docs.snowflake.com/en/user-guide/security-encryption-end-to-end</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 70, "title": "Snowflakeユーザーが実行できるアクションはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeユーザーが実行できるアクションはどれですか？</p>", "options": [{"key": "A", "label": "マイクロパーティションを直接変更する。"}, {"key": "B", "label": "SQLを使用してフェイルセーフストレージの履歴データを取得する。"}, {"key": "C", "label": "マイクロパーティションに直接アクセスする。"}, {"key": "D", "label": "SQLを使用してタイムトラベルのデータを取得する。"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>SQLを使用したタイムトラベルデータの取得</strong></p><p>Snowflakeユーザーは、SQLタイムトラベル拡張機能を使用してタイムトラベルデータにアクセスできます。フェイルセーフストレージに保存されたデータはSnowflakeサポートのみがアクセスできます。ユーザーはフェイルセーフストレージのデータにアクセスできません。ユーザーはマイクロパーティションに直接アクセスまたは変更することはできません。https://docs.snowflake.com/en/user-guide/data-time-travel#time-travel-sql-extensions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 71, "title": "このコースの練習問題が実際の認定試験の問題と同一でないのはなぜですか？", "multiSelect": false, "stemHtml": "<p>このコースの練習問題が実際の認定試験の問題と同一でないのはなぜですか？</p>", "options": [{"key": "A", "label": "関係のないトピックで学生に挑戦し、意図的に混乱させるため。"}, {"key": "B", "label": "特定の問題の丸暗記に頼るのではなく、概念の知識と理解をテストするため。"}, {"key": "C", "label": "コースの作成者が実際の試験問題を知らないため。"}, {"key": "D", "label": "学生が正確な問題と回答を暗記できるようにするため。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>概念の知識と理解をテストするため</strong></p><p>このコースは認定試験に必要な概念とトピックを完全に理解するための設計です。練習問題は、実際の試験の問題を反映するためではなく、知識をテストし、学習内容の理解を強化するために作成されています。</p><p>これらの問題は試験の目標に沿っていますが、認定試験の問題と同一ではありません。目的は、答えを暗記するのではなく、基礎となる概念を習得することで、どんな問題にも自信を持って取り組めるよう準備することです。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "(なし)", "originalCorrect": null, "reviewPoint": ""}}, {"order": 72, "title": "正誤問題：ACCOUNT_USAGEスキーマのビューを使用すると、5分前に発生した使用履歴にアク...", "multiSelect": false, "stemHtml": "<p>正誤問題：ACCOUNT_USAGEスキーマのビューを使用すると、5分前に発生した使用履歴にアクセスできます。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>誤り</strong></p><p>ACCOUNT USAGEスキーマは、アカウントレベルの使用メトリクスとメタデータ情報を提供するいくつかのビューで構成されています。ACCOUNT_USAGEビューが提供するデータはリアルタイムではなく、通常ビューによって45分から3時間のラグでリフレッシュされます。これらのビューのデータは最大365日間保持されます。https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 73, "title": "リーダーアカウントは、そのリーダーアカウントを作成したプロデューサー以外のソースからデータを消費...", "multiSelect": false, "stemHtml": "<p>リーダーアカウントは、そのリーダーアカウントを作成したプロデューサー以外のソースからデータを消費できます。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>誤り</strong></p><p>リーダーアカウントは、そのリーダーアカウントを作成・所有するデータプロバイダー以外のデータプロバイダーからデータを消費することはできません。https://docs.snowflake.com/en/user-guide/data-sharing-reader-create#what-is-restricted-allowed-in-a-reader-account</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 74, "title": "データベースまたはスキーマがクローンされた場合、そのデータベース内のステージについて有効な説明は...", "multiSelect": true, "stemHtml": "<p>データベースまたはスキーマがクローンされた場合、そのデータベース内のステージについて有効な説明はどれですか？</p>", "options": [{"key": "A", "label": "外部ステージはクローンされます。"}, {"key": "B", "label": "外部ステージはクローンされません。"}, {"key": "C", "label": "名前付き内部ステージはクローンされません。"}, {"key": "D", "label": "名前付き内部ステージはクローンされます。"}, {"key": "E", "label": "テーブルステージはクローンされます。"}], "correctAnswers": ["A", "C", "E"], "explanationHtml": "<p>✅ <strong>外部ステージはクローン / 名前付き内部ステージはクローン不可 / テーブルステージはクローン</strong></p><p>名前付き内部ステージはクローンできません。データベースまたはスキーマがクローンされる場合、名前付き内部ステージを指すSnowpipeはクローンされません。名前付き外部ステージはクローンできます。テーブルステージはテーブルに関連付けられているため、テーブルがクローンされると自動的にクローンされます。https://docs.snowflake.com/en/user-guide/object-clone</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 75, "title": "ORGADMINが実行できるアクションはどれですか？2つ選択してください。", "multiSelect": true, "stemHtml": "<p>ORGADMINが実行できるアクションはどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "組織の新しいアカウントを作成する。"}, {"key": "B", "label": "どのアカウントのテーブルのデータも選択する。"}, {"key": "C", "label": "組織配下のすべてのアカウントの使用情報を表示する。"}, {"key": "D", "label": "どのアカウントのテーブルのデータも更新する。"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>新しいアカウントの作成 / すべてのアカウントの使用情報の表示</strong></p><p>ORGADMINロールはすべてのアカウントのリストや新しいアカウントの作成など、組織固有のタスクを実行します。ORGADMINは必要に応じてアカウントを削除することもできます。</p><p>ただし、アカウント内のデータを見ることはできません。例えば、テーブルのデータを選択したり変更したりすることはできません。</p><p>https://docs.snowflake.com/en/user-guide/organizations#orgadmin-role</p><p>https://docs.snowflake.com/en/user-guide/organizations-manage-accounts-delete</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 76, "title": "外部テーブルは外部ステージを使用してのみ作成できます。", "multiSelect": false, "stemHtml": "<p>外部テーブルは外部ステージを使用してのみ作成できます。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>外部テーブルはメタデータ定義です。つまり、外部テーブルの定義を登録しますが、外部テーブル自体にはデータが含まれていません。テーブルのメタデータには、列定義、外部テーブルのデータが含まれる外部ステージの名前、そのデータを読み取るために使用するファイル形式が含まれています。外部ステージは、外部テーブルのデータを含むクラウド上のオブジェクトストレージ（例：AWSバケットまたはAzure Blobストレージ）を指します。外部テーブルは外部ステージのみを指定できることに注意してください。内部ステージを使用して外部テーブルを作成することはできません。https://docs.snowflake.com/en/user-guide/tables-external-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 77, "title": "クエリを実行中にSnowflakeがスキャンプロセスから一部のパーティションを除外することを何と...", "multiSelect": false, "stemHtml": "<p>クエリを実行中にSnowflakeがスキャンプロセスから一部のパーティションを除外することを何と呼びますか？</p>", "options": [{"key": "A", "label": "テーブルスキャン"}, {"key": "B", "label": "パーティションインデックス"}, {"key": "C", "label": "パーティションプルーニング"}, {"key": "D", "label": "インメモリ操作"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>パーティションプルーニング</strong></p><p>Snowflakeのメタデータにより、SnowflakeクエリエンジンはクエリのパーティションをWHERE条件で指定した値に一致しないパーティションをスキャンしないことでクエリ実行を最適化できます。https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions#query-pruning</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 78, "title": "次のシナリオを考えてください。Large サイズのマルチクラスター仮想ウェアハウスでクエリが実行...", "multiSelect": false, "stemHtml": "<p>次のシナリオを考えてください。Large サイズのマルチクラスター仮想ウェアハウスでクエリが実行されており、スケーリングポリシーはEconomyに設定されています。ウェアハウスは現在対応できる最大数のクエリを実行しています。追加のクエリが実行されるとどうなりますか？</p>", "options": [{"key": "A", "label": "仮想ウェアハウスのサイズがX-Largeにスケールアップされる。"}, {"key": "B", "label": "マルチクラスター仮想ウェアハウスは、システムが少なくとも6分間ビジーに保てる十分な作業があると判断した場合にのみ新しい仮想ウェアハウスを追加する。"}, {"key": "C", "label": "追加の仮想ウェアハウス（Largeサイズ）がほぼ即座にクラスターに追加され、追加のクエリを実行する。"}, {"key": "D", "label": "仮想ウェアハウスのサイズがX-Largeにスケールアップされる。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>6分間ビジーに保てる十分な作業がある場合のみ新しいウェアハウスを追加</strong></p><p>スケーリングポリシーがEconomyに設定されている場合、パフォーマンスを犠牲にしてコストを節約するために、スケールアップ前にキューイングをある程度継続することを許可します。新しい仮想ウェアハウスは、システムが新しいウェアハウスを少なくとも6分間ビジーに保てる十分なクエリ負荷があると判断した場合にのみ起動されます。スケールダウン時、システムはワークロードを他のウェアハウスに再割り当てできるかどうかを判断するために5〜6回の連続チェックを実行します。基準が満たされると、仮想ウェアハウスはスケールダウンされます。これらのチェックは1分間隔で実行されます。https://docs.snowflake.com/en/user-guide/warehouses-multicluster#setting-the-scaling-policy-for-a-multi-cluster-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 79, "title": "Snowpipeは次のどこから直接データをロードできますか？該当するものをすべて選択してください...", "multiSelect": true, "stemHtml": "<p>Snowpipeは次のどこから直接データをロードできますか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "内部ステージ"}, {"key": "B", "label": "オンプレミスシステム"}, {"key": "C", "label": "Snowflakeテーブル"}, {"key": "D", "label": "外部ステージ"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>内部ステージ / 外部ステージ</strong></p><p>Snowpipeは外部ステージおよび内部ステージからデータをロードできます。外部ステージを使用する場合、クラウドプラットフォームの通知を使用してSnowpipeをトリガーできます。クラウドストレージバケットで新しいファイルが検出されるとすぐにイベントをトリガーするようにクラウドプラットフォームの通知を設定できます。追加の設定でイベントとSnowpipeをリンクすると、新しいファイルが届くたびにSnowpipeが自動的にトリガーされます。トリガーされると、Snowpipeはその定義からCOPYコマンドを実行し、新しく受信したデータをターゲットテーブルにロードします。代替メカニズムはREST APIコールによるもので、必要に応じてSnowpipe固有のREST APIを呼び出してSnowpipeをトリガーするプログラムを作成する必要があります。REST APIを使用すると、スケジュールされたベースでもアドホックベースでも、いつSnowpipeをトリガーするかを制御できます。内部ステージをSnowpipeで使用する場合は、REST API経由でSnowpipeをトリガーする必要があることに注意してください。内部ステージをソースとして使用する場合、通知ベースのSnowpipe起動のプロビジョニングはありません。注意：SnowpipeはS3バケットを直接チェックしてファイルを探すことができず、通知またはREST APIコールによってトリガーされる必要があります。https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 80, "title": "正誤問題：リソースモニターは単一の仮想ウェアハウス、仮想ウェアハウスのコレクション、またはSno...", "multiSelect": false, "stemHtml": "<p>正誤問題：リソースモニターは単一の仮想ウェアハウス、仮想ウェアハウスのコレクション、またはSnowflakeアカウント全体を管理できます。</p>", "options": [{"key": "A", "label": "誤り"}, {"key": "B", "label": "正しい"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>リソースモニターは定義されたクォータに対して単一の仮想ウェアハウスを追跡・管理できます。リソースモニターは複数の仮想ウェアハウスのクレジット使用量を合わせて追跡するために作成できます。リソースモニターはアカウントレベルでも作成でき、これはすべての仮想ウェアハウスのクレジット使用量を考慮してアカウントレベルでのクレジット使用量を追跡するリソースモニターです。https://docs.snowflake.com/en/user-guide/resource-monitors#assignment-of-resource-monitors</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 81, "title": "Snowflakeの組み込みシステムロールについて正しい説明はどれですか？2つ選択してください。", "multiSelect": true, "stemHtml": "<p>Snowflakeの組み込みシステムロールについて正しい説明はどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "ACCOUNTADMINは組み込みロールにデフォルトで付与された権限を取り消すことができる。"}, {"key": "B", "label": "組み込みロールにデフォルトで付与された権限は取り消すことができません。"}, {"key": "C", "label": "組み込みロールはドロップできません。"}, {"key": "D", "label": "ORGADMINは組み込みロールにデフォルトで付与された権限を取り消すことができる。"}, {"key": "E", "label": "組み込みロールは必要に応じてドロップできます。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>組み込みロールの権限は取り消し不可 / 組み込みロールはドロップ不可</strong></p><p>組み込みのシステム定義ロールはドロップできません。それらのロールに付与されたデフォルトの権限は取り消せません。</p><p>https://docs.snowflake.com/en/user-guide/security-access-control-overview#roles</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 82, "title": "SnowflakeアカウントがSnowflake以外のユーザーまたはSnowflake以外の組織...", "multiSelect": false, "stemHtml": "<p>SnowflakeアカウントがSnowflake以外のユーザーまたはSnowflake以外の組織とデータを共有する場合のコストについて正しい説明はどれですか？</p>", "options": [{"key": "A", "label": "データプロバイダーとデータコンシューマーの両方がコンピュートコストを請求される。"}, {"key": "B", "label": "データプロバイダーはデータコンシューマーが実行するクエリのコンピュートコストを請求される。"}, {"key": "C", "label": "データコンシューマーは実行するクエリのコンピュートコストを請求される。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>データプロバイダーがコンシューマーのクエリのコンピュートコストを負担</strong></p><p>Snowflake以外のユーザーや組織とデータを共有するには、リーダーアカウントを作成します。このリーダーアカウントはデータプロバイダーが共有目的のみで作成します。データプロバイダーがリーダーアカウントを作成・管理するため、リーダーアカウントのすべてのコンピュート費用はプロバイダーアカウントに請求されます。したがって、リーダーアカウントによる仮想ウェアハウスのコンピュート使用はプロバイダーアカウントのコンピュートチャージに追加されます。https://docs.snowflake.com/en/user-guide/data-sharing-reader-create#overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 83, "title": "専用のコンピュートリソースをサポートする最低のSnowflakeエディションはどれですか？", "multiSelect": false, "stemHtml": "<p>専用のコンピュートリソースをサポートする最低のSnowflakeエディションはどれですか？</p>", "options": [{"key": "A", "label": "Standard"}, {"key": "B", "label": "Enterprise"}, {"key": "C", "label": "Virtual Private Snowflake"}, {"key": "D", "label": "Business Critical"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Virtual Private Snowflake</strong></p><p>VPSエディションは他のカスタマーからの分離を提供するために設計されており、各インスタンスは独自のメタデータストアとコンピュートリソースを持っています。https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 84, "title": "正誤問題：クラスタリングキーを定義する際、カーディナリティが非常に低い列を選択すべきです。", "multiSelect": false, "stemHtml": "<p>正誤問題：クラスタリングキーを定義する際、カーディナリティが非常に低い列を選択すべきです。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>誤り</strong></p><p>クラスタリングキーを定義する際、最初の候補となるクラスタリング列はWHERE句や他の選択的フィルターで頻繁に使用される列です。</p><p>さらに、結合に使用される列も検討できます。</p><p>また、列のカーディナリティ（異なる値の数）も重要です。効果的なパーティションプルーニングを可能にするほど高いカーディナリティを持ちながら、Snowflakeがデータをマイクロパーティションに効率的にグループ化できるほど低いカーディナリティを持つ列を選択することが重要です。異なる値が少なすぎる列（例：性別）はパーティションプルーニングがほとんど行われません。一方、異なる値が多すぎる列（例：顧客ID）はパーティションのメンテナンスに過剰なオーバーヘッドをもたらします。</p><p>また、マルチ列クラスターキーを作成する際は、クラスタリングの効果が低下しないよう、最低カーディナリティから最高カーディナリティの順に列を並べてください。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 85, "title": "正誤問題：Snowflakeはオンプレミスサーバーにインストールして利用できます。", "multiSelect": false, "stemHtml": "<p>正誤問題：Snowflakeはオンプレミスサーバーにインストールして利用できます。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>誤り</strong></p><p>誤りです。Snowflakeはクラウド向けに設計されており、AWS、Azure、GCPのみで利用可能です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 86, "title": "高可用性を確保するためにSnowflakeがレプリケートする2つの層はどれですか？該当するものを...", "multiSelect": true, "stemHtml": "<p>高可用性を確保するためにSnowflakeがレプリケートする2つの層はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "クラウドサービス層"}, {"key": "B", "label": "パートナー層"}, {"key": "C", "label": "ストレージ層"}, {"key": "D", "label": "コンピュート層"}, {"key": "E", "label": "オンプレミスストレージ"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>クラウドサービス層 / ストレージ層</strong></p><p>Snowflakeはクラウドサービス層とストレージ層を自動的に3つのアベイラビリティゾーンにレプリケートします。クラウドプロバイダーのBlobストアを使用するストレージ層は、複数のディスクデバイスと少なくとも3つのアベイラビリティゾーンにわたって同期的にレプリケートされ、ユーザーには透過的に行われます。</p><p>同様に、主にメタデータストレージシステムで構成されるクラウドサービス層は3つのアベイラビリティゾーンにわたってデプロイ・レプリケートされます。</p><p>仮想ウェアハウスであるコンピュート層はレプリケートされませんが、必要に応じてSnowflakeは別のアベイラビリティゾーンでコンピュートインスタンスを起動できます。</p><p>https://developers.snowflake.com/wp-content/uploads/2021/06/Snowflake-High-Availability-for-Data-Apps-Whitepaper.pdf</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 87, "title": "一時テーブル（Temporary）をクローンしようとした場合の動作について正しい説明はどれですか...", "multiSelect": true, "stemHtml": "<p>一時テーブル（Temporary）をクローンしようとした場合の動作について正しい説明はどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "一時テーブルは一時テーブルにクローンできます。"}, {"key": "B", "label": "一時テーブルはパーマネントテーブルにクローンできます。"}, {"key": "C", "label": "一時テーブルは外部テーブルにクローンできます。"}, {"key": "D", "label": "一時テーブルはトランジェントテーブルにクローンできます。"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>一時テーブルへのクローン / トランジェントテーブルへのクローン</strong></p><p>一時テーブルはパーマネントテーブルにクローンできません。</p><p>そうすると通常「Temp table cannot be cloned to a permanent table; clone to a transient table instead.」というエラーが表示されます。</p><p>ただし、一時テーブルはトランジェントテーブルまたは別の一時テーブルにクローンできます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 88, "title": "データベースが消費するストレージを表示するために使用できるACCOUNT_USAGEビューはどれ...", "multiSelect": false, "stemHtml": "<p>データベースが消費するストレージを表示するために使用できるACCOUNT_USAGEビューはどれですか？</p>", "options": [{"key": "A", "label": "ACCOUNT_USAGE.TAGS"}, {"key": "B", "label": "ACCOUNT_USAGE.DATABASES"}, {"key": "C", "label": "ACCOUNT_USAGE.SESSIONS"}, {"key": "D", "label": "ACCOUNT_USAGE.DATABASE_STORAGE_USAGE_HISTORY"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>ACCOUNT_USAGE.DATABASE_STORAGE_USAGE_HISTORY</strong></p><p>ACCOUNT_USAGEスキーマのDATABASE_STORAGE_USAGE_HISTORYビューは各データベースが使用したデータベースストレージのバイト数を表示します。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage/database_storage_usage_history</p><p>DATABASESビューは各データベースに関する情報を提供しますが、消費されたサイズは表示されません。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage/databases</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 89, "title": "COPYコマンドでデータをロードする際に使用できる簡単な変換はどれですか？", "multiSelect": true, "stemHtml": "<p>COPYコマンドでデータをロードする際に使用できる簡単な変換はどれですか？</p>", "options": [{"key": "A", "label": "列の省略"}, {"key": "B", "label": "キャスト"}, {"key": "C", "label": "列の並び替え"}, {"key": "D", "label": "ピボット"}, {"key": "E", "label": "転置"}, {"key": "F", "label": "切り捨て（Truncate）"}], "correctAnswers": ["A", "B", "C", "F"], "explanationHtml": "<p>✅ <strong>列の省略 / キャスト / 列の並び替え / 切り捨て</strong></p><p>COPYコマンドを使用してテーブルにデータをロードする場合、Snowflakeはデータのロード中に簡単な変換を実行できます。ロードプロセス中、COPYコマンドは列の順序変更、1つ以上の列の省略、指定したデータ型へのキャスト、値の切り捨てを許可します。ロード中は、結合、フィルター、集計、FLATTENの使用などの複雑な変換はサポートされていません。これらは必須のデータ変換ではないためです。したがって、データの結合、フィルタリング、集計はデータがテーブルにロードされた後にのみサポートされます。https://docs.snowflake.com/en/user-guide/data-load-overview#id2</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 90, "title": "ACCOUNTADMINは次のどのロールの権限を継承しますか？該当するものをすべて選択してくださ...", "multiSelect": true, "stemHtml": "<p>ACCOUNTADMINは次のどのロールの権限を継承しますか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "SECURITYADMIN"}, {"key": "B", "label": "SUPERADMIN"}, {"key": "C", "label": "SYSADMIN"}, {"key": "D", "label": "ORGADMIN"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>SECURITYADMIN / SYSADMIN</strong></p><p>ロール階層と権限の継承により、ACCOUNTADMINはSECURITYADMIN、USERADMIN、SYSADMINが持つすべての権限を持っています。</p><p>https://docs.snowflake.com/en/user-guide/security-access-control-overview#system-defined-roles</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 91, "title": "正誤問題：Snowflakeシステムに複数の仮想ウェアハウスがある場合、それらは同じ共有データに...", "multiSelect": false, "stemHtml": "<p>正誤問題：Snowflakeシステムに複数の仮想ウェアハウスがある場合、それらは同じ共有データにアクセスします。</p>", "options": [{"key": "A", "label": "誤り"}, {"key": "B", "label": "正しい"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>Snowflakeは共有ディスクアーキテクチャと同様にデータを共有して保存します。しかし、それぞれが独自のメモリと処理能力を持つ複数のコンピュートエンジンの使用も可能にしています。仮想ウェアハウスは互いに独立していますが、同じ共有データにアクセスして処理します。https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 92, "title": "外部関数のコードはどこで実行されますか？", "multiSelect": false, "stemHtml": "<p>外部関数のコードはどこで実行されますか？</p>", "options": [{"key": "A", "label": "Snowflakeの外部"}, {"key": "B", "label": "クラウドサービス層内"}, {"key": "C", "label": "仮想ウェアハウスのメモリ内"}, {"key": "D", "label": "Snowflakeのサンドボックス内"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>Snowflakeの外部</strong></p><p>外部関数は他のUDFとは異なり、独自のコードを含まず、代わりにSnowflakeの外部で保存・実行されるコードを呼び出します。外部関数については、Snowflake内に保存されるのはリモートサービスを呼び出すためにSnowflakeが使用する情報のみです。https://docs.snowflake.com/en/sql-reference/external-functions-introduction</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 93, "title": "Snowflakeアカウントで最も強力なロールはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeアカウントで最も強力なロールはどれですか？</p>", "options": [{"key": "A", "label": "SECURITYADMIN"}, {"key": "B", "label": "SYSADMIN"}, {"key": "C", "label": "ACCOUNTADMIN"}, {"key": "D", "label": "PUBLIC"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>ACCOUNTADMIN</strong></p><p>ACCOUNTADMINはSnowflakeアカウントで最も強力なロールです。ACCOUNTADMINロールへのアクセスは慎重に管理する必要があります。ACCOUNTADMINロールを持つユーザーは、アカウントを侵害されにくくするためにMFAを有効にすべきです。https://docs.snowflake.com/en/user-guide/security-access-control-overview#system-defined-roles</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 94, "title": "正誤問題：テーブルがクローンされると、ソーステーブルのデータのスナップショットが取得され、ソース...", "multiSelect": false, "stemHtml": "<p>正誤問題：テーブルがクローンされると、ソーステーブルのデータのスナップショットが取得され、ソースデータの状態を表します。クローンされたテーブルはクローン時のデータのスナップショットに基づいています。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>クローニングはメタデータ操作であり、データの実際のコピーは発生しません。クローンされるオブジェクトのデータのスナップショットが取得され、クローンされたオブジェクトで利用可能になります。クローンされたテーブルのメタデータはスナップショット時の既存のマイクロパーティションを参照します。https://docs.snowflake.com/en/user-guide/tables-storage-considerations#label-cloning-tables</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 95, "title": "正誤問題：どのSnowflakeアカウントもデータプロバイダーまたはコンシューマーとして機能でき...", "multiSelect": false, "stemHtml": "<p>正誤問題：どのSnowflakeアカウントもデータプロバイダーまたはコンシューマーとして機能できるため、どのSnowflakeアカウントもデータを共有または消費できます。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>正しい</strong></p><p>正しいです。どのSnowflakeアカウントもデータを共有しながら、同時に別のプロバイダーからデータを消費できます。したがって、Snowflakeはデータプロバイダーとコンシューマーの両方として機能できます。Virtual Private Snowflake（VPS）アカウントは例外です。VPSアカウントはメタデータとコンピュートが分離されているため、共有機能を持ちません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 96, "title": "Snowpipeは同じ名前のファイルが変更された場合に再ロードできますか？", "multiSelect": false, "stemHtml": "<p>Snowpipeは同じ名前のファイルが変更された場合に再ロードできますか？</p>", "options": [{"key": "A", "label": "いいえ"}, {"key": "B", "label": "はい"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>いいえ</strong></p><p>ロードメタデータには、そのテーブルにロードされたすべてのファイルの名前や対応するファイルがロードされた時のタイムスタンプなど、さまざまな情報が保存されます。このロードメタデータを活用することで、Snowflakeはすでにロードされたファイルを再処理しないことを保証します。https://docs.snowflake.com/en/user-guide/data-load-snowpipe-ts#unable-to-reload-modified-data-modified-data-loaded-unintentionally</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 97, "title": "ProductDetailsというテーブルのInventoryというVARIANT列に以下のJS...", "multiSelect": false, "stemHtml": "<p>ProductDetailsというテーブルのInventoryというVARIANT列に以下のJSON構造が保存されています。</p>", "options": [{"key": "A", "label": "`SELECT Inventory:Product.name FROM ProductDetails`"}, {"key": "B", "label": "`SELECT Inventory:product.Name FROM ProductDetails`"}, {"key": "C", "label": "`SELECT EXTRACT_FROM_JSON(\"name\",\"Inventory\\Product\") FROM ProductDetails`"}, {"key": "D", "label": "`SELECT Inventory.Product:name FROM ProductDetails`"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong><code>SELECT Inventory:Product.name FROM ProductDetails</code></strong></p><p>ドット記法はJSONオブジェクトのパスをトラバースするために使用されます。典型的な構文は <code>&lt;column_name&gt;:&lt;level1_element&gt;.&lt;level2_element&gt;.&lt;level3_element&gt;</code> です。列名と第1レベルの要素名の間にセミコロンが使用されることに注意してください。さらに深いサブ要素にはドットが使用されます。</p><p>要素名は大文字小文字を区別します。したがって、Inventory:Product.name は Inventory:product.Name とは異なります。</p><p>詳細は以下のリンクを参照してください。</p><p>https://docs.snowflake.com/en/user-guide/querying-semistructured#dot-notation</p><p>https://docs.snowflake.com/en/user-guide/querying-semistructured#dot-notation:~:text=element%20names%20are%20case%2Dsensitive</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 98, "title": "Snowflakeテーブルにデータを保存する必要があります。どのデータ型を使用しますか？", "multiSelect": false, "stemHtml": "<p>Snowflakeテーブルにデータを保存する必要があります。どのデータ型を使用しますか？</p>", "options": [{"key": "A", "label": "VARBINARY"}, {"key": "B", "label": "STRING"}, {"key": "C", "label": "VARIANT"}, {"key": "D", "label": "VARCHAR"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>VARIANT</strong></p><p>SnowflakeはJSON等の半構造化データのロードと処理をサポートしています。Snowflakeはあらゆるデータを保存できるVARIANTデータ型を提供しており、半構造化データの入力とクエリに適しています。JSONデータがVARIANT列にロードされると、SQLを使用してJSONデータを読み取ってナビゲートできます。https://docs.snowflake.com/en/user-guide/semistructured-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 99, "title": "PUTコマンドは何に使用されますか？", "multiSelect": false, "stemHtml": "<p>PUTコマンドは何に使用されますか？</p>", "options": [{"key": "A", "label": "クラウドオブジェクトストレージからオンプレミスストレージへのデータ転送"}, {"key": "B", "label": "Snowflakeの内部ステージへのデータ転送"}, {"key": "C", "label": "Snowflakeの外部ステージへのデータ転送"}, {"key": "D", "label": "オンプレミスストレージからクラウドオブジェクトストレージへのデータ転送"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Snowflakeの内部ステージへのデータ転送</strong></p><p>PUTコマンドはオンプレミスシステムから内部ステージにデータをアップロードします。GETコマンドは内部ステージからオンプレミスシステムにデータをダウンロードするために使用されます。外部ステージとのデータのダウンロード・アップロードには、外部ステージが指すクラウドストレージのデータと対話するためにクラウドプロバイダーのユーティリティや他のツールが使用されます。https://docs.snowflake.com/en/user-guide/data-unload-overview#bulk-unloading-process</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 100, "title": "6X-Largeの仮想ウェアハウスのノード数はいくつですか？", "multiSelect": false, "stemHtml": "<p>6X-Largeの仮想ウェアハウスのノード数はいくつですか？</p>", "options": [{"key": "A", "label": "256"}, {"key": "B", "label": "128"}, {"key": "C", "label": "512"}, {"key": "D", "label": "64"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>512</strong></p><p>6X-Largeは現時点で最大のクラスター構成であり、512ノードを持っています。計算の簡単な方法は、8ノードを持つLargeサイズから始めることです。6X-LargeはLargeを6回サイズ倍にしたことを意味します。つまり 8ノード × (2×2×2×2×2×2) = 512 です。https://docs.snowflake.com/en/user-guide/warehouses-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 101, "title": "仮想ウェアハウスが実行中にリサイズできますか？", "multiSelect": false, "stemHtml": "<p>仮想ウェアハウスが実行中にリサイズできますか？</p>", "options": [{"key": "A", "label": "いいえ"}, {"key": "B", "label": "はい"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>はい</strong></p><p>仮想ウェアハウスは実行中でもいつでもリサイズできます。仮想ウェアハウスがリサイズされると、Snowflakeは新しいサイズに応じてノードを追加または削除します。ノードの削除はそのノードのすべてのアクティブなクエリが完了した後にのみ行われます。https://docs.snowflake.com/en/user-guide/warehouses-tasks#resizing-a-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 102, "title": "Snowflakeのキャッシュの例はどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflakeのキャッシュの例はどれですか？</p>", "options": [{"key": "A", "label": "仮想ウェアハウスキャッシュ"}, {"key": "B", "label": "メタデータキャッシュ"}, {"key": "C", "label": "高速キャッシュ"}, {"key": "D", "label": "メモリキャッシュ"}, {"key": "E", "label": "クエリ結果キャッシュ"}], "correctAnswers": ["A", "B", "E"], "explanationHtml": "<p>✅ <strong>仮想ウェアハウスキャッシュ / メタデータキャッシュ / クエリ結果キャッシュ</strong></p><p>統計情報は各テーブル、マイクロパーティション、および列のメタデータキャッシュに保持されます。クエリが単純に行数のカウントや列の最小値・最大値の検索のみを行う場合、メタデータキャッシュが結果を返せます。クエリが以前に実行され、データが変更されていない場合、Snowflakeはクエリ結果キャッシュを使用して結果を返すことができます。各仮想ウェアハウスには独自のキャッシュもあり、クラウドストレージからSSDストレージにマイクロパーティションを移動することで時間をかけて構築されます。仮想ウェアハウスで実行された類似のクエリは、すでにキャッシュにデータが存在する場合があり、クエリパフォーマンスが向上します。https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 103, "title": "過去60分間に実行されたすべてのクエリの履歴を確認する必要があります。どの方法を使用すべきですか...", "multiSelect": true, "stemHtml": "<p>過去60分間に実行されたすべてのクエリの履歴を確認する必要があります。どの方法を使用すべきですか？</p>", "options": [{"key": "A", "label": "ACCOUNT_USAGEスキーマのQUERY_HISTORYビューを使用する。"}, {"key": "B", "label": "INFORMATIONスキーマのQUERY_HISTORYテーブル関数を使用する。"}, {"key": "C", "label": "クエリ履歴ページを使用して過去のクエリを表示する。"}, {"key": "D", "label": "Snowflakeサポートにクエリ履歴の提供を依頼する。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>INFORMATIONスキーマのQUERY_HISTORYテーブル関数 / クエリ履歴ページ</strong></p><p>INFORMATIONスキーマのQUERY_HISTORYテーブル関数はレイテンシなしで最新の情報を提供します。ACCOUNT_USAGEスキーマのQUERY_HISTORYビューは3時間のレイテンシが発生する可能性があるため、過去60分のクエリ履歴の表示には適していません。クエリ履歴ページを使用すると、過去14日間の実行されたクエリの履歴も表示できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 104, "title": "正誤問題：ディレクトリテーブルにクエリを実行すると、対応するステージの各ファイルのファイルURL...", "multiSelect": false, "stemHtml": "<p>正誤問題：ディレクトリテーブルにクエリを実行すると、対応するステージの各ファイルのファイルURLが提供されます。URLは90日間有効です。</p>", "options": [{"key": "A", "label": "正しい"}, {"key": "B", "label": "誤り"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>誤り</strong></p><p>ディレクトリテーブルが提供するファイルURLは長期的なURLであり、期限が切れません。</p><p>https://docs.snowflake.com/en/user-guide/data-load-dirtables-intro#what-are-directory-tables</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 105, "title": "コストよりもパフォーマンスを優先するスケーリングポリシーはどれですか？", "multiSelect": false, "stemHtml": "<p>コストよりもパフォーマンスを優先するスケーリングポリシーはどれですか？</p>", "options": [{"key": "A", "label": "Economy"}, {"key": "B", "label": "Standard"}, {"key": "C", "label": "Fast"}, {"key": "D", "label": "Efficient"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>スケーリングポリシーがStandardに設定されている場合、Snowflakeはクエリがキューに並び始めるとすぐに追加の仮想ウェアハウスを起動することを優先します。Standardスケーリングポリシーはキューイングを防ぐまたは最小化することを目指しています。Economyスケーリングポリシーはパフォーマンスとユーザーエクスペリエンスよりもクレジットの節約を試みます。キューイングが観察されてもすぐに新しい仮想ウェアハウスを起動するのではなく、新しい仮想ウェアハウスを起動するかどうかを判断するために追加の基準を適用します。https://docs.snowflake.com/en/user-guide/warehouses-multicluster#setting-the-scaling-policy-for-a-multi-cluster-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 106, "title": "Snowflakeのデータロードについて正しい説明はどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflakeのデータロードについて正しい説明はどれですか？</p>", "options": [{"key": "A", "label": "Snowflakeはファイルが到着した順序でロードされることを保証する。"}, {"key": "B", "label": "Snowflakeは処理済みファイルを追跡するためにロードメタデータを維持する。"}, {"key": "C", "label": "Snowflakeは処理済みファイルを追跡するためのロードメタデータを維持しない。"}, {"key": "D", "label": "Snowflakeはファイルが到着した順序でロードされることを保証しない。"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>ロードメタデータの維持 / ファイル到着順のロードを保証しない</strong></p><p>データがロードされるたびに、ロードメタデータと呼ばれるメタデータが作成されます。ロードメタデータには、そのテーブルにロードされたすべてのファイルの名前やファイルがロードされた時のタイムスタンプなど、さまざまな情報が保存されます。このロードメタデータを活用することで、Snowflakeは以前にロードされたファイルを再処理しないことを保証します。Snowflakeはファイルが到着した順序でロードされることを保証しません。https://docs.snowflake.com/en/user-guide/data-load-considerations-load</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 107, "title": "COPYコマンドでデータをロードする場合、テーブルとデータをロードするファイルの列数が同じである...", "multiSelect": false, "stemHtml": "<p>COPYコマンドでデータをロードする場合、テーブルとデータをロードするファイルの列数が同じである必要があります。</p>", "options": [{"key": "A", "label": "誤り"}, {"key": "B", "label": "正しい"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>誤り</strong></p><p>ファイルとテーブルの列の順序と数は異なっていてもかまいません。この場合、SELECT文を使用してステージから必要な列のみを選択できます。COPYコマンドを使用してテーブルにデータをロードする際、SnowflakeはSELECT文を使用してデータのロード中に簡単な変換を実行できます。ロードプロセス中、COPYコマンドは列の順序変更、1つ以上の列の省略、指定したデータ型へのキャストを許可します。また、COPYコマンドを使用して、データが希望する列幅より大きい場合にデータを切り捨てることも可能です。https://docs.snowflake.com/en/user-guide/data-load-overview#simple-transformations-during-a-load</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 108, "title": "Snowflakeがサーバーレスタスクに割り当てられる最大コンピュートサイズはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeがサーバーレスタスクに割り当てられる最大コンピュートサイズはどれですか？</p>", "options": [{"key": "A", "label": "Small"}, {"key": "B", "label": "Large"}, {"key": "C", "label": "Medium"}, {"key": "D", "label": "4X-Large"}, {"key": "E", "label": "2X-Large"}], "correctAnswers": ["E"], "explanationHtml": "<p>✅ <strong>2X-Large</strong></p><p>Snowflakeのタスク向けサーバーレスコンピュートモデルは管理されたコンピュートリソースを提供し、ユーザーが仮想ウェアハウスを手動で管理する必要がなくなります。Snowflakeはワークロードの需要に応じて自動的にサーバーレスコンピュートリソースのサイズを調整します。このサイズ決定は、パフォーマンスを最適化するために類似したタスク実行の最近の統計を分析することで動的に決定されます。サーバーレスタスクで利用可能な最大コンピュートサイズは、XXLARGEまたは2X-Largeのユーザー管理仮想ウェアハウスの容量に相当します。<br>詳細は以下のリンクを参照してください：<br>https://docs.snowflake.com/en/user-guide/tasks-intro#serverless-tasks</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タスク", "originalCorrect": null, "reviewPoint": ""}}, {"order": 109, "title": "セッションが閉じられても存在し続ける短期間のSnowflakeテーブルの種類はどれですか？", "multiSelect": false, "stemHtml": "<p>セッションが閉じられても存在し続ける短期間のSnowflakeテーブルの種類はどれですか？</p>", "options": [{"key": "A", "label": "共存テーブル"}, {"key": "B", "label": "一時テーブル（Temporary）"}, {"key": "C", "label": "トランジェントテーブル（Transient）"}, {"key": "D", "label": "パーマネントテーブル（Permanent）"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>トランジェントテーブル（Transient）</strong></p><p>トランジェントテーブルはETLワークテーブルなどの短期間テーブルとして使用でき、セッションが閉じられてもドロップされません。https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ保護", "originalCorrect": null, "reviewPoint": ""}}, {"order": 110, "title": "外部トークン化はSnowflakeでどのようなセキュリティを提供しますか？", "multiSelect": false, "stemHtml": "<p>外部トークン化はSnowflakeでどのようなセキュリティを提供しますか？</p>", "options": [{"key": "A", "label": "行レベルセキュリティ"}, {"key": "B", "label": "列レベルセキュリティ"}, {"key": "C", "label": "データベースレベルセキュリティ"}, {"key": "D", "label": "オブジェクトセキュリティ"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>列レベルセキュリティ</strong></p><p>Snowflakeは列に適用できるマスキングポリシーをサポートしており、列レベルでの適用によって列レベルのセキュリティを提供します。列レベルのセキュリティは動的データマスキングまたは外部トークン化によって実現されます。https://docs.snowflake.com/en/user-guide/security-column</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 111, "title": "正誤問題：仮想ウェアハウスが作成されると、そのサイズは変更できません。", "multiSelect": false, "stemHtml": "<p>正誤問題：仮想ウェアハウスが作成されると、そのサイズは変更できません。</p>", "options": [{"key": "A", "label": "誤り"}, {"key": "B", "label": "正しい"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>誤り</strong></p><p>仮想ウェアハウスは実行中でもいつでもリサイズできます。https://docs.snowflake.com/en/user-guide/warehouses-tasks</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 112, "title": "ユーザーのMINS_TO_BYPASS_NETWORK_POLICYプロパティを変更するために必...", "multiSelect": false, "stemHtml": "<p>ユーザーのMINS_TO_BYPASS_NETWORK_POLICYプロパティを変更するために必要なものはどれですか？</p>", "options": [{"key": "A", "label": "SYSADMINロールを使用する。"}, {"key": "B", "label": "USERADMINロールを使用する。"}, {"key": "C", "label": "Snowflakeサポートに連絡する。"}, {"key": "D", "label": "SECURITYADMINロールを使用する。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Snowflakeサポートに連絡する</strong></p><p>MINS_TO_BYPASS_NETWORK_POLICYプロパティの値を設定できるのはSnowflakeサポートのみです。</p><p>https://docs.snowflake.com/en/user-guide/network-policies#bypassing-a-network-policy</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 113, "title": "Snowflakeのマイクロパーティション内での列の保存方法はどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeのマイクロパーティション内での列の保存方法はどれですか？</p>", "options": [{"key": "A", "label": "独立して - 各列が個別に保存される（列指向ストレージとも呼ばれる）。"}, {"key": "B", "label": "結合して - 特定の行の列が一緒に保存される（行指向ストレージとも呼ばれる）。"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>独立した列指向ストレージ</strong></p><p>Snowflakeは各マイクロパーティション内で列を列指向の方法で保存します。列指向フォーマットにより、Snowflakeは参照された列のみを取得することでクエリを最適化できます。マイクロパーティションの圧縮に加えて、マイクロパーティション内の各列は独立して圧縮されます。Snowflakeは各列に最適な圧縮アルゴリズムを選択します。https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 114, "title": "Snowparkについて正しい説明はどれですか？", "multiSelect": true, "stemHtml": "<p>Snowparkについて正しい説明はどれですか？</p>", "options": [{"key": "A", "label": "Snowparkを使用する場合、Snowflakeの操作はクライアント側ですぐに実行される。"}, {"key": "B", "label": "Snowparkで定義された関数は実行のためにサーバー（Snowflake）にプッシュダウンできます。"}, {"key": "C", "label": "Snowparkを使用する場合、Snowflakeの操作は遅延評価で実行されます。"}, {"key": "D", "label": "SnowparkはHadoopクエリエンジンを実行に使用する。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>サーバーへのプッシュダウン / 遅延評価</strong></p><p>Snowparkはデータ処理プログラミング構造を自動的にSQLに変換し、実行のためにSnowflakeにプッシュダウンします。このアプローチにより、Snowflakeのスケールを活用した並列実行が可能になります。また、遅延評価を使用します。つまり、プログラマーはデータフレームに対して複数の操作を実行できますが、実行操作を行った後にのみコードがSQLに変換されて実行されます。https://docs.snowflake.com/en/developer-guide/snowpark/index</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 115, "title": "Snowflakeがデータを保存する方法について正しい説明はどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeがデータを保存する方法について正しい説明はどれですか？</p>", "options": [{"key": "A", "label": "Snowflakeはテーブルデータを保存するために独自の列指向フォーマットを使用します。"}, {"key": "B", "label": "SnowflakeはテーブルデータをParquetファイル形式で保存します。"}, {"key": "C", "label": "Snowflakeはクラウドストレージにシンプルなカンマ区切りファイルとしてテーブルデータを保存します。"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>独自の列指向フォーマット</strong></p><p>Snowflakeは、AWS S3、Azure Blob Storage、Google Cloud Storageなどのクラウドオブジェクトストレージにプロプライエタリな形式でデータを保存します。Snowflakeは列を列指向の方法で保存します。列指向フォーマットにより、Snowflakeは参照された列のみを取得することでクエリを最適化できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 116, "title": "Snowflake Marketplaceからデータセットをインポートできるロールはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflake Marketplaceからデータセットをインポートできるロールはどれですか？</p>", "options": [{"key": "A", "label": "ACCOUNTADMIN"}, {"key": "B", "label": "SECURITYADMIN"}, {"key": "C", "label": "SYSADMIN"}, {"key": "D", "label": "SHAREADMIN"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>ACCOUNTADMIN</strong></p><p>どのユーザーやロールもSnowflake Marketplaceを探索できますが、データを消費するにはACCOUNTADMIN権限またはIMPORT SHARE権限を持つユーザーが必要です。シンプルにするために、ACCOUNTADMIN権限を持つユーザーを使用することをお勧めします。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 117, "title": "テーブルにクラスタリングキーが必要であることを示す一般的な指標はどれですか？該当するものをすべて...", "multiSelect": true, "stemHtml": "<p>テーブルにクラスタリングキーが必要であることを示す一般的な指標はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "テーブルの列数が多い。"}, {"key": "B", "label": "テーブルのサイズが複数テラバイトである。"}, {"key": "C", "label": "クエリのパフォーマンスが時間とともに低下している。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>複数テラバイトのテーブルサイズ / クエリパフォーマンスの低下</strong></p><p>クラスタリングキーが必要かどうかを判断するのに役立つ指標を以下に示します：</p><ul><li>テーブルのデータ量が多い（例：複数テラバイト）</li><li>テーブルのクエリが期待よりも遅い</li><li>クエリのパフォーマンスが時間とともに低下している</li><li>テーブルのクラスタリング深度が大きい</li></ul><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 118, "title": "最大90日間のタイムトラベルをサポートするSnowflakeエディションはどれですか？該当するも...", "multiSelect": true, "stemHtml": "<p>最大90日間のタイムトラベルをサポートするSnowflakeエディションはどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "Standard"}, {"key": "B", "label": "Enterprise"}, {"key": "C", "label": "Virtual Private Snowflake"}, {"key": "D", "label": "Business Critical"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>Enterprise / Virtual Private Snowflake / Business Critical</strong></p><p>エンタープライズエディション以上では最大90日間のタイムトラベルをサポートしています。https://docs.snowflake.com/en/user-guide/data-time-travel#data-retention-period</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}]}, {"slug": "03_practice_exam", "title": "SnowPro Core 03_practice_exam", "sourcePath": "01_資格/Snowflake/SnowPro_Core/問題/03_practice_exam.md", "metadata": ["問題数: 128問"], "questionCount": 128, "questions": [{"order": 1, "title": "マテリアライズドビューのベーステーブルに新しいカラムが追加された場合、どのような動作になりますか...", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューのベーステーブルに新しいカラムが追加された場合、どのような動作になりますか？（2つ選択）</p>", "options": [{"key": "A", "label": "新しいカラムはマテリアライズドビューに自動的に反映される"}, {"key": "B", "label": "新しいカラムはマテリアライズドビューに自動的には反映されない"}, {"key": "C", "label": "マテリアライズドビューはサスペンドされない"}, {"key": "D", "label": "マテリアライズドビューはサスペンドされる"}, {"key": "E", "label": "再び使用したい場合はマテリアライズドビューを再開する必要がある"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>新しいカラムはマテリアライズドビューに自動的には反映されない / マテリアライズドビューはサスペンドされない</strong></p><p>ベーステーブルに新しいカラムが追加された場合、そのカラムはマテリアライズドビューに自動的には反映されません。マテリアライズドビューで SELECT * を使用していても、マテリアライズドビューのカラムは定義時に確定しているため、新しいカラムは反映されません。また、マテリアライズドビューはサスペンドされないため、引き続き使用できます。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized#adding-columns-to-the-base-table</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 2, "title": "Snowflakeで非構造化データにアクセスするために使用できるURLの種類はどれですか？（該当...", "multiSelect": true, "stemHtml": "<p>Snowflakeで非構造化データにアクセスするために使用できるURLの種類はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "ファイルURL"}, {"key": "B", "label": "事前署名付きURL"}, {"key": "C", "label": "ネットワーク共有パス"}, {"key": "D", "label": "スコープ付きURL"}, {"key": "E", "label": "Samba URL"}], "correctAnswers": ["A", "B", "D"], "explanationHtml": "<p>✅ <strong>ファイルURL / 事前署名付きURL / スコープ付きURL</strong></p><p>クラウドストレージ内の非構造化データにアクセスするために使用できるURLの種類は、スコープ付きURL、ファイルURL、事前署名付きURLの3種類です。</p><p>https://docs.snowflake.com/en/user-guide/unstructured-intro#types-of-urls-available-to-access-files</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 3, "title": "クローニングは、以下のどの条件が満たされない限り、ストレージ全体に影響しませんか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>クローニングは、以下のどの条件が満たされない限り、ストレージ全体に影響しませんか？（2つ選択）</p>", "options": [{"key": "A", "label": "クローンされたテーブルのデータが変更された場合"}, {"key": "B", "label": "クローンされたオブジェクトが大きすぎる場合"}, {"key": "C", "label": "データのクローン時に CREATE_COPY パラメータが true に設定されている場合"}, {"key": "D", "label": "ソーステーブルのデータが変更された場合"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>クローンされたテーブルのデータが変更された場合 / ソーステーブルのデータが変更された場合</strong></p><p>テーブル、スキーマ、データベースがクローンされた場合、ソースまたはターゲットに対してDML操作（既存データの変更・削除、または新規データの追加）が実行されるまで、クローニングはストレージ合計に影響しません。</p><p>https://docs.snowflake.com/en/user-guide/tables-storage-considerations#label-cloning-tables</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 4, "title": "サイズ X-Large のマルチクラスター仮想ウェアハウスが1クラスターで1時間稼働しました。そ...", "multiSelect": false, "stemHtml": "<p>サイズ X-Large のマルチクラスター仮想ウェアハウスが1クラスターで1時間稼働しました。その後、クエリ需要によりスケールアウト（クラスターを追加）し、2クラスターでさらに1時間稼働しました。マルチクラスター仮想ウェアハウスが消費したクレジットの合計数はいくつですか？</p>", "options": [{"key": "A", "label": "48"}, {"key": "B", "label": "32"}, {"key": "C", "label": "64"}, {"key": "D", "label": "16"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>48</strong></p><p>X-Large マルチクラスター仮想ウェアハウス 1クラスターが1時間稼働 = 16クレジット</p><p>X-Large マルチクラスター仮想ウェアハウス 2クラスターが1時間稼働 = 16クレジット × 2 = 32クレジット</p><p>合計 = 48クレジット</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 5, "title": "Partner Connect を通じてトライアルアカウントを作成するために必要な最小ロールはど...", "multiSelect": false, "stemHtml": "<p>Partner Connect を通じてトライアルアカウントを作成するために必要な最小ロールはどれですか？</p>", "options": [{"key": "A", "label": "ORGADMIN"}, {"key": "B", "label": "SECURITYADMIN"}, {"key": "C", "label": "SYSADMIN"}, {"key": "D", "label": "ACCOUNTADMIN"}, {"key": "E", "label": "PUBLIC"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>ACCOUNTADMIN</strong></p><p>Partner Connect にアクセスできるのは、ACCOUNTADMIN ロールを持ち、Snowflake でメールアドレスが確認されたユーザーのみです。</p><p>https://docs.snowflake.com/en/user-guide/ecosystem-partner-connect#connecting-with-a-snowflake-partner</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パートナー", "originalCorrect": null, "reviewPoint": ""}}, {"order": 6, "title": "COPYプロセス中の基本的な変換をサポートするのは、次のどのステージタイプですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>COPYプロセス中の基本的な変換をサポートするのは、次のどのステージタイプですか？（2つ選択）</p>", "options": [{"key": "A", "label": "外部ステージ"}, {"key": "B", "label": "名前付き内部ステージ"}, {"key": "C", "label": "テーブルステージ"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>外部ステージ / 名前付き内部ステージ</strong></p><p>テーブルステージはCOPYプロセス中の基本的な変換をサポートしていないため、基本的な変換は外部ステージ、名前付き内部ステージ、またはユーザーステージからのデータロード時にのみ実行できます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-local-file-system-create-stage#table-stages</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 7, "title": "管理者として、過去15分間にシステムにログインしたすべてのユーザーを検索する必要があります。どの...", "multiSelect": false, "stemHtml": "<p>管理者として、過去15分間にシステムにログインしたすべてのユーザーを検索する必要があります。どのオプションを使用すべきですか？</p>", "options": [{"key": "A", "label": "INFORMATION_SCHEMA スキーマで提供されるテーブル関数を使用する"}, {"key": "B", "label": "ログインしたユーザーを調べるためにシステムログを分析する"}, {"key": "C", "label": "ACCOUNT_USAGE スキーマのビューを使用する"}, {"key": "D", "label": "最近ログインしたユーザーを確認するためにクラウドプロバイダーのログを使用する"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>INFORMATION_SCHEMA スキーマで提供されるテーブル関数を使用する</strong></p><p>過去15分間のログインを確認する要件があるため、リアルタイムに近い情報を含む INFORMATION_SCHEMA を使用する必要があります。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 8, "title": "Snowflake の Time Travel に関して正しい記述はどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflake の Time Travel に関して正しい記述はどれですか？</p>", "options": [{"key": "A", "label": "undrop 機能により、Snowflake は通信中にドロップされたデータパケットを再構築できる"}, {"key": "B", "label": "Undrop によりユーザーはドロップされたアカウントとロールを復元できる"}, {"key": "C", "label": "Undrop によりユーザーはドロップされたテーブル、スキーマ、データベースを復元できる"}, {"key": "D", "label": "Undrop により Snowflake はネットワーク接続が不安定な場合でも安定したクライアント接続を維持できる"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Undrop によりユーザーはドロップされたテーブル、スキーマ、データベースを復元できる</strong></p><p>Undrop によりユーザーはドロップされたテーブル、スキーマ、データベースを復元できます。Snowflake でテーブル、スキーマ、データベースがドロップされても、すぐにシステムから削除されるわけではなく、Time Travel 期間中は復元可能です。テーブルがドロップされると、テーブルの状態を非削除に設定するだけで undrop が適用されます。</p><p>https://docs.snowflake.com/en/user-guide/data-time-travel#restoring-objects</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 9, "title": "Snowflake の CURRENT_TASK_GRAPHS テーブル関数の目的は何ですか？", "multiSelect": false, "stemHtml": "<p>Snowflake の CURRENT_TASK_GRAPHS テーブル関数の目的は何ですか？</p>", "options": [{"key": "A", "label": "CURRENT_TASK_GRAPH テーブル関数はタスク実行の履歴レコードを提供する"}, {"key": "B", "label": "CURRENT_TASK_GRAPH テーブル関数はシステム内のすべてのタスクに関する包括的な詳細を提供する"}, {"key": "C", "label": "CURRENT_TASK_GRAPH テーブル関数はスケジュールされているか現在実行中のタスクの詳細を提供する"}, {"key": "D", "label": "CURRENT_TASK_GRAPH テーブル関数はシステム内のすべてのタスクのリソース使用統計を表示する"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>CURRENT_TASK_GRAPH テーブル関数はスケジュールされているか現在実行中のタスクの詳細を提供する</strong></p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タスク", "originalCorrect": null, "reviewPoint": ""}}, {"order": 10, "title": "Snowflake Scripting コードでサポートされているのはどれですか？（該当するもの...", "multiSelect": true, "stemHtml": "<p>Snowflake Scripting コードでサポートされているのはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "BEGIN"}, {"key": "B", "label": "END"}, {"key": "C", "label": "EXCEPTION"}, {"key": "D", "label": "DECLARE"}, {"key": "E", "label": "NOTIFY"}, {"key": "F", "label": "PARALLEL"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>BEGIN / END / EXCEPTION / DECLARE</strong></p><p>典型的な Snowflake Scripting ブロックには、変数やカーソルを宣言できる DECLARE セクションがあります。BEGIN と END は実際のスクリプトロジックを囲み、オプションで例外を処理する EXCEPTION セクションを含めることができます。</p><p>https://docs.snowflake.com/en/developer-guide/snowflake-scripting/index</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 11, "title": "トランジェントテーブルをクローンしようとした場合の動作として正しいのはどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>トランジェントテーブルをクローンしようとした場合の動作として正しいのはどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "トランジェントテーブルは外部テーブルにクローンできる"}, {"key": "B", "label": "トランジェントテーブルは永続テーブルにクローンできる"}, {"key": "C", "label": "トランジェントテーブルはトランジェントテーブルにクローンできる"}, {"key": "D", "label": "トランジェントテーブルは一時テーブルにクローンできる"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>トランジェントテーブルはトランジェントテーブルにクローンできる / トランジェントテーブルは一時テーブルにクローンできる</strong></p><p>トランジェントテーブルは永続テーブルにクローンできません。「Transient object cannot be cloned to a permanent object.」というエラーが表示されます。ただし、トランジェントテーブルは別のトランジェントテーブルまたは一時テーブルにクローンできます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 12, "title": "Snowflake の4つのエディションはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflake の4つのエディションはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Virtual Private Snowflake"}, {"key": "B", "label": "On-Premise"}, {"key": "C", "label": "Business Critical"}, {"key": "D", "label": "Standard"}, {"key": "E", "label": "Government"}, {"key": "F", "label": "Enterprise"}], "correctAnswers": ["A", "C", "D", "F"], "explanationHtml": "<p>✅ <strong>Virtual Private Snowflake / Business Critical / Standard / Enterprise</strong></p><p>Snowflake は4つのエディションを提供しています：Standard、Enterprise、Business Critical、Virtual Private Snowflake (VPS)。</p><p>https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 13, "title": "Snowflake 仮想ウェアハウスの高可用性に関して正しい記述はどれですか？（該当するものをす...", "multiSelect": true, "stemHtml": "<p>Snowflake 仮想ウェアハウスの高可用性に関して正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Snowflake は仮想ウェアハウス内の障害が発生したコンピューティングインスタンスを中断なく自動的に置き換える"}, {"key": "B", "label": "仮想ウェアハウスの障害はテーブルのデータ破損を引き起こす"}, {"key": "C", "label": "Snowflake は必要に応じて別のアベイラビリティゾーンで仮想ウェアハウスをプロビジョニングできる"}, {"key": "D", "label": "Snowflake は仮想ウェアハウスを3つのアベイラビリティゾーンに複製する"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>Snowflake は仮想ウェアハウス内の障害が発生したコンピューティングインスタンスを中断なく自動的に置き換える / Snowflake は必要に応じて別のアベイラビリティゾーンで仮想ウェアハウスをプロビジョニングできる</strong></p><p>Snowflake は仮想ウェアハウス内の障害が発生したコンピューティングインスタンスを自動的かつ透過的に置き換えます。コンピューティングレイヤー（仮想ウェアハウス）は複製されません。仮想ウェアハウスはデータを永続的に保存しないため、複製は不要です。通常、各仮想ウェアハウスは単一のアベイラビリティゾーンで実行されますが、障害時には別のアベイラビリティゾーンで再プロビジョニングできます。</p><p>https://developers.snowflake.com/wp-content/uploads/2021/06/Snowflake-High-Availability-for-Data-Apps-Whitepaper.pdf</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 14, "title": "Snowsight を最もよく説明しているのはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowsight を最もよく説明しているのはどれですか？</p>", "options": [{"key": "A", "label": "Snowflake インスタンスに接続するためのモバイルアプリ"}, {"key": "B", "label": "Snowflake インスタンスに接続するためのコマンドラインインターフェース"}, {"key": "C", "label": "Snowflake インスタンスに接続するためのウェブベースのインターフェース"}, {"key": "D", "label": "Snowflake インスタンスを管理するための軽量デスクトップアプリケーション"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Snowflake インスタンスに接続するためのウェブベースのインターフェース</strong></p><p>Snowsight は新しいテクノロジーを使用した最新の軽量ウェブインターフェースであり、Snowflake インスタンスと対話するための主要な方法です。</p><p>https://docs.snowflake.com/en/user-guide/ui-snowsight</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 15, "title": "ポイントルックアップクエリのパフォーマンスを向上させることができるのはどれですか？", "multiSelect": false, "stemHtml": "<p>ポイントルックアップクエリのパフォーマンスを向上させることができるのはどれですか？</p>", "options": [{"key": "A", "label": "セキュアビュー"}, {"key": "B", "label": "検索最適化"}, {"key": "C", "label": "自動クラスタリング"}, {"key": "D", "label": "マテリアライズドビュー"}, {"key": "E", "label": "外部テーブル"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>検索最適化</strong></p><p>検索最適化サービスは、等値述語や IN 述語を使用した高い選択性のフィルターを使用して1行または少数の行のみを返すポイントルックアップクエリのパフォーマンスを向上させるために使用できます。</p><p>https://docs.snowflake.com/en/user-guide/search-optimization-service#understanding-the-search-optimization-service</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 16, "title": "ACCOUNT_USAGE スキーマのデータのレイテンシーの範囲はどれですか？", "multiSelect": false, "stemHtml": "<p>ACCOUNT_USAGE スキーマのデータのレイテンシーの範囲はどれですか？</p>", "options": [{"key": "A", "label": "45分〜3時間"}, {"key": "B", "label": "レイテンシーなし"}, {"key": "C", "label": "5〜10日"}, {"key": "D", "label": "5〜10分"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>45分〜3時間</strong></p><p>ACCOUNT_USAGE スキーマはアカウントレベルの使用状況メトリクスとメタデータ情報を提供するいくつかのビューで構成されています。ACCOUNT_USAGE ビューで提供されるデータはリアルタイムではなく、ビューによって異なりますが通常45分〜3時間のラグがあります。これらのビューのデータは最大365日間保持されます。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 17, "title": "クラスタリングキーとして使用できるのはどのデータ型のカラムですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>クラスタリングキーとして使用できるのはどのデータ型のカラムですか？（2つ選択）</p>", "options": [{"key": "A", "label": "GEOMETRY"}, {"key": "B", "label": "OBJECT"}, {"key": "C", "label": "BINARY"}, {"key": "D", "label": "VARIANT"}, {"key": "E", "label": "GEOGRAPHY"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>GEOMETRY / BINARY</strong></p><p>クラスタリングキーには GEOGRAPHY、VARIANT、OBJECT、ARRAY を除く任意のデータ型を使用できます。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-keys#defining-a-clustering-key-for-a-table</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 18, "title": "時間単位のクレジット使用量を確認するために使用できる ACCOUNT_USAGE ビューはどれで...", "multiSelect": false, "stemHtml": "<p>時間単位のクレジット使用量を確認するために使用できる ACCOUNT_USAGE ビューはどれですか？</p>", "options": [{"key": "A", "label": "METERING_DAILY_HISTORY"}, {"key": "B", "label": "METERING_HISTORY"}, {"key": "C", "label": "WAREHOUSE_LOAD_HISTORY"}, {"key": "D", "label": "WAREHOUSE_EVENTS_HISTORY"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>METERING_HISTORY</strong></p><p>METERING_HISTORY は時間単位レベルでクレジット使用データを提供します。このビューはクレジット使用が発生した開始時刻と終了時刻を提供します。また、仮想ウェアハウスのコンピューティング使用量、Snowpipe、自動クラスタリングなど、クレジット使用に貢献したサービスごとの情報の内訳も提供します。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage/metering_history</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 19, "title": "Snowflake アカウントを持たない組織とデータを共有する場合、どの記述が正しいですか？", "multiSelect": false, "stemHtml": "<p>Snowflake アカウントを持たない組織とデータを共有する場合、どの記述が正しいですか？</p>", "options": [{"key": "A", "label": "Snowflake 以外の顧客とデータを共有するには、アカウント継承階層を作成する必要がある"}, {"key": "B", "label": "Snowflake 以外の顧客とデータを共有するには、リーダーアカウントを作成する必要がある"}, {"key": "C", "label": "Snowflake 以外の顧客とデータを共有するには、子アカウントを作成する必要がある"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Snowflake 以外の顧客とデータを共有するには、リーダーアカウントを作成する必要がある</strong></p><p>Snowflake 以外のユーザーと共有するには、リーダーアカウントの作成が必要です。リーダーアカウントは、Snowflake 以外のユーザーが共有データを利用できる Snowflake アカウントを提供します。リーダーアカウントはデータプロバイダーが所有し、すべてのコスト（クエリコストを含む）はデータプロバイダーに請求されます。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-reader-create</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 20, "title": "クエリ結果キャッシュが保持される最大期間はどれですか？", "multiSelect": false, "stemHtml": "<p>クエリ結果キャッシュが保持される最大期間はどれですか？</p>", "options": [{"key": "A", "label": "24時間"}, {"key": "B", "label": "31日"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>31日</strong></p><p>クエリ結果キャッシュの初期有効期間は24時間です。24時間以内に新しいクエリがキャッシュを再利用しない場合、キャッシュはクリアされます。新しいクエリが結果キャッシュを使用すると、有効期間は再び24時間にリセットされます。この拡張は最初にキャッシュが生成された時点から最大31日間継続できます。31日後、クエリ結果キャッシュは完全にクリアされます。</p><p>https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 21, "title": "ストアドプロシージャに関して正しい記述はどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>ストアドプロシージャに関して正しい記述はどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "作成後、ストアドプロシージャを所有者の権限または呼び出し元の権限で実行するように変更することはできない"}, {"key": "B", "label": "ストアドプロシージャを所有者の権限または呼び出し元の権限で実行するように変更できる"}, {"key": "C", "label": "新しく作成されたストアドプロシージャはデフォルトで所有者の権限で実行される"}, {"key": "D", "label": "新しく作成されたストアドプロシージャはデフォルトで呼び出し元の権限で実行される"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>ストアドプロシージャを所有者の権限または呼び出し元の権限で実行するように変更できる / 新しく作成されたストアドプロシージャはデフォルトで所有者の権限で実行される</strong></p><p>ストアドプロシージャを作成するときに、呼び出し元の権限または所有者の権限で実行するかを指定できます。何も指定しない場合は所有者の権限がデフォルトです。この設定は後でストアドプロシージャを変更することで変更できます。</p><p>https://docs.snowflake.com/en/sql-reference/stored-procedures-rights</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 22, "title": "Snowflake システムのコストに影響するのはどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>Snowflake システムのコストに影響するのはどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "テーブル数"}, {"key": "B", "label": "ユーザー数"}, {"key": "C", "label": "アクティブな仮想ウェアハウス"}, {"key": "D", "label": "使用されているストレージ量"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>アクティブな仮想ウェアハウス / 使用されているストレージ量</strong></p><p>再開（アクティブ）状態にある仮想ウェアハウスはコストに影響します。クエリを実行していなくても、再開されていればコストに影響します。</p><p>https://docs.snowflake.com/en/user-guide/cost-understanding-compute</p><p>Snowflake はデータベーステーブル内のデータストレージ、内部ステージにステージングされたファイル、タイムトラベル履歴、フェイルセーフストレージに対して料金を請求します。</p><p>https://docs.snowflake.com/en/user-guide/cost-understanding-data-storage</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "コストと価格", "originalCorrect": null, "reviewPoint": ""}}, {"order": 23, "title": "仮想ウェアハウスが提供するリソースはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>仮想ウェアハウスが提供するリソースはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "一時ローカルストレージ"}, {"key": "B", "label": "共有ストレージ"}, {"key": "C", "label": "メモリ"}, {"key": "D", "label": "CPU"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>一時ローカルストレージ / メモリ / CPU</strong></p><p>仮想ウェアハウスはクエリ処理とデータロードジョブを処理するための CPU、メモリ、一時ストレージリソースを提供します。仮想ウェアハウスコンピュートクラスターの各ノードには独自のメモリ、コンピューティングリソース、およびソリッドステートディスクに保存されたローカルキャッシュがあります。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 24, "title": "Snowflake アーキテクチャのデータベースストレージレイヤーはどこに置くことができますか？...", "multiSelect": true, "stemHtml": "<p>Snowflake アーキテクチャのデータベースストレージレイヤーはどこに置くことができますか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "ハイブリッドクラウド"}, {"key": "B", "label": "AWS S3"}, {"key": "C", "label": "Google Cloud Storage"}, {"key": "D", "label": "Azure Blob Storage"}, {"key": "E", "label": "オンプレミス NAS"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>AWS S3 / Google Cloud Storage / Azure Blob Storage</strong></p><p>Snowflake の共有ストレージレイヤーは低コストのオブジェクトクラウドストレージ上に存在します。Snowflake は現在、データストレージとして AWS S3 ストレージ、Azure Blob Storage、Google Cloud Storage をサポートしています。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 25, "title": "アクティブな仮想ウェアハウスなしで実行できる操作はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>アクティブな仮想ウェアハウスなしで実行できる操作はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "数値カラムの最大値を検索する"}, {"key": "B", "label": "テーブルの行数をカウントする"}, {"key": "C", "label": "数値カラムの合計を検索する"}, {"key": "D", "label": "数値カラムの平均を検索する"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>数値カラムの最大値を検索する / テーブルの行数をカウントする</strong></p><p>Snowflake はメタデータにマイクロパーティションに関する情報（各マイクロパーティション内の各カラムの最大値・最小値など）を保存しています。この情報はメタデータキャッシュに保存されているため、特定のクエリではテーブルからデータを読み取らずにメタデータから直接情報を取得できます。これには COUNT クエリや MIN・MAX などの関数を含むクエリが含まれます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 26, "title": "リージョンおよびクラウドプラットフォーム間でデータを安全に共有する（レプリケーション経由）ために...", "multiSelect": false, "stemHtml": "<p>リージョンおよびクラウドプラットフォーム間でデータを安全に共有する（レプリケーション経由）ために必要な最小 Snowflake エディションはどれですか？</p>", "options": [{"key": "A", "label": "Enterprise"}, {"key": "B", "label": "Virtual Private Snowflake"}, {"key": "C", "label": "Standard"}, {"key": "D", "label": "Business Critical"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>リージョンおよびクラウド間のデータベース共有（レプリケーション経由）はすべての Snowflake エディションでサポートされているため、これをサポートする最小エディションは Standard エディションです。</p><p>https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 27, "title": "マルチクラスター仮想ウェアハウスが自動スケーリングモードで設定されています。サポートされるスケー...", "multiSelect": true, "stemHtml": "<p>マルチクラスター仮想ウェアハウスが自動スケーリングモードで設定されています。サポートされるスケーリングポリシーはどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "Standard"}, {"key": "B", "label": "Fast"}, {"key": "C", "label": "Efficient"}, {"key": "D", "label": "Economy"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>Standard / Economy</strong></p><p>Standard スケーリングポリシーでは、クエリがキューに入り始めるとすぐに追加の仮想ウェアハウスを起動します。Economy スケーリングポリシーはパフォーマンスよりもクレジットの節約を優先し、キューが観察されてもすぐに新しい仮想ウェアハウスを起動しません。スケーリングポリシーは自動スケールモードで実行中の仮想ウェアハウスにのみ適用されます。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-multicluster#setting-the-scaling-policy-for-a-multi-cluster-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 28, "title": "真偽問題：ディレクトリテーブルはステージオブジェクトの作成中、または後から有効にすることができま...", "multiSelect": false, "stemHtml": "<p>真偽問題：ディレクトリテーブルはステージオブジェクトの作成中、または後から有効にすることができます。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>ディレクトリテーブルは独立したデータベースオブジェクトではなく、ステージで利用可能な暗黙的なオブジェクトです。ステージの作成中またはその後からディレクトリテーブルを有効にすることができます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-dirtables</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 29, "title": "外部テーブルに関して正しい記述はどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>外部テーブルに関して正しい記述はどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "外部テーブルは内部ステージを指す"}, {"key": "B", "label": "外部テーブルは他のテーブルと同様にクエリを実行できる"}, {"key": "C", "label": "外部テーブルと標準 Snowflake テーブルを結合できる"}, {"key": "D", "label": "外部テーブルと標準 Snowflake テーブルは結合できない"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>外部テーブルは他のテーブルと同様にクエリを実行できる / 外部テーブルと標準 Snowflake テーブルを結合できる</strong></p><p>Snowflake は外部クラウドストレージに保存されたデータを持つテーブルの作成を可能にする外部テーブルを提供します。外部テーブルを通常のテーブルと同じ方法でクエリでき、他のテーブルと結合したり、外部テーブル上にビューを作成したりすることもできます。</p><p>https://docs.snowflake.com/en/user-guide/tables-external-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 30, "title": "ストレージコストに影響しない Snowflake オブジェクトはどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>ストレージコストに影響しない Snowflake オブジェクトはどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "一時テーブル"}, {"key": "B", "label": "セキュアビュー"}, {"key": "C", "label": "マテリアライズドビュー"}, {"key": "D", "label": "ビュー"}, {"key": "E", "label": "トランジェントテーブル"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>セキュアビュー / ビュー</strong></p><p>ビューとセキュアビューはストレージを使用しません。これらのオブジェクトは実行時に実行される SQL ステートメントで構成されています。マテリアライズドビューは定義の SQL 結果を永続化するためストレージを使用します。一時テーブルとトランジェントテーブルはどちらもストレージを使用します。</p><p>https://docs.snowflake.com/en/user-guide/views-introduction</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake's catalog and objects", "originalCorrect": null, "reviewPoint": ""}}, {"order": 31, "title": "セキュリティ管理者がテーブルに行アクセスポリシーを作成しました。管理者はどのようなセキュリティを...", "multiSelect": false, "stemHtml": "<p>セキュリティ管理者がテーブルに行アクセスポリシーを作成しました。管理者はどのようなセキュリティを実装しましたか？</p>", "options": [{"key": "A", "label": "カラムレベルセキュリティ"}, {"key": "B", "label": "行レベルセキュリティ"}, {"key": "C", "label": "動的データマスキング"}, {"key": "D", "label": "行の削除"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>行レベルセキュリティ</strong></p><p>行レベルセキュリティは行アクセスポリシーを作成することで実装されます。行アクセスポリシーには、クエリ実行中にどの行が返されるかを管理する条件と関数が含まれています。</p><p>https://docs.snowflake.com/en/user-guide/security-row-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 32, "title": "トランジェントテーブルの Time Travel が許可される最大期間はどれですか？", "multiSelect": false, "stemHtml": "<p>トランジェントテーブルの Time Travel が許可される最大期間はどれですか？</p>", "options": [{"key": "A", "label": "7日"}, {"key": "B", "label": "21日"}, {"key": "C", "label": "14日"}, {"key": "D", "label": "1日"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>1日</strong></p><p>Snowflake のトランジェントテーブルと一時テーブルは、使用する Snowflake エディションに関係なく、最大1日間の Time Travel をサポートします。</p><p>https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 33, "title": "Snowflake のフェイルセーフに関して正しい記述はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflake のフェイルセーフに関して正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "フェイルセーフは壊滅的な障害が発生した場合に履歴データが保護されることを保証する"}, {"key": "B", "label": "フェイルセーフは永続テーブルに対して最大7日間の履歴データ保護を提供する"}, {"key": "C", "label": "フェイルセーフは永続テーブルに対して最大90日間の履歴データ保護を提供する"}, {"key": "D", "label": "フェイルセーフは Time Travel と同じである"}, {"key": "E", "label": "フェイルセーフの保護は Time Travel による保護に追加される"}], "correctAnswers": ["A", "B", "E"], "explanationHtml": "<p>✅ <strong>フェイルセーフは壊滅的な障害が発生した場合に履歴データが保護されることを保証する / フェイルセーフは永続テーブルに対して最大7日間の履歴データ保護を提供する / フェイルセーフの保護は Time Travel による保護に追加される</strong></p><p>Time Travel による保護に加えて、変更されたデータはフェイルセーフ期間を経ます。Time Travel 期間が終了すると、Snowflake はさらなる保護として7日間データを保持します。フェイルセーフストレージのデータは一般ユーザーにはアクセスできず、顧客が要求した場合にのみ Snowflake サポートがアクセス・復元できます。</p><p>https://docs.snowflake.com/en/user-guide/data-failsafe</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 34, "title": "Snowflake は TLS 1.2 を使用して転送中の暗号化を実行します。次のどのツールに対...", "multiSelect": true, "stemHtml": "<p>Snowflake は TLS 1.2 を使用して転送中の暗号化を実行します。次のどのツールに対して転送中の暗号化が適用されますか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Snowflake Web UI"}, {"key": "B", "label": "SnowSQL"}, {"key": "C", "label": "ODBC コネクタ"}, {"key": "D", "label": "JDBC コネクタ"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>Snowflake Web UI / SnowSQL / ODBC コネクタ / JDBC コネクタ</strong></p><p>Snowflake は TLS 1.2 を使用してすべての転送中データを暗号化します。これは Snowflake の Web インターフェース、JDBC、ODBC、Python コネクタを通じた接続を含む、すべての Snowflake 接続に適用されます。</p><p>https://docs.snowflake.com/en/user-guide/security-encryption-end-to-end</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 35, "title": "テーブルのデータがマイクロパーティションにどのように編成されるかをユーザーが制御できるのはどれで...", "multiSelect": false, "stemHtml": "<p>テーブルのデータがマイクロパーティションにどのように編成されるかをユーザーが制御できるのはどれですか？</p>", "options": [{"key": "A", "label": "自動クラスタリング"}, {"key": "B", "label": "マテリアライズドビュー"}, {"key": "C", "label": "パーティションプルーニング"}, {"key": "D", "label": "検索最適化"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>自動クラスタリング</strong></p><p>クラスタリングキーが定義されたテーブルに対して、Snowflake サービスである自動クラスタリングが必要に応じてクラスタリングキーに従ってデータを分散させながら再クラスタリングを管理します。</p><p>https://docs.snowflake.com/en/user-guide/tables-auto-reclustering</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 36, "title": "真偽問題：共有からデータベースを作成するのは消費側アカウントです。このデータベースへのアクセスは...", "multiSelect": false, "stemHtml": "<p>真偽問題：共有からデータベースを作成するのは消費側アカウントです。このデータベースへのアクセスは Snowflake のロールベースアクセス制御を使用して設定できます。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>Snowflake アカウントのオブジェクトを保護するために使用されるロールベースアクセス制御（RBAC）は、コンシューマーアカウントにも適用され、共有オブジェクト上に作成されたデータベースへのアクセスを制御できます。</p><p>https://docs.snowflake.com/en/user-guide/data-share-consumers</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 37, "title": "Snowflake アカウントが別の Snowflake アカウントとテーブルを共有する場合、何...", "multiSelect": true, "stemHtml": "<p>Snowflake アカウントが別の Snowflake アカウントとテーブルを共有する場合、何が起こりますか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "ターゲット Snowflake アカウントは共有データストレージの料金を請求される"}, {"key": "B", "label": "アカウント間で実際のデータのコピーや転送は行われない"}, {"key": "C", "label": "データはターゲット Snowflake アカウントにコピーされる"}, {"key": "D", "label": "共有は Snowflake メタデータサービスレイヤーを通じて管理される"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>アカウント間で実際のデータのコピーや転送は行われない / 共有は Snowflake メタデータサービスレイヤーを通じて管理される</strong></p><p>Snowflake 共有ではデータはコピーされません。共有を可能にするのはメタデータのみです。データはコピーされないため、コンシューマーアカウントにはストレージ料金は発生しません。</p><p>https://docs.Snowflake.net/manuals/user-guide/data-sharing-intro.html#how-does-secure-data-sharing-work</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 38, "title": "セッションが閉じられると存在しなくなる Snowflake テーブルの種類はどれですか？", "multiSelect": false, "stemHtml": "<p>セッションが閉じられると存在しなくなる Snowflake テーブルの種類はどれですか？</p>", "options": [{"key": "A", "label": "トランジェント"}, {"key": "B", "label": "一時テーブル"}, {"key": "C", "label": "クラスタリング済み"}, {"key": "D", "label": "永続"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>一時テーブル</strong></p><p>一時テーブルはセッションに限定されており、セッションが閉じられるとすぐにドロップされます。</p><p>https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ保護", "originalCorrect": null, "reviewPoint": ""}}, {"order": 39, "title": "Snowpark を最もよく説明しているのはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowpark を最もよく説明しているのはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Snowflake は開発者が Snowflake クラウドサービスレイヤーの内部にアクセスできる API を提供する"}, {"key": "B", "label": "Snowpark は SQL 以外のプログラミング言語で書かれたアプリケーションでデータにアクセスして処理するための API を提供する Snowflake が作成したライブラリである"}, {"key": "C", "label": "Snowpark はデータ処理プログラミング構造を自動的に SQL に変換し、実行のために Snowflake に送信する"}, {"key": "D", "label": "Snowpark は Snowflake SQL 実行エンジンに依存しない"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>Snowpark は SQL 以外のプログラミング言語で書かれたアプリケーションでデータにアクセスして処理するための API を提供する Snowflake が作成したライブラリである / Snowpark はデータ処理プログラミング構造を自動的に SQL に変換し、実行のために Snowflake に送信する</strong></p><p>Snowpark は Java、Scala、Python などの一般的なプログラミング言語を使用してデータを処理するアプリを構築できます。Snowpark はデータ処理プログラミング構造を自動的に SQL に変換して Snowflake に送信します。</p><p>https://docs.snowflake.com/en/developer-guide/snowpark/index</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 40, "title": "直接データ共有で共有できるオブジェクトはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>直接データ共有で共有できるオブジェクトはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "リソースモニター"}, {"key": "B", "label": "セキュア UDF"}, {"key": "C", "label": "外部テーブル"}, {"key": "D", "label": "テーブル"}, {"key": "E", "label": "仮想ウェアハウス"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>セキュア UDF / 外部テーブル / テーブル</strong></p><p>直接データ共有では次のタイプのオブジェクトを共有できます：テーブル、外部テーブル、セキュアビュー、セキュアマテリアライズドビュー、セキュア UDF。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 41, "title": "MARKETING という名前のデータベースがあります。このデータベースの PUBLIC スキー...", "multiSelect": false, "stemHtml": "<p>MARKETING という名前のデータベースがあります。このデータベースの PUBLIC スキーマに CUSTOMER というテーブルがあり、10,000行のデータがあります。同じセッションで同じ MARKETING データベースの PUBLIC スキーマに CUSTOMER という名前の一時テーブル（データなし）を作成しました。同じセッションで CUSTOMER テーブルにアクセスする SELECT クエリの動作はどれですか？</p>", "options": [{"key": "A", "label": "`SELECT * FROM MARKETING.PUBLIC.CUSTOMER;` クエリは10,000行を返す"}, {"key": "B", "label": "`SELECT * FROM MARKETING.PUBLIC.CUSTOMER;` クエリは不明なオブジェクトエラーで失敗する"}, {"key": "C", "label": "`SELECT * FROM MARKETING.PUBLIC.CUSTOMER;` クエリは重複エラーで失敗する"}, {"key": "D", "label": "`SELECT * FROM MARKETING.PUBLIC.CUSTOMER;` クエリはゼロ行を返す"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong><code>SELECT * FROM MARKETING.PUBLIC.CUSTOMER;</code> クエリはゼロ行を返す</strong></p><p>一時テーブルは永続テーブルやトランジェントテーブルと同様にデータベースとスキーマに属しますが、セッションに限定されているため命名の一意性制約は適用されません。一時テーブルが同じ名前の永続テーブルが存在するスキーマに作成された場合、そのセッションでは一時テーブルが永続テーブルを隠します。</p><p>https://docs.snowflake.com/en/user-guide/tables-temp-transient#potential-naming-conflicts-with-other-table-types</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake's catalog and objects", "originalCorrect": null, "reviewPoint": ""}}, {"order": 42, "title": "多要素認証（MFA）をサポートする最小 Snowflake エディションはどれですか？", "multiSelect": false, "stemHtml": "<p>多要素認証（MFA）をサポートする最小 Snowflake エディションはどれですか？</p>", "options": [{"key": "A", "label": "Enterprise"}, {"key": "B", "label": "Business Critical"}, {"key": "C", "label": "Standard"}, {"key": "D", "label": "Virtual Private Snowflake"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>すべての Snowflake エディションが MFA をサポートしているため、MFA をサポートする最小エディションは Standard エディションです。</p><p>https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 43, "title": "Data Exchange を正しく説明しているのはどれですか？", "multiSelect": false, "stemHtml": "<p>Data Exchange を正しく説明しているのはどれですか？</p>", "options": [{"key": "A", "label": "Data Exchange はオンプレミスから COPY コマンドを使用して Snowflake クラウドストレージにデータを転送するメカニズムである"}, {"key": "B", "label": "Data Exchange は Snowflake テーブルからデータエクスポートを安全にメールで送信するメカニズムである"}, {"key": "C", "label": "Data Exchange は Snowflake データを共有するために使用できる OneDrive ストレージの別名である"}, {"key": "D", "label": "Data Exchange は招待した少人数のグループや組織とデータを共有するための独自のプライベートハブである"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>Data Exchange は招待した少人数のグループや組織とデータを共有するための独自のプライベートハブである</strong></p><p>Data Exchange は招待されたメンバーと少人数のグループや組織でデータを共有するための独自のプライベートハブです。Data Exchange アカウントのオーナーはメンバーの招待と共有・消費・またはその両方が可能かどうかを指定する責任があります。</p><p>https://docs.snowflake.com/en/user-guide/data-exchange</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 44, "title": "外部ステージのディレクトリテーブルのメタデータを定期的に更新する必要があります。どの方法を使用で...", "multiSelect": true, "stemHtml": "<p>外部ステージのディレクトリテーブルのメタデータを定期的に更新する必要があります。どの方法を使用できますか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "`ALTER STAGE <stage-name> REFRESH;` を定期的に実行してメタデータを手動で更新する"}, {"key": "B", "label": "Snowflake サポートにステージを定期的に更新するよう依頼する"}, {"key": "C", "label": "リソースモニターを設定してステージを定期的に更新する"}, {"key": "D", "label": "クラウドプラットフォーム上でイベント通知を設定し、ステージを自動更新するよう設定する"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong><code>ALTER STAGE &lt;stage-name&gt; REFRESH;</code> を定期的に実行してメタデータを手動で更新する / クラウドプラットフォーム上でイベント通知を設定し、ステージを自動更新するよう設定する</strong></p><p>ディレクトリテーブルのメタデータは <code>ALTER STAGE &lt;stage-name&gt; REFRESH;</code> で手動更新できます。外部ステージの場合、クラウドプロバイダーのイベント通知サービスを使用して自動更新も可能です（<code>AUTO_REFRESH = true</code>）。</p><p>https://docs.snowflake.com/en/user-guide/data-load-dirtables-intro#automatically-refreshing-directory-table-metadata</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 45, "title": "最もクラスタリングが不十分なテーブルを表しているのはどれですか？", "multiSelect": false, "stemHtml": "<p>最もクラスタリングが不十分なテーブルを表しているのはどれですか？</p>", "options": [{"key": "A", "label": "3"}, {"key": "B", "label": "2"}, {"key": "C", "label": "4"}, {"key": "D", "label": "1"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>4</strong></p><p>クラスタリング深度は特定のカラムに対してマイクロパーティションが重なり合う平均深度です。クラスタリング深度は1から始まり（よくクラスタリングされたテーブル）、より大きな数値になる可能性があります。平均深度が小さいほど、指定されたカラムのデータがよりよくクラスタリングされています。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions#label-clustering-depth</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 46, "title": "SnowSQL を最もよく説明しているのはどれですか？", "multiSelect": false, "stemHtml": "<p>SnowSQL を最もよく説明しているのはどれですか？</p>", "options": [{"key": "A", "label": "Snowflake インスタンスに接続するためのコマンドラインインターフェース"}, {"key": "B", "label": "Snowflake インスタンスに接続するために使用できるモバイルアプリ"}, {"key": "C", "label": "Snowflake インスタンスに接続するためのウェブベースのインターフェース"}, {"key": "D", "label": "Snowflake インスタンスを管理するための UI を持つ軽量デスクトップアプリケーション"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>Snowflake インスタンスに接続するためのコマンドラインインターフェース</strong></p><p>SnowSQL はコマンドラインから Snowflake に接続し、Snowflake インスタンス上で SQL クエリを実行します。SnowSQL は Linux、Windows、Mac OS で利用可能です。</p><p>https://docs.snowflake.com/en/user-guide/snowsql</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 47, "title": "Snowflake アーキテクチャを正しく説明しているのはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflake アーキテクチャを正しく説明しているのはどれですか？</p>", "options": [{"key": "A", "label": "共有ディスクアーキテクチャ"}, {"key": "B", "label": "シェアードナッシングアーキテクチャ"}, {"key": "C", "label": "マルチクラスター共有データアーキテクチャ"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>マルチクラスター共有データアーキテクチャ</strong></p><p>Snowflake は共有ディスクアーキテクチャとシェアードナッシングアーキテクチャの両方の最良の特徴を組み合わせた新しいハイブリッドアーキテクチャを実装しています。</p><p>https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 48, "title": "URL の有効期限に関して正しい記述はどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>URL の有効期限に関して正しい記述はどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "スコープ付き URL は24時間後に有効期限が切れる"}, {"key": "B", "label": "ファイル URL は24時間後に有効期限が切れる"}, {"key": "C", "label": "スコープ付き URL は有効期限が切れない"}, {"key": "D", "label": "ファイル URL は有効期限が切れない"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>スコープ付き URL は24時間後に有効期限が切れる / ファイル URL は有効期限が切れない</strong></p><p>ファイル URL はステージングされたファイルへの永続的な URL です。有効期限はありません。スコープ付き URL は24時間後に有効期限が切れます。事前署名付き URL の有効期限は設定可能です。</p><p>https://docs.snowflake.com/en/user-guide/unstructured-intro#types-of-urls-available-to-access-files</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 49, "title": "Snowflake はトランジェントテーブルのフェイルセーフストレージにデータを何日間保存します...", "multiSelect": false, "stemHtml": "<p>Snowflake はトランジェントテーブルのフェイルセーフストレージにデータを何日間保存しますか？</p>", "options": [{"key": "A", "label": "14日"}, {"key": "B", "label": "0日"}, {"key": "C", "label": "1日"}, {"key": "D", "label": "7日"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>0日</strong></p><p>Snowflake のトランジェントテーブルと一時テーブルはフェイルセーフ機能を提供しないため、そのようなテーブルのデータは0日間のフェイルセーフストレージとなります。</p><p>https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 50, "title": "サイズ Large のマルチクラスター仮想ウェアハウスでクエリが実行されており、スケーリングポリ...", "multiSelect": false, "stemHtml": "<p>サイズ Large のマルチクラスター仮想ウェアハウスでクエリが実行されており、スケーリングポリシーは Standard に設定されています。ウェアハウスは現在処理できる最大数のクエリを実行しています。追加のクエリが実行されるとどうなりますか？</p>", "options": [{"key": "A", "label": "マルチクラスター仮想ウェアハウスは、少なくとも6分間ビジー状態を保つのに十分な作業があると判断した場合にのみ新しい仮想ウェアハウスを追加する"}, {"key": "B", "label": "ほぼ即座にサイズ Large の追加仮想ウェアハウスがクラスターに追加され、追加のクエリが実行される"}, {"key": "C", "label": "仮想ウェアハウスのサイズが 4X-Large にスケールアップされる"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>ほぼ即座にサイズ Large の追加仮想ウェアハウスがクラスターに追加され、追加のクエリが実行される</strong></p><p>スケーリングポリシーが Standard に設定されている場合、Snowflake はキューイングが検出されるとすぐに追加ウェアハウスを起動してキューを削減しようとします。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-multicluster#setting-the-scaling-policy-for-a-multi-cluster-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 51, "title": "Snowflake のアクセス制御メカニズムに関して正しい記述はどれですか？（該当するものをすべ...", "multiSelect": true, "stemHtml": "<p>Snowflake のアクセス制御メカニズムに関して正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "セキュリティ保護可能なオブジェクトに権限を付与できる"}, {"key": "B", "label": "ロールを他のユーザーに付与できる"}, {"key": "C", "label": "ロールは他のロールに付与できない"}, {"key": "D", "label": "ロールを他のロールに付与できる"}], "correctAnswers": ["A", "B", "D"], "explanationHtml": "<p>✅ <strong>セキュリティ保護可能なオブジェクトに権限を付与できる / ロールを他のユーザーに付与できる / ロールを他のロールに付与できる</strong></p><p>権限はロールにのみ付与でき、個々のユーザーに直接付与することはできません。したがって、ロールを他のユーザーや他のロールに付与することが可能です。</p><p>https://docs.snowflake.com/en/user-guide/security-access-control-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 52, "title": "テーブルのクローニングを実現するのはどのレイヤーですか？", "multiSelect": false, "stemHtml": "<p>テーブルのクローニングを実現するのはどのレイヤーですか？</p>", "options": [{"key": "A", "label": "クエリ処理レイヤー"}, {"key": "B", "label": "クラウドサービスレイヤー"}, {"key": "C", "label": "共有管理レイヤー"}, {"key": "D", "label": "クローニング管理レイヤー"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>クラウドサービスレイヤー</strong></p><p>クローニングはクラウドサービスレイヤーで実行されるメタデータ操作によって実現されます。データは物理的にコピーされず、クローンされたテーブルはソーステーブルのマイクロパーティションを指します。</p><p>https://docs.snowflake.com/en/user-guide/tables-storage-considerations#label-cloning-tables</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 53, "title": "Snowflake のフェデレーション認証に関して正しい記述はどれですか？（該当するものをすべて...", "multiSelect": true, "stemHtml": "<p>Snowflake のフェデレーション認証に関して正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Snowflake は Okta と ADFS のネイティブサポートを持つ"}, {"key": "B", "label": "外部 ID プロバイダーで認証されると、ユーザーは Snowflake のユーザー名とパスワードを個別に送信する必要がない"}, {"key": "C", "label": "Snowflake はほとんどの SAML 2.0 ID プロバイダーと互換性がある"}, {"key": "D", "label": "外部 ID ソースで認証された後、ユーザーは Snowflake のユーザー名とパスワードを入力する必要がある"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>Snowflake は Okta と ADFS のネイティブサポートを持つ / 外部 ID プロバイダーで認証されると、ユーザーは Snowflake のユーザー名とパスワードを個別に送信する必要がない / Snowflake はほとんどの SAML 2.0 ID プロバイダーと互換性がある</strong></p><p>Snowflake は SSO を可能にするフェデレーション認証をサポートしています。IdP 認証後、ユーザーはログインせずに Snowflake にアクセスできます。</p><p>https://docs.snowflake.com/en/user-guide/admin-security-fed-auth</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 54, "title": "クエリ処理レイヤーは複数のコンピュートクラスター（仮想ウェアハウス）を同時に実行できます。コンピ...", "multiSelect": false, "stemHtml": "<p>クエリ処理レイヤーは複数のコンピュートクラスター（仮想ウェアハウス）を同時に実行できます。コンピュートクラスターがデータにアクセスする方法に関して正しい記述はどれですか？</p>", "options": [{"key": "A", "label": "各仮想ウェアハウスはデータの一部を受け取る"}, {"key": "B", "label": "各仮想ウェアハウスは同じ共有データにアクセスする"}, {"key": "C", "label": "各仮想ウェアハウスはすべてのデータの完全なコピーを受け取る"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>各仮想ウェアハウスは同じ共有データにアクセスする</strong></p><p>Snowflake は共有ディスクアーキテクチャと同様にデータを共有形式で保存しますが、それぞれが独自のメモリと処理能力を持つ複数のコンピューティングエンジンが同じ共有データ上で動作できます。</p><p>https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 55, "title": "ロールに付与された権限を確認するために使用できる ACCOUNT_USAGE ビューはどれですか...", "multiSelect": false, "stemHtml": "<p>ロールに付与された権限を確認するために使用できる ACCOUNT_USAGE ビューはどれですか？</p>", "options": [{"key": "A", "label": "ACCESS_HISTORY"}, {"key": "B", "label": "OBJECT_DEPENDENCIES"}, {"key": "C", "label": "GRANTS_TO_USERS"}, {"key": "D", "label": "GRANTS_TO_ROLES"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>GRANTS_TO_ROLES</strong></p><p>GRANTS_TO_ROLES ビューはロールに付与されたアクセス権限に関する情報を確認するために使用できます。このビューには履歴情報（最大365日）も含まれています。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage/grants_to_users</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 56, "title": "Snowflake アカウントが別の Snowflake アカウントとデータを共有する場合のコス...", "multiSelect": true, "stemHtml": "<p>Snowflake アカウントが別の Snowflake アカウントとデータを共有する場合のコストに関して正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "データプロバイダーはデータコンシューマーが実行するクエリのコンピュートコストを請求される"}, {"key": "B", "label": "データコンシューマーは共有データに関連するストレージコストを請求されない"}, {"key": "C", "label": "データコンシューマーは自分が実行するクエリのコンピュートコストを請求される"}, {"key": "D", "label": "データプロバイダーとデータコンシューマーの両方がストレージコストを請求される"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>データコンシューマーは共有データに関連するストレージコストを請求されない / データコンシューマーは自分が実行するクエリのコンピュートコストを請求される</strong></p><p>プロバイダーアカウントがデータストレージの料金を支払うため、データコンシューマーはストレージに対して追加料金を支払う必要がありません。ただし、共有データでクエリを実行するために使用されるコンピュートのコストはデータコンシューマーが支払います。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 57, "title": "クエリが長時間かかりました。クエリプロファイルに「ローカルストレージへのバイトスピル」が大きな数...", "multiSelect": true, "stemHtml": "<p>クエリが長時間かかりました。クエリプロファイルに「ローカルストレージへのバイトスピル」が大きな数値を示していました。クエリパフォーマンスを改善するにはどうすればよいですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "マルチクラスター仮想ウェアハウスでクエリを実行する"}, {"key": "B", "label": "仮想ウェアハウスのサイズを大きくして、より多くのデータがメモリに収まるようにする"}, {"key": "C", "label": "パーティションプルーニングが発生し、クエリが処理するデータが少なくなるようにクエリをより最適に書き直す"}, {"key": "D", "label": "仮想ウェアハウスを再起動してローカルディスクキャッシュをクリアする"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>仮想ウェアハウスのサイズを大きくして、より多くのデータがメモリに収まるようにする / パーティションプルーニングが発生し、クエリが処理するデータが少なくなるようにクエリをより最適に書き直す</strong></p><p>スピルを回避する方法の一つは、より大きなウェアハウスを使用することです。別の最適化方法は、処理する必要がある行数を制限することです。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile#queries-too-large-to-fit-in-memory</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 58, "title": "外部テーブルのデータを追跡するために使用できるストリームの種類はどれですか？", "multiSelect": false, "stemHtml": "<p>外部テーブルのデータを追跡するために使用できるストリームの種類はどれですか？</p>", "options": [{"key": "A", "label": "External（説明: External は有効なストリームの種類ではありません。有効なストリームの種類は Standard、Insert-only、Append-only です）"}, {"key": "B", "label": "Standard（説明: Standard ストリームは Snowflake の内部ストレージの変更を追跡し、外部テーブルでは使用できません）"}, {"key": "C", "label": "Append-only（説明: Append-only ストリームは Snowflake のマネージドストレージ内のテーブルへの行挿入のみを追跡しますが、外部テーブルでは使用できません）"}, {"key": "D", "label": "Insert-only（説明: Insert-only ストリームは挿入と更新を新しい行としてキャプチャすることで外部テーブルの変更を追跡しますが、削除操作は無視します）"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>Insert-only</strong></p><p>https://docs.snowflake.com/en/user-guide/streams-intro#types-of-streams</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ストリーム", "originalCorrect": null, "reviewPoint": ""}}, {"order": 59, "title": "真偽問題：INFORMATION_SCHEMA のビューのデータには最大3時間のレイテンシーがあ...", "multiSelect": false, "stemHtml": "<p>真偽問題：INFORMATION_SCHEMA のビューのデータには最大3時間のレイテンシーがある。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False</strong></p><p>INFORMATION_SCHEMA のビューを通じて提供されるデータはリアルタイムであり、情報に遅延はありません。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 60, "title": "真偽問題：仮想ウェアハウスがサスペンドされる際、その仮想ウェアハウスを使用しているすべての進行中...", "multiSelect": false, "stemHtml": "<p>真偽問題：仮想ウェアハウスがサスペンドされる際、その仮想ウェアハウスを使用しているすべての進行中のクエリが完了するまでサスペンド状態にはなりません。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>仮想ウェアハウスのサスペンドが要求されると、その仮想ウェアハウスを使用するすべてのアクティブなクエリが完了するまでサスペンド状態に入りません。ただし、リソースモニターが「即時サスペンド」を実行する場合、すぐにサスペンドされ実行中のすべてのクエリが停止されます。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-tasks</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 61, "title": "完了したクエリのクエリプロファイルのスニペットを考えてください。強調表示された統計情報を正確に説...", "multiSelect": false, "stemHtml": "<p>完了したクエリのクエリプロファイルのスニペットを考えてください。強調表示された統計情報を正確に説明しているのはどれですか？</p>", "options": [{"key": "A", "label": "クエリプロファイルは非常に効果的なパーティションプルーニングを示している"}, {"key": "B", "label": "クエリプロファイルは使用されている仮想ウェアハウスがクエリに対して小さすぎることを示している"}, {"key": "C", "label": "クエリプロファイルはメタデータキャッシュが使用されたことを示している"}, {"key": "D", "label": "クエリプロファイルは非効果的なパーティションプルーニングを示している"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>クエリプロファイルは非効果的なパーティションプルーニングを示している</strong></p><p>パーティションプルーニングは、スキャンされたパーティション数がパーティション合計より大幅に少ない場合に発生します。スキャンされたパーティションがパーティション合計と等しい場合、クエリはテーブル全体をスキャンしており、パーティションプルーニングは発生していないため、クラスタリングキーを改善する必要があります。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 62, "title": "外部 UDF を作成するために必要な最小 Snowflake エディションはどれですか？", "multiSelect": false, "stemHtml": "<p>外部 UDF を作成するために必要な最小 Snowflake エディションはどれですか？</p>", "options": [{"key": "A", "label": "Business Critical"}, {"key": "B", "label": "Enterprise"}, {"key": "C", "label": "Standard"}, {"key": "D", "label": "Virtual Private Snowflake"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>UDF と外部関数はすべての Snowflake エディションでサポートされている基本機能です。</p><p>https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 63, "title": "複数のカラムでクラスタリングキーを作成する場合、CLUSTER BY 句でカラムはどのような順序...", "multiSelect": false, "stemHtml": "<p>複数のカラムでクラスタリングキーを作成する場合、CLUSTER BY 句でカラムはどのような順序で指定すべきですか？</p>", "options": [{"key": "A", "label": "順序は関係ない"}, {"key": "B", "label": "カーディナリティが高い順から低い順"}, {"key": "C", "label": "逆アルファベット順"}, {"key": "D", "label": "アルファベット順"}, {"key": "E", "label": "カーディナリティが低い順から高い順"}], "correctAnswers": ["E"], "explanationHtml": "<p>✅ <strong>カーディナリティが低い順から高い順</strong></p><p>マルチカラムのクラスタキーを作成する場合、カーディナリティが低い順から高い順にカラムを並べます。そうしないとクラスタリングの効果が低下します。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 64, "title": "Snowflake のストレージ階層に関して正しい記述はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflake のストレージ階層に関して正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "データベースはアカウント内に保存される"}, {"key": "B", "label": "テーブルはスキーマ内に保存される"}, {"key": "C", "label": "データベースは仮想ウェアハウス内に保存される"}, {"key": "D", "label": "仮想ウェアハウスはデータベース内に保存される"}, {"key": "E", "label": "スキーマはデータベース内に保存される"}], "correctAnswers": ["A", "B", "E"], "explanationHtml": "<p>✅ <strong>データベースはアカウント内に保存される / テーブルはスキーマ内に保存される / スキーマはデータベース内に保存される</strong></p><p>Snowflake では、最高レベルは Snowflake アカウントです。アカウント内にデータベースがあります。各データベースには1つ以上のスキーマが含まれています。スキーマはテーブル、ビュー、ファイルフォーマット、シーケンス、UDF、ストアドプロシージャなどのオブジェクトを含みます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake's catalog and objects", "originalCorrect": null, "reviewPoint": ""}}, {"order": 65, "title": "カラムレベルマスキングをサポートする最小 Snowflake エディションはどれですか？", "multiSelect": false, "stemHtml": "<p>カラムレベルマスキングをサポートする最小 Snowflake エディションはどれですか？</p>", "options": [{"key": "A", "label": "Standard"}, {"key": "B", "label": "Virtual Private Snowflake"}, {"key": "C", "label": "Business Critical"}, {"key": "D", "label": "Enterprise"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>Enterprise</strong></p><p>Enterprise エディションには Standard エディションでは提供されていないいくつかの追加機能があります。マルチクラスター仮想ウェアハウス、カラムレベルマスキング、行アクセスポリシー、マテリアライズドビュー、検索最適化などが含まれます。</p><p>https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 66, "title": "内部ステージからオンプレミスシステムにデータをダウンロードするために使用できるコマンドはどれです...", "multiSelect": false, "stemHtml": "<p>内部ステージからオンプレミスシステムにデータをダウンロードするために使用できるコマンドはどれですか？</p>", "options": [{"key": "A", "label": "PUT"}, {"key": "B", "label": "COPY"}, {"key": "C", "label": "GET"}, {"key": "D", "label": "VALIDATE"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>GET</strong></p><p>GET コマンドは内部ステージからオンプレミスシステムにデータをダウンロードするために使用します。PUT コマンドはオンプレミスシステムから内部ステージにデータをアップロードします。</p><p>https://docs.snowflake.com/en/user-guide/data-unload-overview#bulk-unloading-process</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 67, "title": "真偽問題：データベースまたはスキーマがクローンされると、子オブジェクトの権限は自動的にコピーされ...", "multiSelect": false, "stemHtml": "<p>真偽問題：データベースまたはスキーマがクローンされると、子オブジェクトの権限は自動的にコピーされます。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>クローンされたオブジェクトはソースオブジェクトの権限を継承しませんが、データベースまたはスキーマがクローンされると、権限は子オブジェクトに継承されます。</p><p>https://docs.snowflake.com/en/user-guide/object-clone#access-control-privileges-for-cloned-objects</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 68, "title": "テーブルでタイムトラベルクエリを実行するとエラーが発生しました。このエラーが示すことは何ですか？...", "multiSelect": true, "stemHtml": "<p>テーブルでタイムトラベルクエリを実行するとエラーが発生しました。このエラーが示すことは何ですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "AT 句の OFFSET に対してそのテーブルのタイムトラベル保持期間外の値を指定した"}, {"key": "B", "label": "テーブルがロード中のためタイムトラベルが使用できない"}, {"key": "C", "label": "BEFORE 句の STATEMENT にそのテーブルのタイムトラベル保持期間外のクエリ ID を指定した"}, {"key": "D", "label": "自分のロールにタイムトラベルを使用する権限がない"}, {"key": "E", "label": "BEFORE 句の TIMESTAMP にそのテーブルのタイムトラベル保持期間外の値を指定した"}], "correctAnswers": ["A", "C", "E"], "explanationHtml": "<p>✅ <strong>AT 句の OFFSET に対してそのテーブルのタイムトラベル保持期間外の値を指定した / BEFORE 句の STATEMENT にそのテーブルのタイムトラベル保持期間外のクエリ ID を指定した / BEFORE 句の TIMESTAMP にそのテーブルのタイムトラベル保持期間外の値を指定した</strong></p><p>AT | BEFORE 句で指定した TIMESTAMP、OFFSET、STATEMENT がテーブルのタイムトラベル保持期間外の場合、またはテーブルが作成される前のデータにアクセスしようとした場合、タイムトラベルクエリは失敗します。</p><p>https://docs.snowflake.com/en/user-guide/data-time-travel#querying-historical-data</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 69, "title": "マテリアライズドビューのベーステーブルからカラムが変更またはドロップされた場合の動作として正しい...", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューのベーステーブルからカラムが変更またはドロップされた場合の動作として正しいのはどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "再び使用したい場合はマテリアライズドビューを再作成する必要がある"}, {"key": "B", "label": "マテリアライズドビューはサスペンドされない"}, {"key": "C", "label": "マテリアライズドビューはサスペンドされる"}, {"key": "D", "label": "再び使用したい場合はマテリアライズドビューを再開する必要がある"}, {"key": "E", "label": "変更・削除されたカラムはマテリアライズドビューに自動的に反映される"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>再び使用したい場合はマテリアライズドビューを再作成する必要がある / マテリアライズドビューはサスペンドされる</strong></p><p>ベーステーブルからカラムが変更またはドロップされた場合、マテリアライズドビューはサスペンドされ、再開することはできません。変更・削除されたカラムを反映した正しい定義で再作成する必要があります。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized#changing-or-dropping-columns-in-the-base-table</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 70, "title": "組織の Snowflake インスタンスのセキュリティ管理者として、過去60分間にシステムにログ...", "multiSelect": false, "stemHtml": "<p>組織の Snowflake インスタンスのセキュリティ管理者として、過去60分間にシステムにログインしたすべてのユーザーのリストを継続的に追跡する必要があります。どの方法を使用できますか？</p>", "options": [{"key": "A", "label": "Snowflake サポートにこれらの詳細を提供するよう依頼する"}, {"key": "B", "label": "テーブル関数 INFORMATION_SCHEMA.LOGIN_HISTORY_BY_USER() を使用する"}, {"key": "C", "label": "ビュー SNOWFLAKE.ACCOUNT_USAGE.LOGIN_HISTORY をクエリする"}, {"key": "D", "label": "テーブル関数 INFORMATION_SCHEMA.LOGIN_HISTORY() を使用する"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>テーブル関数 INFORMATION_SCHEMA.LOGIN_HISTORY() を使用する</strong></p><p>ACCOUNT_USAGE スキーマのビューは最大3時間のレイテンシーがあります。過去60分間のログイン履歴を継続的に追跡するには INFORMATION_SCHEMA テーブル関数が必要です。なお、INFORMATION_SCHEMA.LOGIN_HISTORY_BY_USER() は単一ユーザーの情報しか提供しないため不適切です。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 71, "title": "クローンできるオブジェクトはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>クローンできるオブジェクトはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "テーブル"}, {"key": "B", "label": "スキーマ"}, {"key": "C", "label": "仮想ウェアハウス"}, {"key": "D", "label": "データベース"}, {"key": "E", "label": "タスク"}, {"key": "F", "label": "共有"}], "correctAnswers": ["A", "B", "D", "E"], "explanationHtml": "<p>✅ <strong>テーブル / スキーマ / データベース / タスク</strong></p><p>仮想ウェアハウスと共有オブジェクトはクローンできません。テーブル、スキーマ、データベースはクローンできます。その他にステージ、ファイルフォーマット、タスク、シーケンス、ストリームもクローンできます。</p><p>https://docs.snowflake.com/en/user-guide/object-clone</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 72, "title": "外部テーブルが適切な解決策となるのはどのような場合ですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>外部テーブルが適切な解決策となるのはどのような場合ですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "データがバイナリ形式で Snowflake にロードできない"}, {"key": "B", "label": "通常、データのサブセットのみがアクセスされる"}, {"key": "C", "label": "データがクラウドプラットフォーム（S3、Azure Blob Storage など）のデータレイクに既に存在している"}, {"key": "D", "label": "データへのアクセスが頻繁でない"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>通常、データのサブセットのみがアクセスされる / データがクラウドプラットフォームのデータレイクに既に存在している / データへのアクセスが頻繁でない</strong></p><p>データへのアクセスが頻繁でない場合や、データの一部のみをクエリする必要がある場合、外部テーブルはコスト効率の良い方法でデータレイクのデータを公開できます。</p><p>https://docs.snowflake.com/en/user-guide/tables-external-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 73, "title": "クラウドサービスレイヤーが実行する機能はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>クラウドサービスレイヤーが実行する機能はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "クエリプランニング"}, {"key": "B", "label": "クエリ最適化"}, {"key": "C", "label": "クエリ結果キャッシング"}, {"key": "D", "label": "クエリ処理"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>クエリプランニング / クエリ最適化 / クエリ結果キャッシング</strong></p><p>クラウドサービスレイヤーはクエリプランニングと最適化を担当します。仮想ウェアハウスがクエリ処理を実行しますが、結果セットが作成されると、クラウドサービスレイヤーの一部であるクエリ結果キャッシュに保存されます。</p><p>https://docs.snowflake.com/en/user-guide/intro-key-concepts#cloud-services</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 74, "title": "真偽問題：ファイルがテーブルにロードされると、Snowflake はそのファイルをメタデータにロ...", "multiSelect": false, "stemHtml": "<p>真偽問題：ファイルがテーブルにロードされると、Snowflake はそのファイルをメタデータにロード済みとしてマークし、再処理されないようにします。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>ロードメタデータにはすべてのファイルの名前やロード時刻のタイムスタンプなどの情報が保存されています。このロードメタデータを使用することで、Snowflake は以前にロードされたファイルを再処理しません。ロードメタデータは64日後に期限切れになります。</p><p>https://docs.snowflake.com/en/user-guide/data-load-considerations-load#load-metadata</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 75, "title": "インバウンド共有によって提供されたオブジェクトに対して実行できる操作はどれですか？", "multiSelect": false, "stemHtml": "<p>インバウンド共有によって提供されたオブジェクトに対して実行できる操作はどれですか？</p>", "options": [{"key": "A", "label": "DELETE"}, {"key": "B", "label": "UPDATE"}, {"key": "C", "label": "DROP"}, {"key": "D", "label": "SELECT"}, {"key": "E", "label": "ALTER"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>SELECT</strong></p><p>共有オブジェクトはコンシューマーにとって読み取り専用であり、コンシューマーが変更することはできません。コンシューマーはオブジェクトを追加、更新、削除、変更、ドロップすることはできません。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 76, "title": "Snowflake アーキテクチャで同じレイヤーを指す用語はどれですか？（該当するものをすべて選...", "multiSelect": true, "stemHtml": "<p>Snowflake アーキテクチャで同じレイヤーを指す用語はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "仮想ウェアハウス"}, {"key": "B", "label": "ストレージレイヤー"}, {"key": "C", "label": "クラウドレイヤー"}, {"key": "D", "label": "コンピュートレイヤー"}, {"key": "E", "label": "クエリ処理レイヤー"}], "correctAnswers": ["A", "D", "E"], "explanationHtml": "<p>✅ <strong>仮想ウェアハウス / コンピュートレイヤー / クエリ処理レイヤー</strong></p><p>クエリ処理レイヤー、仮想ウェアハウス、コンピュートレイヤー、コンピュートノード、コンピュートクラスターは「クエリ処理能力を提供するレイヤー」を指す互換性のある用語として使用できます。</p><p>https://docs.snowflake.com/en/user-guide/intro-key-concepts#query-processing</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 77, "title": "このコースの練習問題が実際の認定試験の問題と同一でないのはなぜですか？", "multiSelect": false, "stemHtml": "<p>このコースの練習問題が実際の認定試験の問題と同一でないのはなぜですか？</p>", "options": [{"key": "A", "label": "学生を無関係なトピックで挑戦させて意図的に混乱させるため"}, {"key": "B", "label": "学生が正確な質問と回答を暗記できるようにするため"}, {"key": "C", "label": "コース作成者が実際の試験問題を知らないから"}, {"key": "D", "label": "特定の質問の機械的な暗記に頼るのではなく、概念の知識と理解をテストするため"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>特定の質問の機械的な暗記に頼るのではなく、概念の知識と理解をテストするため</strong></p><p>このコースは認定試験に必要な概念とトピックを徹底的に理解するのを助けるために設計されています。練習問題は知識をテストして学習を強化するために作られています。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "（メタ問題）", "originalCorrect": null, "reviewPoint": ""}}, {"order": 78, "title": "Snowflake をデータウェアハウスとして使用する通信会社のデータエンジニアです。会社はすべ...", "multiSelect": true, "stemHtml": "<p>Snowflake をデータウェアハウスとして使用する通信会社のデータエンジニアです。会社はすべてのネットワークシグナリングデータをほぼリアルタイムでテーブルにロードする必要があります。ネットワークシグナリングデータは既に1分ごとに S3 バケットに届きます。どのような行動を取るべきですか？（3つ選択）</p>", "options": [{"key": "A", "label": "外部ステージからデータをロードする Snowpipe を作成する"}, {"key": "B", "label": "Snowpipe を設定して S3 バケット内の新しいファイルを継続的に確認する"}, {"key": "C", "label": "S3 バケットで通知イベントを設定し、Snowpipe をトリガーする"}, {"key": "D", "label": "RUN Snowpipe を実行して Snowpipe を起動する"}, {"key": "E", "label": "ほぼリアルタイムデータが届く S3 バケットの上に外部ステージを作成する"}], "correctAnswers": ["A", "C", "E"], "explanationHtml": "<p>✅ <strong>外部ステージからデータをロードする Snowpipe を作成する / S3 バケットで通知イベントを設定し、Snowpipe をトリガーする / ほぼリアルタイムデータが届く S3 バケットの上に外部ステージを作成する</strong></p><p>Snowpipe は外部ステージと内部ステージの両方からデータをロードできます。外部ステージを使用する場合、クラウドプラットフォームの通知を使用して Snowpipe をトリガーできます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 79, "title": "Snowflake が提供するコネクターはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflake が提供するコネクターはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Snowflake Connector for Spark"}, {"key": "B", "label": "Snowflake Connector for Assembly"}, {"key": "C", "label": "Snowflake Connector for Kafka"}, {"key": "D", "label": "Snowflake Connector for Cobol"}, {"key": "E", "label": "Snowflake Connector for Python"}], "correctAnswers": ["A", "C", "E"], "explanationHtml": "<p>✅ <strong>Snowflake Connector for Spark / Snowflake Connector for Kafka / Snowflake Connector for Python</strong></p><p>Snowflake には Snowflake Connector for Python、Snowflake Connector for Spark、Snowflake Connector for Kafka、JDBC ドライバー、ODBC ドライバー、.NET ドライバー、Go 言語用ドライバー、Node.js ドライバーなどが現在利用可能です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 80, "title": "クエリ結果キャッシュがクエリ結果を提供する条件はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>クエリ結果キャッシュがクエリ結果を提供する条件はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "クエリが前のクエリの結果キャッシュを生成した同じユーザーによって実行される"}, {"key": "B", "label": "クエリが以前に実行されたクエリと一致し、キャッシュされた結果がまだ利用可能である"}, {"key": "C", "label": "クエリ内のテーブルのマイクロパーティションが変更されていない"}, {"key": "D", "label": "クエリで使用されるテーブルの1つに新しいマイクロパーティションが追加された"}, {"key": "E", "label": "クエリを実行するロールがクエリで使用されるテーブルに対して必要な権限を持っている"}], "correctAnswers": ["B", "C", "E"], "explanationHtml": "<p>✅ <strong>クエリが以前に実行されたクエリと一致し、キャッシュされた結果がまだ利用可能である / クエリ内のテーブルのマイクロパーティションが変更されていない / クエリを実行するロールがクエリで使用されるテーブルに対して必要な権限を持っている</strong></p><p>クエリ結果キャッシュを使用するには、基礎となるデータとマイクロパーティションが変更されておらず、クエリが構文的に同一である必要があります。</p><p>https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 81, "title": "Snowflake の Enterprise エディションを使用している大手銀行のデータウェアハ...", "multiSelect": false, "stemHtml": "<p>Snowflake の Enterprise エディションを使用している大手銀行のデータウェアハウス管理者です。毎月末に財務部門による Snowflake のクエリ実行数が大幅に増加することに気づきました。財務部門にはラージ（L）サイズの仮想ウェアハウスがありますが、ユーザークエリは待機（キュー）しなければなりません。コストを最小化しながらユーザーエクスペリエンスを向上させるための最善の行動は何ですか？</p>", "options": [{"key": "A", "label": "月末処理中に財務ユーザーを無効にしてシステムの負荷を減らす"}, {"key": "B", "label": "財務専用の仮想ウェアハウスのサイズを XL に永久的に増加させる"}, {"key": "C", "label": "月末処理中に財務専用の仮想ウェアハウスのサイズを L から XL に増加させ、月末後にサイズを戻す"}, {"key": "D", "label": "財務仮想ウェアハウスをマルチクラスター仮想ウェアハウスとして設定する。需要の増減に応じて追加の仮想ウェアハウスが自動的に起動・停止される"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>財務仮想ウェアハウスをマルチクラスター仮想ウェアハウスとして設定する</strong></p><p>マルチクラスター仮想ウェアハウスは、同時クエリ数が単一仮想ウェアハウスの容量を超えるシナリオでよく使用されます。需要に基づいて追加クラスターを動的に追加し、需要が減少すると追加クラスターは廃止されます。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-multicluster</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 82, "title": "真偽問題：Medium 仮想ウェアハウスが2時間稼働する際に使用されるクレジットは、Small ...", "multiSelect": false, "stemHtml": "<p>真偽問題：Medium 仮想ウェアハウスが2時間稼働する際に使用されるクレジットは、Small 仮想ウェアハウスが4時間稼働する場合と同等です。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>X-Small（1ノード）仮想ウェアハウスは1時間で1クレジットを消費します。サイズが1段階大きくなるごとに1時間あたりのクレジット使用量が2倍になります。Small 仮想ウェアハウス（2ノード）は4時間で8クレジットを消費します。Medium 仮想ウェアハウス（4ノード）は2時間で8クレジットを消費します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 83, "title": "Snowflake にデフォルトで存在するロールはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflake にデフォルトで存在するロールはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "SECURITYADMIN"}, {"key": "B", "label": "USERADMIN"}, {"key": "C", "label": "ROOT"}, {"key": "D", "label": "ACCOUNTADMIN"}], "correctAnswers": ["A", "B", "D"], "explanationHtml": "<p>✅ <strong>SECURITYADMIN / USERADMIN / ACCOUNTADMIN</strong></p><p>Snowflake の組み込みロールには ORGADMIN、ACCOUNTADMIN、USERADMIN、SECURITYADMIN、SYSADMIN、PUBLIC があります。</p><p>https://docs.snowflake.com/en/user-guide/security-access-control-overview#system-defined-roles</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 84, "title": "真偽問題：仮想ウェアハウスがサスペンドされるとローカルディスクキャッシュが消去されます。", "multiSelect": false, "stemHtml": "<p>真偽問題：仮想ウェアハウスがサスペンドされるとローカルディスクキャッシュが消去されます。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>仮想ウェアハウスはテーブルからデータにアクセスするたびにそのデータをローカルにキャッシュします。仮想ウェアハウスがサスペンドされるとウェアハウスキャッシュは消去されます。仮想ウェアハウスが再開されると、クエリが処理されるにつれてウェアハウスキャッシュは再構築されます。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-considerations#how-does-warehouse-caching-impact-queries</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 85, "title": "Snowflake を説明するために使用できる用語はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflake を説明するために使用できる用語はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "共有コンピュート"}, {"key": "B", "label": "ハイブリッドカラム型ストレージ"}, {"key": "C", "label": "ネイティブ SQL サポート"}, {"key": "D", "label": "共有ディスク"}, {"key": "E", "label": "共有データ"}, {"key": "F", "label": "クラウドプラットフォームでの実行のためにゼロから設計・構築された"}], "correctAnswers": ["B", "C", "E", "F"], "explanationHtml": "<p>✅ <strong>ハイブリッドカラム型ストレージ / ネイティブ SQL サポート / 共有データ / クラウドプラットフォームでの実行のためにゼロから設計・構築された</strong></p><p>Snowflake はクラウドのために設計されており、ゼロから構築されています。データは共有形式で保存され、ネイティブ SQL サポートを提供し、データをハイブリッドカラム形式で保存します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 86, "title": "外部関数のコードはどこに保存されますか？", "multiSelect": false, "stemHtml": "<p>外部関数のコードはどこに保存されますか？</p>", "options": [{"key": "A", "label": "Snowflake メタデータ内"}, {"key": "B", "label": "クラウドサービスレイヤーのコードリポジトリ内"}, {"key": "C", "label": "Snowflake の外部"}, {"key": "D", "label": "テーブル内"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Snowflake の外部</strong></p><p>外部関数は他の UDF と異なり、独自のコードを含まず、Snowflake の外部に保存・実行されるコードを呼び出します。Snowflake 内に保存されるのは、Snowflake がリモートサービスを呼び出すために使用する情報のみです。</p><p>https://docs.snowflake.com/en/sql-reference/external-functions-introduction</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 87, "title": "以下のリソースモニター設定を考えてください。Warehouse 1 が使用できるクレジットの最大...", "multiSelect": false, "stemHtml": "<p>以下のリソースモニター設定を考えてください。Warehouse 1 が使用できるクレジットの最大数はいくつですか？</p>", "options": [{"key": "A", "label": "1000"}, {"key": "B", "label": "2000"}, {"key": "C", "label": "2500"}, {"key": "D", "label": "5000"}, {"key": "E", "label": "500"}], "correctAnswers": ["E"], "explanationHtml": "<p>✅ <strong>500</strong></p><p>リソースモニターは定義されたクォータに対して単一の仮想ウェアハウスを追跡・管理できます。複数の仮想ウェアハウスを一緒に追跡するリソースモニターも作成できます。</p><p>https://docs.snowflake.com/en/user-guide/resource-monitors#assignment-of-resource-monitors</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 88, "title": "各マイクロパーティションには一般的に______の非圧縮データが含まれています。", "multiSelect": false, "stemHtml": "<p>各マイクロパーティションには一般的に______の非圧縮データが含まれています。</p>", "options": [{"key": "A", "label": "50MB〜500MB"}, {"key": "B", "label": "5MB〜10MB"}, {"key": "C", "label": "1GB〜10GB"}, {"key": "D", "label": "1024KB〜2048KB"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>50MB〜500MB</strong></p><p>マイクロパーティションは小さく、通常50MB〜500MBの非圧縮データを保存します。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 89, "title": "Matillion、Informatica、IBM DataStage、Talend、AbIni...", "multiSelect": false, "stemHtml": "<p>Matillion、Informatica、IBM DataStage、Talend、AbInitio は Snowflake パートナーエコシステムでどのようなパートナーですか？</p>", "options": [{"key": "A", "label": "ビジネスインテリジェンス"}, {"key": "B", "label": "セキュリティ・ガバナンス・可観測性"}, {"key": "C", "label": "機械学習・データサイエンス"}, {"key": "D", "label": "データインテグレーション"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>データインテグレーション</strong></p><p>これらはすべて Snowflake のデータインテグレーションパートナーです。</p><p>https://docs.Snowflake.com/en/user-guide/ecosystem.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パートナー", "originalCorrect": null, "reviewPoint": ""}}, {"order": 90, "title": "Snowflake の共有オブジェクトの内容を正しく説明している記述はどれですか？（該当するもの...", "multiSelect": true, "stemHtml": "<p>Snowflake の共有オブジェクトの内容を正しく説明している記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "共有オブジェクトには、共有されているオブジェクト（テーブル、セキュアビューなど）へのアクセスを許可する権限が含まれる"}, {"key": "B", "label": "共有オブジェクトには、データベースとオブジェクトが共有されるコンシューマーアカウントが含まれる"}, {"key": "C", "label": "共有オブジェクトには、共有されているデータベースとスキーマへのアクセスを許可する権限が含まれる"}, {"key": "D", "label": "共有オブジェクトには、共有オブジェクトでクエリを実行するために使用される仮想ウェアハウスが含まれる"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>共有オブジェクトには共有されているオブジェクトへのアクセスを許可する権限が含まれる / 共有オブジェクトにはコンシューマーアカウントが含まれる / 共有オブジェクトにはデータベースとスキーマへのアクセスを許可する権限が含まれる</strong></p><p>共有は、共有が必要なオブジェクトのコンテナとして機能し、コンシューマーアカウントを指定します。仮想ウェアハウスは共有の一部ではありません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 91, "title": "ストアドプロシージャを作成したロールの権限でストアドプロシージャが実行されるのはどのような条件で...", "multiSelect": false, "stemHtml": "<p>ストアドプロシージャを作成したロールの権限でストアドプロシージャが実行されるのはどのような条件ですか？</p>", "options": [{"key": "A", "label": "ストアドプロシージャがシステムセキュリティ設定を変更する"}, {"key": "B", "label": "ストアドプロシージャが呼び出し元の権限で実行するように設定されている"}, {"key": "C", "label": "ストアドプロシージャがアカウントレベルの変更を実行する"}, {"key": "D", "label": "ストアドプロシージャが所有者の権限で実行するように設定されている"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>ストアドプロシージャが所有者の権限で実行するように設定されている</strong></p><p>ストアドプロシージャは呼び出し元の権限または所有者の権限で呼び出すことができます。呼び出し元の権限で実行するように設定されたストアドプロシージャは呼び出しユーザーの権限で実行されます。所有者の権限で実行するように設定されたストアドプロシージャは、ストアドプロシージャを作成・所有するロールの権限で実行されます。</p><p>https://docs.snowflake.com/en/sql-reference/stored-procedures-rights</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 92, "title": "Snowflake データウェアハウスを実行する小売組織の開発者です。JSON ベースのデータを...", "multiSelect": false, "stemHtml": "<p>Snowflake データウェアハウスを実行する小売組織の開発者です。JSON ベースのデータをテーブルにアップロードする必要があります。どのようなアプローチを取るべきですか？</p>", "options": [{"key": "A", "label": "Snowflake は JSON をサポートしていないため、ソースシステムに CSV を送るよう依頼する"}, {"key": "B", "label": "選択したプログラミング言語（Python、Java など）を使用して JSON ファイルを CSV 構造に処理するプログラムを書き、COPY コマンドを使用して CSV ファイルをテーブルにロードする"}, {"key": "C", "label": "Snowflake が提供する関数を使用してテーブルにロードする際に JSON データを処理する"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Snowflake が提供する関数を使用してテーブルにロードする際に JSON データを処理する</strong></p><p>Snowflake はいくつかの半構造化データフォーマット（JSON、Avro、ORC、Parquet、XML）をサポートしています。Snowflake は任意のデータを保存でき、半構造化データの入力とクエリに適した VARIANT データ型を提供します。</p><p>https://docs.snowflake.com/en/user-guide/semistructured-intro#loading-semi-structured-data</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 93, "title": "真偽問題：Time Travel とフェイルセーフストレージのデータは Snowflake によ...", "multiSelect": false, "stemHtml": "<p>真偽問題：Time Travel とフェイルセーフストレージのデータは Snowflake によって無料で保存されます。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False</strong></p><p>Snowflake は Time Travel とフェイルセーフのデータストレージに対して料金を請求します。Time Travel とフェイルセーフのデータ保存コストは、保持日数と最後に変更された時点からの時間に基づいて24時間ごとに計算されます。</p><p>https://docs.snowflake.com/en/user-guide/data-cdp-storage-costs</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 94, "title": "真偽問題：VARIANT データ型は1行あたり最大16MBのデータを保持できます。", "multiSelect": false, "stemHtml": "<p>真偽問題：VARIANT データ型は1行あたり最大16MBのデータを保持できます。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>VARIANT カラムの1行には最大16MBのデータを保持できます。JSON がそれより大きい場合は、JSON を複数の行に分割するなどの別のテクニックを検討する必要があります。</p><p>https://docs.snowflake.com/en/sql-reference/data-types-semistructured#variant https://docs.snowflake.com/en/user-guide/semistructured-intro#loading-semi-structured-data</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 95, "title": "Snowflake Marketplace からデータセットをインポートできるロールはどれですか...", "multiSelect": true, "stemHtml": "<p>Snowflake Marketplace からデータセットをインポートできるロールはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "SYSADMIN"}, {"key": "B", "label": "IMPORT SHARE 権限を持つロール"}, {"key": "C", "label": "ORGADMIN"}, {"key": "D", "label": "ACCOUNTADMIN"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>IMPORT SHARE 権限を持つロール / ACCOUNTADMIN</strong></p><p>どのユーザーやロールも Snowflake Marketplace を閲覧できますが、データを利用するには ACCOUNTADMIN 権限または IMPORT SHARE 権限を持つユーザーが必要です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 96, "title": "真偽問題：ACCOUNTADMIN または SECURITYADMIN はユーザーの MFA を...", "multiSelect": false, "stemHtml": "<p>真偽問題：ACCOUNTADMIN または SECURITYADMIN はユーザーの MFA を無効にして、必要に応じてユーザーが MFA に再登録できるようにすることができます。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>多要素認証（MFA）はすべての Snowflake アカウントでデフォルトで有効になっており、すべての Snowflake ユーザーが Snowflake Web インターフェースから MFA に登録できます。管理者はユーザーの MFA 登録を無効にすることができ、その場合ユーザーは MFA 機能にアクセスするために再登録する必要があります。SECURITYADMIN 以上のロールを持つ管理者がユーザーの MFA を無効にできます。</p><p>https://docs.snowflake.com/en/user-guide/security-mfa</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 97, "title": "Snowflake のパフォーマンスを向上させる方法はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflake のパフォーマンスを向上させる方法はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "クラスタリングキー"}, {"key": "B", "label": "マルチクラスター仮想ウェアハウス"}, {"key": "C", "label": "セカンダリインデックス"}, {"key": "D", "label": "クエリ結果キャッシング"}, {"key": "E", "label": "専用仮想ウェアハウス"}], "correctAnswers": ["A", "B", "D", "E"], "explanationHtml": "<p>✅ <strong>クラスタリングキー / マルチクラスター仮想ウェアハウス / クエリ結果キャッシング / 専用仮想ウェアハウス</strong></p><p>Snowflake のパフォーマンス向上アプローチには、内部キャッシングメカニズム、仮想ウェアハウスのスケールアップ、マルチクラスター仮想ウェアハウスによる水平スケーリング、パーティションプルーニング、クラスタリングキー、マテリアライズドビュー、検索最適化サービスなどが含まれます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 98, "title": "真偽問題：特定の仮想ウェアハウスを使用してテーブルにデータをロードした場合、そのデータをクエリす...", "multiSelect": false, "stemHtml": "<p>真偽問題：特定の仮想ウェアハウスを使用してテーブルにデータをロードした場合、そのデータをクエリするためにも同じ仮想ウェアハウスを使用する必要があります。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>False</strong></p><p>どの仮想ウェアハウスでもデータにアクセスできます。Snowflake はデータを共有形式で保存しますが、それぞれが独自のメモリと処理能力を持つ複数のコンピューティングエンジンが同じ共有データにアクセスして処理できます。</p><p>https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 99, "title": "ユーザーを作成・管理できるロールはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>ユーザーを作成・管理できるロールはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "USERADMIN"}, {"key": "B", "label": "SYSADMIN"}, {"key": "C", "label": "SECURITYADMIN"}, {"key": "D", "label": "ACCOUNTADMIN"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>USERADMIN / SECURITYADMIN / ACCOUNTADMIN</strong></p><p>USERADMIN ロールは通常、ユーザーの作成と管理を目的としています。ただし、USERADMIN ロールの権限は SECURITYADMIN と ACCOUNTADMIN に継承されるため、これらのロールもユーザーを作成できます。ACCOUNTADMIN は最も強力なロールで、Snowflake アカウントで何でもできます。</p><p>https://docs.snowflake.com/en/user-guide/security-access-control-overview#system-defined-roles</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 100, "title": "クエリの特定ステップのクエリプロファイルを考えてください。強調表示された統計情報を正確に説明して...", "multiSelect": true, "stemHtml": "<p>クエリの特定ステップのクエリプロファイルを考えてください。強調表示された統計情報を正確に説明しているのはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "より大きな仮想ウェアハウスサイズはローカルおよびリモートスピルを削減する可能性が高い"}, {"key": "B", "label": "クエリプロファイルは効果的なパーティションプルーニングを示している"}, {"key": "C", "label": "クエリプロファイルは、そのステップが仮想ウェアハウスのメモリに収まらないほど大きいことを示している"}, {"key": "D", "label": "クエリプロファイルはメタデータキャッシュが使用されたことを示している"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>より大きな仮想ウェアハウスサイズはローカルおよびリモートスピルを削減する可能性が高い / クエリプロファイルは、そのステップが仮想ウェアハウスのメモリに収まらないほど大きいことを示している</strong></p><p>Snowflake はメモリに操作が収まらない場合、ウェアハウスのローカルディスクにデータをスピルします。「ローカルストレージへのバイトスピル」はローカルスピルを示します。ローカルディスクが満杯になると、リモートクラウドストレージにスピルします。スピルを回避する方法の一つは、より大きなウェアハウスを使用することです。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile#queries-too-large-to-fit-in-memory</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 101, "title": "クラウドサービスレイヤーに保存されているキャッシュはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>クラウドサービスレイヤーに保存されているキャッシュはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Web キャッシュ"}, {"key": "B", "label": "クエリ結果キャッシュ"}, {"key": "C", "label": "仮想ウェアハウスキャッシュ"}, {"key": "D", "label": "JDBC キャッシュ"}, {"key": "E", "label": "メタデータキャッシュ"}], "correctAnswers": ["B", "E"], "explanationHtml": "<p>✅ <strong>クエリ結果キャッシュ / メタデータキャッシュ</strong></p><p>クラウドサービスレイヤーはクエリ結果キャッシュとメタデータキャッシュを保存します。仮想ウェアハウスキャッシュは仮想ウェアハウス内にローカルに保存されます。</p><p>https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 102, "title": "COPY コマンドでステージからデータをロードするためのファイル選択オプションはどれですか？（該...", "multiSelect": true, "stemHtml": "<p>COPY コマンドでステージからデータをロードするためのファイル選択オプションはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "パターンに一致するファイルをロードする"}, {"key": "B", "label": "正確なファイル名を指定して特定のファイルをロードする"}, {"key": "C", "label": "特定のパス内のすべてのファイルをロードする"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>パターンに一致するファイルをロードする / 正確なファイル名を指定して特定のファイルをロードする / 特定のパス内のすべてのファイルをロードする</strong></p><p>これらすべてのオプションが正解です。正確なファイル名を指定してロードしたり、特定のパスからすべてのファイルをロードしたり、パターンに一致するファイルをロードしたりすることができます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-considerations-load#options-for-selecting-staged-data-files</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 103, "title": "Snowflake データウェアハウスを実行する大手小売会社のソリューションアーキテクトです。S...", "multiSelect": false, "stemHtml": "<p>Snowflake データウェアハウスを実行する大手小売会社のソリューションアーキテクトです。Snowflake 実装は、組織全体のユーザーが使用する単一の仮想ウェアハウスで稼働中です。最も利用頻度が高いユーザーの一つである財務部門が、クエリの実行に時間がかかると不満を述べています。ユーザーエクスペリエンスを向上させるための最善の即時行動は何ですか？</p>", "options": [{"key": "A", "label": "財務部門専用の仮想ウェアハウスインスタンスを導入し、ニーズに応じてサイズを設定する。新しい仮想ウェアハウスを自動サスペンドと自動再開に設定する"}, {"key": "B", "label": "財務部門が実行できるクエリの数を制限する"}, {"key": "C", "label": "単一仮想ウェアハウスのサイズを最大サイズに増加させる"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>財務部門専用の仮想ウェアハウスインスタンスを導入し、ニーズに応じてサイズを設定する</strong></p><p>専用仮想ウェアハウスを使用することで、特定のユーザーグループのワークロードを分離できます。財務ユーザー専用の仮想ウェアハウスを確保することで、最大かつ専用のパフォーマンスを確保できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 104, "title": "Snowflake の検索最適化に関して正しい記述はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflake の検索最適化に関して正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "検索最適化サービスは永続的なデータ構造を使用する"}, {"key": "B", "label": "検索最適化サービスは永続的なデータ構造を使用しない"}, {"key": "C", "label": "テーブルの検索最適化設定とそのメンテナンスサービスはユーザーに対して透過的である"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>検索最適化サービスは永続的なデータ構造を使用する / テーブルの検索最適化設定とそのメンテナンスサービスはユーザーに対して透過的である</strong></p><p>検索最適化サービスは、ポイントルックアップを高速化するための永続的なデータ構造を最適化された検索アクセスパスとして使用します。テーブルのデータが変更されると、メンテナンスサービスが検索アクセスパスを更新します。テーブルの検索最適化設定とメンテナンスサービスはユーザーに対して透過的です。</p><p>https://docs.snowflake.com/en/user-guide/search-optimization-service</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 105, "title": "真偽問題：COPY コマンドはデフォルトで単一のファイルにエクスポートします。", "multiSelect": false, "stemHtml": "<p>真偽問題：COPY コマンドはデフォルトで単一のファイルにエクスポートします。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False</strong></p><p>アンロードプロセスは Snowflake が提供する並列処理を活用するために自動的に複数のファイルにエクスポートします。必要に応じて SINGLE パラメータを true に設定して単一ファイルにエクスポートすることもできます。デフォルトの各出力ファイルのサイズは16MBですが、MAX_FILE_SIZE パラメータで変更できます。クラウドストレージにデータをエクスポートする場合、ファイルあたりの最大許容サイズは5GBです。</p><p>https://docs.snowflake.com/en/user-guide/data-unload-considerations#unloading-to-a-single-file</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 106, "title": "Snowflake アーキテクチャの主要なレイヤーはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflake アーキテクチャの主要なレイヤーはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "認証サービス"}, {"key": "B", "label": "クエリ処理"}, {"key": "C", "label": "データベースストレージ"}, {"key": "D", "label": "クラウドサービス"}, {"key": "E", "label": "グローバルサービス"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>クエリ処理 / データベースストレージ / クラウドサービス</strong></p><p>Snowflake アーキテクチャには3つの異なるレイヤーがあります：データベースストレージ（AWS、Azure、Google Cloud の低コストクラウドストレージ）、クエリ処理（主に仮想ウェアハウスで構成）、クラウドサービス（全体の操作の頭脳）。</p><p>https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 107, "title": "マテリアライズドビューはどのようなコストに影響しますか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューはどのようなコストに影響しますか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "ストレージコスト"}, {"key": "B", "label": "レプリケーションコスト"}, {"key": "C", "label": "仮想ウェアハウスコスト"}, {"key": "D", "label": "サーバーレスコスト"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>ストレージコスト / サーバーレスコスト</strong></p><p>各マテリアライズドビューはクエリ結果を保存するため、ストレージ使用量に影響します。Snowflake はマテリアライズドビューが古くならないよう自動的にバックグラウンドメンテナンスを実行します。ベーステーブルが変更されると、そのテーブル上に作成されたすべてのマテリアライズドビューがサーバーレスコンピュートを使用するバックグラウンドサービスによって更新されます。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized#materialized-views-cost</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "コストと価格", "originalCorrect": null, "reviewPoint": ""}}, {"order": 108, "title": "週次リリースサイクルで、リリースの2日目に更新される可能性があるアカウントはどれですか？（2つ選...", "multiSelect": true, "stemHtml": "<p>週次リリースサイクルで、リリースの2日目に更新される可能性があるアカウントはどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "すべての Standard エディションアカウント"}, {"key": "B", "label": "早期アクセスにオプトインした Enterprise エディションアカウントのみ"}, {"key": "C", "label": "早期アクセスにオプトインしていないすべての Enterprise エディション（以上）アカウント"}, {"key": "D", "label": "Business Critical エディションアカウントのみ"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>すべての Standard エディションアカウント / 早期アクセスにオプトインしていないすべての Enterprise エディション（以上）アカウント</strong></p><p>Snowflake は新しいバージョンをすべての Snowflake アカウントに即座にデプロイするのではなく、段階的に移行します。1日目（早期アクセス）：早期アクセスを選択した Enterprise エディション（以上）のアカウントにデプロイされます。1日目または2日目（通常アクセス）：すべての Standard エディションのアカウントにデプロイされます。2日目（最後）：残りすべての Enterprise エディション（以上）のアカウントにデプロイされます。</p><p>https://docs.snowflake.com/en/user-guide/intro-releases</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント", "originalCorrect": null, "reviewPoint": ""}}, {"order": 109, "title": "Snowflake がテーブルデータをどのように保存するかに関して正しい記述はどれですか？（該当...", "multiSelect": true, "stemHtml": "<p>Snowflake がテーブルデータをどのように保存するかに関して正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "データはマイクロパーティションに保存される"}, {"key": "B", "label": "データは Parquet として保存される"}, {"key": "C", "label": "データは自動的に圧縮される"}, {"key": "D", "label": "データはカラム形式で保存される"}, {"key": "E", "label": "データは CSV として保存される"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>データはマイクロパーティションに保存される / データは自動的に圧縮される / データはカラム形式で保存される</strong></p><p>Snowflake テーブルのデータは自動的にマイクロパーティションと呼ばれるパーティションに整理されます。各マイクロパーティションには通常50MB〜500MBの非圧縮データが含まれますが、Snowflake データは常に圧縮して保存されるため、保存サイズは小さくなります。各マイクロパーティション内では、データはカラム形式で保存されます。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 110, "title": "Snowflake の自然クラスタリングを正しく説明しているのはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflake の自然クラスタリングを正しく説明しているのはどれですか？</p>", "options": [{"key": "A", "label": "Snowflake はテーブルにロードされた順序でデータをクラスタリングする"}, {"key": "B", "label": "自然クラスタリングは明示的なクラスタリングキーを定義するプロセスである"}, {"key": "C", "label": "自然クラスタリングはマイクロパーティションを管理するサービスの名前である"}, {"key": "D", "label": "Snowflake はテーブルに定義された自然キーに基づいて最適なクラスタリングキーを決定できる"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>Snowflake はテーブルにロードされた順序でデータをクラスタリングする</strong></p><p>データウェアハウスでは通常、データは毎日届いてロードされます。明示的なクラスタリングキーがなければ、Snowflake はテーブルに挿入された順序に基づいてデータをクラスタリングします。注文テーブルなど、日付ベースで到着するデータを持つ大規模なトランザクションテーブルでは、自然クラスタリングで十分な場合が多いです。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 111, "title": "ORGADMIN が SYSTEM$GLOBAL_ACCOUNT_SET_PARAMETER 関...", "multiSelect": true, "stemHtml": "<p>ORGADMIN が SYSTEM$GLOBAL_ACCOUNT_SET_PARAMETER 関数を使用して有効にできるのはどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "クライアントリダイレクト"}, {"key": "B", "label": "タイムトラベル"}, {"key": "C", "label": "データ共有"}, {"key": "D", "label": "レプリケーション"}, {"key": "E", "label": "自動クラスタリング"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>クライアントリダイレクト / レプリケーション</strong></p><p>この関数は、指定されたアカウントのレプリケーションとフェイルオーバー機能（クライアントリダイレクトを含む）を有効にするために使用できます。この関数は組織管理者（ORGADMIN ロールを使用）のみが呼び出すことができます。</p><p>https://docs.snowflake.com/en/sql-reference/functions/system_global_account_set_parameter</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Business Continuity and Disaster Recovery", "originalCorrect": null, "reviewPoint": ""}}, {"order": 112, "title": "Snowflake では、保存時のすべてのデータはどの暗号化方式を使用して暗号化されますか？", "multiSelect": false, "stemHtml": "<p>Snowflake では、保存時のすべてのデータはどの暗号化方式を使用して暗号化されますか？</p>", "options": [{"key": "A", "label": "AES 256ビット暗号化"}, {"key": "B", "label": "AES 128ビット暗号化"}, {"key": "C", "label": "SHA"}, {"key": "D", "label": "MD5"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>AES 256ビット暗号化</strong></p><p>Snowflake では、保存時のすべてのデータは AES 256ビット暗号化を使用して暗号化されます。</p><p>https://docs.snowflake.com/en/user-guide/security-encryption-manage</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 113, "title": "マテリアライズドビューのメンテナンスに関連するコストを決定する要因はどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューのメンテナンスに関連するコストを決定する要因はどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "ベーステーブルがクエリされる頻度"}, {"key": "B", "label": "ベーステーブルのデータが変更される頻度"}, {"key": "C", "label": "マテリアライズドビューにクラスタリングキーが定義されているかどうか"}, {"key": "D", "label": "マテリアライズドビューがクエリされる頻度"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>ベーステーブルのデータが変更される頻度 / マテリアライズドビューにクラスタリングキーが定義されているかどうか</strong></p><p>マテリアライズドビューのデータ保持コストは以下の要因によって影響されます：1）各ベーステーブルに作成されたマテリアライズドビューの数、2）ベーステーブルが変更された場合にこれらのマテリアライズドビューで発生するデータ変更の範囲、3）クラスタリングキーが定義されているマテリアライズドビューの数。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized#label-materialized-views-maintenance-billing</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 114, "title": "7ヶ月前の日付のクエリ履歴を確認する必要があります。7ヶ月前のクエリ履歴を提供するのはどの方法で...", "multiSelect": false, "stemHtml": "<p>7ヶ月前の日付のクエリ履歴を確認する必要があります。7ヶ月前のクエリ履歴を提供するのはどの方法ですか？</p>", "options": [{"key": "A", "label": "Snowflake サポートにクエリ履歴を提供するよう依頼する"}, {"key": "B", "label": "クエリ履歴ページを使用して履歴クエリを表示する"}, {"key": "C", "label": "INFORMATION_SCHEMA の QUERY_HISTORY テーブル関数を使用する"}, {"key": "D", "label": "ACCOUNT_USAGE スキーマの QUERY_HISTORY ビューを使用する"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>ACCOUNT_USAGE スキーマの QUERY_HISTORY ビューを使用する</strong></p><p>ACCOUNT_USAGE スキーマのビューはさまざまな情報に対して最大365日間の履歴を提供します。7ヶ月前のクエリ履歴は ACCOUNT_USAGE スキーマの QUERY_HISTORY ビューを使用してのみ取得できます。INFORMATION_SCHEMA の QUERY_HISTORY テーブル関数は7日間の履歴しか提供できません。クエリ履歴ページは過去14日間の履歴のみを表示できます。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 115, "title": "仮想ウェアハウスの同時ユーザー数が増加した場合の影響はどれですか？", "multiSelect": false, "stemHtml": "<p>仮想ウェアハウスの同時ユーザー数が増加した場合の影響はどれですか？</p>", "options": [{"key": "A", "label": "大規模で複雑なクエリのパフォーマンスが低下する"}, {"key": "B", "label": "小規模なポイントルックアップクエリのパフォーマンスが向上する"}, {"key": "C", "label": "すべてのクエリのパフォーマンスが向上する"}, {"key": "D", "label": "大規模で複雑なクエリのパフォーマンスが向上する"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>大規模で複雑なクエリのパフォーマンスが低下する</strong></p><p>同時クエリはウェアハウスリソースを共有するため、同時クエリ数が多いと各クエリが取得するリソースが少なくなり、パフォーマンスが悪化する可能性があります。</p><p>https://docs.snowflake.com/en/user-guide/performance-query-warehouse-max-concurrency</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 116, "title": "PUT コマンドを使用してデータをアップロードできるステージはどれですか？（該当するものをすべて...", "multiSelect": true, "stemHtml": "<p>PUT コマンドを使用してデータをアップロードできるステージはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "外部ステージ"}, {"key": "B", "label": "テーブルステージ"}, {"key": "C", "label": "名前付き内部ステージ"}, {"key": "D", "label": "ユーザーステージ"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>テーブルステージ / 名前付き内部ステージ / ユーザーステージ</strong></p><p>PUT コマンドはオンプレミスシステムから内部ステージ（名前付き内部ステージ、テーブルステージ、ユーザーステージを含む）にデータをアップロードします。外部ステージへのデータのダウンロードまたはアップロードには、クラウドプロバイダーのユーティリティまたは他のツールを使用します。</p><p>https://docs.snowflake.com/en/user-guide/data-unload-overview#bulk-unloading-process</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 117, "title": "Snowflake の組み込みロールの権限に関して正しい記述はどれですか？（該当するものをすべて...", "multiSelect": true, "stemHtml": "<p>Snowflake の組み込みロールの権限に関して正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "ACCOUNTADMIN は SYSADMIN が作成したオブジェクトを削除できる"}, {"key": "B", "label": "PUBLIC ロールは SYSADMIN が作成したオブジェクトを削除できる"}, {"key": "C", "label": "SECURITYADMIN は USERADMIN が作成したユーザーをドロップできる"}, {"key": "D", "label": "ACCOUNTADMIN は SECURITYADMIN が作成したロールを変更できる"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>ACCOUNTADMIN は SYSADMIN が作成したオブジェクトを削除できる / SECURITYADMIN は USERADMIN が作成したユーザーをドロップできる / ACCOUNTADMIN は SECURITYADMIN が作成したロールを変更できる</strong></p><p>ロール階層と権限継承により、ACCOUNTADMIN は下位ロールが持つすべての権限を持ちます。したがって、下位ロールが作成したオブジェクトを削除・変更できます。同様に、SECURITYADMIN は USERADMIN より上位のロールであるため、USERADMIN が作成したユーザーをドロップできます。</p><p>https://docs.snowflake.com/en/user-guide/security-access-control-overview#system-defined-roles</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 118, "title": "Snowflake のキーペア認証に関して正しい記述はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflake のキーペア認証に関して正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "キーペア認証は Business Critical エディションのみでサポートされる"}, {"key": "B", "label": "必要に応じてキーをローテーションできる"}, {"key": "C", "label": "すべてのログイン試行に Snowflake のユーザー名とパスワードを入力する必要がある"}, {"key": "D", "label": "ユーザーは最大2つの公開鍵を割り当てることができる"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>必要に応じてキーをローテーションできる / ユーザーは最大2つの公開鍵を割り当てることができる</strong></p><p>Snowflake は標準のユーザー名/パスワードログインに加えて、キーペア認証をサポートすることで追加のセキュリティ層を提供します。ユーザーは最大2つの公開鍵を持つことができ、いつでもローテーションできます。キーペア認証はすべての SnowSQL と Snowflake ドライバーおよびコネクターでサポートされており、すべての Snowflake エディションでサポートされています。</p><p>https://docs.snowflake.com/en/user-guide/key-pair-auth</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 119, "title": "自動クラスタリングに関して正しい記述はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>自動クラスタリングに関して正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "自動クラスタリングはアカウントレベルでオフにできる"}, {"key": "B", "label": "自動クラスタリングはサーバーレスサービスである"}, {"key": "C", "label": "自動クラスタリングにはアクティブな仮想ウェアハウスが必要である"}, {"key": "D", "label": "自動クラスタリングはクラスタリングキーに基づいてマイクロパーティション内のデータを再分散する"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>自動クラスタリングはサーバーレスサービスである / 自動クラスタリングはクラスタリングキーに基づいてマイクロパーティション内のデータを再分散する</strong></p><p>クラスタリングキーが定義されたテーブルに対して、Snowflake サービスである自動クラスタリングが必要に応じてクラスタリングキーに従ってデータを分散させながら再クラスタリングを管理します。</p><p>https://docs.snowflake.com/en/user-guide/tables-auto-reclustering</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 120, "title": "仮想ウェアハウスがサスペンド状態でも、サイズを変更できますか？", "multiSelect": false, "stemHtml": "<p>仮想ウェアハウスがサスペンド状態でも、サイズを変更できますか？</p>", "options": [{"key": "A", "label": "No"}, {"key": "B", "label": "Yes"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Yes</strong></p><p>仮想ウェアハウスは稼働中であっても、いつでもサイズを変更できます。仮想ウェアハウスがサイズ変更されると、Snowflake は新しいサイズに応じてノードを追加または削除します。ノードの削除は、そのノード上のすべてのアクティブなクエリが完了した後にのみ行われます。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-tasks#resizing-a-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 121, "title": "Snowflake 以外のユーザーと共有する場合、リーダーアカウントはどのアカウントに属しますか...", "multiSelect": false, "stemHtml": "<p>Snowflake 以外のユーザーと共有する場合、リーダーアカウントはどのアカウントに属しますか？</p>", "options": [{"key": "A", "label": "データプロバイダーでもデータコンシューマーでもない"}, {"key": "B", "label": "データコンシューマー"}, {"key": "C", "label": "データプロバイダーとデータコンシューマーの両方"}, {"key": "D", "label": "データプロバイダー"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>データプロバイダー</strong></p><p>リーダーアカウントはデータプロバイダーによって作成され、データプロバイダーが所有します。リーダーアカウントで発生したコンピュートコストはデータプロバイダーが負担します。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-reader-create#who-provides-support-for-a-reader-account</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 122, "title": "コンシューマーアカウントが共有データベースに対して実行できない操作はどれですか？（該当するものを...", "multiSelect": true, "stemHtml": "<p>コンシューマーアカウントが共有データベースに対して実行できない操作はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "共有データベースをクローンする"}, {"key": "B", "label": "共有テーブルのデータを変更する"}, {"key": "C", "label": "共有テーブルのデータと別のテーブルのデータを結合する"}, {"key": "D", "label": "共有テーブルのデータをクエリする"}, {"key": "E", "label": "共有テーブルで Time Travel を使用する"}, {"key": "F", "label": "共有データベースからテーブルをクローンする"}], "correctAnswers": ["A", "B", "E", "F"], "explanationHtml": "<p>✅ <strong>共有データベースをクローンする / 共有テーブルのデータを変更する / 共有テーブルで Time Travel を使用する / 共有データベースからテーブルをクローンする</strong></p><p>コンシューマーアカウントはデータへのアクセスとクエリのみ可能で、共有データベースにオブジェクトを追加、変更、作成することはできません。共有データベース、そのスキーマ、テーブルのクローンはできません。共有データで Time Travel を使用することもできません。</p><p>https://docs.snowflake.com/en/user-guide/data-share-consumers#general-limitations-for-shared-databases</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 123, "title": "真偽問題：Snowflake はマイクロパーティション内のカラムを圧縮するための最も効率的なアル...", "multiSelect": false, "stemHtml": "<p>真偽問題：Snowflake はマイクロパーティション内のカラムを圧縮するための最も効率的なアルゴリズムを自動的に決定します。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>Snowflake は各マイクロパーティション内でカラムをカラム形式で保存します。各マイクロパーティション内の各カラムは独立して圧縮されます。Snowflake は各カラムに対して最適な圧縮アルゴリズムを選択します。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 124, "title": "Snowflake から AWS S3 の場所にデータをアンロードする際に必要な S3 権限はど...", "multiSelect": true, "stemHtml": "<p>Snowflake から AWS S3 の場所にデータをアンロードする際に必要な S3 権限はどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "s3:PutObject"}, {"key": "B", "label": "s3:DeleteObject"}, {"key": "C", "label": "s3:GetObject"}, {"key": "D", "label": "s3:ListBucket"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>s3:PutObject / s3:DeleteObject</strong></p><p>Snowflake はターゲット S3 バケットに対して s3:DeleteObject と s3:PutObject 権限が必要です。</p><p>https://docs.snowflake.com/en/user-guide/data-unload-s3#configuring-an-s3-bucket-for-unloading-data</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 125, "title": "パーティションプルーニングが発生したかどうかを示す統計情報はどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>パーティションプルーニングが発生したかどうかを示す統計情報はどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "パーティション合計"}, {"key": "B", "label": "スキャンされたバイト数"}, {"key": "C", "label": "書き込まれたバイト数"}, {"key": "D", "label": "スキャンされたパーティション数"}, {"key": "E", "label": "総バイト数"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>パーティション合計 / スキャンされたパーティション数</strong></p><p>パーティションプルーニングは、スキャンされたパーティション数がパーティション合計より大幅に少ない場合に発生します。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 126, "title": "リソースモニターで追跡・管理できるのはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>リソースモニターで追跡・管理できるのはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "アカウント全体"}, {"key": "B", "label": "仮想ウェアハウスのグループ"}, {"key": "C", "label": "単一の仮想ウェアハウス"}, {"key": "D", "label": "単一の Snowpipe"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>アカウント全体 / 仮想ウェアハウスのグループ / 単一の仮想ウェアハウス</strong></p><p>リソースモニターは単一の仮想ウェアハウスまたは複数の仮想ウェアハウスを一緒に追跡・管理できます。また、アカウントレベルのリソースモニターも作成でき、すべての仮想ウェアハウスのクレジット使用量をアカウントレベルで追跡します。リソースモニターは Snowpipe やその他のサーバーレス機能のコストを管理できません。</p><p>https://docs.snowflake.com/en/user-guide/resource-monitors#assignment-of-resource-monitors</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 127, "title": "真偽問題：テーブルのクラスタリングキーが変更されると、サーバーレスコストが発生する可能性がありま...", "multiSelect": false, "stemHtml": "<p>真偽問題：テーブルのクラスタリングキーが変更されると、サーバーレスコストが発生する可能性があります。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>クラスタリングキーが定義されたテーブルに対して、自動クラスタリングが必要に応じてマイクロパーティションを再クラスタリングします。自動クラスタリングは仮想ウェアハウスを必要とせず、Snowflake が管理する CPU、RAM などを使用するため、サーバーレスコストとして表示されるコストが発生します。クラスタリングにより新しいマイクロパーティションが作成される際に追加のストレージも発生します。</p><p>https://docs.snowflake.com/en/user-guide/tables-auto-reclustering#credit-usage-and-warehouses-for-automatic-clustering</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 128, "title": "リソースモニターによって仮想ウェアハウスがサスペンドされた後、仮想ウェアハウスを再開できるのはど...", "multiSelect": true, "stemHtml": "<p>リソースモニターによって仮想ウェアハウスがサスペンドされた後、仮想ウェアハウスを再開できるのはどのような場合ですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "リソースモニターの次のインターバルが開始される"}, {"key": "B", "label": "アカウント管理者が仮想ウェアハウスを再開する"}, {"key": "C", "label": "サスペンドアクションのクレジットしきい値が増加される"}, {"key": "D", "label": "SnowSQL を使用して仮想ウェアハウスを再開する"}, {"key": "E", "label": "モニターのクレジットクォータが増加される"}], "correctAnswers": ["A", "C", "E"], "explanationHtml": "<p>✅ <strong>リソースモニターの次のインターバルが開始される / サスペンドアクションのクレジットしきい値が増加される / モニターのクレジットクォータが増加される</strong></p><p>モニターにサスペンドまたは即時サスペンドのアクションがあり、使用クレジットがアクションのしきい値に達すると、モニターに割り当てられたウェアハウスは保留状態になり、次のいずれかが発生するまで使用できません：次のインターバルが開始される、モニターのクレジットクォータが増加される、サスペンドに必要なクレジットしきい値が増加される、仮想ウェアハウスがモニター設定から削除される（アカウントレベルモニターには適用されない）、またはモニターが完全にドロップされる。</p><p>https://docs.snowflake.com/en/user-guide/resource-monitors</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}]}, {"slug": "04_practice_exam", "title": "SnowPro Core 04_practice_exam", "sourcePath": "01_資格/Snowflake/SnowPro_Core/問題/04_practice_exam.md", "metadata": ["問題数: 127問"], "questionCount": 127, "questions": [{"order": 1, "title": "一時テーブルのタイムトラベルの最大期間はどれですか？", "multiSelect": false, "stemHtml": "<p>一時テーブルのタイムトラベルの最大期間はどれですか？</p>", "options": [{"key": "A", "label": "21日"}, {"key": "B", "label": "1日"}, {"key": "C", "label": "14日"}, {"key": "D", "label": "7日"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>1日</strong></p><p>SnowflakeのトランジェントテーブルおよびTemporaryテーブルは、使用するSnowflakeエディションに関係なく、最大1日のタイムトラベルをサポートします。 https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 2, "title": "ストアドプロシージャが呼び出し元の権限（caller's rights）ストアドプロシージャとし...", "multiSelect": false, "stemHtml": "<p>ストアドプロシージャが呼び出し元の権限（caller&#x27;s rights）ストアドプロシージャとして設定されています。ビジネスユーザーがそのストアドプロシージャを実行しました。次のどの記述がこの場合の動作を正しく説明していますか？</p>", "options": [{"key": "A", "label": "ストアドプロシージャは、実行するユーザーの権限で実行されます。"}, {"key": "B", "label": "ストアドプロシージャはACCOUNTADMINの権限で実行されます。"}, {"key": "C", "label": "ストアドプロシージャはPUBLICロールの権限で実行されます。"}, {"key": "D", "label": "ストアドプロシージャはそのストアドプロシージャを所有するロールの権限で実行されます。"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>ストアドプロシージャは、実行するユーザーの権限で実行されます。</strong></p><p>呼び出し元の権限（caller&#x27;s rights）で実行するよう設定されたストアドプロシージャは、呼び出しユーザーの権限の下で実行されます。 https://docs.snowflake.com/en/sql-reference/stored-procedures-rights</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 3, "title": "新しいSnowflakeアカウントを作成する際に選択できるのは次のどれですか？（該当するものをす...", "multiSelect": true, "stemHtml": "<p>新しいSnowflakeアカウントを作成する際に選択できるのは次のどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "管理者ユーザーの詳細"}, {"key": "B", "label": "アカウントロケーター"}, {"key": "C", "label": "Snowflakeエディション"}, {"key": "D", "label": "リージョン"}, {"key": "E", "label": "アカウント名"}, {"key": "F", "label": "組織名"}], "correctAnswers": ["A", "C", "D", "E"], "explanationHtml": "<p>✅ <strong>管理者ユーザーの詳細 / Snowflakeエディション / リージョン / アカウント名</strong></p><p>CREATE ACCOUNT文を使用すると、アカウント名、Snowflakeエディション、リージョン（クラウドプラットフォーム情報を含む）、リージョングループ、および名前、パスワード、メールなどの管理ユーザーの詳細を指定できます。</p><p>https://docs.snowflake.com/en/sql-reference/sql/create-account</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 4, "title": "ACCOUNTADMIN以外のユーザーがシェアを作成するために必要な権限は何ですか？", "multiSelect": false, "stemHtml": "<p>ACCOUNTADMIN以外のユーザーがシェアを作成するために必要な権限は何ですか？</p>", "options": [{"key": "A", "label": "SECURITYの権限"}, {"key": "B", "label": "CREATE SHAREの権限"}, {"key": "C", "label": "CREATE ACCOUNTの権限"}, {"key": "D", "label": "MANAGE ACCOUNTの権限"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>CREATE SHAREの権限</strong></p><p>ACCOUNTADMINロールまたはCREATE SHARE権限が明示的に付与されたロールのみがシェアを作成できます。 https://docs.snowflake.com/en/user-guide/data-sharing-gs</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 5, "title": "このコースの練習問題が実際の認定試験の問題と同一でないのはなぜですか？", "multiSelect": false, "stemHtml": "<p>このコースの練習問題が実際の認定試験の問題と同一でないのはなぜですか？</p>", "options": [{"key": "A", "label": "無関係なトピックで受講者を挑戦させ、意図的に混乱させるため。"}, {"key": "B", "label": "コース作成者が実際の試験問題を知らないため。"}, {"key": "C", "label": "特定の問題の丸暗記に頼るのではなく、概念の知識と理解をテストするため。"}, {"key": "D", "label": "受講者が正確な問題と答えを丸暗記できるようにするため。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>特定の問題の丸暗記に頼るのではなく、概念の知識と理解をテストするため。</strong></p><p>このコースは、認定試験に必要なコンセプトとトピックを徹底的に理解するためのものです。練習問題は、実際の試験の問題を完全に再現するのではなく、知識をテストし、理解を深めるために作成されています。</p><p>これらの問題は試験の目標に沿っていますが、認定試験の問題とは同一ではありません。目的は、回答を丸暗記するのではなく、基礎となるコンセプトをマスターすることで、どんな問題にも自信を持って取り組めるよう準備することです。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "（なし）", "originalCorrect": null, "reviewPoint": ""}}, {"order": 6, "title": "マテリアライズドビューの維持コストに影響する要因は次のどれですか？（2つ選択してください）", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューの維持コストに影響する要因は次のどれですか？（2つ選択してください）</p>", "options": [{"key": "A", "label": "ベーステーブル内のデータの総量。"}, {"key": "B", "label": "ベーステーブルへの更新が発生したときにマテリアライズドビューで変更されるデータの量。"}, {"key": "C", "label": "マテリアライズドビューの定義で使用されたクエリの結果を保存するために必要なストレージ。"}, {"key": "D", "label": "ベーステーブルの列数。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>ベーステーブルへの更新が発生したときにマテリアライズドビューで変更されるデータの量 / マテリアライズドビューの定義で使用されたクエリの結果を保存するために必要なストレージ</strong></p><p>マテリアライズドビューのデータ維持コストは以下の要因によって影響されます：</p><p>1) 各ベーステーブルに作成されたマテリアライズドビューの数。</p><p>2) ベーステーブルへの変更時にこれらのマテリアライズドビューで発生するデータ変更の範囲。</p><p>3) クラスタリングキーが定義されたマテリアライズドビューの数。</p><p>各マテリアライズドビューはクエリの結果を保存するため、毎月のアカウントのストレージ使用量が増加します。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized#label-materialized-views-maintenance-billing</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 7, "title": "真か偽：Snowflakeのお客様はタイムトラベルSQLの拡張機能を使用してフェイルセーフストレ...", "multiSelect": false, "stemHtml": "<p>真か偽：Snowflakeのお客様はタイムトラベルSQLの拡張機能を使用してフェイルセーフストレージからデータを取得できます。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>偽</strong></p><p>データがフェイルセーフストレージに入ると、Snowflakeサポートのみがデータの取得を支援できます。お客様はフェイルセーフストレージにアクセスできません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 8, "title": "真か偽：クラスタリングキーの定義で式を使用して、列のカーディナリティを下げることができます。", "multiSelect": false, "stemHtml": "<p>真か偽：クラスタリングキーの定義で式を使用して、列のカーディナリティを下げることができます。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>クラスタリングキーに高カーディナリティの列を使用する必要がある場合、キーを式として定義することで、異なる値の数を減らしてカーディナリティを下げることができます。たとえば、クラスタリングキーに使用したいタイムスタンプ列がある場合、タイムスタンプを日付に変換してカーディナリティを下げることができます。このアプローチはパーティションプルーニングの改善に役立ちます。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-keys#strategies-for-selecting-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 9, "title": "Snowflakeがクラスタリングの深さに関する情報を取得するために提供している2つのシステム関...", "multiSelect": true, "stemHtml": "<p>Snowflakeがクラスタリングの深さに関する情報を取得するために提供している2つのシステム関数はどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "SYSTEM$CLUSTERING_DEPTH"}, {"key": "B", "label": "SYSTEM$AVERAGE_DEPTH"}, {"key": "C", "label": "SYSTEM$CLUSTERING_HISTORY"}, {"key": "D", "label": "SYSTEM$CLUSTERING_INFORMATION"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>SYSTEM$CLUSTERING_DEPTH / SYSTEM$CLUSTERING_INFORMATION</strong></p><p>Snowflakeはクラスタリング情報を調べるために使用できる2つのシステム関数を提供しています。2つの関数はSYSTEM$CLUSTERING_DEPTHとSYSTEM$CLUSTERING_INFORMATIONです。 https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions#clustering-depth</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 10, "title": "Snowflakeでの仮想ウェアハウスのスケールアップを最もよく説明する記述はどれですか？（該当...", "multiSelect": true, "stemHtml": "<p>Snowflakeでの仮想ウェアハウスのスケールアップを最もよく説明する記述はどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "スケールアップ時には仮想ウェアハウスに追加のコンピューティングリソースが追加されます。"}, {"key": "B", "label": "スケールアップ時には、仮想ウェアハウスのサイズが大きなサイズに増加されます。"}, {"key": "C", "label": "スケールアップとは、クエリ処理効率の向上により仮想ウェアハウスのサイズを縮小することを意味します。"}, {"key": "D", "label": "一般的に、スケールアップはより複雑なワークロードに対応するために実施されます。"}], "correctAnswers": ["A", "B", "D"], "explanationHtml": "<p>✅ <strong>スケールアップ時には仮想ウェアハウスに追加のコンピューティングリソースが追加されます / スケールアップ時には仮想ウェアハウスのサイズが大きなサイズに増加されます / 一般的にスケールアップはより複雑なワークロードに対応するために実施されます</strong></p><p>変化するワークロードに合わせて仮想ウェアハウスをリサイズすることが可能です。クエリの複雑さの増大に対応するために、当初スモールサイズで始めた仮想ウェアハウスをスケールアップできます。仮想ウェアハウスをスケールアップすると、コンピュートクラスターにさらにノードが追加されます。 https://docs.snowflake.com/en/user-guide/warehouses-tasks</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 11, "title": "あなたは別のSnowflakeアカウントとテーブルを共有しました。コンシューマーアカウントのユー...", "multiSelect": false, "stemHtml": "<p>あなたは別のSnowflakeアカウントとテーブルを共有しました。コンシューマーアカウントのユーザーが共有テーブルに対してクエリを実行しました。クエリコストはどちらに請求されますか？</p>", "options": [{"key": "A", "label": "データコンシューマー"}, {"key": "B", "label": "データプロバイダー（データを共有したアカウント）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>データコンシューマー</strong></p><p>データ共有シナリオでは、Snowflakeはコンシューマーアカウントが使用するコンピューティングコストをコンシューマーアカウントに請求します。 https://docs.Snowflake.net/manuals/user-guide/data-sharing-intro.html#how-does-secure-data-sharing-work</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 12, "title": "完了したクエリのクエリプロファイルの次のスニペットを考えてください。ハイライトされた統計を正確に...", "multiSelect": true, "stemHtml": "<p>完了したクエリのクエリプロファイルの次のスニペットを考えてください。ハイライトされた統計を正確に説明しているのはどれですか？</p>", "options": [{"key": "A", "label": "クエリプロファイルは非効果的なパーティションプルーニングを示しています。"}, {"key": "B", "label": "クエリプロファイルは効果的なパーティションプルーニングを示しています。"}, {"key": "C", "label": "クエリプロファイルは仮想ウェアハウスキャッシュが使用されたことを示しています。"}, {"key": "D", "label": "クエリプロファイルはクエリに対して使用された仮想ウェアハウスが小さすぎることを示しています。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>クエリプロファイルは効果的なパーティションプルーニングを示しています / クエリプロファイルは仮想ウェアハウスキャッシュが使用されたことを示しています</strong></p><p>パーティションプルーニングは、スキャンされたパーティション数が合計パーティション数よりもはるかに少ない場合に発生します。Snowflakeは、操作をメモリに収めることができない場合、ウェアハウスのローカルディスクおよびリモートクラウドストレージにデータを保存します。データのスピルはより多くのIO操作を必要とし、ディスクアクセスはメモリアクセスより遅いため、クエリが遅くなります。各仮想ウェアハウスは、クラウドストレージから関連するマイクロパーティションをローカルSSDストレージに定期的にコピーしてキャッシュを構築します。仮想ウェアハウスのキャッシュには、類似した条件、列、行を持つ複数のクエリのデータが含まれている場合があります。仮想ウェアハウスはクラウドストレージの代わりにローカルキャッシュからデータを取得でき、クエリを高速化します。 https://docs.snowflake.com/en/user-guide/ui-query-profile</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 13, "title": "次のどのテーブルタイプがタイムトラベルクエリを許可しますか？", "multiSelect": true, "stemHtml": "<p>次のどのテーブルタイプがタイムトラベルクエリを許可しますか？</p>", "options": [{"key": "A", "label": "永続テーブル（Permanent Tables）"}, {"key": "B", "label": "トランジェントテーブル（Transient Tables）"}, {"key": "C", "label": "一時テーブル（Temporary Tables）"}, {"key": "D", "label": "ビューベーステーブル"}, {"key": "E", "label": "外部テーブル"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>永続テーブル / トランジェントテーブル / 一時テーブル</strong></p><p>トランジェントテーブルと一時テーブルにはフェイルセーフ機能がなく、そのためこれらのテーブルのデータは0日間のフェイルセーフストレージを経由します。ただし、トランジェントテーブルと一時テーブルには最大1日のタイムトラベルがあります。</p><p>永続テーブルもタイムトラベル機能を持ち、設定に応じて最大90日のタイムトラベルが可能です。</p><p>https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 14, "title": "Snowflakeのデフォルトロールに関して正しい記述はどれですか？（該当するものをすべて選択し...", "multiSelect": true, "stemHtml": "<p>Snowflakeのデフォルトロールに関して正しい記述はどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "ユーザーは必要に応じて現在のロールを切り替えることができます。"}, {"key": "B", "label": "ユーザーがセッション中に別のロールに切り替えると、ユーザーのデフォルトロールが自動的に新しいロールに再設定されます。"}, {"key": "C", "label": "ユーザーがログインすると、ロールは自動的にデフォルトロールに設定されます。"}, {"key": "D", "label": "ユーザーはデフォルトロール以外のロールを使用できません。"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>ユーザーは必要に応じて現在のロールを切り替えることができます / ユーザーがログインするとロールは自動的にデフォルトロールに設定されます</strong></p><p>各Snowflakeユーザーには自動的にPUBLICロールが割り当てられます。各ユーザーには追加のロールを割り当てることができ、そのうちの1つをデフォルトロールとして設定できます。ユーザーのデフォルトロールは、ユーザーが開始するSnowflakeセッションで自動的に使用されるロールを決定しますが、これはデフォルトにすぎません。ユーザーはセッション中いつでもロールを切り替えることができます。</p><p>https://docs.snowflake.com/en/user-guide/admin-user-management#user-roles</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 15, "title": "あなたはSnowflakeデータウェアハウスを持つ大手航空会社のパフォーマンスDBAです。大型テ...", "multiSelect": false, "stemHtml": "<p>あなたはSnowflakeデータウェアハウスを持つ大手航空会社のパフォーマンスDBAです。大型テーブル（5TB超）には飛行機センサーのテレメトリデータが含まれています。</p>", "options": [{"key": "A", "label": "何もしない。Snowflakeは自動的にクエリの効率を確保します。"}, {"key": "B", "label": "2つの列の組み合わせにクラスタキーを導入する。例：CLUSTER BY(event_date,airplane_id)"}, {"key": "C", "label": "2つの列を連結して新しい列を生成し、その列でテーブルをクラスター化する。"}, {"key": "D", "label": "クエリが高速に実行されるよう仮想ウェアハウスのサイズを大きくする。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>CLUSTER BY(event_date,airplane_id)</strong></p><p>特定の列でテーブルをクラスター化することで、クエリ処理から不要なパーティションを排除してクエリを最適化できます。テーブルはクラスタリングキーを定義することで再クラスター化でき、クラスタリングキーに従ってデータをマイクロパーティションに再分配して、クラスター化された列に基づくクエリへの最適なアクセスを確保します。event_dateとairplane_idの両方の列にクラスタキーを導入することで、どちらの列でもアクセスするための最適なパーティショニングスキームを作成します。 https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 16, "title": "クエリ結果キャッシュに関する正しい記述はどれですか？（該当するものをすべて選択してください）", "multiSelect": true, "stemHtml": "<p>クエリ結果キャッシュに関する正しい記述はどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "クエリ結果キャッシュは仮想ウェアハウスのSSDストレージに保存されます。"}, {"key": "B", "label": "クエリ結果キャッシュを保持できる最大日数は31日です。"}, {"key": "C", "label": "元のクエリから24時間以内に同一のクエリが実行された場合、クエリ結果キャッシュが使用されます。"}, {"key": "D", "label": "クラウドサービス層がクエリ結果キャッシュを保存します。"}, {"key": "E", "label": "クエリ結果キャッシュが24時間以内に再利用されない場合、削除されます。"}], "correctAnswers": ["B", "C", "D", "E"], "explanationHtml": "<p>✅ <strong>クエリ結果キャッシュを保持できる最大日数は31日です / 元のクエリから24時間以内に同一のクエリが実行された場合クエリ結果キャッシュが使用されます / クラウドサービス層がクエリ結果キャッシュを保存します / クエリ結果キャッシュが24時間以内に再利用されない場合削除されます</strong></p><p>クエリ結果キャッシュは24時間有効です。その24時間以内に前のクエリと一致する新しいクエリが実行されると、結果はクエリ結果キャッシュから取得されます。クエリ結果キャッシュはクラウドサービス層に維持され、任意のユーザーがクエリ結果を返すために使用できます。クエリの結果キャッシュは最初は24時間有効ですが、新しいクエリがそれを使用すると24時間延長されます。この延長は削除される前の最大31日間続きます。クエリ結果キャッシュが24時間使用されない場合は削除されます。 https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 17, "title": "次のオブジェクトのうち、共有できるものはどれですか？（該当するものをすべて選択してください）", "multiSelect": true, "stemHtml": "<p>次のオブジェクトのうち、共有できるものはどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "マテリアライズドビュー"}, {"key": "B", "label": "セキュアビュー"}, {"key": "C", "label": "テーブル"}, {"key": "D", "label": "セキュアUDF"}, {"key": "E", "label": "セキュアマテリアライズドビュー"}, {"key": "F", "label": "ビュー"}], "correctAnswers": ["B", "C", "D", "E"], "explanationHtml": "<p>✅ <strong>セキュアビュー / テーブル / セキュアUDF / セキュアマテリアライズドビュー</strong></p><p>標準ビューは共有できません。ダイレクトデータ共有では次のタイプのオブジェクトを共有できます：テーブル、外部テーブル、セキュアビュー、セキュアマテリアライズドビュー、セキュアUDF。 https://docs.snowflake.com/en/user-guide/data-sharing-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 18, "title": "テーブルUDFはどのタイプの結果を返しますか？（該当するものをすべて選択してください）", "multiSelect": true, "stemHtml": "<p>テーブルUDFはどのタイプの結果を返しますか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "各入力に対して0行を返すことができます。"}, {"key": "B", "label": "各入力に対して単一列を含む複数行を返すことができます。"}, {"key": "C", "label": "各入力に対して単一列を含む1行を返すことができます。"}, {"key": "D", "label": "各入力に対して複数列を含む複数行を返すことができます。"}, {"key": "E", "label": "各入力に対して複数列を含む1行を返すことができます。"}], "correctAnswers": ["A", "B", "C", "D", "E"], "explanationHtml": "<p>✅ <strong>0行 / 単一列を含む複数行 / 単一列を含む1行 / 複数列を含む複数行 / 複数列を含む1行</strong></p><p>これらはすべて有効な回答です。テーブルUDFは各入力に対してゼロ、1つ、または複数の行を返すことができ、各結果行には1つまたは複数の列が含まれます。UDTFはユーザー定義テーブル関数の別名です。このような関数の例としてFLATTENがあり、単一入力に対して複数の行と列を返します。 https://docs.snowflake.com/en/sql-reference/udf-overview#scalar-and-tabular-functions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 19, "title": "セキュリティインシデント調査の一環として、過去1年間にSnowflakeにログインしたユーザーの...", "multiSelect": false, "stemHtml": "<p>セキュリティインシデント調査の一環として、過去1年間にSnowflakeにログインしたユーザーの履歴を抽出する必要があります。次のどの方法を使用すべきですか？</p>", "options": [{"key": "A", "label": "SNOWFLAKE.ACCOUNT_USAGE.LOGIN_HISTORYビューをクエリする。"}, {"key": "B", "label": "Snowflakeサポートにこれらの詳細を提供するよう依頼する。"}, {"key": "C", "label": "テーブル関数INFORMATION_SCHEMA.LOGIN_HISTORY()を使用する。"}, {"key": "D", "label": "テーブル関数INFORMATION_SCHEMA.LOGIN_HISTORY_BY_USER()を使用する。"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>SNOWFLAKE.ACCOUNT_USAGE.LOGIN_HISTORYビューをクエリする</strong></p><p>ACCOUNT_USAGEスキーマのビューは最大365日間の履歴を提供します。そのため、長い期間のデータが必要なシナリオに役立ちます。ACCOUNT_USAGEスキーマのLOGIN_HISTORYビューは要件を満たします。注意：ACCOUNT_USAGEビューはリアルタイムではなく、最大3時間の遅延が生じる場合があります。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 20, "title": "アドホッククエリを実行するためのミディアムサイズの仮想ウェアハウスがあります。ピーク時に多数のク...", "multiSelect": false, "stemHtml": "<p>アドホッククエリを実行するためのミディアムサイズの仮想ウェアハウスがあります。ピーク時に多数のクエリが同時に実行されるため、クエリがキューに入り始めます。キューイングを減らす最善の方法は何ですか？</p>", "options": [{"key": "A", "label": "ユーザーに1日を通してクエリを分散するよう依頼する。"}, {"key": "B", "label": "複数のミディアムサイズの仮想ウェアハウスを作成し、ユーザーを別々の仮想ウェアハウスに誘導する。"}, {"key": "C", "label": "実行時間の長いクエリをすべて強制終了する。"}, {"key": "D", "label": "仮想ウェアハウスをマルチクラスター仮想ウェアハウスに設定する。仮想ウェアハウスはクエリの需要に応じてスケールアウト・スケールインします。"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>仮想ウェアハウスをマルチクラスター仮想ウェアハウスに設定する</strong></p><p>マルチクラスター仮想ウェアハウスは、同時クエリ数が単一の仮想ウェアハウスの容量を超えるシナリオで頻繁に使用されます。仮想ウェアハウスの同時ワークロードがその最大容量を超えると、追加のクエリがキューに入れられます。マルチクラスター仮想ウェアハウスは需要に基づいて動的に追加クラスターを追加し、キューイングの問題を解決します。需要が低下すると、追加クラスターは廃止されます。このプロセスはスケールアウトまたはオートスケーリングとも呼ばれます。 https://docs.snowflake.com/en/user-guide/warehouses-multicluster</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 21, "title": "Partner Connectを使用してパートナーの新しいトライアルアカウントを作成した場合、次...", "multiSelect": true, "stemHtml": "<p>Partner Connectを使用してパートナーの新しいトライアルアカウントを作成した場合、次のどの記述が正しいですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "新しいユーザーが作成されます。"}, {"key": "B", "label": "データ共有が無効になります。"}, {"key": "C", "label": "新しい空のデータベースが作成されます。"}, {"key": "D", "label": "仮想ウェアハウスが作成されます。"}, {"key": "E", "label": "新しいリーダーアカウントが作成されます。"}, {"key": "F", "label": "新しいカスタムロールが作成されます。"}], "correctAnswers": ["A", "C", "D", "F"], "explanationHtml": "<p>✅ <strong>新しいユーザーが作成されます / 新しい空のデータベースが作成されます / 仮想ウェアハウスが作成されます / 新しいカスタムロールが作成されます</strong></p><p>パートナーアプリケーションに接続する際、Snowflakeは空のデータベース、仮想ウェアハウス、デフォルトユーザー、カスタムロールなどのいくつかのオブジェクトを自動的に作成します。パートナーアプリがアカウントに対して読み書きする場合は、これらのオブジェクトを使用します。</p><p>https://docs.snowflake.com/en/user-guide/ecosystem-partner-connect#connecting-with-a-snowflake-partner</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パートナー", "originalCorrect": null, "reviewPoint": ""}}, {"order": 22, "title": "Snowflakeのリーダーアカウントを最もよく説明する記述はどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeのリーダーアカウントを最もよく説明する記述はどれですか？</p>", "options": [{"key": "A", "label": "リーダーアカウントは読み取り専用データロード操作に使用されます。"}, {"key": "B", "label": "リーダーアカウントはSnowflake以外のユーザー（または組織）とデータを共有するために使用されます。"}, {"key": "C", "label": "リーダーアカウントはSnowflakeのアクセス制御の方法です。"}, {"key": "D", "label": "リーダーアカウントはさまざまなクラウドプロバイダー間でデータを同期するために使用されます。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>リーダーアカウントはSnowflake以外のユーザー（または組織）とデータを共有するために使用されます</strong></p><p>Snowflakeでは、Snowflake以外のユーザー（または組織）とデータを共有するために、そのユーザー（または組織）のリーダーアカウントを作成することができます。このリーダーアカウントはデータプロバイダーによって作成・管理されます。 https://docs.snowflake.com/en/user-guide/data-sharing-reader-create</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 23, "title": "マイクロパーティションは小さいサイズで、（圧縮前は）一般的に___のサイズです。", "multiSelect": false, "stemHtml": "<p>マイクロパーティションは小さいサイズで、（圧縮前は）一般的に___のサイズです。</p>", "options": [{"key": "A", "label": "50-500 MB"}, {"key": "B", "label": "500MB-1GB"}, {"key": "C", "label": "10-50MB"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>50-500 MB</strong></p><p>マイクロパーティションは小さく、通常は50 MBから500 MBの非圧縮データを格納します。 https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 24, "title": "短命のテーブルのコスト管理に使用できるSnowflakeテーブルタイプはどれですか？（2つ選択し...", "multiSelect": true, "stemHtml": "<p>短命のテーブルのコスト管理に使用できるSnowflakeテーブルタイプはどれですか？（2つ選択してください）</p>", "options": [{"key": "A", "label": "外部テーブル"}, {"key": "B", "label": "一時テーブル（Temporary）"}, {"key": "C", "label": "トランジェントテーブル（Transient）"}, {"key": "D", "label": "集計テーブル"}, {"key": "E", "label": "永続テーブル（Permanent）"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>一時テーブル / トランジェントテーブル</strong></p><p>トランジェントテーブルと一時テーブルは短命のデータに適したオプションです。フェイルセーフストレージがなく、タイムトラベルは最大1日のみです。</p><p>https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake's catalog and objects", "originalCorrect": null, "reviewPoint": ""}}, {"order": 25, "title": "Snowflakeシステムのコストに貢献するのは次のどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflakeシステムのコストに貢献するのは次のどれですか？</p>", "options": [{"key": "A", "label": "ストレージ層"}, {"key": "B", "label": "クラウドサービス層"}, {"key": "C", "label": "クエリ数"}, {"key": "D", "label": "クエリ処理層"}], "correctAnswers": ["A", "B", "D"], "explanationHtml": "<p>✅ <strong>ストレージ層 / クラウドサービス層 / クエリ処理層</strong></p><p>クエリ処理層、ストレージ層、クラウドサービス層はすべてSnowflakeシステムのコストに貢献します。 https://docs.snowflake.com/en/user-guide/cost-understanding-overall</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "コストと価格", "originalCorrect": null, "reviewPoint": ""}}, {"order": 26, "title": "データベースまたはスキーマがクローンされるとき、次のどのオブジェクトはクローンされませんか？", "multiSelect": true, "stemHtml": "<p>データベースまたはスキーマがクローンされるとき、次のどのオブジェクトはクローンされませんか？</p>", "options": [{"key": "A", "label": "永続テーブル"}, {"key": "B", "label": "外部テーブル"}, {"key": "C", "label": "名前付き内部Snowflakeステージを指すSnowpipe"}, {"key": "D", "label": "トランジェントテーブル"}, {"key": "E", "label": "内部Snowflakeステージ"}], "correctAnswers": ["B", "C", "E"], "explanationHtml": "<p>✅ <strong>外部テーブル / 名前付き内部Snowflakeステージを指すSnowpipe / 内部Snowflakeステージ</strong></p><p>外部テーブルのクローニングはサポートされていません。外部テーブルのデータはSnowflakeの外部にあるため、外部テーブルのクローニングは機能しません。</p><p>名前付き内部ステージはクローニングによりサポートされていません。</p><p>データベースまたはスキーマがクローンされるとき、名前付き内部ステージを指すSnowpipeはクローンされません。</p><p>https://docs.snowflake.com/en/user-guide/object-clone</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 27, "title": "Snowflakeの多要素認証（MFA）機能を最もよく説明する記述はどれですか？（該当するものを...", "multiSelect": true, "stemHtml": "<p>Snowflakeの多要素認証（MFA）機能を最もよく説明する記述はどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "管理者はユーザーのMFAをオフにすることができます。"}, {"key": "B", "label": "多要素認証（MFA）はすべてのユーザーに対してデフォルトで有効になっていますが、ユーザーは手動でMFAに登録する必要があります。"}, {"key": "C", "label": "SnowflakeのWebインターフェースとSnowSQLのみが多要素認証を許可します。"}, {"key": "D", "label": "SnowSQL、Snowflake ODBC、JDBC、PythonコネクターはすべてMFA対応です。"}], "correctAnswers": ["A", "B", "D"], "explanationHtml": "<p>✅ <strong>管理者はユーザーのMFAをオフにすることができます / MFAはすべてのユーザーにデフォルトで有効 / SnowSQL・ODBC・JDBC・Pythonコネクターがすべてに対応</strong></p><p>多要素認証（MFA）はすべてのSnowflakeアカウントでデフォルトで有効になっており、Snowflakeユーザーは誰でもSnowflake Webインターフェースを通じてMFAに登録できます。管理者はユーザーのMFA登録を無効にすることができます。その場合、ユーザーはMFA機能にアクセスするために再登録する必要があります。SECURITYADMINまたはそれ以上のロールを持つ管理者がユーザーのMFAを無効にできます。WebインターフェースやSnowSQLを含むすべてのSnowflakeクライアントツール、およびさまざまなコネクターとドライバーがMFAをサポートしています。 https://docs.snowflake.com/en/user-guide/security-mfa</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 28, "title": "カーディナリティ（個別値の数）の観点から、クラスタリングキーに追加することを検討すべき列はどれで...", "multiSelect": true, "stemHtml": "<p>カーディナリティ（個別値の数）の観点から、クラスタリングキーに追加することを検討すべき列はどれですか？</p>", "options": [{"key": "A", "label": "クラスタリングキーを定義する際、列のカーディナリティは関係ありません。"}, {"key": "B", "label": "マイクロパーティションでの効率的なグループ化を可能にするほど小さな個別値を持つ列。"}, {"key": "C", "label": "低カーディナリティの列のみ。"}, {"key": "D", "label": "効率的なパーティションプルーニングを可能にするほど大きな個別値を持つ列。"}, {"key": "E", "label": "高カーディナリティの列のみ。"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>マイクロパーティションでの効率的なグループ化を可能にするほど小さな個別値を持つ列 / 効率的なパーティションプルーニングを可能にするほど大きな個別値を持つ列</strong></p><p>クラスタリングキーを定義する際、最初の候補クラスタリング列はWHERE句やその他の選択的フィルターで頻繁に使用される列です。さらに、結合に使用される列も考慮できます。また、列のカーディナリティ（個別値の数）も重要です。効果的なパーティションプルーニングを可能にするほど高いカーディナリティを持ちながら、Snowflakeがデータをマイクロパーティションに効率的にグループ化できるほど低いカーディナリティを持つ列を選択することが重要です。個別値が少なすぎる列（例：性別）は最小限のパーティションプルーニングしか行えません。一方、個別値が多すぎる列（例：顧客ID）はパーティションの維持に過大なオーバーヘッドをもたらします。複数列のクラスタキーを作成する場合は、カーディナリティの低い順に列を並べてください。さもないとクラスタリングの効果が低下します。 https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 29, "title": "真か偽：Snowflakeクレジットは秒単位で請求されます。", "multiSelect": false, "stemHtml": "<p>真か偽：Snowflakeクレジットは秒単位で請求されます。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>Snowflakeクレジットは秒単位の使用量に基づいて請求されます。つまり、仮想ウェアハウスが1分45秒稼働した場合は105秒（60+45）分が請求されます。ただし、最低60秒の請求が適用されるため、仮想ウェアハウスが最初の1分以内に起動・停止した場合でも、最低60秒のクレジット使用が適用されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 30, "title": "クエリキューイングを最小化することを目的とするスケーリングポリシーはどれですか？", "multiSelect": false, "stemHtml": "<p>クエリキューイングを最小化することを目的とするスケーリングポリシーはどれですか？</p>", "options": [{"key": "A", "label": "Standard"}, {"key": "B", "label": "Economy"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>スケーリングポリシーをStandardに設定すると、Snowflakeはクエリがキューに入り始めたことを検出するとほぼすぐに追加の仮想ウェアハウスを起動しようとします。Standardスケーリングポリシーはキューイングを防ぐまたは最小化することを目的としています。Economyスケーリングポリシーはパフォーマンスとユーザーエクスペリエンスよりもクレジットの節約を優先します。キューイングが観察されるとすぐに追加の仮想ウェアハウスを起動するのではなく、追加の基準を適用して新しい仮想ウェアハウスを起動するかどうかを判断します。 https://docs.snowflake.com/en/user-guide/warehouses-multicluster#setting-the-scaling-policy-for-a-multi-cluster-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 31, "title": "次のどのオブジェクトはクローニング操作をサポートしませんか？", "multiSelect": true, "stemHtml": "<p>次のどのオブジェクトはクローニング操作をサポートしませんか？</p>", "options": [{"key": "A", "label": "トランジェントテーブル"}, {"key": "B", "label": "名前付き内部ステージ"}, {"key": "C", "label": "永続テーブル"}, {"key": "D", "label": "シェアから作成されたデータベース"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>名前付き内部ステージ / シェアから作成されたデータベース</strong></p><p>シェアオブジェクトから作成されたデータベースはクローンできません。</p><p>名前付き内部Snowflakeステージもクローニングによってサポートされていません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 32, "title": "テーブルからデータを複数のファイルにアンロードしています。各ファイルの最大サイズを制御できるCO...", "multiSelect": false, "stemHtml": "<p>テーブルからデータを複数のファイルにアンロードしています。各ファイルの最大サイズを制御できるCOPYコマンドのパラメーターはどれですか？</p>", "options": [{"key": "A", "label": "FILE_SIZE_LIMIT"}, {"key": "B", "label": "MAX_FILE_SIZE"}, {"key": "C", "label": "MAX_FILE_BYTES"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>MAX_FILE_SIZE</strong></p><p>Snowflakeからデータをアンロードすると、デフォルトではgzip圧縮で自動的に圧縮されます。これはデフォルトの動作ですが、別の圧縮方法を指定したり圧縮を完全にオフにすることもできます。アンロードプロセスはSnowflakeが提供する並列性を活用するために自動的に複数のファイルにエクスポートします。ただし、必要に応じてSINGLEパラメーターをtrueに設定して単一ファイルへのエクスポートを確実にすることができます。各出力ファイルのデフォルトサイズは16 MBですが、MAX_FILE_SIZEパラメーターを使用して変更できます。クラウドストレージにデータをエクスポートする場合の最大許容ファイルサイズは5GBです。 https://docs.snowflake.com/en/user-guide/data-unload-considerations#unloading-to-a-single-file</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 33, "title": "COPYコマンドは次のどこからデータをロードできますか？", "multiSelect": true, "stemHtml": "<p>COPYコマンドは次のどこからデータをロードできますか？</p>", "options": [{"key": "A", "label": "テープドライブ"}, {"key": "B", "label": "取り外し可能なハードディスク"}, {"key": "C", "label": "外部ステージ"}, {"key": "D", "label": "内部ステージ"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>外部ステージ / 内部ステージ</strong></p><p>データウェアハウスがステージングを使用するように、SnowflakeはステージオブジェクトをSnowflakeテーブルへのデータのロードおよびアンロードの補助に使用します。Snowflakeテーブルにデータをロードするには、まずデータをSnowflakeステージで利用可能にする必要があります。データがステージにロードされた後、COPYコマンドを使用してテーブルにデータをロードできます。データのアンロードまたはエクスポートもステージオブジェクトを介して行われます。データは内部または外部のステージにのみエクスポートできます。 https://docs.snowflake.com/en/user-guide/data-load-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 34, "title": "Snowflakeが提供するデータ共有サービスはどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflakeが提供するデータ共有サービスはどれですか？</p>", "options": [{"key": "A", "label": "Data Exchange"}, {"key": "B", "label": "Seamless Data Share"}, {"key": "C", "label": "Snowflake Marketplace"}, {"key": "D", "label": "ダイレクト共有"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>Data Exchange / Snowflake Marketplace / ダイレクト共有</strong></p><p>Snowflakeは以下のデータ共有サービスを提供しています：ダイレクト共有、Snowflake Marketplace、Data Exchange。 https://docs.snowflake.com/en/guides-overview-sharing</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 35, "title": "ユーザーに付与されたロールを表示するために使用できるACCOUNT_USAGEビューはどれですか...", "multiSelect": false, "stemHtml": "<p>ユーザーに付与されたロールを表示するために使用できるACCOUNT_USAGEビューはどれですか？</p>", "options": [{"key": "A", "label": "OBJECT_DEPENDENCIES"}, {"key": "B", "label": "GRANTS_TO_USERS"}, {"key": "C", "label": "GRANTS_TO_ROLES"}, {"key": "D", "label": "ACCESS_HISTORY"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>GRANTS_TO_USERS</strong></p><p>GRANTS_TO_USERSビューは、ユーザーに付与されたロールに関する情報を表示するために使用できます。このビューには履歴情報（最大365日）も含まれているため、過去365日以内に付与または取り消されたロールも表示されます。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage/grants_to_users</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 36, "title": "オートスケールモードのマルチクラスター仮想ウェアハウスに関する正しい記述はどれですか？", "multiSelect": true, "stemHtml": "<p>オートスケールモードのマルチクラスター仮想ウェアハウスに関する正しい記述はどれですか？</p>", "options": [{"key": "A", "label": "クエリがキューに入り始めたことをSnowflakeが検出すると、追加のウェアハウスが起動されます。"}, {"key": "B", "label": "マルチクラスター仮想ウェアハウスは通常の仮想ウェアハウスと同じプロパティとアクションをサポートします。一時停止、再開、別のサイズへの変更が可能です。"}, {"key": "C", "label": "クエリの需要が低下すると、ウェアハウスは段階的にシャットダウンされます。"}, {"key": "D", "label": "マルチクラスター仮想ウェアハウスは一時停止、再開、またはリサイズ操作をサポートしません。"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>クエリがキューに入り始めると追加ウェアハウスが起動 / 通常の仮想ウェアハウスと同じプロパティをサポート / 需要低下時にウェアハウスが段階的にシャットダウン</strong></p><p>マルチクラスター仮想ウェアハウスをオートスケーリングモードで起動すると、アクティブな仮想ウェアハウスの数は最小ウェアハウス数になります。Snowflakeは需要に応じて最大ウェアハウス数まで新しいウェアハウスを作成します。需要が低下するとウェアハウスの数が最小ウェアハウス数になるまでシャットダウンします。マルチクラスター仮想ウェアハウスは標準の仮想ウェアハウス属性とアクション（ウェアハウスサイズの指定と変更、マルチクラスター仮想ウェアハウスの一時停止またはオート一時停止、一時停止中のマルチクラスター仮想ウェアハウスの再開またはオート再開など）をサポートします。 https://docs.snowflake.com/en/user-guide/warehouses-multicluster</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 37, "title": "真か偽：クローンされたオブジェクトは、ソースまたはターゲットオブジェクトでDML操作が行われるま...", "multiSelect": false, "stemHtml": "<p>真か偽：クローンされたオブジェクトは、ソースまたはターゲットオブジェクトでDML操作が行われるまで、全体のストレージに貢献しません。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>テーブル、スキーマ、またはデータベースがクローンされる場合、既存データの変更・削除や追加データをソースまたはターゲットに対してDML（データ操作言語）操作が実行されるまで、クローンされたアイテムは合計ストレージに貢献しません。 https://docs.snowflake.com/en/user-guide/tables-storage-considerations#label-cloning-tables</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 38, "title": "特定のクエリのクエリ結果キャッシュに関する正しい記述はどれですか？（該当するものをすべて選択して...", "multiSelect": true, "stemHtml": "<p>特定のクエリのクエリ結果キャッシュに関する正しい記述はどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "クエリ結果キャッシュは手動でパージできます。"}, {"key": "B", "label": "クエリがクエリ結果キャッシュを再利用すると、さらに24時間延長されます。"}, {"key": "C", "label": "クエリ結果キャッシュは最大31日間延長できます。"}, {"key": "D", "label": "新しいクエリがクエリ結果キャッシュを再利用しない場合、キャッシュは24時間後にパージされます。"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>クエリ結果キャッシュを再利用すると24時間延長 / 最大31日間延長可能 / 24時間再利用されなければパージ</strong></p><p>クエリの結果キャッシュの最初の有効期間は24時間です。24時間以内に新しいクエリが以前に生成されたキャッシュを再利用しない場合、キャッシュはパージされます。新しいクエリが結果キャッシュを使用すると、クエリ結果キャッシュの有効期間が別の24時間にリセットされます。最初のクエリ結果キャッシュのこの延長は、クエリ結果キャッシュが最初に生成された時点から最大31日間続くことができます。31日後、クエリの結果キャッシュは完全にパージされます。 https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 39, "title": "仮想ウェアハウスがスケールアップまたはスケールダウンされた場合、既存および新しいクエリへの影響は...", "multiSelect": true, "stemHtml": "<p>仮想ウェアハウスがスケールアップまたはスケールダウンされた場合、既存および新しいクエリへの影響はどうなりますか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "既存のクエリへは影響があり、すぐに新しいサイズを使用し始めます。"}, {"key": "B", "label": "既存のクエリへは影響がありません。"}, {"key": "C", "label": "変更されたサイズは新しいクエリにのみ影響します。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>既存のクエリへは影響がありません / 変更されたサイズは新しいクエリにのみ影響します</strong></p><p>変更されたサイズの影響を受けるのは新しいクエリのみで、仮想ウェアハウス上の既存のクエリは影響を受けません。仮想ウェアハウスがスケールダウンされる場合、仮想ウェアハウスにアクティブなクエリがない場合にのみノードが仮想ウェアハウスから削除されます。したがって、既存のクエリはリサイズによって影響を受けません。 https://docs.snowflake.com/en/user-guide/warehouses-considerations#warehouse-resizing-improves-performance</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 40, "title": "120日前のデータの状態にアクセスしようとするタイムトラベルクエリを実行しました。最も可能性の高...", "multiSelect": false, "stemHtml": "<p>120日前のデータの状態にアクセスしようとするタイムトラベルクエリを実行しました。最も可能性の高い結果は何ですか？</p>", "options": [{"key": "A", "label": "クエリは正常に実行されますが、各行に空白の値が返されます。"}, {"key": "B", "label": "クエリは正常に実行され、120日前に存在したデータを表示します。"}, {"key": "C", "label": "クエリは正常に実行されますが、行を表示しません。"}, {"key": "D", "label": "クエリは「タイムトラベルデータはそのテーブルには利用できません。要求された時間は許可されたタイムトラベル期間を超えているか、オブジェクトの作成時間より前です。」というエラーで失敗します。"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>クエリはエラーで失敗します</strong></p><p>AT | BEFORE句で指定されたTIMESTAMP、OFFSET、またはSTATEMENTがテーブルのタイムトラベル保持期間（最大90日）を超えている場合、タイムトラベルクエリは失敗してエラーが返されます。</p><p>テーブルが作成される前のデータにアクセスしようとするタイムトラベルクエリでも同じエラーが発生します。</p><p>https://docs.snowflake.com/en/user-guide/data-time-travel#querying-historical-data</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 41, "title": "Snowparkが提供する機能はどれですか？", "multiSelect": false, "stemHtml": "<p>Snowparkが提供する機能はどれですか？</p>", "options": [{"key": "A", "label": "Snowparkは、Snowflakeへの接続のトラブルシューティングのために設計された診断ツールです。"}, {"key": "B", "label": "SnowparkはSnowflakeのWebベースユーザーインターフェースの名称です。"}, {"key": "C", "label": "Snowparkはデータ処理プログラミング構造を自動的にSQLに変換し、実行のためにSnowflakeにプッシュダウンします。"}, {"key": "D", "label": "Snowparkは、Snowflakeに接続してクエリを実行できるコマンドラインクライアントです。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Snowparkはデータ処理プログラミング構造を自動的にSQLに変換し、実行のためにSnowflakeにプッシュダウンします</strong></p><p>SnowparkはSnowflakeが作成したライブラリで、SQL以外のプログラミング言語で書かれたアプリケーションでデータにアクセスして処理するためのAPIを提供します。SnowparkにはJava、Scala、Pythonなどの一般的なプログラミング言語を使用して標準的なプログラミング構造でデータを処理するアプリを構築することができます。Snowparkはデータ処理プログラミング構造を自動的にSQLに変換し、実行のためにSnowflakeにプッシュダウンします。その結果、開発者はSnowflakeのスケールと実行エンジンを活用しながら親しみやすい言語を使用できます。 https://docs.snowflake.com/en/developer-guide/snowpark/index</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 42, "title": "マテリアライズドビューのベーステーブルが削除された場合の動作を正しく説明しているのはどれですか？...", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューのベーステーブルが削除された場合の動作を正しく説明しているのはどれですか？（2つ選択してください）</p>", "options": [{"key": "A", "label": "マテリアライズドビューは自動的には削除されません。"}, {"key": "B", "label": "マテリアライズドビューは一時停止されます。"}, {"key": "C", "label": "マテリアライズドビューがあるテーブルは削除できません。先にマテリアライズドビューを削除する必要があります。"}, {"key": "D", "label": "マテリアライズドビューは自動的に削除されます。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>マテリアライズドビューは自動的には削除されません / マテリアライズドビューは一時停止されます</strong></p><p>マテリアライズドビューのベーステーブルが削除された場合、マテリアライズドビューは自動的には削除されませんが、一時停止されます。マテリアライズドビューを手動で削除する必要があります。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized#dropping-the-base-table</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 43, "title": "データプロバイダーとは異なるリージョンに存在するSnowflakeのお客様とデータを共有すること...", "multiSelect": false, "stemHtml": "<p>データプロバイダーとは異なるリージョンに存在するSnowflakeのお客様とデータを共有することは可能ですか？</p>", "options": [{"key": "A", "label": "可能ですが、クロスリージョンデータ共有を可能にするためにまずレプリケーションを有効にする必要があります。"}, {"key": "B", "label": "いいえ、他のリージョンのお客様と共有することはできません。"}, {"key": "C", "label": "はい。クロスリージョンデータ共有を有効にするために特別なことは何もする必要はありません。"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>可能ですが、クロスリージョンデータ共有を可能にするためにまずレプリケーションを有効にする必要があります</strong></p><p>他のリージョンとデータを共有することは可能ですが、プロバイダーはレプリケーションを有効にして既存のデータベースを別のリージョンにレプリケートする必要があります。 https://docs.snowflake.com/en/user-guide/secure-data-sharing-across-regions-plaforms</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 44, "title": "あなたはSnowflakeを実行している大手小売業者のデータベース管理者です。transacti...", "multiSelect": false, "stemHtml": "<p>あなたはSnowflakeを実行している大手小売業者のデータベース管理者です。transaction_date列でクラスター化されたtransactionsテーブルがあります。このテーブルからクラスタリングを削除する必要があります。正しい方法は何ですか？</p>", "options": [{"key": "A", "label": "ALTER TABLE transactions DROP CLUSTERING KEY;"}, {"key": "B", "label": "transactionsと同じ構造でクラスタリングキーのないtransactions_2という新しいテーブルを作成し、transactionsテーブルからtransactions_2にデータを挿入し、transactionsテーブルを削除して、transactions_2をtransactionsに名前変更します。"}, {"key": "C", "label": "ALTER TABLE transactions REMOVE CLUSTER BY;"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>ALTER TABLE transactions DROP CLUSTERING KEY;</strong></p><p>テーブルのクラスタリングキーを削除または変更する必要がある場合は、ALTERテーブルコマンドを実行し、適切な構文を使用してクラスタリングキーを削除、追加、または変更できます。 https://docs.snowflake.com/en/user-guide/tables-clustering-keys#dropping-the-clustering-keys-for-a-table</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 45, "title": "タスクを使用して一連のSQL文を実行するための最も適切な方法は何ですか？", "multiSelect": false, "stemHtml": "<p>タスクを使用して一連のSQL文を実行するための最も適切な方法は何ですか？</p>", "options": [{"key": "A", "label": "マルチステップタスクとして作成し、すべてのSQLステップを順番に含める。（CREATE MULTISTEP TASK task1 AS statement1; statement2;.）"}, {"key": "B", "label": "各SQL文のタスクを作成し（task1, task2など）、ルートタスクを使用してtask1、task2などを順番にトリガーするようにシーケンシャルにリンクします。"}, {"key": "C", "label": "複数のSQL文を単一のタスク内で直接実行する。（CREATE TASK task1 AS statement1; statement2;.）"}, {"key": "D", "label": "複数のSQL文を含むストアドプロシージャを作成し、タスクからストアドプロシージャを呼び出す。（CREATE TASK task1 .... AS call sp_with_multiple_SQLs();）"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>複数のSQL文を含むストアドプロシージャを作成し、タスクからストアドプロシージャを呼び出す</strong></p><p>タスクは一度に1つのSQL文しか実行できません。複数のSQL文を実行するには2つのオプションがあります：すべての文をストアドプロシージャに入れるか、各々が1つの文を実行する複数のタスクを作成してそれらをリンクするかです。ただし、ストアドプロシージャを使用することが推奨されるアプローチです。</p><p>https://docs.snowflake.com/en/user-guide/tasks-intro#:~:text=A%20task%20can%20execute%20any%20one%20of%20the%20following%20types%20of%20functions%3A</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タスク", "originalCorrect": null, "reviewPoint": ""}}, {"order": 46, "title": "真か偽：外部関数はC++のみで記述できます。", "multiSelect": false, "stemHtml": "<p>真か偽：外部関数はC++のみで記述できます。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>偽</strong></p><p>外部関数を作成する利点の1つは、標準のUDFでは使用できない言語でも記述できることです。外部関数はSnowflakeの外部に存在するため、多くの言語を使用して外部関数を作成できます。 https://docs.snowflake.com/en/sql-reference/external-functions-introduction#advantages-of-external-functions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 47, "title": "ディレクトリテーブルのメタデータが更新されるときに発生するアクションはどれですか？（該当するもの...", "multiSelect": true, "stemHtml": "<p>ディレクトリテーブルのメタデータが更新されるときに発生するアクションはどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "外部ステージの新しいファイルがディレクトリテーブルのメタデータに追加されます。"}, {"key": "B", "label": "削除されたファイルがディレクトリテーブルのメタデータから削除されます。"}, {"key": "C", "label": "ファイルパスへの変更がディレクトリテーブルのメタデータに反映されます。"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>外部ステージの新しいファイルが追加 / 削除されたファイルが削除 / ファイルパスへの変更が反映</strong></p><p>これらはすべて有効な回答です。ディレクトリテーブルのメタデータは手動で更新するか、自動更新に設定できます。メタデータが更新されると、ステージ内のファイルの現在の状態と同期されます。外部ステージの新しいファイルがディレクトリテーブルのメタデータに追加され、削除されたファイルがディレクトリテーブルのメタデータから削除されます。また、ファイルパスへの変更もディレクトリテーブルのメタデータに反映されます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-dirtables-intro#automatically-refreshing-directory-table-metadata</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 48, "title": "PowerBI、Looker、MicroStrategy、Tableau、QlikはSnowfl...", "multiSelect": false, "stemHtml": "<p>PowerBI、Looker、MicroStrategy、Tableau、QlikはSnowflakeパートナーエコシステムでどのタイプのパートナーですか？</p>", "options": [{"key": "A", "label": "機械学習とデータサイエンス"}, {"key": "B", "label": "データ統合"}, {"key": "C", "label": "ビジネスインテリジェンス"}, {"key": "D", "label": "セキュリティ、ガバナンス、オブザーバビリティ"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>ビジネスインテリジェンス</strong></p><p>これらはすべてSnowflakeのビジネスインテリジェンスパートナーです。 https://docs.Snowflake.com/en/user-guide/ecosystem.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パートナー", "originalCorrect": null, "reviewPoint": ""}}, {"order": 49, "title": "仮想ウェアハウスのクレジット使用量を監視するためのリソースモニターの使用を許可するSnowfla...", "multiSelect": true, "stemHtml": "<p>仮想ウェアハウスのクレジット使用量を監視するためのリソースモニターの使用を許可するSnowflakeエディションはどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "Business Critical"}, {"key": "B", "label": "Standard"}, {"key": "C", "label": "Virtual Private Snowflake"}, {"key": "D", "label": "Enterprise"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>Business Critical / Standard / Virtual Private Snowflake / Enterprise</strong></p><p>すべてのSnowflakeエディションがリソースモニターをサポートしています。 https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 50, "title": "有効期限を設定できるURLタイプはどれですか？", "multiSelect": false, "stemHtml": "<p>有効期限を設定できるURLタイプはどれですか？</p>", "options": [{"key": "A", "label": "プリサインドURL"}, {"key": "B", "label": "ファイルURL"}, {"key": "C", "label": "スコープドURL"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>プリサインドURL</strong></p><p>ファイルURLはステージされたファイルへの永続的なSnowflakeホスト型URLです。ファイルURLは期限切れになりません。</p><p>スコープドURLは、ステージへの権限なしにステージされたファイルへの一時的なアクセスを許可する一時的でエンコードされたURLです。スコープドURLは24時間後に期限切れになります。</p><p>プリサインドURLは、Webブラウザを使用してファイルにアクセスするためのシンプルなHTTPS URLです。プリサインドURLの有効期限は設定可能で、必要な期間に設定できます。</p><p>https://docs.snowflake.com/en/user-guide/unstructured-intro#types-of-urls-available-to-access-files</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 51, "title": "名前付き内部ステージからオンプレミスシステムにデータをダウンロードする必要があります。どのコマン...", "multiSelect": false, "stemHtml": "<p>名前付き内部ステージからオンプレミスシステムにデータをダウンロードする必要があります。どのコマンドを使用すべきですか？</p>", "options": [{"key": "A", "label": "COPY"}, {"key": "B", "label": "GET"}, {"key": "C", "label": "PUT"}, {"key": "D", "label": "VALIDATE"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>GET</strong></p><p>GETコマンドは内部ステージからオンプレミスシステムにデータをダウンロードするために使用されます。PUTコマンドはオンプレミスシステムから内部ステージにデータをアップロードします。外部ステージのデータをダウンロードまたはアップロードするには、外部ステージが指すクラウドストレージのデータを操作するためにクラウドプロバイダーのユーティリティやその他のツールが使用されます。 https://docs.snowflake.com/en/user-guide/data-unload-overview#bulk-unloading-process</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 52, "title": "タイムトラベルは次のどのシナリオで役立ちますか？（タイムトラベル期間を90日と仮定します）", "multiSelect": true, "stemHtml": "<p>タイムトラベルは次のどのシナリオで役立ちますか？（タイムトラベル期間を90日と仮定します）</p>", "options": [{"key": "A", "label": "昨日本番環境にロールアウトされた新しいデータパイプラインが本番テーブルのすべての行を削除した。"}, {"key": "B", "label": "93日前に3つの本番テーブルを破損させたデータ破損の問題が発見された。"}, {"key": "C", "label": "管理者が先週誤って本番テーブルを削除した。"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>昨日の削除行復元 / 先週削除されたテーブルの復元</strong></p><p>タイムトラベルのATおよびBEFORE拡張を使用して、本番テーブルから削除されたすべての行を復元できます。</p><p>UNDROPステートメントを使用して、削除されたテーブル、スキーマ、またはデータベース全体を復元できます。</p><p>タイムトラベルを使用して、最大タイムトラベル期間（90日）より前のデータ問題からは復元できません。フェイルセーフストレージからデータを復元するにはSnowflakeサポートに依頼する必要があります。</p><p>https://docs.snowflake.com/en/user-guide/data-time-travel#time-travel-sql-extensions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 53, "title": "Snowflakeアーキテクチャを正しく説明する記述はどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeアーキテクチャを正しく説明する記述はどれですか？</p>", "options": [{"key": "A", "label": "共有ストレージと複数のコンピューティングエンジン"}, {"key": "B", "label": "共有ストレージと共有コンピューティングエンジン"}, {"key": "C", "label": "分散ストレージと複数のコンピューティングエンジン"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>共有ストレージと複数のコンピューティングエンジン</strong></p><p>Snowflakeは共有ディスクアーキテクチャと共有なしアーキテクチャの両方の最良の機能を組み合わせた新しいハイブリッドアーキテクチャを実装しています。Snowflakeは共有ディスクアーキテクチャと同様にデータを保存します（つまりデータは共有されます）。しかし、各々が独自のメモリと処理能力を持つ複数のコンピューティングエンジンの使用も可能にします。 https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 54, "title": "真か偽：データプロバイダーはリーダーアカウントのコンピューティングコストの責任を負い、支払います...", "multiSelect": false, "stemHtml": "<p>真か偽：データプロバイダーはリーダーアカウントのコンピューティングコストの責任を負い、支払います。</p>", "options": [{"key": "A", "label": "真"}, {"key": "B", "label": "偽"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>データプロバイダーがリーダーアカウントを作成・管理するため、リーダーアカウントのすべてのコンピューティング費用はプロバイダーアカウントに請求されます。したがって、リーダーアカウントの仮想ウェアハウスコンピューティングの使用はプロバイダーアカウントのコンピューティング料金に追加されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 55, "title": "真か偽：クローニングとタイムトラベルを組み合わせて、特定の時点のデータのクローンを作成することは...", "multiSelect": false, "stemHtml": "<p>真か偽：クローニングとタイムトラベルを組み合わせて、特定の時点のデータのクローンを作成することは可能です。</p>", "options": [{"key": "A", "label": "真"}, {"key": "B", "label": "偽"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>クローニングとタイムトラベルを組み合わせて、特定の時点でのテーブル、データベース、またはスキーマのクローンを生成できます。タイムトラベルとクローニングはどちらもメタデータ操作であるため、簡単に組み合わせることができます。 https://docs.snowflake.com/en/user-guide/data-time-travel#cloning-historical-objects</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 56, "title": "真か偽：多要素認証（MFA）はすべてのSnowflakeアカウントでデフォルトで有効になっていま...", "multiSelect": false, "stemHtml": "<p>真か偽：多要素認証（MFA）はすべてのSnowflakeアカウントでデフォルトで有効になっています。</p>", "options": [{"key": "A", "label": "真"}, {"key": "B", "label": "偽"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>MFAはすべてのSnowflakeアカウントでデフォルトで有効になっており、すべてのSnowflakeエディションで利用可能です。 https://docs.snowflake.com/en/user-guide/security-mfa</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 57, "title": "ユーザー定義関数をサポートするエディションはどれですか？", "multiSelect": true, "stemHtml": "<p>ユーザー定義関数をサポートするエディションはどれですか？</p>", "options": [{"key": "A", "label": "Enterprise"}, {"key": "B", "label": "Business Critical"}, {"key": "C", "label": "Standard"}, {"key": "D", "label": "Virtual Private Snowflake"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>Enterprise / Business Critical / Standard / Virtual Private Snowflake</strong></p><p>UDFは基本的な機能であり、すべてのSnowflakeエディションでサポートされています。 https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 58, "title": "クエリの最適化とディスパッチを担当する層はどれですか？", "multiSelect": false, "stemHtml": "<p>クエリの最適化とディスパッチを担当する層はどれですか？</p>", "options": [{"key": "A", "label": "クライアント最適化ライブラリ"}, {"key": "B", "label": "データベースストレージ"}, {"key": "C", "label": "クラウドサービス"}, {"key": "D", "label": "クエリ処理"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>クラウドサービス</strong></p><p>クラウドサービス層はクエリの計画と最適化を担当しています。実際のクエリ処理は仮想ウェアハウスが実行します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 59, "title": "Snowflakeのアーキテクチャ層ではないのはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeのアーキテクチャ層ではないのはどれですか？</p>", "options": [{"key": "A", "label": "クラウドサービス"}, {"key": "B", "label": "仮想ウェアハウス"}, {"key": "C", "label": "仮想マシン"}, {"key": "D", "label": "データベースストレージ"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>仮想マシン</strong></p><p>Snowflakeアーキテクチャには3つの異なる層があります：データベースストレージ（AWS、Azure、またはGoogle Cloud上の安価なクラウドストレージ）、クエリ処理（主に仮想ウェアハウスで構成）、クラウドサービス（全体の操作の頭脳）。 https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 60, "title": "Snowflakeのクエリ処理は________________と呼ばれるコンピューティングエン...", "multiSelect": false, "stemHtml": "<p>Snowflakeのクエリ処理は________________と呼ばれるコンピューティングエンジンによって実行されます。</p>", "options": [{"key": "A", "label": "Hadoopクラスター"}, {"key": "B", "label": "コンピュートノード"}, {"key": "C", "label": "仮想ウェアハウス"}, {"key": "D", "label": "Sparkマシン"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>仮想ウェアハウス</strong></p><p>Snowflakeのコンピューティングエンジンは仮想ウェアハウスと呼ばれています。 https://docs.snowflake.com/en/user-guide/warehouses-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 61, "title": "各マイクロパーティションに対してどのようなメタデータが維持されますか？（該当するものをすべて選択...", "multiSelect": true, "stemHtml": "<p>各マイクロパーティションに対してどのようなメタデータが維持されますか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "各列の最大値と最小値"}, {"key": "B", "label": "列値の範囲"}, {"key": "C", "label": "各列の個別値の数"}, {"key": "D", "label": "各列の平均値・中央値・最頻値"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>各列の最大値と最小値 / 列値の範囲 / 各列の個別値の数</strong></p><p>Snowflakeはメタデータに列値の範囲（各マイクロパーティションの各列の最大値と最小値）を保存します。Snowflakeはこのメタデータを使用してクエリ処理時に読み取るパーティションをインテリジェントに決定できます。さらに、Snowflakeはメタデータにクエリ最適化を支援するその他の情報とともに、各パーティションの各列の個別値の数を保存します。 https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 62, "title": "真か偽：リソースモニターは仮想ウェアハウスに関連するクラウドサービスコストを追跡できますが、クラ...", "multiSelect": false, "stemHtml": "<p>真か偽：リソースモニターは仮想ウェアハウスに関連するクラウドサービスコストを追跡できますが、クラウドサービスコストの発生を止めることはできません。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>リソースモニターはクラウドサービスのコストを制御できません。ウェアハウスレベルのリソースモニターはクラウドサービスによるクレジット使用量を監視できますが、クラウドサービスを一時停止することはできません。 https://docs.snowflake.com/en/user-guide/resource-monitors#assignment-of-resource-monitors</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 63, "title": "外部ステージはステージオブジェクトの作成時または後から有効化できます。次のどのSQLがディレクト...", "multiSelect": false, "stemHtml": "<p>外部ステージはステージオブジェクトの作成時または後から有効化できます。次のどのSQLがディレクトリテーブルを有効化しますか？</p>", "options": [{"key": "A", "label": "ALTER STAGE <STAGE_NAME> SET DIRECTORY = (ENABLE = TRUE);"}, {"key": "B", "label": "GENERATE DIRECTORY TABLE ON <STAGE_NAME>;"}, {"key": "C", "label": "CREATE DIRECTORY TABLE <TABLE_NAME> ON <STAGE_NAME>;"}, {"key": "D", "label": "ALTER STAGE <STAGE_NAME> ADD DIRECTORY;"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>ALTER STAGE &lt;STAGE_NAME&gt; SET DIRECTORY = (ENABLE = TRUE);</strong></p><p>ステージのディレクトリテーブルを有効化（または無効化）する正しい構文は、ステージの作成または変更時にDIRECTORY = (ENABLE = TRUE | FALSE)構文を使用することです。</p><p>https://docs.snowflake.com/en/sql-reference/sql/alter-stage</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 64, "title": "専用のメタデータストレージ、専用のコンピューティングリソースプールを持ち、HIPAAおよびHIT...", "multiSelect": false, "stemHtml": "<p>専用のメタデータストレージ、専用のコンピューティングリソースプールを持ち、HIPAAおよびHITRUST CSF規制に従って保護された医療情報（PHI）データをサポートするSnowflakeエディションはどれですか？</p>", "options": [{"key": "A", "label": "Enterprise Edition"}, {"key": "B", "label": "Business Critical Edition"}, {"key": "C", "label": "Standard Edition"}, {"key": "D", "label": "Virtual Private Snowflake (VPS) edition"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>Virtual Private Snowflake (VPS) edition</strong></p><p>VPSエディションは他のお客様からの分離を提供するためのものです。したがって、各インスタンスには独自のメタデータストアとコンピューティングリソースがあります。また、HIPPAとHITRUST CSF規制もサポートしています。</p><p>https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 65, "title": "真か偽：コンシューマーアカウントが共有データベース上に読み取り専用データベースを作成しました。コ...", "multiSelect": false, "stemHtml": "<p>真か偽：コンシューマーアカウントが共有データベース上に読み取り専用データベースを作成しました。コンシューマーアカウントはこのデータベースとそのテーブルを他のアカウントと共有できます。</p>", "options": [{"key": "A", "label": "真"}, {"key": "B", "label": "偽"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>偽</strong></p><p>コンシューマーアカウントは共有データベースへのアクセスとデータのクエリのみが可能で、データベースオブジェクトの追加、変更、または作成はできません。</p><p>コンシューマーアカウントは共有データベース、そのスキーマ、またはそのテーブルをクローンできません。</p><p>コンシューマーアカウントは共有データに対してタイムトラベルを使用できません。</p><p>コンシューマーアカウントは共有データベースをさらに共有することはできません。</p><p>https://docs.snowflake.com/en/user-guide/data-share-consumers#general-limitations-for-shared-databases</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 66, "title": "次のクエリプロファイルのスニペットのうち、効果的なマイクロパーティションプルーニングを示している...", "multiSelect": true, "stemHtml": "<p>次のクエリプロファイルのスニペットのうち、効果的なマイクロパーティションプルーニングを示しているのはどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "2"}, {"key": "B", "label": "3"}, {"key": "C", "label": "4"}, {"key": "D", "label": "1"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>2 / 3</strong></p><p>パーティションプルーニングは、スキャンされたパーティション数が合計パーティション数よりもはるかに少ない場合に発生します。スキャンされたパーティションが合計パーティションと等しい場合、クエリはテーブル全体をスキャンしたことになります。したがって、パーティションプルーニングは発生しておらず、クラスタリングキーを改善する必要があります。 https://docs.snowflake.com/en/user-guide/ui-query-profile</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 67, "title": "テーブルを読み取る際に大量のデータを除外するクエリのパフォーマンスをSnowflakeはどのよう...", "multiSelect": false, "stemHtml": "<p>テーブルを読み取る際に大量のデータを除外するクエリのパフォーマンスをSnowflakeはどのように向上させますか？</p>", "options": [{"key": "A", "label": "MFAを使用することで"}, {"key": "B", "label": "パーティションプルーニングを使用することで"}, {"key": "C", "label": "フルテーブルスキャンを使用することで"}, {"key": "D", "label": "マテリアライズドビューを使用することで"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>パーティションプルーニングを使用することで</strong></p><p>Snowflakeのメタデータにより、クエリエンジンはクエリ実行を最適化するためにパーティションを除外できます。たとえば、クエリがWHERE条件を指定している場合、その条件に一致する値を含まないパーティションはスキャンされません。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions#query-pruning</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 68, "title": "真か偽：マテリアライズドビューは、基礎となるテーブルのデータが変更された場合に自動的に更新されま...", "multiSelect": false, "stemHtml": "<p>真か偽：マテリアライズドビューは、基礎となるテーブルのデータが変更された場合に自動的に更新されます。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>マテリアライズドビューはSELECTクエリに基づいてデータを事前計算するビューです。クエリの結果は事前計算されて物理的に保存され、将来的に類似するクエリのパフォーマンスを向上させます。基礎となるテーブルが更新されると、マテリアライズドビューは自動的に更新され、追加のメンテナンスは不要です。Snowflakeマネージドサービスがバックグラウンドでユーザーのエクスペリエンスを妨げることなく更新を実行します。 https://docs.snowflake.com/en/user-guide/views-materialized</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 69, "title": "Snowflakeアカウントにネットワークポリシーを適用するために使用できる最小のSnowfla...", "multiSelect": false, "stemHtml": "<p>Snowflakeアカウントにネットワークポリシーを適用するために使用できる最小のSnowflake組み込みロールはどれですか？</p>", "options": [{"key": "A", "label": "SYSADMIN"}, {"key": "B", "label": "SECURITYADMIN"}, {"key": "C", "label": "ORGADMIN"}, {"key": "D", "label": "ACCOUNTADMIN"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>SECURITYADMIN</strong></p><p>SECURITYADMINロールは、アカウントレベルでネットワークポリシーを適用することを許可されている最小のSnowflake組み込みロールです。</p><p>https://docs.snowflake.com/en/sql-reference/sql/desc-user#usage-notes</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 70, "title": "マルチクラスター仮想ウェアハウスが一時停止されると、次のどのキャッシュがパージされますか？", "multiSelect": false, "stemHtml": "<p>マルチクラスター仮想ウェアハウスが一時停止されると、次のどのキャッシュがパージされますか？</p>", "options": [{"key": "A", "label": "クエリ結果キャッシュ"}, {"key": "B", "label": "メタデータキャッシュ"}, {"key": "C", "label": "ウェアハウスキャッシュ（ローカルディスクキャッシュ）"}, {"key": "D", "label": "ブラウザキャッシュ"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>ウェアハウスキャッシュ（ローカルディスクキャッシュ）</strong></p><p>仮想ウェアハウスがテーブルのデータにアクセスするたびに、そのデータをローカルにキャッシュします。このデータキャッシュは、後続のクエリがクラウドストレージのテーブルから読み取る代わりにキャッシュ内のデータを再利用できる場合、パフォーマンスを向上させます。ローカルキャッシュからの読み取りはクラウドストレージからデータを読み取るよりもはるかに効率的な操作であるため、キャッシュを活用できるクエリのパフォーマンスが向上します。</p><p>仮想ウェアハウスが一時停止されるとウェアハウスキャッシュはパージされます。仮想ウェアハウスが再開されると、クエリが処理されるにつれてウェアハウスキャッシュは徐々に再構築されます。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-considerations#how-does-warehouse-caching-impact-queries</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 71, "title": "シェアを正しく説明する記述はどれですか？", "multiSelect": true, "stemHtml": "<p>シェアを正しく説明する記述はどれですか？</p>", "options": [{"key": "A", "label": "シェアオブジェクトはEnterprise顧客のみが利用可能です。"}, {"key": "B", "label": "シェアオブジェクトにはコンシューマーに関する情報が含まれています。"}, {"key": "C", "label": "シェアオブジェクトは共有するオブジェクトを含むコンテナです。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>シェアオブジェクトにはコンシューマーに関する情報が含まれています / シェアオブジェクトは共有するオブジェクトを含むコンテナです</strong></p><p>シェアは共有が必要なオブジェクトのコンテナとして機能します。シェアオブジェクトには、共有するデータベースとスキーマ、共有されるテーブルとセキュアビュー、シェアが利用可能なコンシューマーアカウントがカプセル化されています。共有、ひいてはシェアオブジェクトはすべてのSnowflakeエディションで利用可能です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 72, "title": "すべてのデータの自動暗号化をサポートする最小のSnowflakeエディションはどれですか？", "multiSelect": false, "stemHtml": "<p>すべてのデータの自動暗号化をサポートする最小のSnowflakeエディションはどれですか？</p>", "options": [{"key": "A", "label": "Virtual Private Snowflake"}, {"key": "B", "label": "Standard"}, {"key": "C", "label": "Enterprise"}, {"key": "D", "label": "Business Critical"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>暗号化はすべてのSnowflakeエディションで自動的に提供されるため、それをサポートする最小エディションはStandardエディションです。 https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 73, "title": "クローニングはソースデータベースの権限をコピーしないため、管理者はクローンされたデータベースに対...", "multiSelect": false, "stemHtml": "<p>クローニングはソースデータベースの権限をコピーしないため、管理者はクローンされたデータベースに対して明示的に権限を付与する必要があります。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>クローンされたオブジェクトはそのソースオブジェクトから権限を継承しません。たとえば、クローンされたテーブルはそのソーステーブルから権限を継承しません。</p><p>ただし、データベースまたはスキーマがクローンされる場合、権限はデータベース内の子オブジェクトに継承されます。データベース自体は権限を継承しません。</p><p>https://docs.snowflake.com/en/user-guide/object-clone#access-control-privileges-for-cloned-objects</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 74, "title": "真か偽：Snowflakeはフェデレーション認証（IdP）のためにSAML 2.0準拠の外部ID...", "multiSelect": false, "stemHtml": "<p>真か偽：Snowflakeはフェデレーション認証（IdP）のためにSAML 2.0準拠の外部IDプロバイダーによるシングルサインオン（SSO）を許可します。</p>", "options": [{"key": "A", "label": "真"}, {"key": "B", "label": "偽"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>Snowflakeはフェデレーション認証をサポートし、シングルサインオン（SSO）を可能にします。ユーザーはSAML 2.0準拠の外部IDプロバイダー（IdP）を使用して認証します。IdP認証後、ユーザーはログインなしにSnowflakeにアクセスできます。SnowflakeはOkta、ADFS、OneLogin、Ping Identity PingOneなど、大部分のSAML 2.0準拠のIDプロバイダーをネイティブにサポートしています。 https://docs.snowflake.com/en/user-guide/admin-security-fed-auth</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 75, "title": "Snowflake以外のお客様とテーブルを共有するために新しいリーダーアカウントを作成する必要が...", "multiSelect": false, "stemHtml": "<p>Snowflake以外のお客様とテーブルを共有するために新しいリーダーアカウントを作成する必要があります。SYSADMINロールでログインしています。新しいリーダーアカウントを作成するクエリを実行すると、権限エラーが発生しました。リーダーアカウントを作成できるようにするにはどうすればよいですか？</p>", "options": [{"key": "A", "label": "SECURITYADMINロールに切り替える。新しいリーダーアカウントを作成できるのはSECURITYADMINロールのみです。"}, {"key": "B", "label": "ACCOUNTADMINロールに切り替える。新しいリーダーアカウントを作成できるのはACCOUNTADMINロールのみです。"}, {"key": "C", "label": "WebUIを使用してリーダーアカウントを作成する。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>ACCOUNTADMINロールに切り替える</strong></p><p>ACCOUNTADMINロールのみがアカウントレベルの活動であるため、新しいリーダーアカウントを作成できます。 https://docs.snowflake.com/en/user-guide/data-sharing-reader-create</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 76, "title": "IPアドレスがポリシーのブロックリストと許可リストの両方に含まれている場合、Snowflakeは...", "multiSelect": false, "stemHtml": "<p>IPアドレスがポリシーのブロックリストと許可リストの両方に含まれている場合、Snowflakeはネットワークポリシーをどのように適用しますか？</p>", "options": [{"key": "A", "label": "Snowflakeは最初にブロックリストを適用し、そのIPアドレスが許可リストにも定義されているかどうかに関係なく、アクセスが拒否されることを保証します。"}, {"key": "B", "label": "Snowflakeは最初に許可リストを確認し、そのIPアドレスがブロックリストにも定義されている場合でも接続が許可されることを保証します。"}, {"key": "C", "label": "SnowflakeのネットワークポリシーはIPアドレスをブロックリストと許可リストの両方に追加することを許可しません。"}, {"key": "D", "label": "ネットワークポリシーが無効です。"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>Snowflakeは最初にブロックリストを適用します</strong></p><p>ネットワークポリシーは、名前、承認済みIPアドレスのリスト、ブロックされたIPアドレスのリストの3つのコンポーネントで構成されています。許可リストとブロックリストの両方が設定されている場合、Snowflakeは最初にブロックリストを適用します。 https://docs.snowflake.com/en/user-guide/network-policies</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 77, "title": "Snowflakeは一時テーブルのデータをフェイルセーフストレージに何日間保存しますか？", "multiSelect": false, "stemHtml": "<p>Snowflakeは一時テーブルのデータをフェイルセーフストレージに何日間保存しますか？</p>", "options": [{"key": "A", "label": "7日"}, {"key": "B", "label": "1日"}, {"key": "C", "label": "0日"}, {"key": "D", "label": "14日"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>0日</strong></p><p>Snowflakeにはフェイルセーフ機能を提供しないトランジェントテーブルと一時テーブルがあります。したがって、これらのテーブルのデータは0日間のフェイルセーフストレージがあります。 https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 78, "title": "真か偽：セキュリティ管理者が新しいカスタムロールを作成すると、そのカスタムロールは既存のすべての...", "multiSelect": false, "stemHtml": "<p>真か偽：セキュリティ管理者が新しいカスタムロールを作成すると、そのカスタムロールは既存のすべてのユーザーに自動的に割り当てられます。</p>", "options": [{"key": "A", "label": "真"}, {"key": "B", "label": "偽"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>偽</strong></p><p>新しいカスタムロールはどのユーザーにも自動的に割り当てられません。すべての新しいロールはユーザーに手動で割り当てる必要があります。 https://docs.snowflake.com/en/user-guide/security-access-control-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 79, "title": "SnowflakeのSearch Optimizationサービスはどのようにクエリパフォーマン...", "multiSelect": true, "stemHtml": "<p>SnowflakeのSearch Optimizationサービスはどのようにクエリパフォーマンスを向上させますか？（2つ選択してください）</p>", "options": [{"key": "A", "label": "一般的なクエリの結果を事前計算します。"}, {"key": "B", "label": "ポイントルックアップを高速化するための最適化された検索アクセスパスとして永続的なデータ構造を使用します。"}, {"key": "C", "label": "等値述語を使用するクエリのパフォーマンスを向上させます。"}, {"key": "D", "label": "より多くのクエリをキャッシュから回答できるようにキャッシュのタイムアウトを増加させます。"}, {"key": "E", "label": "定義されたクラスタリングキーに従ってデータを再配布します。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>ポイントルックアップを高速化する永続的なデータ構造を使用 / 等値述語を使用するクエリのパフォーマンスを向上</strong></p><p>Search Optimizationサービスは、フィルタリングに多くの述語を使用する一部のルックアップおよび分析クエリのパフォーマンスを大幅に向上させることができます。</p><p>Search Optimizationサービスはポイントルックアップを高速化するための最適化された検索アクセスパスとして永続的なデータ構造を使用します。</p><p>https://docs.snowflake.com/en/user-guide/search-optimization-service</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 80, "title": "SnowflakeのSearch Optimizationに関する正しい記述はどれですか？（該当...", "multiSelect": true, "stemHtml": "<p>SnowflakeのSearch Optimizationに関する正しい記述はどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "Search Optimizationサービスはスノーフレーク管理のサービスです。"}, {"key": "B", "label": "Search Optimizationはバックグラウンドで動作し、基礎となるテーブルデータが変更されると検索アクセスパスを更新します。"}, {"key": "C", "label": "Search Optimizationサービスにはアクティブな仮想ウェアハウスが必要です。"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>Snowflake管理のサービス / バックグラウンドで動作し基礎テーブルデータ変更時に検索アクセスパスを更新</strong></p><p>Search Optimizationサービスはスノーフレーク管理のサービスで、バックグラウンドで実行され仮想ウェアハウスを必要としません。ただし、Search Optimizationにはクレジットとストレージコストが関連していることに注意してください。テーブルのデータが変更された場合（例えば、新しいデータセットのロードやDML操作の実行）、メンテナンスサービスは変更を反映するために検索アクセスパスを更新します。テーブルのSearch Optimization設定とメンテナンスサービスはユーザーに対して透過的です。 https://docs.snowflake.com/en/user-guide/search-optimization-service</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 81, "title": "新しいテーブルを作成する際にタイプが指定されていない場合、テーブルはどのタイプとして自動的に作成...", "multiSelect": false, "stemHtml": "<p>新しいテーブルを作成する際にタイプが指定されていない場合、テーブルはどのタイプとして自動的に作成されますか？</p>", "options": [{"key": "A", "label": "一時テーブル"}, {"key": "B", "label": "永続テーブル"}, {"key": "C", "label": "トランジェントテーブル"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>永続テーブル</strong></p><p>新しいテーブルのデフォルトおよび暗黙のタイプは永続テーブルです。他のタイプのテーブルを作成するには、一時テーブル、トランジェントテーブル、または外部テーブルとして明示的に指定する必要があります。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ保護", "originalCorrect": null, "reviewPoint": ""}}, {"order": 82, "title": "真か偽：Snowflakeはデータが挿入された順序でマイクロパーティションを作成します。", "multiSelect": false, "stemHtml": "<p>真か偽：Snowflakeはデータが挿入された順序でマイクロパーティションを作成します。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>マイクロパーティションはデータがテーブルに到着した順序でテーブルに追加されます。したがって、新しいデータがテーブルに追加されると、そのデータを収容するための新しいマイクロパーティションが作成されます。Snowflakeパーティションは不変で、作成後に変更することはできません。したがって、既存データの更新やテーブルへの新しいデータのロードはすべて新しいマイクロパーティションを作成します。マイクロパーティションはデータが到着した順序で作成・データが格納されます。 https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 83, "title": "Snowflakeインスタンスをプロビジョニングする方法はどれですか？（該当するものをすべて選択...", "multiSelect": true, "stemHtml": "<p>Snowflakeインスタンスをプロビジョニングする方法はどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "AWSアカウントの仮想マシンに手動でインストールする。"}, {"key": "B", "label": "コモディティハードウェアにオンプレミスでインストールする。"}, {"key": "C", "label": "Snowflakeがホスト・管理するインスタンスをプロビジョニングする（AWSを基盤インフラとして使用）。"}, {"key": "D", "label": "Snowflakeがホスト・管理するインスタンスをプロビジョニングする（Azureを基盤インフラとして使用）。"}, {"key": "E", "label": "オンプレミス技術とクラウドインフラの混合を使用するハイブリッドインストールを実行する。"}, {"key": "F", "label": "Snowflakeがホスト・管理するインスタンスをプロビジョニングする（GCPを基盤インフラとして使用）。"}], "correctAnswers": ["C", "D", "F"], "explanationHtml": "<p>✅ <strong>AWS / Azure / GCPを基盤インフラとしてSnowflakeがホスト・管理するインスタンスをプロビジョニングする</strong></p><p>Snowflakeはクラウドのためにエンジニアリングされており、AWS、Azure、GCPでのみ利用可能です。Snowflakeインスタンスは必ずSnowflakeを通じてプロビジョニングする必要があります。インスタンスはAWS、Azure、またはGCPを基盤インフラとして使用してSnowflakeがホストします。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 84, "title": "Europe/Middle Eastリージョンに1つ、Asia Pacificリージョンに1つの...", "multiSelect": false, "stemHtml": "<p>Europe/Middle Eastリージョンに1つ、Asia Pacificリージョンに1つの合計2つのSnowflakeインスタンスを作成するには、何個のSnowflakeアカウントが必要ですか？</p>", "options": [{"key": "A", "label": "ゼロ"}, {"key": "B", "label": "2つ"}, {"key": "C", "label": "1つ"}, {"key": "D", "label": "4つ"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>2つ</strong></p><p>各リージョンに1つずつ、合計2つの異なるアカウントを作成する必要があります。各Snowflakeアカウントは特定のSnowflakeリージョンでホストされています。複数のリージョンでSnowflakeを使用するには、Snowflakeのお客様は少なくともリージョンごとに1つ、複数のSnowflakeアカウントを管理する必要があります。 https://docs.snowflake.com/en/user-guide/intro-regions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 85, "title": "SnowsightのユーザープロファイルでAnで設定できるのはどれですか？（2つ選択してください...", "multiSelect": true, "stemHtml": "<p>SnowsightのユーザープロファイルでAnで設定できるのはどれですか？（2つ選択してください）</p>", "options": [{"key": "A", "label": "多要素認証"}, {"key": "B", "label": "通知"}, {"key": "C", "label": "シングルサインオン"}, {"key": "D", "label": "Tri Secret Secure"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>多要素認証 / 通知</strong></p><p>Snowsightのプロファイルダイアログを使用して、MFAに登録したり、通知設定を指定したり、メールアドレスを設定したり、プロファイルのデフォルトロールとデフォルトウェアハウスを設定したりできます。名前、パスワード、言語なども設定可能です。</p><p>https://docs.snowflake.com/en/user-guide/ui-snowsight-profile</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 86, "title": "真か偽：Snowflakeはテーブルへのデータ挿入時に自動的にデータをクラスター化します。", "multiSelect": false, "stemHtml": "<p>真か偽：Snowflakeはテーブルへのデータ挿入時に自動的にデータをクラスター化します。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>Snowflakeはデータがテーブルに挿入されるときに自動的にデータをクラスター化します。 https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions#what-is-data-clustering</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 87, "title": "クエリの結果キャッシュが将来のクエリによって使用されない場合、何時間後にパージされますか？", "multiSelect": false, "stemHtml": "<p>クエリの結果キャッシュが将来のクエリによって使用されない場合、何時間後にパージされますか？</p>", "options": [{"key": "A", "label": "24時間"}, {"key": "B", "label": "31日"}, {"key": "C", "label": "365日"}, {"key": "D", "label": "3600秒"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>24時間</strong></p><p>クエリの結果キャッシュが生成されると24時間有効です。その24時間の窓内にクエリ結果キャッシュを再利用する別のクエリが実行されると、結果キャッシュの有効期限はその時点からさらに24時間延長されます。クエリの結果キャッシュが使用され続けると、最大31日間有効です。31日後、クエリの結果キャッシュは他の条件に関係なくパージされます。 https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 88, "title": "真か偽：INFORMATION_SCHEMAには削除されたオブジェクトに関する情報が含まれていま...", "multiSelect": false, "stemHtml": "<p>真か偽：INFORMATION_SCHEMAには削除されたオブジェクトに関する情報が含まれています。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>偽</strong></p><p>INFORMATION SCHEMAには削除されたオブジェクトの情報は含まれていません。ただし、削除されたオブジェクトの情報が必要な場合は、ACCOUNT_USAGEビューをクエリする必要があります。 https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 89, "title": "リソースモニターは次のどのコストを制御できませんか？（該当するものをすべて選択してください）", "multiSelect": true, "stemHtml": "<p>リソースモニターは次のどのコストを制御できませんか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "クラウドサービスコスト"}, {"key": "B", "label": "ユーザーが作成した仮想ウェアハウス"}, {"key": "C", "label": "サーバーレスコンピューティング"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>クラウドサービスコスト / サーバーレスコンピューティング</strong></p><p>リソースモニターはSnowpipe、自動再クラスタリング、マテリアライズドビューメンテナンスなどのサーバーレス機能のクレジット使用量を制御できません。したがって、リソースモニターはお客様が作成した仮想ウェアハウスのみを管理でき、ユーザーが操作する仮想ウェアハウスのみを一時停止できます。Snowpipe、サーバーレスタスクなどのSnowflake管理のコンピューティングリソースはリソースモニターで追跡・管理できません。さらに、リソースモニターはクラウドサービスのコストを制御できません。ウェアハウスレベルのリソースモニターはクラウドサービスによるクレジット使用量を監視できますが、クラウドサービスを一時停止することはできません。 https://docs.snowflake.com/en/user-guide/resource-monitors#assignment-of-resource-monitors</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 90, "title": "クエリに対して仮想ウェアハウスのサイズが小さすぎることを示すクエリプロファイルの結果はどれですか...", "multiSelect": true, "stemHtml": "<p>クエリに対して仮想ウェアハウスのサイズが小さすぎることを示すクエリプロファイルの結果はどれですか？</p>", "options": [{"key": "A", "label": "結果ノードが多くの行を返す。"}, {"key": "B", "label": "クエリプロファイルに「ローカルストレージへのバイトのスピル」の大きな値が表示される。"}, {"key": "C", "label": "クエリはフルテーブルスキャンを実行しており、パーティションプルーニングが発生していない。"}, {"key": "D", "label": "クエリプロファイルに「リモートストレージへのバイトのスピル」の大きな値が表示される。"}, {"key": "E", "label": "多くのJoinノードがある。"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>「ローカルストレージへのバイトのスピル」の大きな値 / 「リモートストレージへのバイトのスピル」の大きな値</strong></p><p>Snowflakeは操作をメモリに収めることができない場合、ウェアハウスのローカルディスクにデータを保存します。データのスピルはより多くのIO操作を必要とし、ディスクアクセスはメモリアクセスより遅いため、クエリが遅くなります。「ローカルストレージへのバイトのスピル」はローカルスピルを示します。ローカルディスクがいっぱいになると、Snowflakeはリモートクラウドストレージにデータをスピルし、これはローカルディスクよりもさらに遅いストレージです。クエリプロファイルの「リモートストレージへのバイトのスピル」はリモートスピルを示します。スピルを回避する方法の1つは、より大きなウェアハウスを使用することで、全体的な利用可能なRAM、ローカルストレージ、並列性が増加し、クエリをメモリに収めることができる場合があります。 https://docs.snowflake.com/en/user-guide/ui-query-profile#queries-too-large-to-fit-in-memory</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 91, "title": "真か偽：INFORMATION_SCHEMAのビューを使用して、5分前に発生した使用履歴にアクセ...", "multiSelect": false, "stemHtml": "<p>真か偽：INFORMATION_SCHEMAのビューを使用して、5分前に発生した使用履歴にアクセスできます。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>INFORMATION_SCHEMAビューが提供するデータはリアルタイムで、提供される情報に遅延はありません。したがって、リアルタイムデータを表示する要件がある場合に使用すべきスキーマを問われたら、リアルタイム情報を含むINFORMATION SCHEMAのビューを使用すべきです。 https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 92, "title": "真か偽：SnowsightワークシートビューでSnowflakeアカウント内の別のユーザーとワー...", "multiSelect": false, "stemHtml": "<p>真か偽：SnowsightワークシートビューでSnowflakeアカウント内の別のユーザーとワークシートを共有できます。</p>", "options": [{"key": "A", "label": "真"}, {"key": "B", "label": "偽"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>Snowsightでは、アカウント内の他のSnowflakeユーザーとワークシートやフォルダーを共有でき、他のユーザーがワークシートやフォルダー内のSQLを表示・実行できます。 https://docs.snowflake.com/en/user-guide/ui-snowsight</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 93, "title": "外部テーブルに関する正しい記述はどれですか？", "multiSelect": true, "stemHtml": "<p>外部テーブルに関する正しい記述はどれですか？</p>", "options": [{"key": "A", "label": "外部テーブルは外部ステージを指します。"}, {"key": "B", "label": "外部テーブルのデータはDELETE SQLコマンドを使用して削除できます。"}, {"key": "C", "label": "外部テーブルは読み取り専用です。"}, {"key": "D", "label": "外部テーブルのデータはDML言語を使用して更新できます。"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>外部テーブルは外部ステージを指します / 外部テーブルは読み取り専用です</strong></p><p>外部テーブルは外部ストレージの場所を指しているため、DML（データ操作言語）操作はできません。外部テーブルはクラウドオブジェクトストレージの場所を指す外部ステージに対してのみ作成できます。 https://docs.snowflake.com/en/user-guide/tables-external-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 94, "title": "あなたはSnowflakeテーブルにデータをロードするジョブを開発しているデータエンジニアです。...", "multiSelect": false, "stemHtml": "<p>あなたはSnowflakeテーブルにデータをロードするジョブを開発しているデータエンジニアです。100行を含む単一のファイルを含むS3ステージが定義されています。その100行をロードしました。</p>", "options": [{"key": "A", "label": "Snowflakeステージのファイルが破損しているため、ロードできません。"}, {"key": "B", "label": "定義したファイル形式が正しくないため、データがロードされていません。"}, {"key": "C", "label": "Snowflakeステージにあった単一ファイルをすでにロードしました。Snowflakeはメタデータでファイルがすでにロードされているかどうかを追跡し、再度ロードしません。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Snowflakeステージにあった単一ファイルをすでにロードしました</strong></p><p>ロードメタデータには、そのテーブルにロードされたすべてのファイルの名前とファイルがロードされた時刻に対応するタイムスタンプなどのさまざまな情報が格納されています。このロードメタデータを利用することで、Snowflakeは以前にロードされたファイルを再処理しないことを確認します。このファイルはすでにロードされているため、Snowflakeはメタデータを通じてどのファイルがロードされたかを追跡し、再度処理しません。COPYコマンドを再テストするには、新しいファイルを配置するか、ロードプロセス中に特定のパラメーターを指定して強制的に再ロードする必要があります。 https://docs.snowflake.com/en/user-guide/data-load-considerations-load#load-metadata</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 95, "title": "真か偽：ACCOUNT_USAGEスキーマのビューのデータはリアルタイムです。", "multiSelect": false, "stemHtml": "<p>真か偽：ACCOUNT_USAGEスキーマのビューのデータはリアルタイムです。</p>", "options": [{"key": "A", "label": "真"}, {"key": "B", "label": "偽"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>偽</strong></p><p>ACCOUNT USAGEスキーマには、アカウントレベルでの使用メトリクスとメタデータ情報を提供するいくつかのビューが含まれています。ACCOUNT_USAGEビューが提供するデータはリアルタイムではなく、ビューによって通常45分から3時間の遅延で更新されます。これらのビューのデータは最大365日間保持されます。 https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 96, "title": "新しいデータベースと一緒に自動的に作成されるスキーマはどれですか？（該当するものをすべて選択して...", "multiSelect": true, "stemHtml": "<p>新しいデータベースと一緒に自動的に作成されるスキーマはどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "INFORMATION_SCHEMA"}, {"key": "B", "label": "PUBLIC"}, {"key": "C", "label": "INTERNAL"}, {"key": "D", "label": "CATALOGUE"}, {"key": "E", "label": "PRIVATE"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>INFORMATION_SCHEMA / PUBLIC</strong></p><p>INFORMATION_SCHEMAはINFORMATION_SCHEMAの親データベース内のオブジェクトに関するメタデータを提供します。すべてのデータベースと一緒に自動的に作成され、削除、名前変更、または移動はできません。</p><p>PUBLICスキーマもすべてのデータベースと一緒に自動的に作成されますが、通常のスキーマと同様です。削除、名前変更、または移動できます。必要に応じて、データベースの下に追加のスキーマを作成することもできます。</p><p>https://docs.snowflake.com/en/sql-reference/info-schema#information-schema-views-and-table-functions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake's catalog and objects", "originalCorrect": null, "reviewPoint": ""}}, {"order": 97, "title": "JDBCドライバーを使用してアプリケーションから呼び出した場合、CURRENT_CLIENT関数...", "multiSelect": false, "stemHtml": "<p>JDBCドライバーを使用してアプリケーションから呼び出した場合、CURRENT_CLIENT関数はどの値を返しますか？</p>", "options": [{"key": "A", "label": "アプリケーションの名前"}, {"key": "B", "label": "JDBCドライバーのバージョン"}, {"key": "C", "label": "文字列「JDBC」"}, {"key": "D", "label": "文字列「External Application」"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>JDBCドライバーのバージョン</strong></p><p>CURRENT_CLIENT関数はクエリが実行されたクライアントのバージョンを返します。JDBCまたはODBCドライバーを使用するアプリケーションが実行したクエリから呼び出された場合、ドライバーのバージョンが返されます。例えば、SnowsightでCURRENT_CLIENTを呼び出すとGoドライバーを使用しているため「Go 1.1.5」が返されます。従来のWeb UIでのCURRENT_CLIENTはドライバーなしで直接接続するため「Snowflake UI 20230324175929」を返します。SnowSQLでのCURRENT_CLIENTの呼び出しは「SnowSQL 1.2.24」を返します。 https://docs.snowflake.com/en/sql-reference/functions/current_client</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 98, "title": "一時停止中の仮想ウェアハウスのサイズが大きくなりました。何が起こるかを正しく説明しているのはどれ...", "multiSelect": true, "stemHtml": "<p>一時停止中の仮想ウェアハウスのサイズが大きくなりました。何が起こるかを正しく説明しているのはどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "ウェアハウスは一時停止されたままです。"}, {"key": "B", "label": "追加のノードがすぐにプロビジョニングされます。"}, {"key": "C", "label": "追加のノードは仮想ウェアハウスが再開されたときにのみプロビジョニングされます。"}, {"key": "D", "label": "仮想ウェアハウスはすぐに再開されます。"}, {"key": "E", "label": "仮想ウェアハウスの設定が新しいサイズを反映するように更新されます。"}], "correctAnswers": ["A", "C", "E"], "explanationHtml": "<p>✅ <strong>ウェアハウスは一時停止されたままです / 追加のノードは仮想ウェアハウスが再開されたときにのみプロビジョニングされます / 仮想ウェアハウスの設定が新しいサイズを反映するように更新されます</strong></p><p>仮想ウェアハウスは一時停止中でもいつでもリサイズできます。一時停止中の仮想ウェアハウスをリサイズすると、その設定が新しいサイズを反映するように更新されます。一時停止中の仮想ウェアハウスにはプロビジョニングされたノードがなく、Snowflakeに何をプロビジョニングするかを指示する設定のみがあります。</p><p>新しいノードのプロビジョニングはウェアハウスが再開されたときにのみ発生します。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-tasks#resizing-a-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 99, "title": "変更されたデータに対して操作を実行できるようにDML（データ操作言語）のデータ変更を追跡するSn...", "multiSelect": false, "stemHtml": "<p>変更されたデータに対して操作を実行できるようにDML（データ操作言語）のデータ変更を追跡するSnowflakeオブジェクトはどれですか？</p>", "options": [{"key": "A", "label": "ステージ（Stage）"}, {"key": "B", "label": "Snowpipe"}, {"key": "C", "label": "タスク（Task）"}, {"key": "D", "label": "ストリーム（Stream）"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>ストリーム（Stream）</strong></p><p>Snowflakeストリームは、テーブルに加えられた変更（新しいデータの追加（挿入）、既存データの変更（更新）、データの削除（削除）など）を追跡するのに役立ちます。最後のオフセット以降に変更されたデータのみをクエリして処理できます。</p><p>詳細については https://docs.snowflake.com/en/user-guide/streams-intro を参照してください。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ストリーム", "originalCorrect": null, "reviewPoint": ""}}, {"order": 100, "title": "Snowsightに関する正しい記述はどれですか？（2つ選択してください）", "multiSelect": true, "stemHtml": "<p>Snowsightに関する正しい記述はどれですか？（2つ選択してください）</p>", "options": [{"key": "A", "label": "1人のユーザーは特定の時点で1つのクエリしか実行できません。"}, {"key": "B", "label": "Snowsightの各ワークシートは独立したSnowflakeセッションです。"}, {"key": "C", "label": "ワークシートはユーザーのセッションを共有します。"}, {"key": "D", "label": "ユーザーが別のワークシートに切り替えると、Snowflakeセッションが終了します。"}, {"key": "E", "label": "Snowsightの各ワークシートは異なるコンテキスト（ロール、仮想ウェアハウス、データベース、スキーマ）を持つことができます。"}], "correctAnswers": ["B", "E"], "explanationHtml": "<p>✅ <strong>Snowsightの各ワークシートは独立したSnowflakeセッションです / 各ワークシートは異なるコンテキストを持つことができます</strong></p><p>Snowsightの各ワークシートは一意のセッションです。他のワークシートとは異なるコンテキストを持つことができます。ユーザーは必要に応じて複数のワークシートを使用して複数のクエリを実行できます。</p><p>別のワークシートに切り替えてもセッションは終了せず、アクティブのままです。前のワークシートでクエリが実行中であれば、それは継続されます。</p><p>https://docs.snowflake.com/en/user-guide/ui-snowsight-worksheets#change-the-session-context-for-a-worksheet</p><p>https://docs.snowflake.com/en/user-guide/ui-snowsight-worksheets#organizing-worksheets-in-folders</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 101, "title": "半構造化データを最適に格納できるデータ型はどれですか？（3つ選択してください）", "multiSelect": true, "stemHtml": "<p>半構造化データを最適に格納できるデータ型はどれですか？（3つ選択してください）</p>", "options": [{"key": "A", "label": "CHAR"}, {"key": "B", "label": "VARCHAR"}, {"key": "C", "label": "OBJECT"}, {"key": "D", "label": "ARRAY"}, {"key": "E", "label": "VARIANT"}, {"key": "F", "label": "STRING"}], "correctAnswers": ["C", "D", "E"], "explanationHtml": "<p>✅ <strong>OBJECT / ARRAY / VARIANT</strong></p><p>OBJECT、ARRAY、VARIANTは半構造化データの格納と処理に適したデータ型です。</p><p>https://docs.snowflake.com/en/sql-reference/data-types-semistructured</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 102, "title": "データロードの代替として、SnowflakeはデータをロードせずにExternalテーブルの作成...", "multiSelect": false, "stemHtml": "<p>データロードの代替として、SnowflakeはデータをロードせずにExternalテーブルの作成を通じて外部データのクエリを可能にします。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>Snowflakeは外部テーブルを提供しており、外部クラウドストレージに保存されたデータでテーブルを作成することができます。外部テーブルを使用してSnowflakeにロードすることなくデータをクエリできます。 https://docs.snowflake.com/en/user-guide/data-load-overview#external-tables-data-lake</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 103, "title": "永続テーブルは他のどのテーブルタイプにクローンできますか？（該当するものをすべて選択してください...", "multiSelect": true, "stemHtml": "<p>永続テーブルは他のどのテーブルタイプにクローンできますか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "外部テーブル"}, {"key": "B", "label": "一時テーブル"}, {"key": "C", "label": "トランジェントテーブル"}, {"key": "D", "label": "永続テーブル"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>一時テーブル / トランジェントテーブル / 永続テーブル</strong></p><p>永続テーブルは別の永続テーブル、トランジェントテーブル、または一時テーブルにクローンできます。</p><p>ただし、トランジェントテーブルまたは一時テーブルは永続テーブルにクローンできません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 104, "title": "行レベルのセキュリティを実装するには、どのタイプのポリシーを設定すべきですか？", "multiSelect": false, "stemHtml": "<p>行レベルのセキュリティを実装するには、どのタイプのポリシーを設定すべきですか？</p>", "options": [{"key": "A", "label": "マスキングポリシー"}, {"key": "B", "label": "オブジェクトポリシー"}, {"key": "C", "label": "テーブルポリシー"}, {"key": "D", "label": "行アクセスポリシー"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>行アクセスポリシー</strong></p><p>行レベルのセキュリティは行アクセスポリシーを作成することで実装され、クエリ実行時にどの行が返されるかを管理する条件と関数を含みます。 https://docs.snowflake.com/en/user-guide/security-row-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 105, "title": "真か偽：テーブルにクラスタリングキーが定義されている場合、クラスタリングキーに従ってマイクロパー...", "multiSelect": false, "stemHtml": "<p>真か偽：テーブルにクラスタリングキーが定義されている場合、クラスタリングキーに従ってマイクロパーティションを維持・再編成するためのコストが発生します。</p>", "options": [{"key": "A", "label": "真"}, {"key": "B", "label": "偽"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>クラスタリングキーが定義されたテーブルに対して、SnowflakeサービスのAutomatic Clusteringがクラスタリングキーによってデータを分配して適切なパーティションプルーニングを実現するために必要に応じてマイクロパーティションを再クラスター化します。Snowflakeはクラスター化されたテーブルと自動クラスタリングに必要なリソースを内部的に維持します。Automatic Clusteringは再クラスタリングプロセスから恩恵を受けるマイクロパーティションのみを調整します。Automatic Clusteringには仮想ウェアハウスは必要ありませんが、Snowflake管理のCPU、RAMなどを使用します。したがって、サーバーレスコストとして表示されるべきコストが関連しています。テーブルのクラスター化はSnowflakeの他のデータ変更（DML）アクションと同様にクレジットを使用します。再クラスタリングはデータが物理的に再配布されて新しいマイクロパーティションが作成される際にストレージを追加します。元のマイクロパーティションはタイムトラベルとフェイルセーフのために保持され、結果としてストレージが増加します。 https://docs.snowflake.com/en/user-guide/tables-auto-reclustering#credit-usage-and-warehouses-for-automatic-clustering</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 106, "title": "Snowflakeで実行するのに適したユースケースはどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflakeで実行するのに適したユースケースはどれですか？</p>", "options": [{"key": "A", "label": "データサイエンス処理"}, {"key": "B", "label": "データ共有"}, {"key": "C", "label": "データウェアハウス実装"}, {"key": "D", "label": "組み込みデータベースとしての使用"}, {"key": "E", "label": "データレイク実装"}], "correctAnswers": ["A", "B", "C", "E"], "explanationHtml": "<p>✅ <strong>データサイエンス処理 / データ共有 / データウェアハウス実装 / データレイク実装</strong></p><p>Snowflakeはデータレイク、データウェアハウス、データレイクハウスの実装、データサイエンスワークロードの実行、データエンジニアリングプロセスの実行、ビジネスインテリジェンス、アドホック分析、データ共有などのための分析データベースです。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 107, "title": "PUTコマンドは次のどのシナリオで使用できますか？", "multiSelect": false, "stemHtml": "<p>PUTコマンドは次のどのシナリオで使用できますか？</p>", "options": [{"key": "A", "label": "Snowflake内部ステージからSnowflakeテーブルにデータをロードする。"}, {"key": "B", "label": "Snowflake外部ステージからSnowflakeテーブルにデータをロードする。"}, {"key": "C", "label": "Snowflake Web UIからデータをロードする。"}, {"key": "D", "label": "オンプレミスシステムからSnowflakeステージにデータを転送する。"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>オンプレミスシステムからSnowflakeステージにデータを転送する</strong></p><p>PUTコマンドはオンプレミスシステムから内部ステージにデータをアップロードします。GETコマンドは内部ステージからオンプレミスシステムにデータをダウンロードするために使用されます。外部ステージのデータをダウンロードまたはアップロードするには、外部ステージが指すクラウドストレージのデータを操作するためにクラウドプロバイダーのユーティリティやその他のツールが使用されます。 https://docs.snowflake.com/en/user-guide/data-unload-overview#bulk-unloading-process</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 108, "title": "MARKETINGという名前のデータベースを考えます。このデータベースにはPUBLICスキーマに...", "multiSelect": true, "stemHtml": "<p>MARKETINGという名前のデータベースを考えます。このデータベースにはPUBLICスキーマにCUSTOMERというテーブルがあり、CUSTOMER テーブルには10,000行があります。PUBLICスキーマにはCUSTOMER_COUNTというビューもあり、次の定義を持ちます。</p>", "options": [{"key": "A", "label": "一時テーブルが作成された同じセッションで実行される「SELECT * FROM CUSTOMER_COUNT;」クエリは0を結果として返します。"}, {"key": "B", "label": "一時テーブルが作成された同じセッションで実行される「SELECT * FROM CUSTOMER_COUNT;」クエリは10,000を結果として返します。"}, {"key": "C", "label": "新しいセッションで実行される「SELECT * FROM CUSTOMER_COUNT;」クエリは0行を結果として返します。"}, {"key": "D", "label": "新しいセッションで実行される「SELECT * FROM CUSTOMER_COUNT;」クエリは10,000を結果として返します。"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>同セッションでは0 / 新しいセッションでは10,000</strong></p><p>一時テーブルが永続（またはトランジェント）テーブルと同じ名前でスキーマに作成された場合、一時テーブルはそのセッション内の永続テーブルを効果的に隠します。セッション中のクエリやその他の操作は一時テーブルにのみ影響します。</p><p>この動作はビューにも影響する場合があります。一時テーブルが作成された同じセッションでは、一時テーブルがビューで使用されている永続テーブルを隠し、予期しない結果をもたらす可能性があります。ただし、一時テーブルはそれが作成されたセッションに限定されるため、別のセッションからクエリされるとビューは影響を受けません。</p><p>https://docs.snowflake.com/en/user-guide/tables-temp-transient#potential-naming-conflicts-with-other-table-types</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake's catalog and objects", "originalCorrect": null, "reviewPoint": ""}}, {"order": 109, "title": "クエリプロファイルの統計ボックスに表示される情報はどれですか？（2つ選択してください）", "multiSelect": true, "stemHtml": "<p>クエリプロファイルの統計ボックスに表示される情報はどれですか？（2つ選択してください）</p>", "options": [{"key": "A", "label": "ローカルストレージへのバイトのスピル"}, {"key": "B", "label": "オペレーターツリー"}, {"key": "C", "label": "クエリステップ"}, {"key": "D", "label": "リモートストレージへのバイトのスピル"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>ローカルストレージへのバイトのスピル / リモートストレージへのバイトのスピル</strong></p><p>詳細については以下のリンクを参照してください。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile#statistics</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 110, "title": "COPYコマンドがサポートする変換はどれですか？", "multiSelect": false, "stemHtml": "<p>COPYコマンドがサポートする変換はどれですか？</p>", "options": [{"key": "A", "label": "SUM"}, {"key": "B", "label": "CAST"}, {"key": "C", "label": "AVG"}, {"key": "D", "label": "FLATTEN"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>CAST</strong></p><p>COPYコマンドを使用してテーブルにデータをロードする際、Snowflakeはロード中にデータに対して簡単な変換を実行できます。ロードプロセス中に、COPYコマンドは列の順序の変更、1つ以上の列の省略、指定されたデータ型へのデータのキャスト、値の切り捨てを許可します。ロード中に結合、フィルター、集計、FLATTENの使用などの複雑な変換はサポートされていません。これらは重要なデータ変換ではないためです。したがって、データの結合、フィルタリング、集計はデータがテーブルにロードされた後にのみサポートされます。 https://docs.snowflake.com/en/user-guide/data-load-overview#id2</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 111, "title": "行アクセスポリシーをサポートする最小のSnowflakeエディションはどれですか？", "multiSelect": false, "stemHtml": "<p>行アクセスポリシーをサポートする最小のSnowflakeエディションはどれですか？</p>", "options": [{"key": "A", "label": "Business Critical"}, {"key": "B", "label": "Standard"}, {"key": "C", "label": "Virtual Private Snowflake"}, {"key": "D", "label": "Enterprise"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>Enterprise</strong></p><p>Enterpriseエディションにはスタンダードエディションでは提供されないいくつかの追加機能があります。これにはマルチクラスター仮想ウェアハウス、列レベルのマスキング、行アクセスポリシー、マテリアライズドビュー、Search Optimizationが含まれます。 https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 112, "title": "過去12か月間の各仮想ウェアハウスが使用したクレジットを取得するにはどのアプローチが最適ですか？", "multiSelect": false, "stemHtml": "<p>過去12か月間の各仮想ウェアハウスが使用したクレジットを取得するにはどのアプローチが最適ですか？</p>", "options": [{"key": "A", "label": "ACCOUNT_USAGEスキーマのMETERING_DAILY_HISTORYビューをクエリする。"}, {"key": "B", "label": "ACCOUNT_USAGEスキーマのMETERING_HISTORYビューをクエリする。"}, {"key": "C", "label": "Snowflakeサポートに詳細な仮想ウェアハウスのクレジット使用レポートを提供するよう依頼する。"}, {"key": "D", "label": "ACCOUNT_USAGEスキーマのWAREHOUSE_METERING_HISTORYビューをクエリする。"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>ACCOUNT_USAGEスキーマのWAREHOUSE_METERING_HISTORYビューをクエリする</strong></p><p>ACCOUNT_USAGEスキーマのWAREHOUSE_METERING_HISTORYビューは、システム内の各仮想ウェアハウスのクレジット使用量を時間単位で提供します。このビューは過去365日間の情報を提供します。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage/warehouse_metering_history</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 113, "title": "Snowflakeがサポートするセキュリティ機能はどれですか？（該当するものをすべて選択してくだ...", "multiSelect": true, "stemHtml": "<p>Snowflakeがサポートするセキュリティ機能はどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "キーローテーション"}, {"key": "B", "label": "MD5による保存データの暗号化"}, {"key": "C", "label": "AES 256ビットによる保存データの暗号化"}, {"key": "D", "label": "Tri-Secret Secure暗号化"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>キーローテーション / AES 256ビットによる保存データの暗号化 / Tri-Secret Secure暗号化</strong></p><p>Snowflakeはすべてのお客様データを保護するための保存データの標準としてAES 256ビット暗号化を使用します。SnowflakeはSnowflake管理キーを30日ごとに自動的にローテーションします。Snowflake管理キーとお客様管理キーを組み合わせると、データを保護する複合マスターキーが生成されます。Tri-Secret Secureはこのキーの組み合わせを説明するために使用される名称です。 https://docs.snowflake.com/en/user-guide/security-encryption-end-to-end</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 114, "title": "Snowflakeは何の間隔で新しいリリースを展開しますか？", "multiSelect": false, "stemHtml": "<p>Snowflakeは何の間隔で新しいリリースを展開しますか？</p>", "options": [{"key": "A", "label": "週次"}, {"key": "B", "label": "月次"}, {"key": "C", "label": "日次"}, {"key": "D", "label": "隔週"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>週次</strong></p><p>Snowflakeは毎週新しいソフトウェアをリリースします。更新はバックグラウンドで行われるため、ダウンタイムや中断はありません。お客様が常に最新バージョンのソフトウェアを使用できるよう、自動リリースにはバグ修正、新機能、その他の変更が含まれる場合があります。 https://docs.snowflake.com/en/user-guide/intro-releases</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント", "originalCorrect": null, "reviewPoint": ""}}, {"order": 115, "title": "Mediumサイズの仮想ウェアハウスのノード数はいくつですか？", "multiSelect": false, "stemHtml": "<p>Mediumサイズの仮想ウェアハウスのノード数はいくつですか？</p>", "options": [{"key": "A", "label": "256"}, {"key": "B", "label": "3"}, {"key": "C", "label": "6"}, {"key": "D", "label": "4"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>4</strong></p><p>X-Smallサイズの仮想ウェアハウスは単一ノードで構成され、Snowflake仮想ウェアハウスで最小のコンフィグレーションです。Smallサイズの仮想ウェアハウスは2つのノードで構成され、Mediumサイズの仮想ウェアハウスは4つのノードで構成されます。クラスターサイズが大きくなるにつれて、そのクラスターのノード数は倍増します。 https://docs.snowflake.com/en/user-guide/warehouses-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 116, "title": "クローンできるオブジェクトはどれですか？（該当するものをすべて選択してください）", "multiSelect": true, "stemHtml": "<p>クローンできるオブジェクトはどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "ステージ"}, {"key": "B", "label": "仮想ウェアハウス"}, {"key": "C", "label": "タスク"}, {"key": "D", "label": "シェア"}, {"key": "E", "label": "ファイル形式"}, {"key": "F", "label": "シーケンス"}], "correctAnswers": ["A", "C", "E", "F"], "explanationHtml": "<p>✅ <strong>ステージ / タスク / ファイル形式 / シーケンス</strong></p><p>仮想ウェアハウスとシェアオブジェクトはクローンできません。テーブル、スキーマ、データベースはクローンできます。クローンできる他のオブジェクトにはステージ、ファイル形式、タスク、シーケンス、ストリームが含まれます。 https://docs.snowflake.com/en/user-guide/object-clone</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 117, "title": "Snowflake Marketplaceに関する正しい記述はどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflake Marketplaceに関する正しい記述はどれですか？</p>", "options": [{"key": "A", "label": "データをSnowflake Marketplaceに公開するには別のSnowflakeアカウントが必要です。"}, {"key": "B", "label": "SnowflakeアカウントはSnowflake Marketplaceからのみデータを消費できます。"}, {"key": "C", "label": "Snowflake Marketplaceに新しいデータセットを公開できるのはSnowflakeのみです。"}, {"key": "D", "label": "どのSnowflakeアカウントもSnowflake Marketplaceでデータを消費または公開できます。"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>どのSnowflakeアカウントもSnowflake Marketplaceでデータを消費または公開できます</strong></p><p>Virtual Private SnowflakeアカウントをA除き、Snowflake MarketplaceはAmazon Web Services、Google Cloud Platform、Microsoft Azureでホストされているすべてのものが利用可能です。いずれのSnowflakeアカウント（VPSアカウントを除く）もデータプロバイダーになり、有料または無料でMarketplaceにデータセットを公開できます。さらに、まずパートナーとして登録して承認済みデータプロバイダーになる必要があります。 https://other-docs.snowflake.com/en/collaboration/collaboration-marketplace-about.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 118, "title": "VARIANT列ではNULL値はリテラル文字列「null」として格納されます。", "multiSelect": false, "stemHtml": "<p>VARIANT列ではNULL値はリテラル文字列「null」として格納されます。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>NULL値はVARIANT列ではリテラル文字列「null」として格納されます。 https://docs.snowflake.com/en/user-guide/semistructured-considerations#null-values</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 119, "title": "Snowflakeが提供するサーバーレス機能はどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflakeが提供するサーバーレス機能はどれですか？</p>", "options": [{"key": "A", "label": "仮想ウェアハウス"}, {"key": "B", "label": "マルチクラスター仮想ウェアハウス"}, {"key": "C", "label": "Snowpipe"}, {"key": "D", "label": "自動クラスタリング"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>Snowpipe / 自動クラスタリング</strong></p><p>Snowpipeは継続的なデータロードのためのサーバーレスサービスです。自動クラスタリングは定義されたクラスタリングキーに従ってテーブルのマイクロパーティションを維持するSnowflake管理のサーバーレスサービスです。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 120, "title": "真か偽：仮想ウェアハウスのサイズが大きくなるにつれて、1秒あたりに消費されるSnowflakeク...", "multiSelect": false, "stemHtml": "<p>真か偽：仮想ウェアハウスのサイズが大きくなるにつれて、1秒あたりに消費されるSnowflakeクレジット量が増加します。</p>", "options": [{"key": "A", "label": "真"}, {"key": "B", "label": "偽"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>消費されるSnowflakeクレジットの数は仮想ウェアハウスのサイズ、実行状態の期間、作成した仮想ウェアハウスの数によって異なります。仮想ウェアハウスのサイズが大きくなるにつれて、1時間または1秒あたりに消費されるクレジット数も増加します。 https://docs.snowflake.com/en/user-guide/warehouses-considerations#how-are-credits-charged-for-warehouses</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 121, "title": "真か偽：タイムトラベルとフェイルセーフストレージに保存されたデータのストレージコストはお客様に請...", "multiSelect": false, "stemHtml": "<p>真か偽：タイムトラベルとフェイルセーフストレージに保存されたデータのストレージコストはお客様に請求されます。</p>", "options": [{"key": "A", "label": "偽"}, {"key": "B", "label": "真"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真</strong></p><p>Snowflakeはタイムトラベルとフェイルセーフのデータストレージを請求します。タイムトラベルとフェイルセーフのデータ維持コストは、維持日数と最後に変更された時刻からの経過時間に基づいて24時間ごとに計算されます。 https://docs.snowflake.com/en/user-guide/data-cdp-storage-costs</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 122, "title": "Snowflake Scriptingがサポートするのはどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflake Scriptingがサポートするのはどれですか？</p>", "options": [{"key": "A", "label": "例外処理"}, {"key": "B", "label": "IF-ELSEやCASEステートメントなどの分岐構造"}, {"key": "C", "label": "FOR、WHILE、REPEAT、LOOPなどのループ構造"}, {"key": "D", "label": "変数の宣言と使用"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>例外処理 / 分岐構造 / ループ構造 / 変数の宣言と使用</strong></p><p>これらはすべてSnowflake Scriptingでサポートされています。Snowflake Scriptingでは変数の使用、if-else式、ループ、カーソル、結果セットの管理、エラー処理ができます。Snowflake Scriptingは通常ストアドプロシージャの作成に使用されますが、ストアドプロシージャ以外でも手続き型コードを作成するために使用できます。 https://docs.snowflake.com/en/developer-guide/snowflake-scripting/index</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 123, "title": "仮想ウェアハウスが実行中で複雑なクエリを実行しています。管理者が仮想ウェアハウスのサイズを大きく...", "multiSelect": true, "stemHtml": "<p>仮想ウェアハウスが実行中で複雑なクエリを実行しています。管理者が仮想ウェアハウスのサイズを大きくしました。実行中のクエリと将来のクエリへの影響を最もよく説明しているのはどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "実行中のクエリへの影響はありません。"}, {"key": "B", "label": "現在のクエリはリサイズ操作後すぐに追加されたノードを使用し始めます。"}, {"key": "C", "label": "既存の実行中のクエリは停止し、仮想ウェアハウスがリサイズされた後に再送されます。"}, {"key": "D", "label": "将来のクエリのみが増加したサイズを活用できます。"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>実行中のクエリへの影響はありません / 将来のクエリのみが増加したサイズを活用できます</strong></p><p>仮想ウェアハウスがリサイズされると、現在実行中のクエリは影響を受けません。新しいクエリのみが新しいサイズの影響を受けます。 https://docs.snowflake.com/en/user-guide/warehouses-tasks#resizing-a-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 124, "title": "クエリプロファイルによって容易に特定できるパフォーマンスの問題はどれですか？（2つ選択してくださ...", "multiSelect": true, "stemHtml": "<p>クエリプロファイルによって容易に特定できるパフォーマンスの問題はどれですか？（2つ選択してください）</p>", "options": [{"key": "A", "label": "ウィンドウ関数の不正な使用"}, {"key": "B", "label": "ALL句なしのUNION"}, {"key": "C", "label": "爆発的な結合（Exploding joins）"}, {"key": "D", "label": "GROUP BY句のフィールドが多すぎる"}, {"key": "E", "label": "SELECT句のフィールドが多すぎる"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>ALL句なしのUNION / 爆発的な結合（Exploding joins）</strong></p><p>クエリプロファイルを使用して特定できる典型的なパフォーマンスの問題には、爆発的な結合、ALL句なしのUNION、メモリに収まらないクエリ、パーティションプルーニングの問題が含まれます。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile#common-query-problems-identified-by-query-profile</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 125, "title": "Snowflakeに標準で用意されているロールはどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflakeに標準で用意されているロールはどれですか？</p>", "options": [{"key": "A", "label": "PUBLIC"}, {"key": "B", "label": "ORGADMIN"}, {"key": "C", "label": "SUPERUSER"}, {"key": "D", "label": "SYSADMIN"}], "correctAnswers": ["A", "B", "D"], "explanationHtml": "<p>✅ <strong>PUBLIC / ORGADMIN / SYSADMIN</strong></p><p>Snowflakeの組み込みロールにはORGADMIN、ACCOUNTADMIN、USERADMIN、SECURITYADMIN、SYSADMIN、PUBLICがあります。 https://docs.snowflake.com/en/user-guide/security-access-control-overview#system-defined-roles.</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 126, "title": "データベースとテーブルのクローニングは次のどのシナリオを満たすために使用できますか？（該当するも...", "multiSelect": true, "stemHtml": "<p>データベースとテーブルのクローニングは次のどのシナリオを満たすために使用できますか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "本番オブジェクトのクローンを作成して非本番データベースを素早く作成する。"}, {"key": "B", "label": "データを段階的にロードする。"}, {"key": "C", "label": "JOINパフォーマンスを改善する。"}, {"key": "D", "label": "重要なデータベースのバックアップを作成する。"}, {"key": "E", "label": "SELECTクエリのパフォーマンスを改善する。"}, {"key": "F", "label": "タイムトラベルを使用してポイントインタイムバックアップを作成する。"}], "correctAnswers": ["A", "D", "F"], "explanationHtml": "<p>✅ <strong>本番オブジェクトのクローンで非本番DBを素早く作成 / 重要なデータベースのバックアップを作成 / タイムトラベルを使用してポイントインタイムバックアップを作成</strong></p><p>Snowflakeのクローニングにより、データベース、スキーマ、またはテーブルのコピーを作成することで開発・テスト環境を素早く構築できます。</p><p>SnowflakeのTime Travel機能を使用すると、保持期間内の特定の時点でデータにアクセスしてクローンを作成できます。タイムトラベルとクローニングを活用することで、特定のシナリオや過去のデータ状態を反映するテスト環境を作成できます。</p><p>Time Travelは自動的にバックアップ・リカバリ機能を提供しますが、最大データ保持期間（最大90日）に制限されています。したがって、Snowflakeで定期的なバックアップを実行することは依然として必要です。Snowflakeでデータをバックアップする方法の1つは個々のテーブルからクラウドストレージにデータをエクスポートすることですが、SnowflakeのクローニングマJEcapabilities能を利用して重要なデータベースのバックアップを実行することもできます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 127, "title": "Snowflakeのリソースモニターに関する正しい記述はどれですか？（該当するものをすべて選択し...", "multiSelect": true, "stemHtml": "<p>Snowflakeのリソースモニターに関する正しい記述はどれですか？（該当するものをすべて選択してください）</p>", "options": [{"key": "A", "label": "リソースモニターは高精度でクレジット使用量を制御できます。"}, {"key": "B", "label": "リソースモニターは分単位でクレジット使用量を監視できます。"}, {"key": "C", "label": "リソースモニターは使用できるクレジットに対して高精度の制限を設定することを意図していません。"}, {"key": "D", "label": "リソースモニターは1時間ごとの正確なクレジット使用量を制御することを意図していません。"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>高精度の制限は意図していません / 1時間ごとの正確な制御は意図していません</strong></p><p>リソースモニターは1時間（または1分）ごとの使用量を正確に制御することを意図していません。代わりに、毎日、毎週、毎月などの使用量を追跡・制御することを意図しています。使用できるクレジットの厳密な制限を設定するためのものではありません。リソースモニターのクレジット制限に達した場合、アクションが「Suspend Immediately」であっても、割り当てられたウェアハウスが保留になるまで時間がかかる場合があり、クレジット制限よりも多くのクレジットが使用される可能性があります。</p><p>https://docs.snowflake.com/en/user-guide/resource-monitors</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}]}, {"slug": "05_practice_exam", "title": "SnowPro Core 05_practice_exam", "sourcePath": "01_資格/Snowflake/SnowPro_Core/問題/05_practice_exam.md", "metadata": ["問題数: 124問"], "questionCount": 124, "questions": [{"order": 1, "title": "以下のロードメソッドのうち、仮想ウェアハウスのリソースを使用するのはどれですか？", "multiSelect": false, "stemHtml": "<p>以下のロードメソッドのうち、仮想ウェアハウスのリソースを使用するのはどれですか？</p>", "options": [{"key": "A", "label": "COPYコマンド"}, {"key": "B", "label": "Snowpipe"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>COPYコマンド</strong></p><p>COPYコマンドは仮想ウェアハウスのリソースを使用します。Snowpipeは別途課金され、仮想ウェアハウスのリソースを使用しません。Snowpipeはサーバーレスであり、独自のコンピューティング能力を持ちます。そのため、処理に仮想ウェアハウスを必要としません。SnowflakeはSnowpipeが必要とするコンピューティングを自動的に管理し、データロード要件に応じてSnowpipeのスケールアップ・ダウンも管理します。Snowpipeはサーバーレスであるため、そのコストは仮想ウェアハウスの費用とは別に課金されます。https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 2, "title": "Snowflakeの顧客はどのような基準でクレジット使用量を請求されますか？", "multiSelect": false, "stemHtml": "<p>Snowflakeの顧客はどのような基準でクレジット使用量を請求されますか？</p>", "options": [{"key": "A", "label": "1分単位"}, {"key": "B", "label": "1日単位"}, {"key": "C", "label": "1ナノ秒単位"}, {"key": "D", "label": "1時間単位"}, {"key": "E", "label": "1秒単位"}], "correctAnswers": ["E"], "explanationHtml": "<p>✅ <strong>1秒単位</strong></p><p>Snowflakeのクレジットは1秒単位の使用量で請求されます。つまり、仮想ウェアハウスが1分45秒稼働した場合、105秒分（60+45）が課金されます。ただし、最低60秒の請求が適用されるため、最初の1分以内に仮想ウェアハウスが起動・停止された場合でも、最低60秒分のクレジット使用量が適用されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 3, "title": "以下のうち、Snowflakeが提供する組み込みロールではないものはどれですか？", "multiSelect": false, "stemHtml": "<p>以下のうち、Snowflakeが提供する組み込みロールではないものはどれですか？</p>", "options": [{"key": "A", "label": "ACCOUNTADMIN"}, {"key": "B", "label": "SUPERADMIN"}, {"key": "C", "label": "SECURITYADMIN"}, {"key": "D", "label": "USERADMIN"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>SUPERADMIN</strong></p><p>Snowflakeには以下のロールが事前設定されています。ACCOUNTADMINはフル権限のアカウント管理者ロールです。USERADMINはUSERSとROLESを作成する機能を提供します。SECURITYADMINはUSERADMINから権限を継承し、グローバルなオブジェクト付与を管理できます。SYSADMINはSnowflakeオブジェクトの大部分を作成・管理できます。ORGADMINは組織レベルの運用を管理します。また、すべてのユーザーに自動的に割り当てられるPUBLICロールも存在します。https://docs.snowflake.com/en/user-guide/security-access-control-overview#system-defined-roles</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 4, "title": "以下のSnowflake機能のうち、テーブルの変更追跡メタデータに依存するものはどれですか？（2...", "multiSelect": true, "stemHtml": "<p>以下のSnowflake機能のうち、テーブルの変更追跡メタデータに依存するものはどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "Streamオブジェクト"}, {"key": "B", "label": "CHANGES句"}, {"key": "C", "label": "JOIN句"}, {"key": "D", "label": "FETCH句"}, {"key": "E", "label": "Snowpipeオブジェクト"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>Streamオブジェクト / CHANGES句</strong></p><p>StreamオブジェクトとCHANGES句はどちらもテーブルの変更追跡メタデータを利用します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ストリーム", "originalCorrect": null, "reviewPoint": ""}}, {"order": 5, "title": "Snowflakeアカウントのストレージコストの計算において考慮される項目はどれですか？（該当す...", "multiSelect": true, "stemHtml": "<p>Snowflakeアカウントのストレージコストの計算において考慮される項目はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "非圧縮データ"}, {"key": "B", "label": "圧縮データ"}, {"key": "C", "label": "月中の使用ストレージ合計量"}, {"key": "D", "label": "月中の使用ストレージの日次平均"}, {"key": "E", "label": "月末時点の保存データ量"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>圧縮データ / 月中の使用ストレージの日次平均</strong></p><p>Snowflakeのストレージコストは、月中の使用ストレージの平均量に基づいて計算されます。計算は、データに圧縮が適用された後の保存データ量をもとに行われます。https://docs.snowflake.com/en/user-guide/cost-understanding-overall</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "コストと価格", "originalCorrect": null, "reviewPoint": ""}}, {"order": 6, "title": "真偽問題：必要に応じて、特定のテーブルに対してマイクロパーティションを無効にすることができる。", "multiSelect": false, "stemHtml": "<p>真偽問題：必要に応じて、特定のテーブルに対してマイクロパーティションを無効にすることができる。</p>", "options": [{"key": "A", "label": "偽（False）"}, {"key": "B", "label": "真（True）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>偽（False）</strong></p><p>マイクロパーティションは無効にすることができず、Snowflakeによって自動的に管理されます。クラスタリングキーのみ制御可能であり、これによってマイクロパーティションのアプローチは変わりますが、無効にすることはできません。https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 7, "title": "Snowflake Standard エディションで許可されるタイムトラベルの最大期間はどれくら...", "multiSelect": false, "stemHtml": "<p>Snowflake Standard エディションで許可されるタイムトラベルの最大期間はどれくらいですか？</p>", "options": [{"key": "A", "label": "0日"}, {"key": "B", "label": "1日"}, {"key": "C", "label": "45日"}, {"key": "D", "label": "90日"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>1日</strong></p><p>Snowflakeエディションによって、タイムトラベルの期間は1〜90日の範囲となります。Standardエディションでは1日のタイムトラベルが可能です。Enterpriseエディション以上では最大90日のタイムトラベルが可能です。https://docs.snowflake.com/en/user-guide/data-time-travel#data-retention-period</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 8, "title": "Alation、Immuta、CollibraはSnowflakeパートナーエコシステムにおいて...", "multiSelect": false, "stemHtml": "<p>Alation、Immuta、CollibraはSnowflakeパートナーエコシステムにおいてどのような種類のパートナーですか？</p>", "options": [{"key": "A", "label": "データインテグレーション"}, {"key": "B", "label": "SQL開発と管理"}, {"key": "C", "label": "機械学習とデータサイエンス"}, {"key": "D", "label": "セキュリティ、ガバナンスと可観測性"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>セキュリティ、ガバナンスと可観測性</strong></p><p>これらはすべてSnowflakeのセキュリティ、ガバナンスと可観測性パートナーです。https://docs.Snowflake.com/en/user-guide/ecosystem.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パートナー", "originalCorrect": null, "reviewPoint": ""}}, {"order": 9, "title": "行アクセスポリシーを作成する理由として正しいものはどれですか？", "multiSelect": false, "stemHtml": "<p>行アクセスポリシーを作成する理由として正しいものはどれですか？</p>", "options": [{"key": "A", "label": "ユーザーが特権ロールに切り替えるのを防ぐため"}, {"key": "B", "label": "テーブルへのデータロード操作を防ぐため"}, {"key": "C", "label": "ユーザーがテーブルに対してDML操作を行うのを防ぐため"}, {"key": "D", "label": "クエリによってテーブルから返される行を制御するため"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>クエリによってテーブルから返される行を制御するため</strong></p><p>行レベルセキュリティ（RLS）は、特定の行のみを返すために使用できます。RLSは行アクセスポリシーを作成することで実装され、クエリ実行中にどの行が返されるかを管理する条件や関数が含まれます。https://docs.snowflake.com/en/user-guide/security-row-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 10, "title": "フェデレーション認証をサポートするSnowflakeの最小エディションはどれですか？", "multiSelect": false, "stemHtml": "<p>フェデレーション認証をサポートするSnowflakeの最小エディションはどれですか？</p>", "options": [{"key": "A", "label": "Business Critical"}, {"key": "B", "label": "Enterprise"}, {"key": "C", "label": "Standard"}, {"key": "D", "label": "Virtual Private Snowflake"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>フェデレーション認証はすべてのSnowflakeエディションでサポートされているため、最小エディションはStandardです。https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 11, "title": "仮想ウェアハウスのクレジット使用量を管理するのに役立つものはどれですか？", "multiSelect": false, "stemHtml": "<p>仮想ウェアハウスのクレジット使用量を管理するのに役立つものはどれですか？</p>", "options": [{"key": "A", "label": "クラウド通知"}, {"key": "B", "label": "請求アラート"}, {"key": "C", "label": "リソースモニター"}, {"key": "D", "label": "Snowpark"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>リソースモニター</strong></p><p>リソースモニターは仮想ウェアハウスのコスト管理と予期しないクレジット使用を回避するのに役立ちます。定義された上限に対するクレジット使用量の監視、限度の一定割合に達したときの管理者への通知、必要に応じた仮想ウェアハウスの一時停止などにより、クレジット使用量を制御できます。https://docs.snowflake.com/en/user-guide/resource-monitors</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 12, "title": "真偽問題：COPYコマンドはSELECTクエリを使ってデータをロードできる。", "multiSelect": false, "stemHtml": "<p>真偽問題：COPYコマンドはSELECTクエリを使ってデータをロードできる。</p>", "options": [{"key": "A", "label": "真（True）"}, {"key": "B", "label": "偽（False）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>真（True）</strong></p><p>COPYコマンドを使ってテーブルにデータをロードする際、SnowflakeではSELECT文を使用してデータのロード中に簡単な変換を行うことができます。ロード処理中、COPYコマンドでは列の順序変更、1つ以上の列の省略、指定されたデータ型へのキャスト、およびCOPYコマンドを使ったデータの切り捨てが可能です。https://docs.snowflake.com/en/user-guide/data-load-transform</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 13, "title": "このコースの練習問題が実際の認定試験の問題と同一でない理由はどれですか？", "multiSelect": false, "stemHtml": "<p>このコースの練習問題が実際の認定試験の問題と同一でない理由はどれですか？</p>", "options": [{"key": "A", "label": "特定の問題の丸暗記ではなく、概念の知識と理解を試すため"}, {"key": "B", "label": "生徒が正確な問題と答えを暗記できるようにするため"}, {"key": "C", "label": "コース作成者が実際の試験問題を知らないため"}, {"key": "D", "label": "生徒を意図的に混乱させるために無関係なトピックで試すため"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>特定の問題の丸暗記ではなく、概念の知識と理解を試すため</strong></p><p>このコースは、認定試験に必要な概念とトピックを徹底的に理解するために設計されています。練習問題は、実際の試験の問題を模倣するのではなく、知識をテストし、主題の理解を強化するために作られています。これらの問題は試験の目標に沿っていますが、認定テストの問題と同一ではありません。答えを暗記するのではなく、基礎となる概念を習得することで、あらゆる問題に自信を持って対応できるよう準備するためです。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "（分野記載なし）", "originalCorrect": null, "reviewPoint": ""}}, {"order": 14, "title": "AWSプラットフォームでホストされているSnowflakeアカウントを考えます。このアカウントで...", "multiSelect": true, "stemHtml": "<p>AWSプラットフォームでホストされているSnowflakeアカウントを考えます。このアカウントで作成された外部テーブルは、以下のどこからデータを読み取ることができますか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Amazon S3"}, {"key": "B", "label": "Google Cloud Storage"}, {"key": "C", "label": "Azure Blob Storage"}, {"key": "D", "label": "オンプレミスのSQLサーバーファイル"}, {"key": "E", "label": "オンプレミスのPostgresデータファイル"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>Amazon S3 / Google Cloud Storage / Azure Blob Storage</strong></p><p>Snowflakeアカウントがどのクラウドプラットフォームでホストされているかは関係ありません。Amazon、Azure、Googleなどのサポートされているクラウドプラットフォームのオブジェクトストレージからデータを読み取ることができます。外部テーブルは外部ステージから読み取るように設定されます。外部ステージはクラウドストレージ上のオブジェクトストレージを指し、そこに外部テーブルのデータが含まれます。外部ステージが指すオブジェクトストレージは、Amazon S3、Google Cloud Storage、Azure Blob Storage、およびその他のS3互換ストレージオプションである可能性があります。https://docs.snowflake.com/en/user-guide/tables-external-intro#workflow</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 15, "title": "クラスタリングキーを定義する際、どのような種類の列を検討すべきですか？", "multiSelect": false, "stemHtml": "<p>クラスタリングキーを定義する際、どのような種類の列を検討すべきですか？</p>", "options": [{"key": "A", "label": "非常に低いカーディナリティの列"}, {"key": "B", "label": "非常に高いカーディナリティの列"}, {"key": "C", "label": "効率的なパーティションプルーニングを可能にするのに十分なカーディナリティを持つ列"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>効率的なパーティションプルーニングを可能にするのに十分なカーディナリティを持つ列</strong></p><p>クラスタリングキーを定義する際、初期候補となるクラスタリング列は、WHERE句や他の選択的フィルターで頻繁に使用される列です。また、結合に使用される列も検討できます。さらに、列のカーディナリティ（個別値の数）も重要です。効果的なパーティションプルーニングを可能にするのに十分なカーディナリティを持ちながら、Snowflakeがデータをマイクロパーティションに効率的にグループ化できるよう低いカーディナリティを持つ列を選択することが重要です。個別値が少なすぎる列（例：性別）はパーティションプルーニングがほとんどできません。一方、個別値が多すぎる列（例：顧客ID）はパーティションの維持に過大なオーバーヘッドが発生します。複数列のクラスタキーを作成する場合は、カーディナリティの低い列から高い列の順に並べてください。そうしないとクラスタリングの効果が低下します。https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 16, "title": "タイムトラベルとフェイルセーフには追加のストレージが必要であり、そのストレージに関連するコストが...", "multiSelect": false, "stemHtml": "<p>タイムトラベルとフェイルセーフには追加のストレージが必要であり、そのストレージに関連するコストが発生する。</p>", "options": [{"key": "A", "label": "真（True）"}, {"key": "B", "label": "偽（False）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>真（True）</strong></p><p>Snowflakeは更新または削除されたマイクロパーティションを保持することで、タイムトラベルとフェイルセーフストレージを実現します。これらのマイクロパーティションは、タイムトラベルSQLまたはフェイルセーフストレージを使ったデータ復元のために保持されます。削除または更新されたマイクロパーティションを保持するにはストレージが必要となり、追加コストが発生します。https://docs.snowflake.com/en/user-guide/data-cdp-storage-costs</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 17, "title": "真偽問題：SnowflakeのネットワークポリシーはIPv4のみをサポートしている。", "multiSelect": false, "stemHtml": "<p>真偽問題：SnowflakeのネットワークポリシーはIPv4のみをサポートしている。</p>", "options": [{"key": "A", "label": "真（True）"}, {"key": "B", "label": "偽（False）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>真（True）</strong></p><p>ネットワークポリシーは、ポリシー名、カンマ区切りの許可IPアドレスリスト、および禁止IPアドレスリストで構成されます。許可または禁止IPアドレスリストでは、個別のIPアドレスまたはIPアドレス範囲を指定できますが、ネットワークポリシーは現在IPv4アドレスのみをサポートしています。https://docs.snowflake.com/en/user-guide/network-policies</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 18, "title": "以下のアクティビティのうち、Snowflakeの顧客が実行する必要がないものはどれですか？", "multiSelect": true, "stemHtml": "<p>以下のアクティビティのうち、Snowflakeの顧客が実行する必要がないものはどれですか？</p>", "options": [{"key": "A", "label": "データセンターレベルでSnowflakeデータベースをインストールするためのハードウェアのプロビジョニング"}, {"key": "B", "label": "データセンターレベルのハードウェアの高可用性の設定とテスト"}, {"key": "C", "label": "Snowflakeソフトウェアのインストール"}, {"key": "D", "label": "ユーザーアクセスと権限の管理"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>ハードウェアのプロビジョニング / 高可用性の設定とテスト / Snowflakeソフトウェアのインストール</strong></p><p>Snowflakeはサービスとしてのソフトウェア（SaaS）製品であり、顧客がデータセンター、ハードウェアのインストール、ソフトウェアの管理、または高可用性の管理を行う必要はありません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 19, "title": "真偽問題：COPYコマンドはデータのロード中に単純または基本的な変換のみを許可する。", "multiSelect": false, "stemHtml": "<p>真偽問題：COPYコマンドはデータのロード中に単純または基本的な変換のみを許可する。</p>", "options": [{"key": "A", "label": "偽（False）"}, {"key": "B", "label": "真（True）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真（True）</strong></p><p>COPYコマンドを使ってテーブルにデータをロードする際、Snowflakeではロード中に簡単な変換を行うことができます。ロード処理中、COPYコマンドでは列の順序変更、1つ以上の列の省略、指定されたデータ型へのキャスト、および値の切り捨てが可能です。ロード中、結合、フィルター、集計、FLATTENの使用などの複雑な変換はサポートされていません。これらは必須のデータ変換ではないためです。したがって、データの結合、フィルタリング、集計はデータがテーブルにロードされた後にのみサポートされます。https://docs.snowflake.com/en/user-guide/data-load-overview#id2</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 20, "title": "JavaでユーザーDefinedFunctions（UDFs）を作成するために必要なSnowfl...", "multiSelect": false, "stemHtml": "<p>JavaでユーザーDefinedFunctions（UDFs）を作成するために必要なSnowflakeの最小エディションはどれですか？</p>", "options": [{"key": "A", "label": "Enterprise"}, {"key": "B", "label": "Business Critical"}, {"key": "C", "label": "Virtual Private Snowflake"}, {"key": "D", "label": "Standard"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>UDFはすべてのSnowflakeエディションでサポートされているため、サポートする最小エディションはStandardエディションです。https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 21, "title": "Snowflakeのロールについて正しい記述はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeのロールについて正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "使用できるのはSnowflakeの組み込みロールのみで、新しいカスタムロールは作成できない"}, {"key": "B", "label": "ユーザーは1つ以上のロールを割り当てることができる"}, {"key": "C", "label": "ユーザーは1つのロールのみ割り当てることができる"}, {"key": "D", "label": "すべてのユーザーには自動的にPUBLICロールが付与される"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>ユーザーは1つ以上のロールを割り当てることができる / すべてのユーザーには自動的にPUBLICロールが付与される</strong></p><p>Snowflakeのアクセス制御は、ロールに権限を割り当て、ユーザーにロールを割り当てるロールベースアクセス制御（RBAC）アプローチに基づいています。ロールに付与された権限は、そのロールのすべてのユーザーに継承されます。PUBLICロールは最も少ない権限を持ち、すべてのユーザーに自動的に割り当てられます。https://docs.snowflake.com/en/user-guide/security-access-control-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 22, "title": "Snowflakeにおけるテーブル列の保存方法について正しい記述はどれですか？（該当するものをす...", "multiSelect": true, "stemHtml": "<p>Snowflakeにおけるテーブル列の保存方法について正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Snowflakeは各列に対して最適な圧縮アルゴリズムを自動的に決定する"}, {"key": "B", "label": "列は各マイクロパーティション内に列指向形式で保存される"}, {"key": "C", "label": "列指向形式でデータを保存することで、Snowflakeはクエリ実行中に不要な列を除外できる"}, {"key": "D", "label": "各列のデータは個別に圧縮される"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>Snowflakeは各列に対して最適な圧縮アルゴリズムを自動的に決定する / 列は各マイクロパーティション内に列指向形式で保存される / 列指向形式でデータを保存することで、Snowflakeはクエリ実行中に不要な列を除外できる / 各列のデータは個別に圧縮される</strong></p><p>これらはすべて正しいです。Snowflakeは各マイクロパーティション内で列を列指向形式で保存します。列指向形式により、Snowflakeは参照された列のみを取得することでクエリを最適化できます。また、マイクロパーティションの圧縮に加えて、マイクロパーティション内の各列は独立して圧縮されます。Snowflakeは各列に対して最適な圧縮アルゴリズムを選択します。https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 23, "title": "フェイルセーフストレージからデータを回復するためにSnowflakeサポートへの依頼が必要なシナ...", "multiSelect": false, "stemHtml": "<p>フェイルセーフストレージからデータを回復するためにSnowflakeサポートへの依頼が必要なシナリオはどれですか？</p>", "options": [{"key": "A", "label": "93日前に3つの本番テーブルを破損させたデータ破損問題が発見された"}, {"key": "B", "label": "昨日本番環境に展開された新しいデータパイプラインが本番テーブルのすべての行を削除した"}, {"key": "C", "label": "管理者が先週本番テーブルを誤って削除した"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>93日前に3つの本番テーブルを破損させたデータ破損問題が発見された</strong></p><p>タイムトラベルの最大期間、つまり90日より前のデータ問題からは回復できません。フェイルセーフストレージからデータを回復するには、Snowflakeサポートに依頼する必要があります。削除されたデータやドロップされたテーブルに関する他のシナリオでは、タイムトラベルで十分対応できます。https://docs.snowflake.com/en/user-guide/data-failsafe</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 24, "title": "以下の図のうち、同じクラスタリング深度を持つテーブルを表しているものはどれですか？（該当するもの...", "multiSelect": true, "stemHtml": "<p>以下の図のうち、同じクラスタリング深度を持つテーブルを表しているものはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "4"}, {"key": "B", "label": "3"}, {"key": "C", "label": "1"}, {"key": "D", "label": "2"}], "correctAnswers": ["A", "B", "D"], "explanationHtml": "<p>✅ <strong>4 / 3 / 2</strong></p><p>テーブルが存在する場合、クラスタリング深度は特定の列に対するマイクロパーティションの重複の平均深度です。クラスタリング深度は1（適切にクラスタリングされたテーブル）から始まり、より大きな数値になる場合があります。平均深度が小さいほど、指定された列のデータが適切にクラスタリングされています。https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions#label-clustering-depth</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 25, "title": "SECURITYADMINロールに関して正しい記述はどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>SECURITYADMINロールに関して正しい記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "SECURITYADMINロールを持つユーザーは新しいロールを作成できる"}, {"key": "B", "label": "SECURITYADMINを持つユーザーは新しいReaderアカウントを作成できる"}, {"key": "C", "label": "SECURITYADMINロールを持つユーザーは新しいユーザーを作成できる"}, {"key": "D", "label": "SECURITYADMINロールを持つユーザーはオブジェクト付与を管理できる"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>SECURITYADMINロールを持つユーザーは新しいロールを作成できる / SECURITYADMINロールを持つユーザーは新しいユーザーを作成できる / SECURITYADMINロールを持つユーザーはオブジェクト付与を管理できる</strong></p><p>SECURITYADMINは、組織のUSERSとROLESを作成するUSERADMINの権限を継承します。さらに、このロールはシステム全体のオブジェクト付与も制御できます。https://docs.snowflake.com/en/user-guide/security-access-control-overview#system-defined-roles</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 26, "title": "マテリアライズドビューを正しく説明しているものはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューを正しく説明しているものはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "マテリアライズドビューはSQL文の結果を事前計算する"}, {"key": "B", "label": "マテリアライズドビューはセカンダリインデックスのようなものである"}, {"key": "C", "label": "マテリアライズドビューはクエリが使用するたびに結果を再計算する"}, {"key": "D", "label": "マテリアライズドビューは結果を物理的に保存する"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>マテリアライズドビューはSQL文の結果を事前計算する / マテリアライズドビューは結果を物理的に保存する</strong></p><p>マテリアライズドビューは、SELECTクエリに基づいてデータを事前計算するビューです。クエリの結果は事前計算されて物理的に保存され、将来実行される同様のクエリのパフォーマンスを向上させます。基となるテーブルが更新されると、マテリアライズドビューは自動的に更新され、追加のメンテナンスは不要です。Snowflakeが管理するサービスがユーザーのエクスペリエンスを妨げることなく、バックグラウンドで更新を実行します。https://docs.snowflake.com/en/user-guide/views-materialized</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 27, "title": "仮想ウェアハウスがスケールダウンされた場合、ノードはいつ仮想ウェアハウスから削除されますか？", "multiSelect": false, "stemHtml": "<p>仮想ウェアハウスがスケールダウンされた場合、ノードはいつ仮想ウェアハウスから削除されますか？</p>", "options": [{"key": "A", "label": "仮想ウェアハウスが一時停止されたとき"}, {"key": "B", "label": "60秒後"}, {"key": "C", "label": "既存のすべてのアクティブなクエリが実行を完了した後"}, {"key": "D", "label": "即時"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>既存のすべてのアクティブなクエリが実行を完了した後</strong></p><p>仮想ウェアハウスがスケールダウンされる際、ノードはクエリを実行していない状態になった場合にのみ仮想ウェアハウスから削除されます。https://docs.snowflake.com/en/user-guide/warehouses-tasks#resizing-a-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 28, "title": "エコノミースケーリングポリシーを使用する自動スケールモードのマルチクラスター仮想ウェアハウスにお...", "multiSelect": false, "stemHtml": "<p>エコノミースケーリングポリシーを使用する自動スケールモードのマルチクラスター仮想ウェアハウスにおいて、別のクラスターが起動する前にクエリはキューでどれくらい待機しますか？</p>", "options": [{"key": "A", "label": "6分"}, {"key": "B", "label": "2分"}, {"key": "C", "label": "1分"}, {"key": "D", "label": "10分"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>6分</strong></p><p>スケーリングポリシーがエコノミーに設定されている場合、パフォーマンスよりもコスト節約を優先して、スケールアップ前にキューが一定時間続くことを許可します。新しい仮想ウェアハウスは、システムが新しいウェアハウスを少なくとも6分間稼働させ続けるのに十分なクエリワークロードがあると判断した場合にのみ起動されます。スケールダウン時、システムは別のウェアハウスを再度起動することなくワークロードを他のウェアハウスに再配分できるかどうかを5〜6回連続でチェックします。条件が満たされると、仮想ウェアハウスはスケールダウンされます。これらのチェックは1分間隔で実行されます。https://docs.snowflake.com/en/user-guide/warehouses-multicluster#setting-the-scaling-policy-for-a-multi-cluster-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 29, "title": "外部ステージからオンプレミスシステムにデータをダウンロードするために使用できるものはどれですか？", "multiSelect": false, "stemHtml": "<p>外部ステージからオンプレミスシステムにデータをダウンロードするために使用できるものはどれですか？</p>", "options": [{"key": "A", "label": "COPY"}, {"key": "B", "label": "GET"}, {"key": "C", "label": "PUT"}, {"key": "D", "label": "クラウドプロバイダーユーティリティ"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>クラウドプロバイダーユーティリティ</strong></p><p>GETコマンドは内部ステージからオンプレミスシステムにデータをダウンロードするために使用されます。PUTコマンドはオンプレミスシステムから内部ステージにデータをアップロードします。外部ステージとの間でデータをダウンロードまたはアップロードするには、外部ステージが指すクラウドストレージのデータを操作するために、クラウドプロバイダーユーティリティやその他のツールを使用します。https://docs.snowflake.com/en/user-guide/data-unload-overview#bulk-unloading-process</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 30, "title": "COPYコマンドはテーブルからデータを以下のどの場所にアンロードできますか？（該当するものをすべ...", "multiSelect": true, "stemHtml": "<p>COPYコマンドはテーブルからデータを以下のどの場所にアンロードできますか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "外部ステージ"}, {"key": "B", "label": "ローカルNAS"}, {"key": "C", "label": "オンプレミスシステム"}, {"key": "D", "label": "名前付き内部ステージ"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>外部ステージ / 名前付き内部ステージ</strong></p><p>データウェアハウスがステージングを使用するのと同様に、Snowflakeはステージオブジェクトを使用します。Snowflakeはデータのロードとアンロードを支援するためにステージを使用します。Snowflakeテーブルにデータをロードするには、まずSnowflakeステージにデータを用意する必要があります。データがステージにロードされた後、COPYコマンドを使ってテーブルにデータをロードできます。データのアンロードまたはエクスポートもステージオブジェクトを介して行われます。データは内部または外部のステージにのみ抽出できます。https://docs.snowflake.com/en/user-guide/data-load-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 31, "title": "クエリ仕様から派生し、結果が後で使用するために保存され、大きなテーブルの高コストな集計を高速化す...", "multiSelect": false, "stemHtml": "<p>クエリ仕様から派生し、結果が後で使用するために保存され、大きなテーブルの高コストな集計を高速化するために使用できるSnowflakeデータベースオブジェクトはどれですか？</p>", "options": [{"key": "A", "label": "セキュアビュー"}, {"key": "B", "label": "出力ビュー"}, {"key": "C", "label": "ビュー"}, {"key": "D", "label": "マテリアライズドビュー"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>マテリアライズドビュー</strong></p><p>マテリアライズドビューは、SELECTクエリに基づいてデータを事前計算するビューです。クエリの結果は事前計算されて物理的に保存され、将来実行される同様のクエリのパフォーマンスを向上させます。基となるテーブルが更新されると、マテリアライズドビューは自動的に更新され、追加のメンテナンスは不要です。Snowflakeが管理するサービスがユーザーのエクスペリエンスを妨げることなく、バックグラウンドで更新を実行します。https://docs.snowflake.com/en/user-guide/views-materialized</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 32, "title": "Snowflakeのデータクラスタリングについて正しい記述はどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflakeのデータクラスタリングについて正しい記述はどれですか？</p>", "options": [{"key": "A", "label": "Snowflakeはテーブルにデータを自動的にクラスタリングする"}, {"key": "B", "label": "Snowflakeテーブルのデータは再クラスタリングできない"}, {"key": "C", "label": "Snowflakeはテーブルデータを自動的にクラスタリングしない"}, {"key": "D", "label": "必要に応じて、クラスタリングキーを定義してデータを再クラスタリングまたは再構成できる"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>Snowflakeはテーブルにデータを自動的にクラスタリングする / 必要に応じて、クラスタリングキーを定義してデータを再クラスタリングまたは再構成できる</strong></p><p>Snowflakeはテーブルにデータが追加されると自動的にクラスタリングします。クラスタリングキーを手動で指定し、そのキーに基づいてデータを再配布することも可能です。https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 33, "title": "Snowflakeでタスクを作成するためにユーザーが必要とする権限はどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeでタスクを作成するためにユーザーが必要とする権限はどれですか？</p>", "options": [{"key": "A", "label": "タスクを作成できるのはACCOUNTADMINロールのみであるため、ユーザーはACCOUNTADMINロールを持っている必要がある"}, {"key": "B", "label": "ユーザーは特定の権限なしにタスクを作成・実行できる"}, {"key": "C", "label": "ユーザーは新しいタスクを作成するためにグローバルなEXECUTE MANAGED TASK権限を持っている必要がある"}, {"key": "D", "label": "ユーザーはタスクが作成されるスキーマへのアクセス権と「CREATE TASK」権限を持っている必要がある"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>ユーザーはタスクが作成されるスキーマへのアクセス権と「CREATE TASK」権限を持っている必要がある</strong></p><p>Snowflakeでタスクを作成するには特定の権限が必要です。ロールは、タスクが配置される親データベースとターゲットスキーマの両方に対するUSAGE権限を持っている必要があります。さらに、そのスキーマに対するCREATE TASK権限も必要です。これは、ユーザーが必要なアクセス権を付与されたスキーマにのみタスクを作成できることを意味し、タスクが許可された場所にのみ作成されることを保証します。https://docs.snowflake.com/en/sql-reference/sql/create-task</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タスク", "originalCorrect": null, "reviewPoint": ""}}, {"order": 34, "title": "以下のテーブルタイプのうち、フェイルセーフストレージで保護されないものはどれですか？（該当するも...", "multiSelect": true, "stemHtml": "<p>以下のテーブルタイプのうち、フェイルセーフストレージで保護されないものはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "永続テーブル（Permanent）"}, {"key": "B", "label": "クラスター化テーブル（Clustered）"}, {"key": "C", "label": "一時テーブル（Temporary）"}, {"key": "D", "label": "過渡テーブル（Transient）"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>一時テーブル（Temporary） / 過渡テーブル（Transient）</strong></p><p>過渡テーブルと一時テーブルにはフェイルセーフがありません。これは一時的なデータと過渡的なデータのストレージコストを削減するためです。https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ保護", "originalCorrect": null, "reviewPoint": ""}}, {"order": 35, "title": "Snowflakeのクラウドサービス層が提供するものはどれですか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeのクラウドサービス層が提供するものはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "クエリ最適化"}, {"key": "B", "label": "クエリ実行"}, {"key": "C", "label": "認証"}, {"key": "D", "label": "クエリプランニング"}, {"key": "E", "label": "認可"}], "correctAnswers": ["A", "C", "D", "E"], "explanationHtml": "<p>✅ <strong>クエリ最適化 / 認証 / クエリプランニング / 認可</strong></p><p>クラウドサービス層は認証と認可を管理します。ユーザーがログインすると、クラウドサービス層が認証情報を検証します。ユーザーがクエリを送信すると、クラウドサービス層がクエリプランを解析して最適化します。クエリの実行は仮想ウェアハウスが行います。https://docs.snowflake.com/en/user-guide/intro-key-concepts</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 36, "title": "Snowflakeが毎週デプロイするリリースの種類はどれですか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeが毎週デプロイするリリースの種類はどれですか？（2つ選択）</p>", "options": [{"key": "A", "label": "フルリリース"}, {"key": "B", "label": "アルファリリース"}, {"key": "C", "label": "ベータリリース"}, {"key": "D", "label": "パッチリリース"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>フルリリース / パッチリリース</strong></p><p>Snowflakeは毎週2つの計画・スケジュールされたリリースを行います。リリースは2種類に分類されます。1つは1つ以上の問題の修正のみを含むパッチリリースです。もう1つは新機能、既存機能の拡張、またはバグ修正を含むフルリリースです。https://docs.snowflake.com/en/user-guide/intro-releases</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント", "originalCorrect": null, "reviewPoint": ""}}, {"order": 37, "title": "Snowflakeアーキテクチャのクラウドサービス層を最もよく説明している記述はどれですか？（該...", "multiSelect": true, "stemHtml": "<p>Snowflakeアーキテクチャのクラウドサービス層を最もよく説明している記述はどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "高可用性、耐障害性を持つ常時稼働のサービスである"}, {"key": "B", "label": "Snowflakeアカウントへのすべてのアクセスはクラウドサービス層を経由する"}, {"key": "C", "label": "クラウドサービス層はSnowflakeの顧客によってシャットダウンおよび再起動できる"}, {"key": "D", "label": "クラウドサービスはSnowflakeの顧客がコストをより効率的に管理できるオプションサービスである"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>高可用性、耐障害性を持つ常時稼働のサービスである / Snowflakeアカウントへのすべてのアクセスはクラウドサービス層を経由する</strong></p><p>SnowflakeのクラウドサービスLayerはその頭脳であり、信頼性の高い常時稼働のサービスです。SnowflakeアカウントはクラウドサービスLayerを経由してのみアクセス可能です。Snowflakeウェブ UIまたはSnowSQL経由のすべてのSnowflakeへのリクエストはこのLayerを通過します。https://docs.snowflake.com/en/user-guide/intro-key-concepts#cloud-services</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 38, "title": "テーブルのロードメタデータは何日後に期限切れになりますか？", "multiSelect": false, "stemHtml": "<p>テーブルのロードメタデータは何日後に期限切れになりますか？</p>", "options": [{"key": "A", "label": "128日"}, {"key": "B", "label": "64日"}, {"key": "C", "label": "365日"}, {"key": "D", "label": "30日"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>64日</strong></p><p>ロードメタデータには、そのテーブルにロードされたすべてのファイルの名前やファイルがロードされた時刻のタイムスタンプなど、様々な情報が保存されます。このロードメタデータを利用することで、Snowflakeは以前にロードされたファイルを再処理しないようにします。ロードメタデータは64日後に期限切れになります。Snowflakeはロードステータスが不明な古いファイルをスキップします。https://docs.snowflake.com/en/user-guide/data-load-considerations-load#load-metadata</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 39, "title": "真偽問題：仮想ウェアハウスを自動停止・自動再開に設定すると、設定された時間使用されない場合は一時...", "multiSelect": false, "stemHtml": "<p>真偽問題：仮想ウェアハウスを自動停止・自動再開に設定すると、設定された時間使用されない場合は一時停止モードになり、クエリが実行されると再開する。</p>", "options": [{"key": "A", "label": "真（True）"}, {"key": "B", "label": "偽（False）"}], "correctAnswers": ["A"], "explanationHtml": "<p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 40, "title": "真偽問題：Readerアカウントは、そのReaderアカウントを作成したデータプロバイダー以外の...", "multiSelect": false, "stemHtml": "<p>真偽問題：Readerアカウントは、そのReaderアカウントを作成したデータプロバイダー以外のソースからデータを利用できる。</p>", "options": [{"key": "A", "label": "偽（False）"}, {"key": "B", "label": "真（True）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>偽（False）</strong></p><p>Readerアカウントは、そのアカウントを作成したデータプロバイダーアカウントからのデータのみを利用できます。https://docs.snowflake.com/en/user-guide/data-sharing-reader-create#what-is-restricted-allowed-in-a-reader-account</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 41, "title": "真偽問題：Snowflakeの顧客は、データを複製せずに異なるクラウドプラットフォーム/リージョ...", "multiSelect": false, "stemHtml": "<p>真偽問題：Snowflakeの顧客は、データを複製せずに異なるクラウドプラットフォーム/リージョンのデータコンシューマーとデータを共有できる。</p>", "options": [{"key": "A", "label": "偽（False）"}, {"key": "B", "label": "真（True）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>偽（False）</strong></p><p>別のクラウドプラットフォームのSnowflakeアカウントとデータを共有することは可能ですが、プロバイダーはレプリケーションを有効にして、既存のデータベースを他のクラウドプラットフォームにレプリケートする必要があります。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 42, "title": "レプリケーションを有効にするために以下の文を実行するには、どのロールが必要ですか？", "multiSelect": false, "stemHtml": "<p>レプリケーションを有効にするために以下の文を実行するには、どのロールが必要ですか？</p>", "options": [{"key": "A", "label": "SYSADMIN"}, {"key": "B", "label": "ORGADMIN"}, {"key": "C", "label": "SECURITYADMIN"}, {"key": "D", "label": "ACCOUNTADMIN"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>ORGADMIN</strong></p><p>ORGADMINロールを持つユーザーのみがSYSTEM$GLOBAL_ACCOUNT_SET_PARAMETER関数を呼び出せます。https://docs.snowflake.com/en/sql-reference/functions/system_global_account_set_parameter</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 43, "title": "Snowflakeでは列レベルのセキュリティを以下のどの方法で実装できますか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>Snowflakeでは列レベルのセキュリティを以下のどの方法で実装できますか？（2つ選択）</p>", "options": [{"key": "A", "label": "外部トークン化（External Tokenization）"}, {"key": "B", "label": "動的データマスキング（Dynamic data masking）"}, {"key": "C", "label": "検索最適化（Search Optimization）"}, {"key": "D", "label": "列指向ストレージ（Columnar Storage）"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>外部トークン化（External Tokenization） / 動的データマスキング（Dynamic data masking）</strong></p><p>Snowflakeは、列に適用して列レベルで強制することができるマスキングポリシーをサポートし、列レベルのセキュリティを提供します。列レベルのセキュリティは、動的データマスキングまたは外部トークン化によって実現されます。https://docs.snowflake.com/en/user-guide/security-column</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 44, "title": "新しいShareを作成するにはどのロールを使用できますか？（該当するものをすべて選択）", "multiSelect": true, "stemHtml": "<p>新しいShareを作成するにはどのロールを使用できますか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "PUBLICロール"}, {"key": "B", "label": "CREATE SHARE権限を持つロール"}, {"key": "C", "label": "DATA_SHAREロール"}, {"key": "D", "label": "ACCOUNTADMINロール"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>CREATE SHARE権限を持つロール / ACCOUNTADMINロール</strong></p><p>ACCOUNTADMINロールまたはCREATE SHARE権限が特別に付与されたロールのみがShareを作成できます。https://docs.snowflake.com/en/user-guide/data-sharing-gs</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 45, "title": "外部テーブルに関して正しい記述はどれですか？", "multiSelect": true, "stemHtml": "<p>外部テーブルに関して正しい記述はどれですか？</p>", "options": [{"key": "A", "label": "外部テーブルと標準のSnowflakeテーブルは結合できる"}, {"key": "B", "label": "パフォーマンスを向上させるため、外部テーブルにマテリアライズドビューを作成できる"}, {"key": "C", "label": "外部テーブルはマテリアライズドビューをサポートしない"}, {"key": "D", "label": "外部テーブルのデータはUPDATE SQLコマンドで更新できる"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>外部テーブルと標準のSnowflakeテーブルは結合できる / パフォーマンスを向上させるため、外部テーブルにマテリアライズドビューを作成できる</strong></p><p>外部テーブルは外部ストレージの場所を指しているため、データ操作言語（DML）操作はできません。外部テーブルはクラウドオブジェクトストレージの場所を指す外部ステージに対してのみ作成できます。パフォーマンスを向上させるために外部テーブルにマテリアライズドビューを作成できます。これらのマテリアライズドビューは手動または通知システムを通じて更新する必要があります。https://docs.snowflake.com/en/user-guide/tables-external-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 46, "title": "マルチクラスター仮想ウェアハウスはどのようなシナリオで使用されますか？", "multiSelect": false, "stemHtml": "<p>マルチクラスター仮想ウェアハウスはどのようなシナリオで使用されますか？</p>", "options": [{"key": "A", "label": "クエリの同時実行数が1つの仮想ウェアハウスのキャパシティを超えた場合"}, {"key": "B", "label": "ストリーミングデータをロードする必要がある場合"}, {"key": "C", "label": "クエリの複雑さが低下した場合"}, {"key": "D", "label": "クエリの複雑さが増加した場合"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>クエリの同時実行数が1つの仮想ウェアハウスのキャパシティを超えた場合</strong></p><p>マルチクラスター仮想ウェアハウスは、同時ユーザー数が単一の仮想ウェアハウスのキャパシティを超えた場合に使用されます。仮想ウェアハウスの同時ワークロードが最大に達すると、新しいクエリはキューに入れられます。マルチクラスター仮想ウェアハウスは、需要に応じてクラスターを追加することでこのキュー問題を解決します。需要が減少すると、追加のクラスターは削除されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 47, "title": "MARKETINGという名前のデータベースがあります。このデータベースのPUBLICスキーマにC...", "multiSelect": false, "stemHtml": "<p>MARKETINGという名前のデータベースがあります。このデータベースのPUBLICスキーマにCUSTOMERというテーブルがあります。同じ名前（CUSTOMER）の一時テーブルをMARKETINGデータベースのPUBLICスキーマに作成しました。同じセッションで「DROP TABLE MARKETING.PUBLIC.CUSTOMER;」を実行すると何が起きますか？</p>", "options": [{"key": "A", "label": "「重複オブジェクト」エラーでステートメントが失敗する"}, {"key": "B", "label": "永続テーブルが削除される"}, {"key": "C", "label": "「オブジェクトが見つからない」エラーでステートメントが失敗する"}, {"key": "D", "label": "一時テーブルが削除される"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>一時テーブルが削除される</strong></p><p>永続テーブルや過渡テーブルと同様に、一時テーブルはデータベースとスキーマに属します。ただし、セッションに限定されているため、命名の一意性制約は適用されません。そのため、既存のテーブルと同じ名前の一時テーブルを作成することが可能です。これにより、潜在的な競合や予期しない動作が生じる可能性があります。同じスキーマに永続（または過渡）テーブルと同じ名前で一時テーブルが作成された場合、セッション中は一時テーブルが永続テーブルを実質的に隠します。セッション中のクエリやその他の操作は一時テーブルにのみ影響します。https://docs.snowflake.com/en/user-guide/tables-temp-transient#potential-naming-conflicts-with-other-table-types</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflakeのカタログとオブジェクト", "originalCorrect": null, "reviewPoint": ""}}, {"order": 48, "title": "INFORMATION_SCHEMAクエリで指定されたフィルターが十分に選択的でない場合、何が起...", "multiSelect": false, "stemHtml": "<p>INFORMATION_SCHEMAクエリで指定されたフィルターが十分に選択的でない場合、何が起きますか？</p>", "options": [{"key": "A", "label": "エラー"}, {"key": "B", "label": "成功"}, {"key": "C", "label": "空の結果セット"}, {"key": "D", "label": "警告"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>エラー</strong></p><p>INFORMATION SCHEMAクエリで指定されたフィルターが十分に選択的でない場合、以下のエラーが返されます。「Information schema query returned too much data. Please repeat the query with more selective predicates.」（情報スキーマクエリが多すぎるデータを返しました。より選択的な述語を使用してクエリを繰り返してください。）https://docs.snowflake.com/en/sql-reference/info-schema#general-usage-notes</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 49, "title": "Snowflake Marketplaceからデータを利用するために必要なSnowflakeの最...", "multiSelect": false, "stemHtml": "<p>Snowflake Marketplaceからデータを利用するために必要なSnowflakeの最小エディションはどれですか？</p>", "options": [{"key": "A", "label": "Business Critical"}, {"key": "B", "label": "Standard"}, {"key": "C", "label": "エディション不要"}, {"key": "D", "label": "Virtual Private Snowflake"}, {"key": "E", "label": "Enterprise"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>Data MarketplaceはすべてのSnowflakeエディションでサポートされているため、サポートする最小エディションはStandardエディションです。VPSはData Marketplaceをサポートしていないことに注意してください。https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 50, "title": "共有データベースのコンシューマーが実行できないアクションはどれですか？（該当するものをすべて選択...", "multiSelect": true, "stemHtml": "<p>共有データベースのコンシューマーが実行できないアクションはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "共有データを複雑なクエリで使用する"}, {"key": "B", "label": "共有データベースのテーブルの一覧を表示する"}, {"key": "C", "label": "共有テーブルにデータを挿入する"}, {"key": "D", "label": "共有データベースに新しいテーブルを作成する"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>共有テーブルにデータを挿入する / 共有データベースに新しいテーブルを作成する</strong></p><p>共有データベースはコンシューマーにとって読み取り専用であるため、新しいオブジェクトを作成したり、データを変更・追加したりすることはできません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 51, "title": "真偽問題：Snowparkはユーザー定義関数をデータベースサーバーにプッシュダウンでき、そこでコ...", "multiSelect": false, "stemHtml": "<p>真偽問題：Snowparkはユーザー定義関数をデータベースサーバーにプッシュダウンでき、そこでコードがデータを操作する。</p>", "options": [{"key": "A", "label": "偽（False）"}, {"key": "B", "label": "真（True）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>真（True）</strong></p><p>Java、Python、ScalaなどのプログラミングLanguageを使って関数を作成し、それらの関数をSnowflakeのUDFとして公開できます。これらのUDFを通常のUDFと同様にSQLで使用することができます。これらのUDFを実行するために、Snowflakeは仮想ウェアハウス内にランタイム環境サンドボックスを作成します。UDFはサンドボックス内で実行されます。このアプローチはSnowflakeインフラを使ってスケールするため、UDFのデフォルト並列実行も保証します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 52, "title": "仮想ウェアハウスはSQLクエリを処理するために通常稼働している必要があります。実行中の仮想ウェア...", "multiSelect": true, "stemHtml": "<p>仮想ウェアハウスはSQLクエリを処理するために通常稼働している必要があります。実行中の仮想ウェアハウスなしで結果を生成できるクエリはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "1つのテーブルのみを使用するクエリ"}, {"key": "B", "label": "すでに実行されて結果キャッシュを生成したクエリ"}, {"key": "C", "label": "100MB未満の結果セットを生成するクエリ"}, {"key": "D", "label": "列の行数、最小値、最大値などのクエリ"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>すでに実行されて結果キャッシュを生成したクエリ / 列の行数、最小値、最大値などのクエリ</strong></p><p>Snowflakeがクエリを実行すると、結果は一定期間キャッシュされます。クエリ結果キャッシュは、クエリを再実行せず、アクティブな仮想ウェアハウスを必要とせずに、後続の同一検索の結果を返します。Snowflakeはメタデータキャッシュを使用してCOUNT、MIN、MAXクエリも処理でき、アクティブなウェアハウスを必要としません。https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 53, "title": "Snowflake Marketplaceにアクセスするために必要なSnowflakeの最小エデ...", "multiSelect": false, "stemHtml": "<p>Snowflake Marketplaceにアクセスするために必要なSnowflakeの最小エディションはどれですか？</p>", "options": [{"key": "A", "label": "Enterprise"}, {"key": "B", "label": "Virtual Private Snowflake (VPS)"}, {"key": "C", "label": "Business Critical"}, {"key": "D", "label": "Standard"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>Virtual private Snowflakeアカウントを除き、Snowflake MarketplaceはAmazon Web Services、Google Cloud Platform、Microsoft Azureでホストされているすべてのsnowflakeアカウントで利用可能です。https://other-docs.snowflake.com/en/collaboration/collaboration-marketplace-about.html#about-the-snowflake-marketplace</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 54, "title": "ポイントルックアップクエリを最適化するための検索最適化サービスをサポートするSnowflakeエ...", "multiSelect": true, "stemHtml": "<p>ポイントルックアップクエリを最適化するための検索最適化サービスをサポートするSnowflakeエディションはどれですか？（該当するものをすべて選択）</p>", "options": [{"key": "A", "label": "Standard Edition"}, {"key": "B", "label": "Business Critical Edition"}, {"key": "C", "label": "Enterprise Edition"}, {"key": "D", "label": "Virtual Private Snowflake (VPS) Edition"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>Business Critical Edition / Enterprise Edition / Virtual Private Snowflake (VPS) Edition</strong></p><p>Enterpriseエディションには、検索最適化を含むStandardエディションでは提供されない追加機能がいくつかあります。Business CriticalエディションとVPSエディション（Enterpriseより上位のエディション）もこの機能を継承しています。https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 55, "title": "Snowflake Enterprise Editionをデータウェアハウスとして使用している航...", "multiSelect": false, "stemHtml": "<p>Snowflake Enterprise Editionをデータウェアハウスとして使用している航空会社のデータウェアハウス管理者です。マーケティングユーザーがSnowflakeに接続してクエリを実行する数が急激に増加する処理期間があることに気づきました。これらのユーザーはクエリの遅延とキューイングを経験しています。このクエリの増加に特定のパターンはなく、週のいつでもランダムに発生する可能性があります。マーケティング部門にはすでにラージサイズ（L）の専用仮想ウェアハウスが割り当てられています。最善の対処法はどれですか？</p>", "options": [{"key": "A", "label": "マーケティングユーザーに毎日ではなく、週全体にクエリを分散させるよう強制する"}, {"key": "B", "label": "ピーク処理期間中にマーケティング専用の仮想ウェアハウスのサイズをLからXLに拡大する。このサイズアップにより処理能力が2倍になり、クエリがより速く完了する。ピーク期間後にサイズを縮小する"}, {"key": "C", "label": "マーケティングの仮想ウェアハウスでマルチクラスターウェアハウスを有効にする。マルチクラスター仮想ウェアハウスは需要の増減に応じて追加の仮想ウェアハウスを自動的に起動・停止する"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>マーケティングの仮想ウェアハウスでマルチクラスターウェアハウスを有効にする</strong></p><p>マルチクラスター仮想ウェアハウスは、同時クエリ数が単一の仮想ウェアハウスのキャパシティを超えるシナリオでよく使用されます。仮想ウェアハウスの同時ワークロードが最大キャパシティを超えると、追加のクエリはキューに入れられます。マルチクラスター仮想ウェアハウスは、キューの問題を解決するために需要に基づいて動的に追加のクラスターを追加します。需要が減少すると、追加のクラスターは廃止されます。このプロセスはスケールアウトまたは自動スケーリングとも呼ばれます。https://docs.snowflake.com/en/user-guide/warehouses-multicluster</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 56, "title": "仮想ウェアハウスがより大きなサイズにスケールアップされた場合、Snowflakeはいつから新しい...", "multiSelect": false, "stemHtml": "<p>仮想ウェアハウスがより大きなサイズにスケールアップされた場合、Snowflakeはいつから新しいサイズの課金を開始しますか？</p>", "options": [{"key": "A", "label": "即時"}, {"key": "B", "label": "仮想ウェアハウスが一時停止して再開されたとき"}, {"key": "C", "label": "5分後"}, {"key": "D", "label": "すべての新しいノードがプロビジョニングされた後"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>すべての新しいノードがプロビジョニングされた後</strong></p><p>仮想ウェアハウスがスケールアップされる場合、新しい規模の課金は、より大きな仮想ウェアハウスのすべての新しいノードがプロビジョニングされるまで開始されません。https://docs.snowflake.com/en/user-guide/warehouses-considerations#warehouse-resizing-improves-performance</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 57, "title": "SnowflakeのTri-Secret Secure暗号化は何を提供しますか？（2つ選択）", "multiSelect": true, "stemHtml": "<p>SnowflakeのTri-Secret Secure暗号化は何を提供しますか？（2つ選択）</p>", "options": [{"key": "A", "label": "Tri-Secret Secureでは顧客が暗号化用に独自のキーを持ち込める"}, {"key": "B", "label": "Tri-Secret SecureはBusiness Criticalエディション以上が必要"}, {"key": "C", "label": "Tri-Secret SecureはEnterpriseエディション以上が必要"}, {"key": "D", "label": "Tri-Secret SecureはSnowflakeにおける多要素認証機能を提供する"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>Tri-Secret Secureでは顧客が暗号化用に独自のキーを持ち込める / Tri-Secret SecureはBusiness Criticalエディション以上が必要</strong></p><p>Tri-Secret Secureとは、Snowflakeが管理するキーと顧客が管理するキーを組み合わせて、データを保護するコンポジットマスターキーを生成する機能を指します。Tri-Secret SecureはBusiness Criticalエディションを最小要件とし、Snowflakeサポートへの連絡により有効化できます。https://docs.snowflake.com/en/user-guide/security-encryption-manage</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 58, "title": "Snowflakeスクリプティングを最もよく説明しているものはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeスクリプティングを最もよく説明しているものはどれですか？</p>", "options": [{"key": "A", "label": "Snowflakeスクリプティングは、プログラミング言語に見られるような手続き型ロジックを使用できるSQLの拡張機能である"}, {"key": "B", "label": "Snowflakeスクリプティングはウェブブラウザで実行されるクライアントサイドコードを作成するために使用される"}, {"key": "C", "label": "SnowflakeスクリプティングはActionScriptコードの一種であり、モバイルアプリの作成に使用できる"}, {"key": "D", "label": "Snowflakeスクリプティングは既存のSnowflake SQL実行エンジンに並列実行機能を追加する"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>Snowflakeスクリプティングは、プログラミング言語に見られるような手続き型ロジックを使用できるSQLの拡張機能である</strong></p><p>Snowflakeスクリプティングは、プログラミング言語に見られるような手続き型ロジックを使用できるSQLの拡張機能です。変数、if-else式、ループ、カーソル、結果セットの管理、エラーハンドリングなどが使用できます。Snowflakeスクリプティングはストアドプロシージャの作成に通常使用されますが、ストアドプロシージャの外での手続き型コードの作成にも使用できます。https://docs.snowflake.com/en/developer-guide/snowflake-scripting/index</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 59, "title": "過去12ヶ月間にクエリで読み取られたテーブルと列の情報を提供するACCOUNT_USAGEビュー...", "multiSelect": false, "stemHtml": "<p>過去12ヶ月間にクエリで読み取られたテーブルと列の情報を提供するACCOUNT_USAGEビューはどれですか？</p>", "options": [{"key": "A", "label": "METERING_HISTORY"}, {"key": "B", "label": "QUERY_HISTORY"}, {"key": "C", "label": "WAREHOUSE_EVENTS_HISTORY"}, {"key": "D", "label": "ACCESS_HISTORY"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>ACCESS_HISTORY</strong></p><p>ACCOUNT_USAGEスキーマのACCESS_HISTORYビューは、クエリによってどのオブジェクトにアクセスされたかの情報を提供します。このビューは365日分の履歴を提供します。このビューは、列、テーブル、ビュー、ストアドプロシージャ、UDFなどのアクセスされたオブジェクトに関する情報を提供します。また、間接的にアクセスされた基本オブジェクト（例：ビューを通じてアクセスされたテーブルと列）や変更されたオブジェクトに関する情報も提供します。https://docs.snowflake.com/en/sql-reference/account-usage/access_history</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 60, "title": "タイムトラベル期間が完了した後、Snowflakeはフェイルセーフストレージにデータを保存します...", "multiSelect": false, "stemHtml": "<p>タイムトラベル期間が完了した後、Snowflakeはフェイルセーフストレージにデータを保存します。永続テーブルのデータはフェイルセーフストレージにどれくらいの期間保存されますか？</p>", "options": [{"key": "A", "label": "14日"}, {"key": "B", "label": "21日"}, {"key": "C", "label": "7日"}, {"key": "D", "label": "1日"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>7日</strong></p><p>永続テーブルのデータはフェイルセーフストレージに7日間保存されます。Snowflakeはフェイルセーフ機能を提供しない過渡テーブルと一時テーブルも提供しています。したがって、そのようなテーブルのデータのフェイルセーフストレージは0日間です。https://docs.snowflake.com/en/user-guide/data-failsafe</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 61, "title": "接続診断に使用されるツールはどれですか？", "multiSelect": false, "stemHtml": "<p>接続診断に使用されるツールはどれですか？</p>", "options": [{"key": "A", "label": "Snowsight"}, {"key": "B", "label": "Snowpipe"}, {"key": "C", "label": "SnowSQL"}, {"key": "D", "label": "SnowCD"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>SnowCD</strong></p><p>SnowCDはSnowflake接続診断ツールです。https://docs.snowflake.com/en/user-guide/snowcd</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 62, "title": "X-Small仮想ウェアハウスのノード数はいくつですか？", "multiSelect": false, "stemHtml": "<p>X-Small仮想ウェアハウスのノード数はいくつですか？</p>", "options": [{"key": "A", "label": "3"}, {"key": "B", "label": "2"}, {"key": "C", "label": "1"}, {"key": "D", "label": "4"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>1</strong></p><p>X-Small仮想ウェアハウスは1つのノードで構成され、Snowflake仮想ウェアハウスで最小の構成です。Small仮想ウェアハウスは2つのノードで構成され、Medium仮想ウェアハウスは4つのノードで構成されます。クラスターサイズが大きくなるにつれて、そのクラスター内のノード数は倍増していきます。https://docs.snowflake.com/en/user-guide/warehouses-overview</p><p><strong>問:</strong> クラスタリングに関して、以下のうち正しい記述はどれですか？</p><p>該当するものをすべて選択してください。</p><ul><li><strong>正解:</strong> クラスタリングキーは複数の列を持つことができる。</li><li><strong>正解:</strong> クラスタリングキーの定義は必須ではない。</li><li>クラスタリングキーには日付列のみを含めることができる。</li><li>1つのテーブルに複数のクラスタリングキーを定義できる。</li><li>クラスタリングキーは各テーブルに必ず定義しなければならない。</li></ul><h2 id=\"解説\">解説</h2><p>✅ <strong>クラスタリングキーは複数の列を持つことができる / クラスタリングキーの定義は必須ではない</strong></p><p>クラスタリングキーはすべてのテーブルに必要なわけではありません。テーブルにクラスタリングキーを設定すべきかどうかは、コストと効果を評価して判断する必要があります。一般的に、Snowflakeは明示的なクラスタリングキーを必要とせずに、ほとんどのテーブルでデータを十分にクラスタリングします。</p><p>クラスタリングキーは複数の列を持つことができますが、マルチカラムクラスタリングキーを定義する場合は列数を3〜4列に制限することが推奨されます。列は基本的にどのデータ型でも使用でき、日付列に限定されるわけではありません。</p><p>ただし、1つのテーブルに複数のクラスタリングキーを定義することはできません。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ## 問題63", "originalCorrect": null, "reviewPoint": ""}}, {"order": 64, "title": "最も頻繁にアクセスされるテーブルを特定するために使用できるACCOUNT_USAGEビューはどれ...", "multiSelect": false, "stemHtml": "<p>最も頻繁にアクセスされるテーブルを特定するために使用できるACCOUNT_USAGEビューはどれですか？</p>", "options": [{"key": "A", "label": "OBJECT_DEPENDENCIES"}, {"key": "B", "label": "ACCESS_HISTORY"}, {"key": "C", "label": "QUERY_HISTORY"}, {"key": "D", "label": "DATABASE_STORAGE_USAGE_HISTORY"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>ACCESS_HISTORY</strong></p><p>ACCESS_HISTORYビューを使用することで、どのデータに、いつ、誰がアクセスしたかを特定できます。この情報を利用して、まったくアクセスされていないデータも特定できます。</p><p>ACCESS_HISTORYデータを使用することには他にも利点があります。詳細は以下のリンクを参照してください。</p><p>https://docs.snowflake.com/en/user-guide/access-history#benefits</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 65, "title": "ストアドプロシージャがオーナーの権限（owner's rights）で実行されるように設定されて...", "multiSelect": false, "stemHtml": "<p>ストアドプロシージャがオーナーの権限（owner&#x27;s rights）で実行されるように設定されています。システム管理者がこのストアドプロシージャを実行した場合、ストアドプロシージャはどのように実行されますか？</p>", "options": [{"key": "A", "label": "ストアドプロシージャは、そのストアドプロシージャを所有するロールの権限で実行される。"}, {"key": "B", "label": "ストアドプロシージャはACCOUNTADMINロールの権限で実行される。"}, {"key": "C", "label": "ストアドプロシージャは実行するユーザーの権限で実行される。"}, {"key": "D", "label": "ストアドプロシージャはSYSADMINロールの権限で実行される。"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>ストアドプロシージャは、そのストアドプロシージャを所有するロールの権限で実行される</strong></p><p>オーナーの権限で実行されるように設定されたストアドプロシージャは、そのストアドプロシージャを作成・所有するロールの権限で実行されます。</p><p>https://docs.snowflake.com/en/sql-reference/stored-procedures-rights</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 66, "title": "Snowpipeに関して、正しい記述はどれですか？該当するものをすべて選択してください。", "multiSelect": true, "stemHtml": "<p>Snowpipeに関して、正しい記述はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "Snowpipeのリソースは、Snowflakeによって自動的にスケールアップ・スケールダウンされる。"}, {"key": "B", "label": "Snowpipeで利用可能なコンピュートを管理するために、仮想ウェアハウスを自分でスケールさせる必要がある。"}, {"key": "C", "label": "Snowpipeは、Snowflakeが管理するサーバーレスコンピュートリソースを使用する。"}, {"key": "D", "label": "Snowpipeはコンピュートリソースとしてアクティブな仮想ウェアハウスを使用する。"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>Snowpipeのリソースは自動スケール / サーバーレスコンピュートリソースを使用する</strong></p><p>Snowpipeはサーバーレスであり、独自のコンピュート能力を持っているため、処理に仮想ウェアハウスを使用しません。SnowflakeはSnowpipeに必要なコンピュートを自動管理します。また、データロード要件に応じてSnowpipeのスケールアップ・スケールダウンも自動で行います。Snowpipeはサーバーレスであるため、そのコストは仮想ウェアハウスの費用とは別途請求されます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 67, "title": "ディレクトリテーブルをクエリしたときの結果セットに含まれる列はどれですか？", "multiSelect": true, "stemHtml": "<p>ディレクトリテーブルをクエリしたときの結果セットに含まれる列はどれですか？</p>", "options": [{"key": "A", "label": "SIZE"}, {"key": "B", "label": "ENCRYPTION_KEY"}, {"key": "C", "label": "FILE_URL"}, {"key": "D", "label": "RELATIVE_PATH"}, {"key": "E", "label": "IS_COMPRESSED"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>SIZE / FILE_URL / RELATIVE_PATH</strong></p><p>ディレクトリテーブルをクエリすると、ステージオブジェクト内の各ファイルのFILE_URLが結果セットに含まれます。また、ステージを基準としたファイルのパスを示すRELATIVE_PATHなどの追加メタデータも含まれます。さらに、ファイルのサイズ（バイト単位）や最終更新日時のタイムスタンプ、ファイルのMD5チェックサム、ファイルの内容が変更されると更新されるETAGファイルなどのメタデータも含まれます。ディレクトリテーブルをクエリする際は、WHERE句を使用してこれらのフィールドで結果セットをフィルタリングできます。例えば、SIZEカラムを使用して10MB以上のファイルのみに結果を絞り込むことができます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-dirtables-manage#output</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 68, "title": "正誤問題：クラスタキーは、DMLステートメントのブロックを避けるために、ピーク時間外にのみ変更す...", "multiSelect": false, "stemHtml": "<p>正誤問題：クラスタキーは、DMLステートメントのブロックを避けるために、ピーク時間外にのみ変更すべきである。</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False</strong></p><p>Snowflakeの再クラスタリング操作はユーザーに対して透過的であり、DMLやSELECTクエリをブロックしません。再クラスタリング中のテーブルは、クエリ、更新、変更の際に他のテーブルとまったく同じように動作します。</p><p>https://docs.snowflake.com/en/user-guide/tables-auto-reclustering#non-blocking-dml</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 69, "title": "以下のリソースモニターの設定を考慮してください。次の3つの記述のうち、正しいものはどれですか？", "multiSelect": true, "stemHtml": "<p>以下のリソースモニターの設定を考慮してください。次の3つの記述のうち、正しいものはどれですか？</p>", "options": [{"key": "A", "label": "他のウェアハウスがクレジットを使用していない場合、ウェアハウス5は最大5,000クレジットを使用できる。"}, {"key": "B", "label": "他のウェアハウスがクレジットを使用していない場合、ウェアハウス1は最大5,000クレジットを使用できる。"}, {"key": "C", "label": "ウェアハウス1が500クレジットを使用した場合、ウェアハウス4とウェアハウス5の合計クレジット使用量は最大4,500になる。"}, {"key": "D", "label": "ウェアハウス2とウェアハウス3の合計クレジット使用量は最大2,500になる。"}, {"key": "E", "label": "ウェアハウス2とウェアハウス3の合計クレジット使用量は最大2,000クレジットになる。"}], "correctAnswers": ["A", "C", "E"], "explanationHtml": "<p>✅ <strong>ウェアハウス5は最大5,000クレジット / ウェアハウス4と5の合計は最大4,500 / ウェアハウス2と3の合計は最大2,000</strong></p><p>リソースモニターは、定義されたクォータに対して単一の仮想ウェアハウスを追跡・管理できます。複数の仮想ウェアハウスのクレジット使用量をまとめて追跡するリソースモニターを作成することもできます。</p><p>リソースモニターはアカウントレベルでも作成でき、その場合はすべての仮想ウェアハウスのクレジット使用量を考慮したアカウントレベルのクレジット使用量を追跡します。</p><p>https://docs.snowflake.com/en/user-guide/resource-monitors#assignment-of-resource-monitors</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 70, "title": "リーダーアカウントで作成されたユーザーが実行できない操作はどれですか？該当するものをすべて選択し...", "multiSelect": true, "stemHtml": "<p>リーダーアカウントで作成されたユーザーが実行できない操作はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "データのINSERT"}, {"key": "B", "label": "データのUPDATE"}, {"key": "C", "label": "新しいデータのロード"}, {"key": "D", "label": "データのSELECT"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>INSERT / UPDATE / 新しいデータのロード</strong></p><p>リーダーアカウントのユーザーは共有データをクエリすることはできますが、DML操作は実行できません。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-reader-create#what-is-restricted-allowed-in-a-reader-account</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 71, "title": "過去12ヶ月間にSnowflakeアカウントにログインしたユーザーのリストを抽出する必要がありま...", "multiSelect": false, "stemHtml": "<p>過去12ヶ月間にSnowflakeアカウントにログインしたユーザーのリストを抽出する必要があります。次のうち、どのオプションを使用すべきですか？</p>", "options": [{"key": "A", "label": "ACCOUNT_USAGE.ACCESS_HISTORYビューをクエリする"}, {"key": "B", "label": "INFORMATION_SCHEMAのQUERY_HISTORYテーブル関数を使用する"}, {"key": "C", "label": "ACCOUNT_USAGE.LOGIN_HISTORYビューをクエリする"}, {"key": "D", "label": "INFORMATION_SCHEMAのLOGIN_HISTORYテーブル関数を使用する"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>ACCOUNT_USAGE.LOGIN_HISTORYビューをクエリする</strong></p><p>過去12ヶ月のログイン履歴はACCOUNT_USAGEスキーマを使用してのみ取得できます。</p><p>ACCOUNT_USAGEスキーマのビューは、さまざまな情報について最大365日分の履歴を提供します。</p><p>LOGIN_HISTORYビューにはログイン試行情報が含まれています。ACCESS_HISTORYビューはSnowflakeオブジェクトへのアクセス履歴の情報を提供します。</p><p>https://docs.snowflake.com/en/sql-reference/functions/login_history</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 72, "title": "IPアドレスがブロックリストと許可リストの両方に存在する場合、Snowflakeはネットワークポ...", "multiSelect": false, "stemHtml": "<p>IPアドレスがブロックリストと許可リストの両方に存在する場合、Snowflakeはネットワークポリシーをどのように適用しますか？</p>", "options": [{"key": "A", "label": "Snowflakeは許可リストを最初に使用し、IPアドレスがブロックリストにも含まれていても接続を許可する。"}, {"key": "B", "label": "Snowflakeはブロックリストを最初に適用し、許可リストにも定義されていても、そのIPアドレスからの接続を拒否する。"}, {"key": "C", "label": "その特定のIPアドレスはネットワークポリシーから無視される。"}, {"key": "D", "label": "許可リストとブロックリストの両方が入力されている場合、ネットワークポリシーは無効になる。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Snowflakeはブロックリストを最初に適用する</strong></p><p>ネットワークポリシーは、ポリシー名、カンマ区切りの許可IPアドレスリスト、および禁止IPアドレスリストで構成されます。許可または禁止IPアドレスリストでは、個別のIPアドレスまたはIPアドレス範囲を指定できます。ただし、現在ネットワークポリシーはIPv4アドレスのみをサポートしています。許可IPアドレスリストとブロックIPアドレスリストの両方が入力されている場合、Snowflakeはまずブロックリストを適用し、その後許可リストを適用します。</p><p>https://docs.snowflake.com/en/user-guide/network-policies</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 73, "title": "テーブルの検索最適化を追加または削除するために必要な権限はどれですか？", "multiSelect": true, "stemHtml": "<p>テーブルの検索最適化を追加または削除するために必要な権限はどれですか？</p>", "options": [{"key": "A", "label": "SYSADMIN権限"}, {"key": "B", "label": "SECURITYADMIN権限"}, {"key": "C", "label": "テーブルへのUPDATE権限"}, {"key": "D", "label": "テーブルへのOWNERSHIP権限"}, {"key": "E", "label": "テーブルを含むスキーマへのADD SEARCH OPTIMIZATION権限"}, {"key": "F", "label": "ORGADMIN権限"}], "correctAnswers": ["D", "E"], "explanationHtml": "<p>✅ <strong>OWNERSHIP権限 / ADD SEARCH OPTIMIZATION権限</strong></p><p>テーブルの検索最適化を追加、設定、または削除するには以下が必要です。</p><p>a) テーブルへのOWNERSHIP権限。</p><p>b) テーブルを含むスキーマへのADD SEARCH OPTIMIZATION権限。</p><p>https://docs.snowflake.com/en/user-guide/search-optimization-service#what-access-control-privileges-are-needed-for-the-search-optimization-service</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 74, "title": "ワークシートビューでSQLステートメントを作成しました。そのSQLステートメントをSnowfla...", "multiSelect": false, "stemHtml": "<p>ワークシートビューでSQLステートメントを作成しました。そのSQLステートメントをSnowflakeアカウント内の別のユーザーと共有する必要があります。最も簡単な方法はどれですか？</p>", "options": [{"key": "A", "label": "SQLステートメントをコピーして他のユーザーにメールで送る。"}, {"key": "B", "label": "SQLを含むワークシートを他のユーザーと共有する。"}, {"key": "C", "label": "SQLステートメントを内部ステージに保存し、他のユーザーが内部ステージからステートメントを読み込むようにする。"}, {"key": "D", "label": "SQLステートメントを含むビューを作成する。他のユーザーにビュー名と場所を知らせる。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>SQLを含むワークシートを共有する</strong></p><p>このシナリオで最も簡単な方法はSQLステートメントのワークシートを共有することです。Snowsightでは、アカウント内の他のSnowflakeユーザーとワークシートやフォルダーを共有でき、他のユーザーがワークシートやフォルダーのSQLを表示・実行できるようになります。</p><p>https://docs.snowflake.com/en/user-guide/ui-snowsight</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 75, "title": "ポイントルックアップクエリに対して検索最適化サービスを使用するために必要な最低限のSnowfla...", "multiSelect": false, "stemHtml": "<p>ポイントルックアップクエリに対して検索最適化サービスを使用するために必要な最低限のSnowflakeエディションはどれですか？</p>", "options": [{"key": "A", "label": "Enterprise"}, {"key": "B", "label": "Business Critical"}, {"key": "C", "label": "Virtual Private Snowflake"}, {"key": "D", "label": "Standard"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>Enterprise</strong></p><p>Enterpriseエディションには、Standardエディションでは提供されていないいくつかの追加機能があります。これには、マルチクラスター仮想ウェアハウス、列レベルのマスキング、行アクセスポリシー、マテリアライズドビュー、検索最適化などが含まれます。</p><p>https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 76, "title": "Snowflakeがサポートする半構造化ファイル形式はどれですか？該当するものをすべて選択してく...", "multiSelect": true, "stemHtml": "<p>Snowflakeがサポートする半構造化ファイル形式はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "YAML"}, {"key": "B", "label": "XML"}, {"key": "C", "label": "HTML"}, {"key": "D", "label": "PARQUET"}, {"key": "E", "label": "JSON"}], "correctAnswers": ["B", "D", "E"], "explanationHtml": "<p>✅ <strong>XML / PARQUET / JSON</strong></p><p>Snowflakeはいくつかの半構造化データ形式の組み込みサポートを含んでいます。SnowflakeはJSON、Avro、ORC、Parquet、XMLをサポートしています。</p><p>https://docs.snowflake.com/en/user-guide/semistructured-intro.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 77, "title": "正誤問題：Snowflakeのデータプロバイダーが別のSnowflakeアカウントとデータを共有...", "multiSelect": false, "stemHtml": "<p>正誤問題：Snowflakeのデータプロバイダーが別のSnowflakeアカウントとデータを共有する場合、データコンシューマーは実行するクエリのコンピュート費用を負担しますか？</p>", "options": [{"key": "A", "label": "False（誤り）"}, {"key": "B", "label": "True（正しい）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>クラウドサービスレイヤーのメタデータ操作により、データを物理的にコピーすることなくデータ共有が可能です。プロバイダーアカウントがデータストレージを保持・支払いを行うため、データコンシューマーはストレージの追加費用を支払う必要はありません。ただし、データコンシューマーは共有データに対してクエリを実行する際に使用されるコンピュートの費用を負担します。共有データに対してクエリが実行される場合、データコンシューマーのコンピュートが使用されます。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-intro#how-does-secure-data-sharing-work</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 78, "title": "正誤問題：フェイルセーフストレージ内のデータにアクセスできるのはSnowflakeスタッフのみで...", "multiSelect": false, "stemHtml": "<p>正誤問題：フェイルセーフストレージ内のデータにアクセスできるのはSnowflakeスタッフのみですか？</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>データがフェイルセーフストレージに入ると、Snowflakeサポートのみがデータ回復を支援できます。顧客はフェイルセーフストレージにアクセスできません。</p><p>https://docs.snowflake.com/en/user-guide/data-failsafe</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 79, "title": "次のシナリオのうち、仮想ウェアハウスのスケールアウトが適切なオプションはどれですか？", "multiSelect": false, "stemHtml": "<p>次のシナリオのうち、仮想ウェアハウスのスケールアウトが適切なオプションはどれですか？</p>", "options": [{"key": "A", "label": "クエリがマテリアライズドビューを使用している。"}, {"key": "B", "label": "クエリの複雑さが増加している。"}, {"key": "C", "label": "クエリが5つ以上のテーブルにアクセスしている。"}, {"key": "D", "label": "現在の仮想ウェアハウスが処理できる以上のアクティブな同時クエリがある。"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>同時クエリが仮想ウェアハウスの処理能力を超えている</strong></p><p>マルチクラスター仮想ウェアハウスは、同時クエリ数が単一の仮想ウェアハウスの処理能力を超えるシナリオで頻繁に使用されます。仮想ウェアハウスの同時ワークロードが最大処理能力を超えると、追加クエリはキューに入れられます。マルチクラスター仮想ウェアハウスは需要に基づいて動的に追加クラスターを追加し、キューイング問題を解決します。需要が減少すると、追加クラスターは廃止されます。このプロセスはスケールアウトまたは自動スケーリングとも呼ばれます。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-multicluster</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 80, "title": "Snowflakeアーキテクチャにおいて、データ共有の管理を担当するレイヤーはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeアーキテクチャにおいて、データ共有の管理を担当するレイヤーはどれですか？</p>", "options": [{"key": "A", "label": "データ共有レイヤー"}, {"key": "B", "label": "クエリ処理レイヤー"}, {"key": "C", "label": "クラウドストレージレイヤー"}, {"key": "D", "label": "クラウドサービスレイヤー"}, {"key": "E", "label": "共有管理レイヤー"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>クラウドサービスレイヤー</strong></p><p>クラウドサービスレイヤーは、メタデータ操作を通じてデータ共有を促進します。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-intro#how-does-secure-data-sharing-work</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 81, "title": "Snowflake管理者として、テーブル内の少数の行のサブセットにアクセスするクエリのパフォーマ...", "multiSelect": false, "stemHtml": "<p>Snowflake管理者として、テーブル内の少数の行のサブセットにアクセスするクエリのパフォーマンスを最適化したいと考えています。クエリは実行のたびに大きな処理が必要です。テーブルのデータはあまり変更されません。どのアプローチを取るべきですか？</p>", "options": [{"key": "A", "label": "テーブルの検索最適化を有効にする。"}, {"key": "B", "label": "テーブルにカスタムクラスタリングキーを追加する。"}, {"key": "C", "label": "クエリのマテリアライズドビューを作成する。"}, {"key": "D", "label": "必要な行だけを含む新しいテーブルを作成する。新しいテーブルを使用するようにクエリを変更する。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>マテリアライズドビューを作成する</strong></p><p>マテリアライズドビューは、クエリまたは若干のバリエーションが頻繁に実行される場合に役立ちます。</p><p>実行されるクエリが複雑で時間とリソースがかかる場合、マテリアライズドビューは結果を事前計算して処理を高速化できます。</p><p>クエリ結果が一定であまり変化しない。これはクエリの基となるデータがあまり頻繁に変更されないことを示しています。頻繁に変更される場合は、マテリアライズドビューを最新の状態に保つために必要なリソースとコンピュートが、ビューが提供するメリットを上回ってしまいます。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 82, "title": "PUTコマンドを使用してSnowflakeの内部ステージにファイルをアップロードする必要がありま...", "multiSelect": true, "stemHtml": "<p>PUTコマンドを使用してSnowflakeの内部ステージにファイルをアップロードする必要があります。PUTコマンドを実行してファイルを正常にアップロードするために使用できるものはどれですか？</p>", "options": [{"key": "A", "label": "SQL API"}, {"key": "B", "label": "Snowpipe"}, {"key": "C", "label": "Pythonコネクター"}, {"key": "D", "label": "Snowsight Webインターフェース"}, {"key": "E", "label": "SnowSQL"}], "correctAnswers": ["C", "E"], "explanationHtml": "<p>✅ <strong>Pythonコネクター / SnowSQL</strong></p><p>PUTコマンドはSnowSQLまたはSnowflakeが提供するドライバー/コネクターのいずれかから使用できます。</p><p>Snowsightは内部ステージへのファイルのステージング（少量のファイルの場合）に使用できますが、PUTコマンドの実行は許可されていません。</p><p>https://docs.snowflake.com/en/user-guide/data-load-local-file-system-stage</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 83, "title": "Snowflakeはクラウドプラットフォームでの実行に特化してゼロから設計・構築されていますか？", "multiSelect": false, "stemHtml": "<p>Snowflakeはクラウドプラットフォームでの実行に特化してゼロから設計・構築されていますか？</p>", "options": [{"key": "A", "label": "はい（Yes）"}, {"key": "B", "label": "いいえ（No）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>はい</strong></p><p>Snowflakeはクラウド向けに設計されており、ゼロから設計されています。Snowflakeはコンピュートとストレージを分離した新しいハイブリッドアーキテクチャを実装しています。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 84, "title": "ユーザーが基になるデータを見ることができないビューの種類はどれですか？", "multiSelect": false, "stemHtml": "<p>ユーザーが基になるデータを見ることができないビューの種類はどれですか？</p>", "options": [{"key": "A", "label": "セキュアビュー"}, {"key": "B", "label": "永続ビュー"}, {"key": "C", "label": "外部ビュー"}, {"key": "D", "label": "マテリアライズドビュー"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>セキュアビュー</strong></p><p>セキュアビューは、テーブルから特定の行のみを返すために使用できます。さらに、セキュアビューはSnowflakeの内部最適化の一部を除去することで、基となるデータを隠します。</p><p>https://docs.snowflake.com/en/user-guide/views-secure</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 85, "title": "ソーステーブルに既に読み込まれたファイルを、クローンされたテーブルに再度読み込むことはできますか...", "multiSelect": false, "stemHtml": "<p>ソーステーブルに既に読み込まれたファイルを、クローンされたテーブルに再度読み込むことはできますか？</p>", "options": [{"key": "A", "label": "はい（Yes）"}, {"key": "B", "label": "いいえ（No）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>はい</strong></p><p>クローニングはロードメタデータをコピーしないため、ソーステーブルに以前読み込まれたファイルは問題なくクローンされたテーブルに再読み込みできます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 86, "title": "スカラーUDFはどのような種類の結果を返しますか？", "multiSelect": false, "stemHtml": "<p>スカラーUDFはどのような種類の結果を返しますか？</p>", "options": [{"key": "A", "label": "各入力に対して、複数の列を含む複数の行を返す"}, {"key": "B", "label": "各入力に対して、複数の列を含む1行を返す"}, {"key": "C", "label": "各入力に対して、1つの列を含む複数の行を返す"}, {"key": "D", "label": "各入力に対して、1つの列を含む1行を返す"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>各入力に対して、1つの列を含む1行を返す</strong></p><p>スカラーUDFは入力行ごとに1行を返し、各出力行は単一の列または値を含みます。UDFの例としてはMAX関数があり、指定された入力に対して単一の値を返します。</p><p>https://docs.snowflake.com/en/sql-reference/udf-overview#scalar-and-tabular-functions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 87, "title": "Snowflakeが提供するデータロード方法はどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflakeが提供するデータロード方法はどれですか？</p>", "options": [{"key": "A", "label": "Tiny（微小）"}, {"key": "B", "label": "継続的（Continuous）"}, {"key": "C", "label": "バルク（Bulk）"}, {"key": "D", "label": "Intermittent（断続的）"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>継続的 / バルク</strong></p><p>Snowflakeは2つの主な方法でデータロードをサポートしています。COPYコマンドはバルクデータや大きなファイルのロードに使用できます。テーブルへのデータロードにはCOPYコマンドに仮想ウェアハウスが必要です。もう一つのSnowflakeへのデータロード方法はSnowpipeです。Snowpipeは、メッセージングやストリーミング形式でデータが継続的に到着する場合に最適な技術です。</p><p>https://docs.snowflake.com/en/user-guide/data-load-overview#bulk-vs-continuous-loading</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 88, "title": "`ALTER STAGE <stage-name> REFRESH;` コマンドによってディレク...", "multiSelect": true, "stemHtml": "<p><code>ALTER STAGE &lt;stage-name&gt; REFRESH;</code> コマンドによってディレクトリテーブルのメタデータを手動更新する際のコストに関して、正しい記述はどれですか？</p>", "options": [{"key": "A", "label": "更新操作には小さなメンテナンスコストが発生する。"}, {"key": "B", "label": "コストは仮想ウェアハウスのコストとして計上される。"}, {"key": "C", "label": "コストはクラウドサービスのコストとして計上される。"}, {"key": "D", "label": "更新操作は無料である。"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>小さなメンテナンスコストが発生する / クラウドサービスのコストとして計上される</strong></p><p>ディレクトリテーブルのメタデータの更新には、通知経由か手動（<code>ALTER STAGE &lt;stage-name&gt; REFRESH</code>経由）かに関わらず、小さなメンテナンスコストが発生します。この小さなメンテナンスコストはクラウドサービスのコストとして計上されます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-dirtables-intro#billing-for-directory-tables</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 89, "title": "すべてのSnowflakeエディションにおけるタイムトラベルのデフォルト保持期間はどのくらいです...", "multiSelect": false, "stemHtml": "<p>すべてのSnowflakeエディションにおけるタイムトラベルのデフォルト保持期間はどのくらいですか？</p>", "options": [{"key": "A", "label": "14日"}, {"key": "B", "label": "1日"}, {"key": "C", "label": "7日"}, {"key": "D", "label": "90日"}, {"key": "E", "label": "0日"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>1日</strong></p><p>タイムトラベルのデフォルト保持期間は、すべてのSnowflakeアカウントで1日です。デフォルトはSnowflakeエディションで許可される最大タイムトラベル期間に応じて変更できます（Standardは1日、EnterpriseおよびそれIF以上は最大90日）。また、テーブルなどの個別のオブジェクトをデフォルトと異なる日数に設定することもできます。</p><p>https://docs.snowflake.com/en/user-guide/data-time-travel#data-retention-period</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 90, "title": "INFORMATION_SCHEMAスキーマのデータのレイテンシ範囲はどのくらいですか？", "multiSelect": false, "stemHtml": "<p>INFORMATION_SCHEMAスキーマのデータのレイテンシ範囲はどのくらいですか？</p>", "options": [{"key": "A", "label": "5〜10日"}, {"key": "B", "label": "レイテンシなし"}, {"key": "C", "label": "5〜10分"}, {"key": "D", "label": "45分〜3時間"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>レイテンシなし</strong></p><p>INFORMATION_SCHEMAビューが提供するデータはリアルタイムであり、情報にレイテンシはありません。したがって、リアルタイムデータを表示する要件がある場合に使用するスキーマを尋ねられたら、INFORMATION SCHEMAのビューを使用する必要があります。これらはリアルタイム情報を含んでいます。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 91, "title": "ACCOUNT_USAGEスキーマのデータ保持期間はどのくらいですか？", "multiSelect": false, "stemHtml": "<p>ACCOUNT_USAGEスキーマのデータ保持期間はどのくらいですか？</p>", "options": [{"key": "A", "label": "7日"}, {"key": "B", "label": "128日"}, {"key": "C", "label": "永久"}, {"key": "D", "label": "365日"}, {"key": "E", "label": "512日"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>365日</strong></p><p>ACCOUNT USAGEスキーマは、アカウントレベルの使用量メトリクスとメタデータ情報を提供するいくつかのビューで構成されています。ACCOUNT_USAGEビューが提供するデータはリアルタイムではなく、ビューによって通常45分〜3時間の遅延で更新されます。これらのビューのデータは最大365日間保持されます。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 92, "title": "Tri-Secret Secure暗号化をサポートする最低限のSnowflakeエディションはど...", "multiSelect": false, "stemHtml": "<p>Tri-Secret Secure暗号化をサポートする最低限のSnowflakeエディションはどれですか？</p>", "options": [{"key": "A", "label": "Virtual Private Snowflake"}, {"key": "B", "label": "Enterprise"}, {"key": "C", "label": "Standard"}, {"key": "D", "label": "Business Critical"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>Business Critical</strong></p><p>Tri-Secret Secureには最低でもBusiness Criticalエディションが必要で、Snowflakeカスタマーサービスに連絡することで有効化できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 93, "title": "マテリアライズドビューの制限事項はどれですか？", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューの制限事項はどれですか？</p>", "options": [{"key": "A", "label": "マテリアライズドビューは他のテーブルと結合できない。"}, {"key": "B", "label": "マテリアライズドビューは1つのテーブルのみのクエリをサポートする。"}, {"key": "C", "label": "マテリアライズドビューの定義は他のテーブルとの結合を含めることができない。"}, {"key": "D", "label": "マテリアライズドビューは集計関数をサポートしない。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>1つのテーブルのみサポート / 結合を含めることができない</strong></p><p>マテリアライズドビュー（MV）の定義には一定の制限があります。これらには以下が含まれます。</p><p>MVは単一のテーブルのみをクエリできます。</p><p>MVの定義には結合（自己結合も含む）を含めることができません。</p><p>MVはいくつかの集計関数をサポートします。</p><p>完全な制限事項のリストについては以下のリンクを参照してください。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized#limitations-on-creating-materialized-views</p><p>なお、マテリアライズドビューをクエリする際は、他のテーブルと同様に使用できるため、必要に応じて他のテーブルと結合することができます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 94, "title": "タイムトラベルSQLを使用して、ユーザーが実行できる操作はどれですか？", "multiSelect": true, "stemHtml": "<p>タイムトラベルSQLを使用して、ユーザーが実行できる操作はどれですか？</p>", "options": [{"key": "A", "label": "365日前に存在していたデータを取得する。"}, {"key": "B", "label": "クエリが実行される前のデータを取得する。"}, {"key": "C", "label": "タイムスタンプ時点でのデータを取得する。"}, {"key": "D", "label": "将来に存在するデータを取得する。"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>クエリ実行前のデータ / タイムスタンプ時点のデータ</strong></p><p>タイムトラベルSQL拡張機能により、特定の時点またはそれ以前のデータを表示できます。SQLステートメントが実行される前や、SQLステートメントが実行された時点のデータを表示するためにも使用できます。タイムトラベルでは過去90日以上前のデータを回復することはできません。</p><p>https://docs.snowflake.com/en/user-guide/data-time-travel#time-travel-sql-extensions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 95, "title": "Snowflakeのスキーマに関して、正しい記述はどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflakeのスキーマに関して、正しい記述はどれですか？</p>", "options": [{"key": "A", "label": "INFORMATION_SCHEMAは削除、名前変更、移動できない。"}, {"key": "B", "label": "PUBLICスキーマは削除、名前変更、移動できない。"}, {"key": "C", "label": "必要に応じてPUBLICスキーマは削除、名前変更、移動できる。"}, {"key": "D", "label": "必要に応じて追加のスキーマを作成できる。"}, {"key": "E", "label": "必要に応じてINFORMATION_SCHEMAスキーマは削除、名前変更、移動できる。"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>INFORMATION_SCHEMAは削除・名前変更・移動不可 / PUBLICスキーマは削除・名前変更・移動可 / 追加スキーマの作成可</strong></p><p>INFORMATION_SCHEMAは、INFORMATION_SCHEMAの親データベース内のオブジェクトに関するメタデータを提供します。すべてのデータベースとともに自動的に作成され、削除、名前変更、移動することはできません。</p><p>PUBLICスキーマもすべてのデータベースとともに自動的に作成されますが、通常のスキーマと同様です。削除、名前変更、移動が可能です。必要に応じて、データベース下に追加のスキーマを作成することもできます。</p><p>https://docs.snowflake.com/en/sql-reference/info-schema#information-schema-views-and-table-functions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake's Catalog and objects", "originalCorrect": null, "reviewPoint": ""}}, {"order": 96, "title": "SnowflakeがSaaS（Software-as-a-Service）製品と見なされる理由は...", "multiSelect": true, "stemHtml": "<p>SnowflakeがSaaS（Software-as-a-Service）製品と見なされる理由はなんですか？</p>", "options": [{"key": "A", "label": "従量課金ライセンスを提供しており、ユーザーは使用したリソースと機能分のみ支払う。"}, {"key": "B", "label": "顧客はハードウェアの調達、インストール、管理が不要である。"}, {"key": "C", "label": "Snowflakeは定期的にソフトウェアを更新し、すべてのアカウントにこれらの更新が自動的に適用されるため、手動インストール、メンテナンス、パッチが不要になる。"}, {"key": "D", "label": "Snowflakeはクラウドで動作し、インターネット経由で利用可能である。"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>全選択肢</strong></p><p>これらはすべてSoftware-as-a-Service製品の特徴です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 97, "title": "クエリの完了に長時間かかりました。クエリのクエリプロファイルには「ローカルストレージへのスピルバ...", "multiSelect": false, "stemHtml": "<p>クエリの完了に長時間かかりました。クエリのクエリプロファイルには「ローカルストレージへのスピルバイト数」の大きな値が表示されています。データスピリングの原因はどれですか？</p>", "options": [{"key": "A", "label": "クラウドサービスレイヤーにクエリ結果を保持するメモリが不足している。"}, {"key": "B", "label": "仮想ウェアハウスにクエリ処理中に生成される中間結果を保持するためのメモリが不足している。"}, {"key": "C", "label": "データをスピルしているクエリの処理にはマルチクラスター仮想ウェアハウスが必要である。"}, {"key": "D", "label": "仮想ウェアハウスがアクティブになりすぎて、これ以上クエリを処理できなくなっている。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>仮想ウェアハウスのメモリ不足</strong></p><p>操作をメモリに収めることができない場合、Snowflakeはウェアハウスのローカルディスクにデータを保存します。データスピリングはIOオペレーションが増加し、ディスクアクセスはメモリアクセスより遅いため、クエリが遅くなります。「ローカルストレージへのスピルバイト数」はローカルスピリングを示しています。ローカルディスクが満杯になると、Snowflakeはリモートクラウドストレージにデータをスピルし、ローカルディスクよりもさらに遅いストレージとなるため、この操作はさらに遅くなります。クエリプロファイルの「リモートストレージへのスピルバイト数」はリモートスピリングを示しています。スピリングを避ける方法の一つは、より大きなウェアハウスを使用することです。これにより全体的な使用可能なRAM、ローカルストレージ、並列性が増加し、クエリをメモリに収めることができるかもしれません。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile#queries-too-large-to-fit-in-memory</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 98, "title": "ゼロコピークローニングに関して、正しい記述はどれですか？該当するものをすべて選択してください。", "multiSelect": true, "stemHtml": "<p>ゼロコピークローニングに関して、正しい記述はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "クローン可能なのはテーブルのみ"}, {"key": "B", "label": "ゼロコピークローニングはデータの物理的なコピーを伴う"}, {"key": "C", "label": "テーブル、スキーマ、さらにはデータベースもクローンできる。"}, {"key": "D", "label": "ゼロコピークローニングはメタデータプロセスである。"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>テーブル・スキーマ・データベースのクローン可 / メタデータプロセス</strong></p><p>クラウドサービスレイヤーのマイクロパーティションとメタデータにより、クローンされたテーブルのメタデータが既存のマイクロパーティションを参照するため、迅速かつ効率的なゼロコピークローニングが可能です。CLONEコマンドはテーブル、スキーマ、データベースを含む幅広いSnowflakeオブジェクトのコピーを作成できます。</p><p>https://docs.snowflake.com/en/user-guide/tables-storage-considerations#label-cloning-tables</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 99, "title": "Snowflakeアカウントで実行されたクエリの履歴を確認する方法はどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflakeアカウントで実行されたクエリの履歴を確認する方法はどれですか？</p>", "options": [{"key": "A", "label": "ACCOUNT_USAGEスキーマのQUERY_HISTORYビューを使用する"}, {"key": "B", "label": "INFORMATIONスキーマのQUERY_HISTORYテーブル関数を使用する"}, {"key": "C", "label": "Snowflakeサポートにクエリ履歴の提供を依頼する"}, {"key": "D", "label": "クエリ履歴ページを使用して過去のクエリを確認する"}], "correctAnswers": ["A", "B", "D"], "explanationHtml": "<p>✅ <strong>ACCOUNT_USAGEのQUERY_HISTORYビュー / INFORMATIONスキーマのQUERY_HISTORYテーブル関数 / クエリ履歴ページ</strong></p><p>クエリ履歴は3つの方法で確認できます。1) Snowflake Web UIの履歴タブを使用する 2) INFORMATIONスキーマのQUERY_HISTORYテーブル関数をクエリする 3) ACCOUNT_USAGEスキーマのQUERY_HISTORYビューをクエリする。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 100, "title": "プロデューサーとしてデータを共有し、コンシューマーとして共有データを消費するには、共有用と共有デ...", "multiSelect": false, "stemHtml": "<p>プロデューサーとしてデータを共有し、コンシューマーとして共有データを消費するには、共有用と共有データ消費用の2つのSnowflakeアカウントが必要ですか？</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False</strong></p><p>同じSnowflakeアカウントがデータの共有（プロデューサー）を行いながら、データの消費（コンシューマー）もできます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 101, "title": "次のクエリが実行された場合、最初に利用されるものはどれですか？", "multiSelect": false, "stemHtml": "<p>次のクエリが実行された場合、最初に利用されるものはどれですか？</p>", "options": [{"key": "A", "label": "ローカルディスクキャッシュ"}, {"key": "B", "label": "リモートキャッシュ"}, {"key": "C", "label": "クエリ結果キャッシュ"}, {"key": "D", "label": "メタデータキャッシュ"}, {"key": "E", "label": "ブラウザキャッシュ"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>メタデータキャッシュ</strong></p><p>Snowflakeはマイクロパーティションに関する情報をメタデータに保存しています。各マイクロパーティション内の各列の最大値と最小値を含む列値の範囲をメタデータに保存しています。また、各列の個別値の数と、クエリを最適化するための他の特定情報もメタデータに保存しています。</p><p>この情報はメタデータキャッシュに保存されているため、特定のクエリではテーブルからデータを読み取ることなく、メタデータから必要な情報を直接取得することができます。これらのクエリにはカウントクエリやMINまたはMAXなどの関数を含むクエリが含まれます。文字のみを含む列でMINまたはMAXを実行する場合、メタデータキャッシュは使用されません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 102, "title": "完了したクエリのクエリプロファイルの次のスニペットを考えてください。ハイライトされた統計を正確に...", "multiSelect": false, "stemHtml": "<p>完了したクエリのクエリプロファイルの次のスニペットを考えてください。ハイライトされた統計を正確に説明しているのはどれですか？</p>", "options": [{"key": "A", "label": "クエリプロファイルはクエリ結果キャッシュが使用されたことを示している。"}, {"key": "B", "label": "クエリプロファイルは効果的なパーティションプルーニングを示している。"}, {"key": "C", "label": "クエリプロファイルはメタデータキャッシュが使用されたことを示している。"}, {"key": "D", "label": "クエリプロファイルは効果のないパーティションプルーニングを示している。"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>効果的なパーティションプルーニング</strong></p><p>パーティションプルーニングは、スキャンされたパーティション数がパーティション総数よりもはるかに少ない場合に発生します。スキャンされたパーティションがパーティション総数と等しい場合、クエリはテーブル全体をスキャンしています。したがって、パーティションプルーニングは行われず、クラスタリングキーを改善すべきです。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 103, "title": "パートナーへの接続プロセス中にPartner Connectが作成した仮想ウェアハウスに関して、...", "multiSelect": true, "stemHtml": "<p>パートナーへの接続プロセス中にPartner Connectが作成した仮想ウェアハウスに関して、正しい記述はどれですか？</p>", "options": [{"key": "A", "label": "必要に応じて仮想ウェアハウスのサイズを変更できる。"}, {"key": "B", "label": "仮想ウェアハウスのサイズはデフォルトで6X-Largeになる。"}, {"key": "C", "label": "仮想ウェアハウスのサイズはデフォルトでX-Smallになる。"}, {"key": "D", "label": "一度作成された仮想ウェアハウスのサイズは変更できない。"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>サイズ変更可 / デフォルトはX-Small</strong></p><p>パートナーアプリケーションへの接続プロセス中に、Snowflakeは空のデータベース、仮想ウェアハウス、デフォルトユーザー、カスタムロールなどのいくつかのオブジェクトを自動的に作成します。パートナーアプリがアカウントの読み取りまたは書き込みを行うときは、これらのオブジェクトを使用します。</p><p>自動的に作成された仮想ウェアハウスはデフォルトでX-Smallになりますが、必要に応じて変更できます。</p><p>https://docs.snowflake.com/en/user-guide/ecosystem-partner-connect#connecting-with-a-snowflake-partner</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パートナー", "originalCorrect": null, "reviewPoint": ""}}, {"order": 104, "title": "正誤問題：Snowflakeはデータとコンピュートが分離され、両方が独立してスケールできるユニー...", "multiSelect": false, "stemHtml": "<p>正誤問題：Snowflakeはデータとコンピュートが分離され、両方が独立してスケールできるユニークなアーキテクチャを使用していますか？</p>", "options": [{"key": "A", "label": "False（誤り）"}, {"key": "B", "label": "True（正しい）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>Snowflakeはコンピュートとストレージを分離した新しいハイブリッドアーキテクチャを実装しています。Snowflakeのアーキテクチャは共有ディスクと共有なしアーキテクチャの最良の特徴を組み合わせています。Snowflakeは共有ディスクアーキテクチャと同様にデータを保存（データは共有される）しますが、同じ共有データ上で複数のコンピュートエンジンを使用でき、それぞれが独自のメモリと処理能力を持ちます。</p><p>https://docs.snowflake.com/en/user-guide/intro-key-concepts#snowflake-architecture</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 105, "title": "クラスタリングキーはどのようにクエリパフォーマンスを向上させますか？", "multiSelect": false, "stemHtml": "<p>クラスタリングキーはどのようにクエリパフォーマンスを向上させますか？</p>", "options": [{"key": "A", "label": "データを圧縮することで。"}, {"key": "B", "label": "クエリ結果を事前計算して物理的に保存することで。"}, {"key": "C", "label": "データをそれぞれが処理するデータのサブセットを持つ多数のコンピュートクラスターに分散することで。"}, {"key": "D", "label": "クエリ実行中により最適なパーティションプルーニングが行えるように、データをマイクロパーティションに分散することで。"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>マイクロパーティションへの分散によるパーティションプルーニングの最適化</strong></p><p>特定の列にテーブルをクラスタリングすることで、クエリ処理から不要なパーティションを排除してクエリを最適化できます。クラスタリングキーを定義することでテーブルを再クラスタリングでき、データをマイクロパーティションに効果的に再分散してクラスタリングされた列への最適なアクセスを確保します。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions#what-is-data-clustering</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 106, "title": "フェデレーテッド認証を使用して実行できるシングルサインオン（SSO）ワークフローはどれですか？", "multiSelect": true, "stemHtml": "<p>フェデレーテッド認証を使用して実行できるシングルサインオン（SSO）ワークフローはどれですか？</p>", "options": [{"key": "A", "label": "Snowflakeへのログイン"}, {"key": "B", "label": "行レベルセキュリティ"}, {"key": "C", "label": "ユーザー認可"}, {"key": "D", "label": "Snowflakeからのログアウト"}, {"key": "E", "label": "非アクティブによるシステムタイムアウト"}, {"key": "F", "label": "ロール認可"}], "correctAnswers": ["A", "D", "E"], "explanationHtml": "<p>✅ <strong>Snowflakeへのログイン / ログアウト / 非アクティブによるシステムタイムアウト</strong></p><p>Snowflakeのフェデレーテッド認証で可能なSSOワークフローは以下の通りです。</p><ul><li>Snowflakeへのログイン</li><li>Snowflakeからのログアウト</li><li>非アクティブによるシステムタイムアウト</li></ul><p>https://docs.snowflake.com/en/user-guide/admin-security-fed-auth-overview#supported-sso-workflows</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 107, "title": "ローカルおよびリモートストレージへのデータスピリングを減らすために役立つものはどれですか？", "multiSelect": true, "stemHtml": "<p>ローカルおよびリモートストレージへのデータスピリングを減らすために役立つものはどれですか？</p>", "options": [{"key": "A", "label": "仮想ウェアハウスのサイズを大きくする"}, {"key": "B", "label": "共通テーブル式（CTE）の代わりに一時テーブルを使用する。"}, {"key": "C", "label": "一時テーブルの代わりに共通テーブル式（CTE）を使用する。"}, {"key": "D", "label": "メタデータキャッシュのサイズを大きくする"}, {"key": "E", "label": "クエリ結果キャッシュのサイズを大きくする"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>仮想ウェアハウスのサイズを大きくする / 一時テーブルを使用する</strong></p><p>スピリングを避ける方法の一つは、より大きなウェアハウスを使用することです。これにより全体的な使用可能なRAM、ローカルストレージ、並列性が増加し、クエリをメモリに収めることができるかもしれません。</p><p>もう一つの方法は、一時テーブルを使用して処理を分割し、中間結果がメモリに保持されないようにすることです。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile#queries-too-large-to-fit-in-memory</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 108, "title": "データプロバイダーとは異なるクラウドプラットフォームにSnowflakeインスタンスが存在するS...", "multiSelect": false, "stemHtml": "<p>データプロバイダーとは異なるクラウドプラットフォームにSnowflakeインスタンスが存在するSnowflake顧客とデータを共有することは可能ですか？</p>", "options": [{"key": "A", "label": "はい。クロスクラウドプラットフォームのデータ共有を有効にするために特別な操作は必要ありません。"}, {"key": "B", "label": "いいえ、他のクラウドプラットフォームの顧客との共有は不可能です。"}, {"key": "C", "label": "はい、ただし異なるクラウドプラットフォームへのデータ共有を有効にするには、まずレプリケーションを有効にする必要があります。"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>はい、ただしレプリケーションが必要</strong></p><p>別のクラウドプラットフォームのSnowflakeアカウントとデータを共有することは可能ですが、プロバイダーはレプリケーションを有効にして、既存のデータベースを他のクラウドプラットフォームにレプリケートする必要があります。</p><p>https://docs.snowflake.com/en/user-guide/secure-data-sharing-across-regions-plaforms</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 109, "title": "データベースをクローニングすると、以下のうちどれがクローンされますか？該当するものをすべて選択し...", "multiSelect": true, "stemHtml": "<p>データベースをクローニングすると、以下のうちどれがクローンされますか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "データベース内のPUBLICスキーマのみ"}, {"key": "B", "label": "データベース"}, {"key": "C", "label": "データベース内のすべてのスキーマ"}, {"key": "D", "label": "データベース内のPUBLICスキーマのすべてのテーブルのみ"}, {"key": "E", "label": "そのデータベース内のすべてのスキーマ内のすべてのテーブル"}], "correctAnswers": ["B", "C", "E"], "explanationHtml": "<p>✅ <strong>データベース / すべてのスキーマ / すべてのテーブル</strong></p><p>データベースがクローンされると、すべての子スキーマとそれらのスキーマ内のオブジェクトがクローンされます。</p><p>https://docs.snowflake.com/en/sql-reference/sql/create-clone#additional-rules-that-apply-to-cloning-objects</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 110, "title": "正誤問題：新しいリソースモニターはACCOUNTADMINロールのみが作成できますか？", "multiSelect": false, "stemHtml": "<p>正誤問題：新しいリソースモニターはACCOUNTADMINロールのみが作成できますか？</p>", "options": [{"key": "A", "label": "False（誤り）"}, {"key": "B", "label": "True（正しい）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>権限の観点から、リソースモニターを作成できるのはアカウント管理者（ACCOUNTADMINロールを持つユーザー）のみです。ただし、アカウント管理者はリソースモニターに権限を付与して、他のユーザーがリソースモニターの設定を表示・変更できるようにすることができます。リソースモニターのMONITORおよびMODIFY権限により、他のユーザーが特定のリソースモニターを表示・変更できるようになります。</p><p>https://docs.snowflake.com/en/user-guide/resource-monitors</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 111, "title": "通常のクエリを実行する際、Snowflakeが様々なキャッシュを利用する順序はどれですか？", "multiSelect": false, "stemHtml": "<p>通常のクエリを実行する際、Snowflakeが様々なキャッシュを利用する順序はどれですか？</p>", "options": [{"key": "A", "label": "1 - メタデータキャッシュ / 2 - クエリ結果キャッシュ / 3 - 仮想ウェアハウスキャッシュ"}, {"key": "B", "label": "1 - 仮想ウェアハウスキャッシュ / 2 - クエリ結果キャッシュ / 3 - メタデータキャッシュ"}, {"key": "C", "label": "1 - クエリ結果キャッシュ / 2 - 仮想ウェアハウスキャッシュ / 3 - メタデータキャッシュ"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>1 - メタデータキャッシュ / 2 - クエリ結果キャッシュ / 3 - 仮想ウェアハウスキャッシュ</strong></p><p>Snowflakeはまず、単純なCOUNTまたはSUMクエリにおいてメタデータキャッシュでクエリを満たせるかどうかを検証します。</p><p>メタデータキャッシュでクエリを満たせない場合、Snowflakeはクエリ結果キャッシュ（以前に実行されたクエリの場合）でクエリを満たせるかどうかを確認します。</p><p>メタデータキャッシュとクエリ結果キャッシュの両方でクエリを満たせない場合、Snowflakeはクエリの実行を開始します。この場合、Snowflakeはクエリパフォーマンスを向上させるために仮想ウェアハウスキャッシュを使用しようとします。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 112, "title": "次のクエリプロファイルのスニペットのうち、マイクロパーティションプルーニングが効果的でないことを...", "multiSelect": false, "stemHtml": "<p>次のクエリプロファイルのスニペットのうち、マイクロパーティションプルーニングが効果的でないことを示しているのはどれですか？</p>", "options": [{"key": "A", "label": "1"}, {"key": "B", "label": "3"}, {"key": "C", "label": "2"}, {"key": "D", "label": "4"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>1</strong></p><p>パーティションプルーニングは、スキャンされたパーティション数がパーティション総数よりもはるかに少ない場合に発生します。スキャンされたパーティションがパーティション総数と等しい場合、クエリはテーブル全体をスキャンしています。したがって、パーティションプルーニングは行われず、クラスタリングキーを改善すべきです。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 113, "title": "正誤問題：Snowflakeはスカラー外部関数のみをサポートしていますか？", "multiSelect": false, "stemHtml": "<p>正誤問題：Snowflakeはスカラー外部関数のみをサポートしていますか？</p>", "options": [{"key": "A", "label": "False（誤り）"}, {"key": "B", "label": "True（正しい）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>正しいです。Snowflakeは現在スカラー外部関数のみをサポートしており、つまり関数は1つの値のみを返す必要があります。</p><p>https://docs.snowflake.com/en/sql-reference/external-functions-introduction</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 114, "title": "マルチクラスター仮想ウェアハウスが持つことができる2つのスケーリングモードはどれですか？", "multiSelect": true, "stemHtml": "<p>マルチクラスター仮想ウェアハウスが持つことができる2つのスケーリングモードはどれですか？</p>", "options": [{"key": "A", "label": "自動スケーリング（Auto scale）"}, {"key": "B", "label": "スケジュールによるスケーリング（Scale on Schedule）"}, {"key": "C", "label": "最大化（Maximized）"}, {"key": "D", "label": "オンデマンドスケーリング（Scale on Demand）"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>自動スケーリング / 最大化</strong></p><p>マルチクラスター仮想ウェアハウスは最大化モードまたは自動スケーリングモードで作成できます。最大化モードは、マルチクラスターの最小および最大ウェアハウス数を同じ値に設定することで有効になります。したがって、マルチクラスター仮想ウェアハウスが確立されるとすぐに、マルチクラスター内のすべてのウェアハウスが起動されます。自動スケーリングモードは、マルチクラスターの最小および最大ウェアハウス数に異なる値を選択することで有効になります。その結果、Snowflakeはワークロードのニーズに基づいてウェアハウスを動的に起動・停止します。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-multicluster#setting-the-scaling-policy-for-a-multi-cluster-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 115, "title": "スコープ付きURLに関して、正しい記述はどれですか？", "multiSelect": true, "stemHtml": "<p>スコープ付きURLに関して、正しい記述はどれですか？</p>", "options": [{"key": "A", "label": "スコープ付きURLを生成したユーザーのみが、そのURLを使用して参照ファイルにアクセスできる。"}, {"key": "B", "label": "スコープ付きURLは、ステージへの権限を必要とせずにステージングされたファイルへのアクセスを可能にする一時的なエンコードURLである。"}, {"key": "C", "label": "スコープ付きURLはユーザーまたはアプリケーションへの一時的なアクセス提供に適している。"}, {"key": "D", "label": "スコープ付きURLは24時間後に期限切れになる。"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>すべての選択肢</strong></p><p>これらはすべて正しい記述です。</p><p>スコープ付きURLは、ステージへの権限を必要とせずにステージングされたファイルへの一時的なアクセスを可能にする一時的なエンコードURLです。スコープ付きURLは24時間後に期限切れになります。</p><p>スコープ付きURLを生成したユーザーのみが、そのURLを使用して参照ファイルにアクセスできます。スコープ付きURLはユーザーまたはアプリケーションへの一時的なアクセス提供に適しています。</p><p>https://docs.snowflake.com/en/user-guide/unstructured-intro#types-of-urls-available-to-access-files</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 116, "title": "クエリ結果キャッシュがクエリ結果を返す条件はどれですか？該当するものをすべて選択してください。", "multiSelect": true, "stemHtml": "<p>クエリ結果キャッシュがクエリ結果を返す条件はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "クエリが10万行未満の結果セットを返す。"}, {"key": "B", "label": "クエリが以前に実行されたクエリと同じ仮想ウェアハウスから実行されている。"}, {"key": "C", "label": "クエリ結果キャッシュが24時間以内に生成または使用されている。"}, {"key": "D", "label": "クエリ内のテーブルのマイクロパーティションが変更されていない。"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>24時間以内に生成または使用 / マイクロパーティションが変更されていない</strong></p><p>クエリ結果キャッシュが使用されるためには、基となるデータが変更されておらず、クエリが構文的に同一である必要があります。キャッシュが24時間以内に生成（または最後に使用）されている必要があります。</p><p>https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 117, "title": "MFAに関して正しい記述はどれですか？該当するものをすべて選択してください。", "multiSelect": true, "stemHtml": "<p>MFAに関して正しい記述はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "MFAはSnowflake Webインターフェースのみでサポートされている。"}, {"key": "B", "label": "MFAはBusiness Criticalエディション以上でのみ利用可能である。"}, {"key": "C", "label": "すべてのSnowflakeクライアントツールがMFAをサポートしている。"}, {"key": "D", "label": "すべてのSnowflakeエディションがMFAをサポートしている。"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>すべてのクライアントツールがMFAをサポート / すべてのエディションがMFAをサポート</strong></p><p>MFAはすべてのSnowflakeアカウントでデフォルトで有効化されており、すべてのSnowflakeエディションで利用できます。Webインターフェース、SnowSQL、および様々なコネクターやドライバーを含むすべてのSnowflakeクライアントツールがMFAをサポートしています。</p><p>https://docs.snowflake.com/en/user-guide/security-mfa</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 118, "title": "Snowflakeのコンピュートエンジンは何と呼ばれますか？", "multiSelect": false, "stemHtml": "<p>Snowflakeのコンピュートエンジンは何と呼ばれますか？</p>", "options": [{"key": "A", "label": "並列クエリエグゼキューター"}, {"key": "B", "label": "クエリ処理ユニット"}, {"key": "C", "label": "プロセッサー"}, {"key": "D", "label": "仮想ウェアハウス"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>仮想ウェアハウス</strong></p><p>Snowflakeのコンピュートエンジンは仮想ウェアハウスと呼ばれています。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 119, "title": "Snowflakeがクラスタリングキーに推奨する最大列数はいくつですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeがクラスタリングキーに推奨する最大列数はいくつですか？</p>", "options": [{"key": "A", "label": "1"}, {"key": "B", "label": "3〜4"}, {"key": "C", "label": "10"}, {"key": "D", "label": "2"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>3〜4</strong></p><p>Snowflakeはクラスタリングキーに最大3〜4列の使用を推奨しています。クラスタリングキーの列数がそれ以上になると、メンテナンスコストが増加し、クラスタリングコストを正当化するほどの十分な利点が得られません。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 120, "title": "テーブルをクローニングする際、現在のロールにはソーステーブルに対してどの権限が必要ですか？", "multiSelect": false, "stemHtml": "<p>テーブルをクローニングする際、現在のロールにはソーステーブルに対してどの権限が必要ですか？</p>", "options": [{"key": "A", "label": "SELECT"}, {"key": "B", "label": "USAGE"}, {"key": "C", "label": "WRITE"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>SELECT</strong></p><p>テーブルをクローンするには、ソーステーブルへのSELECT権限が必要です。パイプ、ストリーム、タスクのクローニングにはOWNERSHIP権限が必要で、クローン可能な他のすべてのオブジェクトにはUSAGE権限が必要です。</p><p>https://docs.snowflake.com/en/sql-reference/sql/create-clone#general-usage-notes</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 121, "title": "大きなテーブルにクラスタリングキーが追加または変更された場合、パフォーマンスが向上する可能性が高...", "multiSelect": true, "stemHtml": "<p>大きなテーブルにクラスタリングキーが追加または変更された場合、パフォーマンスが向上する可能性が高いクエリはどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "クラスタキーの一部である列でフィルタリングするクエリ。"}, {"key": "B", "label": "テーブルのすべての行を選択するクエリ。"}, {"key": "C", "label": "テーブルのすべての列を選択するクエリ。"}, {"key": "D", "label": "クラスタキーの一部である列でグループ化するクエリ。"}, {"key": "E", "label": "クラスタキーの一部である列で結合するクエリ。"}, {"key": "F", "label": "クラスタキーの一部である列でソートするクエリ。"}], "correctAnswers": ["A", "D", "E", "F"], "explanationHtml": "<p>✅ <strong>フィルタリング / グループ化 / 結合 / ソートするクエリ</strong></p><p>クラスタリングキーを定義すると、一般的にクエリ実行中にクラスタリングキーでのフィルタリングまたはソートが必要なクエリに利点があります。ORDER BY、GROUP BY、および特定の結合はクエリ実行中にソートが必要です。クラスタリングキーでWHERE句を使用するクエリも、適切に定義されたクラスタリングキーから恩恵を受けます。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 122, "title": "パーティションプルーニングが発生したかどうかを示す統計はどれですか？", "multiSelect": true, "stemHtml": "<p>パーティションプルーニングが発生したかどうかを示す統計はどれですか？</p>", "options": [{"key": "A", "label": "総バイト数"}, {"key": "B", "label": "書き込みバイト数"}, {"key": "C", "label": "スキャンバイト数"}, {"key": "D", "label": "パーティション総数"}, {"key": "E", "label": "スキャンされたパーティション数"}], "correctAnswers": ["D", "E"], "explanationHtml": "<p>✅ <strong>パーティション総数 / スキャンされたパーティション数</strong></p><p>パーティションプルーニングは、スキャンされたパーティション数がパーティション総数よりもはるかに少ない場合に発生します。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 123, "title": "正誤問題：Snowflakeはマイクロパーティション内の列を圧縮するための最も効率的なアルゴリズ...", "multiSelect": false, "stemHtml": "<p>正誤問題：Snowflakeはマイクロパーティション内の列を圧縮するための最も効率的なアルゴリズムを自動的に決定しますか？</p>", "options": [{"key": "A", "label": "True（正しい）"}, {"key": "B", "label": "False（誤り）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>Snowflakeは各マイクロパーティション内に列を列指向形式で保存します。列指向形式により、参照された列のみを取得することでSnowflakeはクエリを最適化できます。マイクロパーティションの圧縮に加えて、マイクロパーティション内の各列は独立して圧縮されます。Snowflakeは各列に対して最適な圧縮アルゴリズムを自動的に選択します。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 124, "title": "クエリのクエリ結果キャッシュを保持できる最大期間はどのくらいですか？", "multiSelect": false, "stemHtml": "<p>クエリのクエリ結果キャッシュを保持できる最大期間はどのくらいですか？</p>", "options": [{"key": "A", "label": "31日"}, {"key": "B", "label": "365日"}, {"key": "C", "label": "24時間"}, {"key": "D", "label": "3600秒"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>31日</strong></p><p>クエリの結果キャッシュが生成されると、24時間有効です。その24時間のウィンドウ内にクエリ結果キャッシュを再利用する別のクエリが実行されると、その時点から24時間分、結果キャッシュの期限が延長されます。クエリの結果キャッシュが使われ続ける場合、最大31日間有効です。31日後、クエリの結果キャッシュは他の条件に関わらず削除されます。</p><p>https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 125, "title": "MFAに関して正しい記述はどれですか？該当するものをすべて選択してください。", "multiSelect": true, "stemHtml": "<p>MFAに関して正しい記述はどれですか？該当するものをすべて選択してください。</p>", "options": [{"key": "A", "label": "MFAに登録できるのは管理者のみである。"}, {"key": "B", "label": "ユーザーのMFA登録は管理者によって無効にできる。"}, {"key": "C", "label": "一度MFAが有効化されたユーザーは無効にできない。"}, {"key": "D", "label": "ユーザーはSnowflake Webインターフェースを通じてMFAに自分で登録できる。"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>管理者によるMFA登録の無効化可 / ユーザー自身によるMFA登録可</strong></p><p>多要素認証（MFA）はすべてのSnowflakeアカウントでデフォルトで有効化されており、すべてのSnowflakeユーザーがSnowflake Webインターフェースを通じてMFAに自分で登録できます。管理者はユーザーのMFA登録を無効にすることができます。この場合、ユーザーはMFAの機能を使用するために再登録する必要があります。SECURITYADMINまたはそれIF以上のロールを持つ管理者がユーザーのMFAを無効にできます。</p><p>https://docs.snowflake.com/en/user-guide/security-mfa</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}]}, {"slug": "06_practice_exam", "title": "SnowPro Core 06_practice_exam", "sourcePath": "01_資格/Snowflake/SnowPro_Core/問題/06_practice_exam.md", "metadata": ["問題数: 124問"], "questionCount": 124, "questions": [{"order": 1, "title": "どのビュータイプが、Snowflakeの内部最適化の一部を使用しないですか？", "multiSelect": false, "stemHtml": "<p>どのビュータイプが、Snowflakeの内部最適化の一部を使用しないですか？</p>", "options": [{"key": "A", "label": "永続ビュー（Permanent Views）"}, {"key": "B", "label": "セキュアビュー（Secure views）"}, {"key": "C", "label": "マテリアライズドビュー（Materialized Views）"}, {"key": "D", "label": "外部ビュー（External Views）"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>セキュアビュー（Secure views）</strong></p><p>通常のビューでは、内部最適化によって間接的にデータがユーザーに露出する可能性があります。セキュアビューは、Snowflakeの内部最適化の一部を除去することで、基礎データを非表示にします。</p><p>https://docs.snowflake.com/en/user-guide/views-secure</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 2, "title": "Snowsightのワークシートについてのどのステートメントが正しいですか？", "multiSelect": true, "stemHtml": "<p>Snowsightのワークシートについてのどのステートメントが正しいですか？</p>", "options": [{"key": "A", "label": "どのワークシートのコンテキスト（ロール、ウェアハウス、スキーマ、データベース）も変更できない"}, {"key": "B", "label": "各ワークシートに異なるコンテキスト（ロール、ウェアハウス、スキーマ、データベース）を設定できる"}, {"key": "C", "label": "各ワークシートは異なるセッションとして機能する"}, {"key": "D", "label": "全てのワークシートは同じセッションを共有する"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>各ワークシートに異なるコンテキストを設定できる / 各ワークシートは異なるセッションとして機能する</strong></p><p>ワークシートビューでは、クエリが実行されるプライマリロールと、クエリの実行に使用する仮想ウェアハウスを選択できます。また、デフォルトのデータベースとスキーマも選択でき、各ワークシートは独立したセッションです。</p><p>https://docs.snowflake.com/en/user-guide/ui-snowsight</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 3, "title": "フェイルセーフをサポートするSnowflakeの最低エディションはどれですか？", "multiSelect": false, "stemHtml": "<p>フェイルセーフをサポートするSnowflakeの最低エディションはどれですか？</p>", "options": [{"key": "A", "label": "Standard"}, {"key": "B", "label": "Business Critical"}, {"key": "C", "label": "Virtual Private Snowflake"}, {"key": "D", "label": "Enterprise"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>フェイルセーフは全てのSnowflakeエディションでサポートされているため、フェイルセーフをサポートする最低エディションはStandardエディションです。</p><p>https://docs.snowflake.com/en/user-guide/data-failsafe</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 4, "title": "Snowflakeがマイクロパーティション内のデータについて保存するメタデータはどれですか？該当...", "multiSelect": true, "stemHtml": "<p>Snowflakeがマイクロパーティション内のデータについて保存するメタデータはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "マイクロパーティション内の各列の値の範囲"}, {"key": "B", "label": "個別の値の数"}, {"key": "C", "label": "最適化と効率的な処理のための追加プロパティ"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>列の値の範囲 / 個別の値の数 / 最適化のための追加プロパティ</strong></p><p>これらはSnowflakeがマイクロパーティション用に保存するメタデータの有効な例です。Snowflakeは各マイクロパーティションの各列の最大値と最小値をメタデータに保存します。このメタデータを使用して、クエリ処理時にどのパーティションを読み取るかを決定できます。また、各パーティションの各列の個別値の数と、クエリ最適化を支援するその他の情報も保存します。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 5, "title": "真か偽か：Snowflakeはパートナーソフトウェアがロードした後にデータを変換できる。", "multiSelect": false, "stemHtml": "<p>真か偽か：Snowflakeはパートナーソフトウェアがロードした後にデータを変換できる。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>パートナーソフトウェアを通じてSnowflakeにデータがロードされた後、Snowflake SQL または他のメカニズムを使用してSnowflake内でデータを変換できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 6, "title": "Snowflakeで列レベルのセキュリティを実装する必要があります。どのテクニックを使用できます...", "multiSelect": true, "stemHtml": "<p>Snowflakeで列レベルのセキュリティを実装する必要があります。どのテクニックを使用できますか？2つ選択してください。</p>", "options": [{"key": "A", "label": "外部トークン化（External Tokenization）"}, {"key": "B", "label": "行レベルセキュリティ（Row-level security）"}, {"key": "C", "label": "動的データマスキング（Dynamic Data Masking）"}, {"key": "D", "label": "オブジェクトセキュリティ（Object Security）"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>外部トークン化（External Tokenization） / 動的データマスキング（Dynamic Data Masking）</strong></p><p>Snowflakeはマスキングポリシーをサポートしており、列に適用して列レベルのセキュリティを提供できます。列レベルセキュリティは動的データマスキングまたは外部トークン化によって実現されます。</p><p>https://docs.snowflake.com/en/user-guide/security-column</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 7, "title": "以下のどれがタイムトラベルのSQL拡張機能ですか？", "multiSelect": true, "stemHtml": "<p>以下のどれがタイムトラベルのSQL拡張機能ですか？</p>", "options": [{"key": "A", "label": "TIME"}, {"key": "B", "label": "BEFORE"}, {"key": "C", "label": "UNDROP"}, {"key": "D", "label": "TIMETRAVEL"}, {"key": "E", "label": "AT"}], "correctAnswers": ["B", "C", "E"], "explanationHtml": "<p>✅ <strong>BEFORE / UNDROP / AT</strong></p><p>タイムトラベルクエリをサポートするために、SnowflakeはSQLの特別な拡張機能をサポートしています。SELECTステートメントや、テーブル・スキーマ・データベースのクローン作成時に使用できるATおよびBEFOREステートメントをサポートします。また、テーブル・スキーマ・完全なデータベースをドロップ後に復元するためのUNDROPステートメントもサポートします。</p><p>https://docs.snowflake.com/en/user-guide/data-time-travel#time-travel-sql-extensions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 8, "title": "作成後、他のテーブルタイプに変換できないものはどれですか？2つ選択してください。", "multiSelect": true, "stemHtml": "<p>作成後、他のテーブルタイプに変換できないものはどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "Permanent（永続）"}, {"key": "B", "label": "Temporary（一時）"}, {"key": "C", "label": "Transient（過渡）"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>Temporary（一時） / Transient（過渡）</strong></p><p>一度作成されると、一時テーブルと過渡テーブルは他のテーブルタイプに変更できません。</p><p>https://docs.snowflake.com/en/user-guide/tables-temp-transient#creating-a-temporary-table</p><p>https://docs.snowflake.com/en/user-guide/tables-temp-transient#creating-a-transient-table-schema-or-database</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake's Catalog and objects", "originalCorrect": null, "reviewPoint": ""}}, {"order": 9, "title": "SnowpipeおよびCOPY INTOコマンドを通じてテーブルにロードされたデータの履歴を取得...", "multiSelect": false, "stemHtml": "<p>SnowpipeおよびCOPY INTOコマンドを通じてテーブルにロードされたデータの履歴を取得するにはどのメソッドを使用できますか？</p>", "options": [{"key": "A", "label": "ACCOUNT_USAGEスキーマのCOPY_HISTORYビューにクエリを実行する"}, {"key": "B", "label": "ACCOUNT_USAGEスキーマのLOAD_HISTORYビューにクエリを実行する"}, {"key": "C", "label": "INFORMATION_SCHEMAのQUERY_HISTORYテーブル関数を使用する"}, {"key": "D", "label": "ACCOUNT_USAGEスキーマのPIPE_USAGE_HISTORYビューにクエリを実行する"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>ACCOUNT_USAGEスキーマのCOPY_HISTORYビューにクエリを実行する</strong></p><p>ACCOUNT_USAGEスキーマのCOPY_HISTORYビューは、COPYコマンドまたはSnowpipeによる継続的なデータロードのどちらかを通じてロードされたデータの履歴を表示するために使用できます。COPY_HISTORYビューは過去365日間の履歴を表示します。LOAD_HISTORYビューはCOPYコマンドのみのデータを表示します。PIPE_USAGE_HISTORYビューはSnowpipeの履歴のみを表示します。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage/copy_history</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 10, "title": "Snowflakeのアーキテクチャでユーザー認証と認可を担当するレイヤーはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeのアーキテクチャでユーザー認証と認可を担当するレイヤーはどれですか？</p>", "options": [{"key": "A", "label": "クラウドサービス（Cloud Services）"}, {"key": "B", "label": "クエリ処理（Query Processing）"}, {"key": "C", "label": "クライアントツール（Client Tools）"}, {"key": "D", "label": "データベースストレージ（Database Storage）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>クラウドサービス（Cloud Services）</strong></p><p>クラウドサービスレイヤーが認証と認可を管理します。ユーザーがログインすると、クラウドサービスレイヤーが資格情報を検証します。ユーザーがクエリを送信すると、クラウドサービスレイヤーがクエリプランを解析して最適化します。</p><p>https://docs.snowflake.com/en/user-guide/intro-key-concepts</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 11, "title": "真か偽か：ネットワークポリシーを使用して特定のIPアドレスへのアクセスを許可または拒否できる。", "multiSelect": false, "stemHtml": "<p>真か偽か：ネットワークポリシーを使用して特定のIPアドレスへのアクセスを許可または拒否できる。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>管理者はネットワークポリシーを通じて特定のIPアドレスへのアクセスを許可または拒否するようにシステムを設定できます。ネットワークポリシーは、ポリシー名、許可されたIPアドレスのカンマ区切りリスト、およびブロックされたIPアドレスのリストで構成されます。</p><p>https://docs.snowflake.com/en/user-guide/network-policies</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 12, "title": "ACCOUNT_USAGEスキーマのビューを通じてアクセスできる履歴データは何日分ですか？", "multiSelect": false, "stemHtml": "<p>ACCOUNT_USAGEスキーマのビューを通じてアクセスできる履歴データは何日分ですか？</p>", "options": [{"key": "A", "label": "7日"}, {"key": "B", "label": "365日"}, {"key": "C", "label": "90日"}, {"key": "D", "label": "1日"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>365日</strong></p><p>ACCOUNT USAGEスキーマは、アカウントレベルでの使用量メトリクスとメタデータ情報を提供するいくつかのビューで構成されています。ACCOUNT_USAGEビューが提供するデータはリアルタイムではなく、ビューによって45分〜3時間のラグがあります。これらのビューのデータは最大365日間保持されます。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 13, "title": "テーブルステージを使用してEMPLOYEEというテーブルにデータをロードする場合、有効なステート...", "multiSelect": true, "stemHtml": "<p>テーブルステージを使用してEMPLOYEEというテーブルにデータをロードする場合、有効なステートメントはどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "COPY INTO EMPLOYEE FROM TABLE_STAGE;"}, {"key": "B", "label": "COPY INTO EMPLOYEE FROM @%EMPLOYEE;"}, {"key": "C", "label": "COPY INTO EMPLOYEE;"}, {"key": "D", "label": "COPY INTO EMPLOYEE SELECT * FROM TABLE_STAGE;"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>COPY INTO EMPLOYEE FROM @%EMPLOYEE; / COPY INTO EMPLOYEE;</strong></p><p>テーブルステージからデータをロードする場合、FROM句を省略できます。その場合、Snowflakeは自動的にテーブルステージからデータをロードすると見なします。したがって、<code>COPY INTO EMPLOYEE;</code> と <code>COPY INTO EMPLOYEE FROM @%EMPLOYEE;</code> の両方が正しいです。</p><p>https://docs.snowflake.com/en/user-guide/data-load-local-file-system-copy#table-stage</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 14, "title": "マルチクラスター仮想ウェアハウスに関する正しいステートメントはどれですか？該当するものを全て選択...", "multiSelect": true, "stemHtml": "<p>マルチクラスター仮想ウェアハウスに関する正しいステートメントはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "マルチクラスター仮想ウェアハウスは、標準の仮想ウェアハウスと同様に自動サスペンドまたは自動レジュームを設定できる"}, {"key": "B", "label": "マルチクラスター仮想ウェアハウスは自動サスペンドまたは自動レジュームを設定できない"}, {"key": "C", "label": "マルチクラスター仮想ウェアハウスは、変化するワークロード需要に応じて仮想ウェアハウスを自動的に追加または削除する"}, {"key": "D", "label": "マルチクラスター仮想ウェアハウスのクラスターは手動で追加または削除する必要がある"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>自動サスペンド・レジューム設定可能 / ワークロードに応じて自動追加・削除</strong></p><p>仮想ウェアハウスの同時ワークロードが最大に達すると、新しいクエリはキューに入ります。マルチクラスター仮想ウェアハウスは必要に応じてクラスターを追加することでこれに対応します。需要が下がると、追加クラスターは削除されます。マルチクラスター仮想ウェアハウスは他の仮想ウェアハウスと同様にサスペンドまたはレジュームでき、自動サスペンド・自動レジュームも設定できます。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-multicluster</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 15, "title": "マテリアライズドビューを正しく説明しているものはどれですか？該当するものを全て選択してください。", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューを正しく説明しているものはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "マテリアライズドビューをベーステーブルと同期するにはアクティブな仮想ウェアハウスが必要"}, {"key": "B", "label": "基礎テーブルのデータが変更された場合、マテリアライズドビューは手動で更新する必要がある"}, {"key": "C", "label": "Snowflakeが管理するサービスがマテリアライズドビューをベーステーブルと同期し続ける"}, {"key": "D", "label": "基礎テーブルのデータが変更された場合、マテリアライズドビューは自動的に更新される"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>Snowflake管理サービスが同期 / 基礎テーブル変更時に自動更新</strong></p><p>マテリアライズドビューはSELECTクエリに基づいてデータを事前計算するビューです。基礎テーブルが更新されると、マテリアライズドビューは自動的にリフレッシュされ、追加のメンテナンスは不要です。Snowflakeが管理するサービスがユーザーの操作を妨げることなくバックグラウンドで更新を行います。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 16, "title": "組織のセキュリティポリシーにより、テーブルの特定の行をユーザーがクエリできないようにする必要があ...", "multiSelect": true, "stemHtml": "<p>組織のセキュリティポリシーにより、テーブルの特定の行をユーザーがクエリできないようにする必要があります。この要件を満たすためにどのSnowflake機能を使用できますか？2つ選択してください。</p>", "options": [{"key": "A", "label": "外部ビュー（External Views）"}, {"key": "B", "label": "行アクセスポリシー（Row Access Policies）"}, {"key": "C", "label": "列レベルセキュリティ（Column Level Security）"}, {"key": "D", "label": "セキュアビュー（Secure Views）"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>行アクセスポリシー（Row Access Policies） / セキュアビュー（Secure Views）</strong></p><p>セキュアビューはテーブルから特定の行のみを返すために使用できます。また、セキュアビューはSnowflakeの内部最適化の一部を削除することで基礎データを非表示にします。あるいは、行レベルセキュリティ（RLS）を使用して特定の行のみを返すこともできます。RLSは行アクセスポリシーを作成することで実装されます。</p><p>https://docs.snowflake.com/en/user-guide/views-secure<br>https://docs.snowflake.com/en/user-guide/security-row-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 17, "title": "真か偽か：Snowflakeのデータプロバイダーがデータコンシューマーとデータを共有する場合、デ...", "multiSelect": false, "stemHtml": "<p>真か偽か：Snowflakeのデータプロバイダーがデータコンシューマーとデータを共有する場合、データコンシューマーは追加のストレージコストを請求されない。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>クラウドサービスレイヤーのメタデータ操作により、データを物理的にコピーすることなくデータ共有が可能です。プロバイダーアカウントがデータストレージを保存し支払うため、データコンシューマーはストレージに追加料金を払う必要がありません。ただし、データコンシューマーは共有データでクエリを実行するために使用されるコンピューティングの費用を支払います。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-intro#how-does-secure-data-sharing-work</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 18, "title": "真か偽か：ストアドプロシージャは値を返す必要がある。", "multiSelect": false, "stemHtml": "<p>真か偽か：ストアドプロシージャは値を返す必要がある。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False</strong></p><p>ストアドプロシージャは必要に応じて単一の値または表形式データを返すこともできますが、ストアドプロシージャが値を返す必要はありません。</p><p>https://docs.snowflake.com/en/developer-guide/stored-procedures-vs-udfs</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 19, "title": "未入力テーブルのクラスタリング深度はいくつですか？", "multiSelect": false, "stemHtml": "<p>未入力テーブルのクラスタリング深度はいくつですか？</p>", "options": [{"key": "A", "label": "1"}, {"key": "B", "label": "-1"}, {"key": "C", "label": "ゼロ（Zero）"}, {"key": "D", "label": "1000"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>ゼロ（Zero）</strong></p><p>入力済みテーブルの場合、クラスタリング深度は特定の列のオーバーラップするマイクロパーティションの平均深度です。クラスタリング深度は1（よくクラスタリングされたテーブル）から始まり、より大きな数になる可能性があります。未入力テーブルの場合、クラスタリング深度はゼロです。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions#label-clustering-depth</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 20, "title": "ユーザーがミディアムサイズの仮想ウェアハウスで完了に2時間かかった複雑なクエリを実行しました。ユ...", "multiSelect": false, "stemHtml": "<p>ユーザーがミディアムサイズの仮想ウェアハウスで完了に2時間かかった複雑なクエリを実行しました。ユーザーが6時間後に新しいセッションでクエリを再実行したところ、ほぼ即座に結果が返されました。この素早い実行の理由は何ですか？</p>", "options": [{"key": "A", "label": "基礎テーブルのデータが削除されたため、処理するものがなくてクエリが速かった"}, {"key": "B", "label": "ブラウザキャッシュから結果が取得された"}, {"key": "C", "label": "クエリ結果キャッシュを使用して結果が即座に返された"}, {"key": "D", "label": "ユーザーステージから結果が取得されたため実行が速かった"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>クエリ結果キャッシュを使用して結果が即座に返された</strong></p><p>Snowflakeはクエリを実行すると、そのクエリの結果を一定期間キャッシュします。保存されたクエリ結果はクエリ結果キャッシュと呼ばれます。クエリ結果キャッシュは、以前に実行したクエリと類似していて、クエリされているテーブルのデータに変更がない場合に、将来のクエリを満たすために使用できます。</p><p>https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 21, "title": "復旧のためにレプリケーションの設定が必要なシナリオはどれですか？該当するものを全て選択してくださ...", "multiSelect": true, "stemHtml": "<p>復旧のためにレプリケーションの設定が必要なシナリオはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "管理者が先週、本番テーブルを誤ってドロップした"}, {"key": "B", "label": "昨日本番環境にロールアウトされた新しいデータパイプラインが本番テーブルの全行を削除した"}, {"key": "C", "label": "プライマリSnowflakeインスタンスをホストしているクラウドプラットフォームが失敗し、利用できなくなった"}, {"key": "D", "label": "93日前に3つの本番テーブルを破損したデータ破損の問題が発見された"}, {"key": "E", "label": "プライマリSnowflakeインスタンスをホストしているクラウドリージョンが壊滅的な障害によりダウンし、データが利用できない"}], "correctAnswers": ["C", "E"], "explanationHtml": "<p>✅ <strong>クラウドプラットフォーム障害 / クラウドリージョン壊滅的障害</strong></p><p>クラウドプロバイダーまたはリージョンがダウンすると、Snowflakeユーザーに影響が生じる可能性があります。影響を最小限に抑えるため、クラウドプロバイダーの停止に備えてSnowflakeをユーザーが利用できる状態を維持する必要があります。</p><p>Snowflakeのアカウントレベルのレプリケーションとデータベースレプリケーションは、プライマリアカウントから異なるリージョンまたはクラウドプラットフォームの1つ以上のセカンダリアカウントに重要なアカウントオブジェクトとデータを同期します。</p><p>https://docs.snowflake.com/en/user-guide/account-replication-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ保護", "originalCorrect": null, "reviewPoint": ""}}, {"order": 22, "title": "Snowflakeがサポートする半構造化ファイル形式はどれですか？該当するものを全て選択してくだ...", "multiSelect": true, "stemHtml": "<p>Snowflakeがサポートする半構造化ファイル形式はどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "YAML"}, {"key": "B", "label": "AVRO"}, {"key": "C", "label": "JSON"}, {"key": "D", "label": "ORC"}, {"key": "E", "label": "PDF"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>AVRO / JSON / ORC</strong></p><p>Snowflakeにはいくつかの半構造化データ形式のサポートが組み込まれています。SnowflakeはJSON、Avro、ORC、Parquet、XMLをサポートしています。</p><p>https://docs.snowflake.com/en/user-guide/semistructured-intro.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 23, "title": "真か偽か：INFORMATION_SCHEMAのビューのデータはリアルタイムである。", "multiSelect": false, "stemHtml": "<p>真か偽か：INFORMATION_SCHEMAのビューのデータはリアルタイムである。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>INFORMATION_SCHEMAビューを通じて提供されるデータはリアルタイムであり、提供される情報に遅延はありません。リアルタイムデータを表示する要件がある場合は、INFORMATION SCHEMAのビューを使用する必要があります。</p><p>https://docs.snowflake.com/en/sql-reference/account-usage#differences-between-account-usage-and-information-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 24, "title": "タイムトラベルとフェイルセーフストレージに関する正しいステートメントはどれですか？該当するものを...", "multiSelect": true, "stemHtml": "<p>タイムトラベルとフェイルセーフストレージに関する正しいステートメントはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "一時テーブルの最大タイムトラベル期間は1日"}, {"key": "B", "label": "一時テーブルには7日間のフェイルセーフストレージがある"}, {"key": "C", "label": "一時テーブルの最大タイムトラベル期間は7日"}, {"key": "D", "label": "一時テーブルにはフェイルセーフストレージがない"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>最大タイムトラベル期間は1日 / フェイルセーフストレージなし</strong></p><p>過渡テーブルと一時テーブルにはフェイルセーフ機能がないため、これらのテーブルのデータはゼロ日のフェイルセーフストレージを通過します。また、過渡テーブルと一時テーブルの最大タイムトラベルは1日です。</p><p>https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 25, "title": "以下のうちクローンできるものはどれですか？", "multiSelect": true, "stemHtml": "<p>以下のうちクローンできるものはどれですか？</p>", "options": [{"key": "A", "label": "データベース（Databases）"}, {"key": "B", "label": "スキーマ（Schemas）"}, {"key": "C", "label": "テーブル（Tables）"}, {"key": "D", "label": "内部名前付きステージ（Internal Named Stages）"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>データベース / スキーマ / テーブル</strong></p><p>名前付き内部ステージはクローンできません。データベースまたはスキーマをクローンする場合、名前付き内部ステージを指すSnowpipeはクローンされません。名前付き外部ステージはクローンできます。テーブルステージはテーブルに関連付けられているため、テーブルがクローンされると自動的にクローンされます。また、外部テーブルもクローンできません。</p><p>https://docs.snowflake.com/en/user-guide/object-clone#cloning-and-stages</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 26, "title": "管理者がMARKETINGデータベースのPUBLICスキーマにマテリアライズドビューを作成できる...", "multiSelect": false, "stemHtml": "<p>管理者がMARKETINGデータベースのPUBLICスキーマにマテリアライズドビューを作成できるようにロールにアクセスを付与する必要があります。必要な権限を提供するステートメントはどれですか？</p>", "options": [{"key": "A", "label": "GRANT MATERIALIZED VIEW ON SCHEMA MARKETING.PUBLIC TO ROLE <role_name>;"}, {"key": "B", "label": "GRANT CREATE MATERIALIZED VIEW ON SCHEMA MARKETING.PUBLIC TO ROLE <role_name>;"}, {"key": "C", "label": "GRANT CREATE MATERIALIZED VIEW ON SCHEMA MARKETING.PUBLIC TO <role_name>;"}, {"key": "D", "label": "GRANT MATERIALIZED VIEW ON SCHEMA MARKETING.PUBLIC TO <role_name>;"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>GRANT CREATE MATERIALIZED VIEW ON SCHEMA MARKETING.PUBLIC TO ROLE &lt;role_name&gt;;</strong></p><p>正しい構文は <code>GRANT CREATE MATERIALIZED VIEW ON SCHEMA &lt;schema_name&gt; TO ROLE &lt;role_name&gt;;</code> です。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized#privileges-on-a-materialized-view-s-schema</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 27, "title": "SnowflakeのEnterpriseエディションでタイムトラベルの最大期間はどれですか？", "multiSelect": false, "stemHtml": "<p>SnowflakeのEnterpriseエディションでタイムトラベルの最大期間はどれですか？</p>", "options": [{"key": "A", "label": "1日"}, {"key": "B", "label": "45日"}, {"key": "C", "label": "0日"}, {"key": "D", "label": "90日"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>90日</strong></p><p>Snowflakeエディションによって、タイムトラベルの期間は1〜90日の範囲になる場合があります。Standardエディションでは1日のタイムトラベルが可能です。EnterpriseバージョンおよびそれEE以上のバージョンでは最大90日のタイムトラベルが可能です。</p><p>https://docs.snowflake.com/en/user-guide/data-time-travel#data-retention-period</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タイムトラベル", "originalCorrect": null, "reviewPoint": ""}}, {"order": 28, "title": "GETコマンドはどの目的で使用されますか？", "multiSelect": false, "stemHtml": "<p>GETコマンドはどの目的で使用されますか？</p>", "options": [{"key": "A", "label": "Snowflakeテーブルから任意のタイプのステージにデータをダウンロードする"}, {"key": "B", "label": "オンプレミスシステム上の外部ステージからデータをダウンロードする"}, {"key": "C", "label": "内部ステージからオンプレミスシステムにデータをダウンロードする"}, {"key": "D", "label": "内部ステージからクラウドストレージにデータをダウンロードする"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>内部ステージからオンプレミスシステムにデータをダウンロードする</strong></p><p>GETコマンドは内部ステージからオンプレミスシステムにデータをダウンロードするために使用されます。PUTコマンドはオンプレミスシステムから内部ステージにデータをアップロードします。外部ステージへのデータのダウンロードまたはアップロードには、クラウドプロバイダーのユーティリティやその他のツールが使用されます。</p><p>https://docs.snowflake.com/en/user-guide/data-unload-overview#bulk-unloading-process</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 29, "title": "Snowflakeのストリームオブジェクトに関して正しいステートメントはどれですか？該当するもの...", "multiSelect": true, "stemHtml": "<p>Snowflakeのストリームオブジェクトに関して正しいステートメントはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "マテリアライズドビューはストリームをサポートしない"}, {"key": "B", "label": "ストリームオブジェクトはテーブルへのDML変更（挿入、更新、削除）を行レベルで記録する"}, {"key": "C", "label": "ストリームオブジェクトは数年間テーブルのDML変更を追跡できる"}, {"key": "D", "label": "外部テーブルはストリームをサポートしない"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>マテリアライズドビューはストリームをサポートしない / ストリームはDML変更を行レベルで記録する</strong></p><p>マテリアライズドビューは現在ストリームをサポートしていません。</p><p>Snowflakeストリームは、新しいデータの追加（挿入）、既存データの変更（更新）、データの削除などのテーブルへの変更を追跡するのに役立ちます。最後のオフセット以降に変更されたデータのみをクエリおよび処理できます。</p><p>ストリームオブジェクトは指定されたデータ保持期間内のソーステーブルへのDML変更を監視・記録します。その後、ストリームは古くなり、DML変更は利用できなくなります。</p><p>外部テーブルはストリームをサポートしています。Snowflakeの挿入専用ストリームは、挿入と更新の両方を新しい行としてキャプチャすることで外部テーブルへの変更を追跡しますが、削除操作は無視されます。</p><p>https://docs.snowflake.com/en/user-guide/streams-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ストリーム", "originalCorrect": null, "reviewPoint": ""}}, {"order": 30, "title": "既存のリソースモニターを表示および変更できるのはどれですか？該当するものを全て選択してください。", "multiSelect": true, "stemHtml": "<p>既存のリソースモニターを表示および変更できるのはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "システムの任意のユーザー"}, {"key": "B", "label": "アカウント管理者（ACCOUNTADMINロールを持つ人）"}, {"key": "C", "label": "システム管理者（SYSADMINロールを持つ人）"}, {"key": "D", "label": "リソースモニターのMONITORおよびMODIFY権限を持つユーザー"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>アカウント管理者（ACCOUNTADMIN） / MONITORおよびMODIFY権限を持つユーザー</strong></p><p>権限の観点から、リソースモニターを作成できるのはアカウント管理者（ACCOUNTADMINロールを持つユーザー）のみです。ただし、アカウント管理者はリソースモニターの設定を表示・変更できるように他のユーザーに権限を付与できます。リソースモニターのMONITORおよびMODIFY権限により、他のユーザーが特定のリソースモニターを表示・変更できます。</p><p>https://docs.snowflake.com/en/user-guide/resource-monitors#access-control-privileges-for-resource-monitors</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 31, "title": "SYSADMINロールを持つJohnがクエリを実行しました。別のユーザーJaneがSnowsig...", "multiSelect": false, "stemHtml": "<p>SYSADMINロールを持つJohnがクエリを実行しました。別のユーザーJaneがSnowsightのクエリ履歴を使用してJohnが実行したクエリの結果を表示しようとしました。以下のうちどれが結果を正しく説明していますか？</p>", "options": [{"key": "A", "label": "JaneはJohnが実行したクエリの結果セットを見ることができない"}, {"key": "B", "label": "JaneはJohnが権限を付与した場合のみJohnが実行したクエリの結果セットを見ることができる"}, {"key": "C", "label": "JaneはJohnもSYSADMINロールの一部である場合のみJohnが実行したクエリの結果セットを見ることができる"}, {"key": "D", "label": "JaneはACCOUNTADMINロールを持っている場合のみJohnが実行したクエリの結果セットを見ることができる"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>JaneはJohnが実行したクエリの結果セットを見ることができない</strong></p><p>自分が実行した履歴クエリの結果のみを見ることができます。プライバシー上の理由から、クエリ詳細ページは他のユーザーが実行したクエリの結果を表示しません（そのクエリの詳細を見る権限があっても同様です）。</p><p>https://docs.snowflake.com/en/user-guide/ui-history#viewing-query-details-and-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 32, "title": "真か偽か：クロスクラウドまたはクロスリージョンのデータ共有のためにレプリケーションを設定する場合...", "multiSelect": false, "stemHtml": "<p>真か偽か：クロスクラウドまたはクロスリージョンのデータ共有のためにレプリケーションを設定する場合、データプロバイダーはデータコンシューマーごとに1回データをレプリケートする必要がある。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>False</strong></p><p>クラウドまたはリージョンごとに1つのデータインスタンスのみをレプリケートする必要があります。インスタンスがレプリケートされると、複数のコンシューマーがこのデータを使用できます。</p><p>https://docs.snowflake.com/en/user-guide/secure-data-sharing-across-regions-plaforms<br>https://docs.snowflake.com/en/user-guide/secure-data-sharing-across-regions-plaforms#data-sharing-considerations</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 33, "title": "マテリアライズドビューをサポートするSnowflakeの最低エディションはどれですか？", "multiSelect": false, "stemHtml": "<p>マテリアライズドビューをサポートするSnowflakeの最低エディションはどれですか？</p>", "options": [{"key": "A", "label": "Standard"}, {"key": "B", "label": "Enterprise"}, {"key": "C", "label": "Business Critical"}, {"key": "D", "label": "Virtual Private Snowflake"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Enterprise</strong></p><p>マテリアライズドビューをサポートするSnowflakeの最低エディションはEnterpriseです。Enterpriseエディション以上の全エディションもマテリアライズドビューをサポートします。</p><p>https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 34, "title": "SQL Workbench、DBeaver、ErwinはSnowflakeパートナーエコシステム...", "multiSelect": false, "stemHtml": "<p>SQL Workbench、DBeaver、ErwinはSnowflakeパートナーエコシステムのどのタイプのパートナーですか？</p>", "options": [{"key": "A", "label": "SQL開発と管理（SQL Development and Management）"}, {"key": "B", "label": "データ統合（Data Integration）"}, {"key": "C", "label": "機械学習とデータサイエンス（Machine Learning & Data Science）"}, {"key": "D", "label": "セキュリティ、ガバナンス、オブザービリティ（Security, Governance & Observability）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>SQL開発と管理（SQL Development and Management）</strong></p><p>これらは全てSnowflakeのSQL開発と管理パートナーです。</p><p>https://docs.Snowflake.com/en/user-guide/ecosystem.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パートナー", "originalCorrect": null, "reviewPoint": ""}}, {"order": 35, "title": "Snowflakeがサポートする認証メカニズムはどれですか？該当するものを全て選択してください。", "multiSelect": true, "stemHtml": "<p>Snowflakeがサポートする認証メカニズムはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "平文パスワード認証（Plain Text Password authentication）"}, {"key": "B", "label": "MD5認証（MD5 authentication）"}, {"key": "C", "label": "キーペア認証（Key Pair Authentication）"}, {"key": "D", "label": "多要素認証（Multi-factor authentication）"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>キーペア認証 / 多要素認証</strong></p><p>多要素認証はSnowflakeのログインプロセスに追加の保護を加えます。Snowflakeは従来のユーザー名/パスワード認証のより安全な代替手段としてキーペア認証を提供します。さらに、Snowflakeはフェデレーション認証をサポートしており、ユーザーはSAML 2.0準拠のシングルサインオン（SSO）を通じてアクセスできます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 36, "title": "SnowflakeのどのエディションがSnowflakeの内部ステージへのプライベート接続をサポ...", "multiSelect": true, "stemHtml": "<p>SnowflakeのどのエディションがSnowflakeの内部ステージへのプライベート接続をサポートしていますか？</p>", "options": [{"key": "A", "label": "Enterprise Edition"}, {"key": "B", "label": "Virtual Private Snowflake (VPS) エディション"}, {"key": "C", "label": "Business Critical Edition"}, {"key": "D", "label": "Standard Edition"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>Virtual Private Snowflake (VPS) / Business Critical Edition</strong></p><p>プライベート接続により、Snowflakeインスタンスへのアクセスがセキュアな接続を経由することを保証し、インターネットベースのアクセスを完全にブロックすることも可能です。SnowflakeへのプライベートはBusiness Criticalエディション以上が必要です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 37, "title": "クエリ結果キャッシュの再利用はどのパラメーターを使用して無効にできますか？", "multiSelect": false, "stemHtml": "<p>クエリ結果キャッシュの再利用はどのパラメーターを使用して無効にできますか？</p>", "options": [{"key": "A", "label": "USE_CACHED_RESULT"}, {"key": "B", "label": "ENABLE_QUERY_RESULT_CACHE"}, {"key": "C", "label": "PURGE_CACHED_RESULTS"}, {"key": "D", "label": "DISABLE_QUERY_RESULT_CACHE"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>USE_CACHED_RESULT</strong></p><p>クエリ結果キャッシュはデフォルトで有効になっていますが、USE_CACHED_RESULTパラメーターを使用してセッション、ユーザー、またはアカウントレベルで無効にできます。</p><p>https://docs.snowflake.com/en/user-guide/querying-persisted-results</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 38, "title": "MARKETINGスキーマのCUSTOMERテーブルに対してSearch Optimizatio...", "multiSelect": false, "stemHtml": "<p>MARKETINGスキーマのCUSTOMERテーブルに対してSearch Optimizationを追加、設定、または削除できるように、MKT_USERSというロールに正しい権限を付与するステートメントはどれですか？</p>", "options": [{"key": "A", "label": "GRANT SEARCH OPTIMIZATION ON SCHEMA MARKETING TO ROLE MKT_USERS;"}, {"key": "B", "label": "GRANT ADD SEARCH OPTIMIZATION ON TABLE CUSTOMER TO ROLE MKT_USERS;"}, {"key": "C", "label": "GRANT ADD SEARCH OPTIMIZATION ON SCHEMA MARKETING TO ROLE MKT_USERS;"}, {"key": "D", "label": "GRANT SEARCH OPTIMIZATION ON TABLE CUSTOMER TO ROLE MKT_USERS;"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>GRANT ADD SEARCH OPTIMIZATION ON SCHEMA MARKETING TO ROLE MKT_USERS;</strong></p><p>テーブルに対して検索最適化を追加、設定、または削除するには、テーブルに対するOWNERSHIP権限と、テーブルを含むスキーマに対するADD SEARCH OPTIMIZATION権限が必要です。構文は <code>GRANT ADD SEARCH OPTIMIZATION ON SCHEMA &lt;schema_name&gt; TO ROLE &lt;role&gt;</code> です。</p><p>https://docs.snowflake.com/en/user-guide/search-optimization-service#what-access-control-privileges-are-needed-for-the-search-optimization-service</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 39, "title": "SNOWFLAKE_SAMPLE_DATA.TPCH_SF1スキーマのCUSTOMERテーブルを...", "multiSelect": true, "stemHtml": "<p>SNOWFLAKE_SAMPLE_DATA.TPCH_SF1スキーマのCUSTOMERテーブルを考えてください。仮想ウェアハウスはサスペンド状態ですが、自動レジュームが設定されています。以下のどのクエリが仮想ウェアハウスを再開させますか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "SELECT * FROM SNOWFLAKE_SAMPLE_DATA.TPCH_SF1.CUSTOMER;"}, {"key": "B", "label": "USE SNOWFLAKE_SAMPLE_DATA.TPCH_SF1;"}, {"key": "C", "label": "SHOW TABLES LIKE '%CUSTOMER%';"}, {"key": "D", "label": "SELECT C_MKTSEGMENT,SUM(C_ACCTBAL) FROM SNOWFLAKE_SAMPLE_DATA.TPCH_SF1.CUSTOMER GROUP BY C_MKTSEGMENT;"}, {"key": "E", "label": "DESCRIBE TABLE SNOWFLAKE_SAMPLE_DATA.TPCH_SF1;"}, {"key": "F", "label": "SELECT COUNT(*) FROM SNOWFLAKE_SAMPLE_DATA.TPCH_SF1.CUSTOMER;"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>SELECT * ... / SELECT C_MKTSEGMENT,SUM(C_ACCTBAL)...</strong></p><p>メタデータキャッシュまたはクラウドサービス操作はアクティブな仮想ウェアハウスを必要としません。他のクエリにはアクティブな仮想ウェアハウスが必要です。</p><p>統計は各テーブル、マイクロパーティション、列のクラウドサービスレイヤーのメタデータキャッシュに保持されます。クエリが単に行数をカウントするだけであれば、メタデータキャッシュが結果を返せます。同様に、クラウドサービスレイヤーはテーブル定義（DESCRIBE）やスキーマ内のテーブルリスト（SHOW TABLES LIKE）を提供できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 40, "title": "リソースモニターは何のために使用されますか？", "multiSelect": false, "stemHtml": "<p>リソースモニターは何のために使用されますか？</p>", "options": [{"key": "A", "label": "キューに入っているクエリ数を監視する"}, {"key": "B", "label": "仮想ウェアハウスを自動的にスケールアップ・ダウンする"}, {"key": "C", "label": "各仮想ウェアハウスのリソース割り当てを監視する"}, {"key": "D", "label": "仮想ウェアハウスのコストとクレジット使用を制御する"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>仮想ウェアハウスのコストとクレジット使用を制御する</strong></p><p>リソースモニターは仮想ウェアハウスのコスト管理と予期しないクレジット使用を避けるのに役立ちます。リソースモニターは定義された上限に対してクレジット使用を監視し、上限の一定割合に達すると管理者に通知し、必要に応じて仮想ウェアハウスをサスペンドすることでクレジット使用を制御できます。</p><p>https://docs.snowflake.com/en/user-guide/resource-monitors</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 41, "title": "Snowflakeシステムのストレージコストに貢献するものはどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflakeシステムのストレージコストに貢献するものはどれですか？</p>", "options": [{"key": "A", "label": "過渡テーブル（Transient tables）"}, {"key": "B", "label": "一時テーブル（Temporary Tables）"}, {"key": "C", "label": "永続テーブル（Permanent tables）"}, {"key": "D", "label": "外部テーブル（External tables）"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>過渡テーブル / 一時テーブル / 永続テーブル</strong></p><p>外部テーブルのデータはSnowflake外部のクラウドストレージに保存されるため、外部テーブルはストレージコストに貢献しません。ただし、永続テーブル、一時テーブル、過渡テーブルはそれぞれ異なるストレージコストに貢献します。</p><p>https://docs.snowflake.com/en/user-guide/cost-understanding-data-storage#temporary-and-transient-tables-costs</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "コストと価格", "originalCorrect": null, "reviewPoint": ""}}, {"order": 42, "title": "仮想ウェアハウスをより大きなサイズにスケールアップする場合、正しいものはどれですか？該当するもの...", "multiSelect": true, "stemHtml": "<p>仮想ウェアハウスをより大きなサイズにスケールアップする場合、正しいものはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "新しいサイズへの課金は、より大きな仮想ウェアハウスの全ての新しいノードがプロビジョニングされるまで開始されない"}, {"key": "B", "label": "仮想ウェアハウスをより小さなサイズにスケールダウンできない"}, {"key": "C", "label": "サイズの増加は仮想ウェアハウスで既に実行中のクエリに影響しない"}, {"key": "D", "label": "既存の全クエリは終了し、再送信する必要がある"}, {"key": "E", "label": "新しいクエリのみがより大きな仮想ウェアハウスサイズの恩恵を受ける"}], "correctAnswers": ["A", "C", "E"], "explanationHtml": "<p>✅ <strong>新ノードプロビジョニング後に課金開始 / 既存クエリに影響なし / 新クエリのみ恩恵を受ける</strong></p><p>仮想ウェアハウスをスケールアップすると、より大きな仮想ウェアハウスの全ての新しいノードがプロビジョニングされるまで新しいサイズへの課金は開始されません。新しいクエリのみが変更されたサイズの影響を受け、仮想ウェアハウスの既存クエリは影響を受けません。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 43, "title": "マルチクラスター仮想ウェアハウスの最大クラスター数はいくつですか？", "multiSelect": false, "stemHtml": "<p>マルチクラスター仮想ウェアハウスの最大クラスター数はいくつですか？</p>", "options": [{"key": "A", "label": "24"}, {"key": "B", "label": "10"}, {"key": "C", "label": "50"}, {"key": "D", "label": "1"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>10</strong></p><p>マルチクラスター仮想ウェアハウスは同時に1〜10の異なるクラスターをサポートします。サポートされるクラスターの最小数は1で、許可されるクラスターの最大数は10です。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-multicluster#what-is-a-multi-cluster-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 44, "title": "真か偽か：テーブルがクローンされた後、元のテーブルをドロップするとクローンもドロップされる。", "multiSelect": false, "stemHtml": "<p>真か偽か：テーブルがクローンされた後、元のテーブルをドロップするとクローンもドロップされる。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False</strong></p><p>クラウドサービスレイヤーのマイクロパーティションとメタデータにより、クローンされたテーブルのメタデータが既存のマイクロパーティションを参照するため、迅速かつ効率的なゼロコピークローニングが可能です。ソースとクローンされたアイテムは独立しているため、一方のデータを変更しても他方には影響しません。例えば、ソーステーブルを完全にドロップしてもクローンされたテーブルには影響しません。</p><p>https://docs.snowflake.com/en/user-guide/tables-storage-considerations#label-cloning-tables</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 45, "title": "PUBLICロールに関する正しいステートメントはどれですか？該当するものを全て選択してください。", "multiSelect": true, "stemHtml": "<p>PUBLICロールに関する正しいステートメントはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "PUBLICロールは事前定義されておらず、アカウント管理者が作成する必要がある"}, {"key": "B", "label": "PUBLICロールはSnowflakeシステムで最も権限の低いロールである"}, {"key": "C", "label": "PUBLICロールはSnowflakeシステムで最も権限の高いロールである"}, {"key": "D", "label": "PUBLICロールはSnowflakeの全てのユーザーに自動的に割り当てられる"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>最も権限が低いロール / 全ユーザーに自動割り当て</strong></p><p>PUBLICロールはSnowflakeの既製ロールの1つです。PUBLICロールは最も少ない権限を持ち、全てのユーザーに自動的に割り当てられます。</p><p>https://docs.snowflake.com/en/user-guide/security-access-control-overview#system-defined-roles</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 46, "title": "SnowflakeのタスクについてのどのステートメントはXXXですか？該当するものを全て選択して...", "multiSelect": true, "stemHtml": "<p>SnowflakeのタスクについてのどのステートメントはXXXですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "タスクはEXECUTE TASKコマンドを使用して手動で実行できる"}, {"key": "B", "label": "単一のタスクでは、ユーザーは事前定義されたスケジュールで複数のSQLステートメントを実行できる"}, {"key": "C", "label": "タスクは定義されたスケジュールで単一のSQLコマンドまたはステートメントを実行できる"}, {"key": "D", "label": "タスクは特定の権限なしに作成できる"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>EXECUTE TASKコマンドで手動実行可能 / 定義されたスケジュールで単一SQL実行</strong></p><p>EXECUTE TASKコマンドを使用すると、スタンドアロンタスクまたはタスクグラフのルートタスクを手動でトリガーできます。</p><p>各Snowflakeタスクは単一のSQLコマンドまたはステートメントの実行に限定されています。複数のSQLステートメントを同じタスク定義内で実行することはできません。</p><p>Snowflakeタスクを作成するには、タスクが配置されるスキーマに対して&quot;CREATE TASK&quot;権限が必要です。</p><p>https://docs.snowflake.com/en/sql-reference/sql/execute-task<br>https://docs.snowflake.com/en/sql-reference/sql/create-task#required-parameters</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "タスク", "originalCorrect": null, "reviewPoint": ""}}, {"order": 47, "title": "新しいシェアを作成できるのはどれですか？該当するものを全て選択してください。", "multiSelect": true, "stemHtml": "<p>新しいシェアを作成できるのはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "SECURITY ADMINロールを持つユーザー"}, {"key": "B", "label": "CREATE SHARE権限を持つロールを持つユーザー"}, {"key": "C", "label": "SYSADMINロールを持つユーザー"}, {"key": "D", "label": "ACCOUNTADMINロールを持つユーザー"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>CREATE SHARE権限を持つロール / ACCOUNTADMINロール</strong></p><p>シェアを作成できるのはACCOUNTADMINロールを持つユーザーまたはCREATE SHARE権限が付与されているユーザーのみです。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-gs</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 48, "title": "仮想ウェアハウスが起動し、5分15秒間使用されてシャットダウンされました。顧客は何秒分請求されま...", "multiSelect": false, "stemHtml": "<p>仮想ウェアハウスが起動し、5分15秒間使用されてシャットダウンされました。顧客は何秒分請求されますか？</p>", "options": [{"key": "A", "label": "360秒"}, {"key": "B", "label": "3600秒"}, {"key": "C", "label": "315秒"}, {"key": "D", "label": "0秒"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>315秒</strong></p><p>Snowflakeのクレジットは1秒単位で請求されます。仮想ウェアハウスが5分15秒間実行された場合、315秒（5×60+15）が請求されます。ただし、最低60秒の請求が適用されるため、仮想ウェアハウスが最初の1分以内に起動してシャットダウンされた場合は、最低60秒のクレジット使用が適用されます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 49, "title": "真か偽か：COPYコマンドはSELECTクエリを使用してデータをアンロードできる。", "multiSelect": false, "stemHtml": "<p>真か偽か：COPYコマンドはSELECTクエリを使用してデータをアンロードできる。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>COPYコマンドはテーブルまたはビューからデータをアンロード/エクスポートできるほか、クエリ（SELECT）を使用してデータをアンロードすることも可能です。</p><p>https://docs.snowflake.com/en/user-guide/data-unload-overview#bulk-unloading-using-queries</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 50, "title": "S3ステージから特定のファイルリストをロードする場合、正しい構文はどれですか？（ファイル名はde...", "multiSelect": false, "stemHtml": "<p>S3ステージから特定のファイルリストをロードする場合、正しい構文はどれですか？（ファイル名はdelta1.csv、delta2.csv、delta3.csv、ステージはmy_stage、テーブルはmy_tableとします）</p>", "options": [{"key": "A", "label": "COPY INTO my_table FROM @my_stage files=('delta1.csv', 'delta2.csv', 'delta3.csv')"}, {"key": "B", "label": "COPY INTO my_table FROM @my_stage/delta1.csv,@my_stage/delta2.csv,@my_stage/delta3.csv"}, {"key": "C", "label": "COPY delta1.csv,delta2.csv,delta3.csv INTO my_table FROM @my_stage"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>COPY INTO my_table FROM @my_stage files=(&#x27;delta1.csv&#x27;, &#x27;delta2.csv&#x27;, &#x27;delta3.csv&#x27;)</strong></p><p>COPYコマンドに正確なファイル名を指定することで、それらのファイルのみがアクセスされてロードされます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-considerations-load#lists-of-files</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 51, "title": "ACCOUNT_USAGEスキーマのACCESS_HISTORYビューで達成できることはどれです...", "multiSelect": true, "stemHtml": "<p>ACCOUNT_USAGEスキーマのACCESS_HISTORYビューで達成できることはどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "ログインしたユーザーが使用したロールを特定する"}, {"key": "B", "label": "アクセスされたデータ、いつ、誰がアクセスしたかを特定する"}, {"key": "C", "label": "システムにログインした人を特定する"}, {"key": "D", "label": "使用されておらずクエリされていないデータを特定するのに役立つ"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>アクセスされたデータ・いつ・誰がアクセスしたかを特定 / 未使用データの特定</strong></p><p>ACCESS_HISTORYビューを使用して、アクセスされたデータ、いつ、誰がアクセスしたかを特定できます。この情報を使用して、全くアクセスされていないデータも特定できます。</p><p>https://docs.snowflake.com/en/user-guide/access-history#benefits</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 52, "title": "データベースをクローンする際、現在のロールはソースデータベースに対して（最低限）どの権限が必要で...", "multiSelect": false, "stemHtml": "<p>データベースをクローンする際、現在のロールはソースデータベースに対して（最低限）どの権限が必要ですか？</p>", "options": [{"key": "A", "label": "USAGE"}, {"key": "B", "label": "WRITE"}, {"key": "C", "label": "SELECT"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>USAGE</strong></p><p>テーブルをクローンするにはソーステーブルへのSELECT権限が必要です。Pipe、Stream、Taskのクローンにはオーナーシップ権限が必要です。それ以外のクローン可能なオブジェクトには全てUSAGE権限が必要です。</p><p>https://docs.snowflake.com/en/sql-reference/sql/create-clone#general-usage-notes</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 53, "title": "Snowflakeのストレージコストに貢献するものはどれですか？該当するものを全て選択してくださ...", "multiSelect": true, "stemHtml": "<p>Snowflakeのストレージコストに貢献するものはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "クエリ結果キャッシュ（Query Result Cache）"}, {"key": "B", "label": "過渡テーブル（Transient Tables）"}, {"key": "C", "label": "一時テーブル（Temporary Tables）"}, {"key": "D", "label": "ウェアハウスキャッシュ（Warehouse Cache）"}, {"key": "E", "label": "永続テーブル（Permanent Tables）"}], "correctAnswers": ["B", "C", "E"], "explanationHtml": "<p>✅ <strong>過渡テーブル / 一時テーブル / 永続テーブル</strong></p><p>永続テーブルに保存されたデータはストレージコストに計上されます。一時テーブルと過渡テーブルに保存されたデータも、ドロップまたはデータがクリアされるまでストレージコストに貢献します。フェイルセーフストレージとタイムトラベルストレージのデータもストレージコストに貢献します。過渡テーブルと一時テーブルはフェイルセーフストレージコストには貢献せず、最大1日のタイムトラベルコストがかかります。キャッシュはストレージコストの決定には考慮されません。クエリ結果キャッシュとメタデータキャッシュはクラウドサービスレイヤーの一部であり、ウェアハウスキャッシュ（ローカルディスクキャッシュ）は仮想ウェアハウスの一部でストレージコストには貢献しません。</p><p>https://docs.snowflake.com/en/user-guide/cost-understanding-overall</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "コストと価格", "originalCorrect": null, "reviewPoint": ""}}, {"order": 54, "title": "Snowpipeの使用が最適な選択肢となるシナリオはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowpipeの使用が最適な選択肢となるシナリオはどれですか？</p>", "options": [{"key": "A", "label": "毎月到着する大きなファイルをロードしている"}, {"key": "B", "label": "ユーザーが頻繁な戦術的クエリを実行している"}, {"key": "C", "label": "ユーザーが大規模なデータサイエンスワークロードを実行している"}, {"key": "D", "label": "頻繁に到着する少量のデータをロードする必要がある"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>頻繁に到着する少量のデータをロードする必要がある</strong></p><p>Snowpipeは、データがメッセージングまたはストリーミング方式で継続的に到着し、ほぼ即座にデータをロードする必要がある場合に最適な方法です。</p><p>https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 55, "title": "Snowflakeの共有を通じて、データプロバイダーは誰とデータを共有できますか？該当するものを...", "multiSelect": true, "stemHtml": "<p>Snowflakeの共有を通じて、データプロバイダーは誰とデータを共有できますか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "Snowflakeを使用していない顧客（Non-Snowflake customer）"}, {"key": "B", "label": "別のSnowflake顧客"}, {"key": "C", "label": "Google Driveユーザー"}, {"key": "D", "label": "One Driveユーザー"}, {"key": "E", "label": "複数のSnowflake顧客"}], "correctAnswers": ["A", "B", "E"], "explanationHtml": "<p>✅ <strong>Snowflake未使用顧客 / 別のSnowflake顧客 / 複数のSnowflake顧客</strong></p><p>Snowflake顧客、Snowflake未使用顧客、またはその両方の組み合わせなど、複数のコンシューマーとデータを共有できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 56, "title": "真か偽か：Snowflakeはクラウドで実行するように改修された既存のデータベーステクノロジーに...", "multiSelect": false, "stemHtml": "<p>真か偽か：Snowflakeはクラウドで実行するように改修された既存のデータベーステクノロジーに基づいている。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>False</strong></p><p>Snowflakeはクラウド向けに設計されており、ゼロから設計されています。Snowflakeはコンピュートとストレージを分離する新しいハイブリッドアーキテクチャを実装しています。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 57, "title": "Snowflakeはデータをロードするためにどの2つのアプローチを許可していますか？", "multiSelect": true, "stemHtml": "<p>Snowflakeはデータをロードするためにどの2つのアプローチを許可していますか？</p>", "options": [{"key": "A", "label": "継続的データロード（Continuous Data Loading）"}, {"key": "B", "label": "断続的データロード（Intermittent Data Loading）"}, {"key": "C", "label": "バルクデータロード（Bulk Data Loading）"}], "correctAnswers": ["A", "C"], "explanationHtml": "<p>✅ <strong>継続的データロード / バルクデータロード</strong></p><p>Snowflakeは主に2つの方法でデータロードをサポートします。COPYコマンドはバルクデータまたは大きなファイルのロードに使用できます。COPYコマンドはテーブルへのデータロードに仮想ウェアハウスの使用が必要です。もう1つの方法はSnowpipeを通じたデータロードです。Snowpipeはデータがメッセージングまたはストリーミング方式で継続的に到着する場合に最適な技術です。</p><p>https://docs.snowflake.com/en/user-guide/data-load-overview#bulk-vs-continuous-loading</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 58, "title": "COPYコマンドがサポートする変換はどれですか？該当するものを全て選択してください。", "multiSelect": true, "stemHtml": "<p>COPYコマンドがサポートする変換はどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "列の並び替え（Reorder columns）"}, {"key": "B", "label": "列の省略（Omit columns）"}, {"key": "C", "label": "列のキャスト（Cast columns）"}, {"key": "D", "label": "他のテーブルとの結合（Join with other tables）"}], "correctAnswers": ["A", "B", "C"], "explanationHtml": "<p>✅ <strong>列の並び替え / 列の省略 / 列のキャスト</strong></p><p>COPYコマンドを使用してテーブルにデータをロードする際、Snowflakeはロード中にデータの簡単な変換を行うことができます。ロードプロセス中に、COPYコマンドは列の順序の変更、1つ以上の列の省略、指定したデータ型へのキャスト、値の切り捨てが可能です。結合、フィルター、集計、FLATTENの使用などの複雑な変換はサポートされていません。</p><p>https://docs.snowflake.com/en/user-guide/data-load-overview#id2</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 59, "title": "マテリアライズドビューのリフレッシュ方法を正しく説明しているものはどれですか？", "multiSelect": true, "stemHtml": "<p>マテリアライズドビューのリフレッシュ方法を正しく説明しているものはどれですか？</p>", "options": [{"key": "A", "label": "マテリアライズドビューは手動でのみリフレッシュできる"}, {"key": "B", "label": "基礎テーブルのデータが変更された場合、マテリアライズドビューは自動的に更新される"}, {"key": "C", "label": "マテリアライズドビューはSnowflakeが管理するサービスによって自動的にリフレッシュされる"}, {"key": "D", "label": "マテリアライズドビューをリフレッシュするには追加のSQLステートメントをスケジュールする必要がある"}, {"key": "E", "label": "REFRESH_ON_BASE_TABLE_UPDATEパラメーターを使用してマテリアライズドビューの自動リフレッシュを設定できる"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>基礎テーブル変更時に自動更新 / Snowflake管理サービスが自動リフレッシュ</strong></p><p>基礎テーブルが更新されると、マテリアライズドビューは自動的にリフレッシュされ、追加のメンテナンスは不要です。Snowflakeが管理するサービスがユーザーの操作を妨げることなくバックグラウンドで更新を行います。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 60, "title": "プレサインドURLに関する正しいものはどれですか？該当するものを全て選択してください。", "multiSelect": true, "stemHtml": "<p>プレサインドURLに関する正しいものはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "プレサインドURLの有効期限を設定できる"}, {"key": "B", "label": "プレサインドURLは24時間後に期限切れになる"}, {"key": "C", "label": "プレサインドURLは認証や認可なしにユーザーやアプリケーションにアクセスを提供するのに適している"}, {"key": "D", "label": "プレサインドURLを持つ誰でも、そのURLを使用して参照されているファイルにアクセスできる"}, {"key": "E", "label": "プレサインドURLはアクセストークンで生成され、認証なしにアクセスできる"}], "correctAnswers": ["A", "C", "D", "E"], "explanationHtml": "<p>✅ <strong>有効期限の設定可能 / 認証不要でアクセス可能 / URL所持者誰でもアクセス可能 / アクセストークンで生成</strong></p><p>プレサインドURLはWebブラウザを使用してファイルにアクセスするためのシンプルなHTTPS URLです。プレサインドURLはプレサインドアクセストークンを使用して生成されます。ユーザーは認可なしにプレサインドURLを通じてファイルに一時的にアクセスできます。プレサインドURLの有効期間は設定可能で、必要な期間に設定できます。</p><p>https://docs.snowflake.com/en/user-guide/unstructured-intro#types-of-urls-available-to-access-files</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 61, "title": "Snowflakeのクラウドサービスレイヤーはどの機能を提供しますか？該当するものを全て選択して...", "multiSelect": true, "stemHtml": "<p>Snowflakeのクラウドサービスレイヤーはどの機能を提供しますか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "データ共有（Data Sharing）"}, {"key": "B", "label": "データのストレージ（Storage for data）"}, {"key": "C", "label": "クローニング（Cloning）"}, {"key": "D", "label": "トランザクション制御・ACID準拠（Transaction control / ACID compliance）"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>データ共有 / クローニング / トランザクション制御・ACID準拠</strong></p><p>Snowflakeのデータ共有、クローニング、データ交換機能はすべてメタデータを使用してクラウドサービスレイヤーを通じて管理されます。クラウドサービスレイヤーはACID準拠も提供します。ACIDとは、データベースシステムがトランザクションをユニットとして分離して実行し、コミットまたはロールバックすることで、システムの一貫性を確保することを意味します。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 62, "title": "現在のセッションで実行された最新クエリのクエリIDを見つけるために使用できるものはどれですか？2...", "multiSelect": true, "stemHtml": "<p>現在のセッションで実行された最新クエリのクエリIDを見つけるために使用できるものはどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "SELECT LAST_QUERY_ID();"}, {"key": "B", "label": "SELECT LAST_QUERY_ID(-1);"}, {"key": "C", "label": "SELECT LAST_QUERY_ID(2);"}, {"key": "D", "label": "SELECT LAST_QUERY_ID(1);"}, {"key": "E", "label": "SELECT LAST_QUERY_ID(-2);"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>SELECT LAST_QUERY_ID(); / SELECT LAST_QUERY_ID(-1);</strong></p><p>LAST_QUERY_ID関数は現在のセッション内の指定されたクエリのクエリIDを返します。この関数はセッション内のクエリの位置を指定する数値をパラメーターとして受け取ります。パラメーターは正または負の値を取れます。負の値はセッション内の最新クエリを取得することを意味します（-1=最新クエリ、-2=2番目に新しいクエリ、など）。関数はデフォルトで-1なので、値が指定されない場合は最新クエリのIDを返します。正の数はセッション内の最初のクエリから順に返します（1=最初のクエリ、2=2番目のクエリ、など）。</p><p>https://docs.snowflake.com/en/sql-reference/functions/last_query_id</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "General", "originalCorrect": null, "reviewPoint": ""}}, {"order": 63, "title": "クエリプロファイルで、TableScanオペレーターは何を表しますか？", "multiSelect": false, "stemHtml": "<p>クエリプロファイルで、TableScanオペレーターは何を表しますか？</p>", "options": [{"key": "A", "label": "テーブルへのレコードの追加"}, {"key": "B", "label": "特定の条件で2つの入力を結合する"}, {"key": "C", "label": "ステージオブジェクトに保存されたデータへのアクセス"}, {"key": "D", "label": "単一テーブルへのアクセス"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>単一テーブルへのアクセス</strong></p><p>TableScanオペレーターは単一テーブルへのアクセスを表します。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile#data-access-and-generation-operators</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 64, "title": "Snowflakeアーキテクチャのコンピュートレイヤーはどの機能を担当していますか？", "multiSelect": false, "stemHtml": "<p>Snowflakeアーキテクチャのコンピュートレイヤーはどの機能を担当していますか？</p>", "options": [{"key": "A", "label": "クエリ処理（Query Processing）"}, {"key": "B", "label": "クエリ計画（Query Planning）"}, {"key": "C", "label": "クエリ最適化（Query Optimization）"}, {"key": "D", "label": "クエリ結果のキャッシュ（Cache Query Results）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>クエリ処理（Query Processing）</strong></p><p>コンピュートレイヤーはクエリ処理またはクエリ実行を担当します。クエリ計画と最適化はクラウドサービスレイヤーが行います。クエリ結果キャッシュはクラウドサービスレイヤーに保存・管理されます。</p><p>https://docs.snowflake.com/en/user-guide/intro-key-concepts</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 65, "title": "Snowflake Marketplaceに関する正しいものはどれですか？", "multiSelect": true, "stemHtml": "<p>Snowflake Marketplaceに関する正しいものはどれですか？</p>", "options": [{"key": "A", "label": "Snowflake Marketplaceを使用して、顧客は会社外からデータをSnowflakeインスタンスにインポートし、自社データを強化するために活用できる"}, {"key": "B", "label": "Snowflake Marketplaceは、データセットを購入・販売できるオンラインマーケットプレイスである"}, {"key": "C", "label": "Snowflake Marketplace上の全てのデータセットは有料で提供される"}, {"key": "D", "label": "Snowflake Marketplaceを使用して、顧客は異なるデータセットに入札でき、最高入札者のみがデータセットにアクセスできる"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>外部データのインポートとデータ強化が可能 / データセットを購入・販売できるマーケットプレイス</strong></p><p>Snowflake Marketplaceは、様々な組織が提供するサードパーティデータセットを見つけてアクセスするためのマーケットプレイスです。これらのサードパーティデータセットは一般的に有料ですが、無料で提供されることもあります。入札はなく、データセットは誰でも利用可能です（無料または有料）。</p><p>https://other-docs.snowflake.com/en/collaboration/collaboration-marketplace-about.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 66, "title": "マルチクラスター仮想ウェアハウスに関する正しいステートメントはどれですか？該当するものを全て選択...", "multiSelect": true, "stemHtml": "<p>マルチクラスター仮想ウェアハウスに関する正しいステートメントはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "マルチクラスター仮想ウェアハウスはクエリ需要が減少すると追加クラスターを自動的に削除する"}, {"key": "B", "label": "マルチクラスター仮想ウェアハウスは自動サスペンドまたは自動レジュームを設定できない"}, {"key": "C", "label": "マルチクラスター仮想ウェアハウスは、同時クエリが既存の仮想ウェアハウスで処理できない数に増加すると追加クラスターを自動的に追加する"}, {"key": "D", "label": "マルチクラスター仮想ウェアハウス機能にはEnterpriseエディション以上が必要"}], "correctAnswers": ["A", "C", "D"], "explanationHtml": "<p>✅ <strong>需要減少時に自動削除 / 需要増加時に自動追加 / Enterpriseエディション以上が必要</strong></p><p>マルチクラスター仮想ウェアハウスは、同時ユーザー数が単一仮想ウェアハウスのキャパシティを超える場合に使用されます。Enterpriseエディションがマルチクラスター仮想ウェアハウス機能の使用に必要です。自動追加・削除以外の動作は通常の仮想ウェアハウスと同様で、サスペンド・レジュームや自動サスペンド・自動レジュームも設定できます。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-multicluster</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 67, "title": "ディレクトリテーブルのメタデータをリフレッシュするためにイベント通知を使用するコストに関して正し...", "multiSelect": true, "stemHtml": "<p>ディレクトリテーブルのメタデータをリフレッシュするためにイベント通知を使用するコストに関して正しいものはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "リフレッシュ操作は無料である"}, {"key": "B", "label": "リフレッシュ操作には小額のメンテナンスコストが請求される"}, {"key": "C", "label": "イベント通知は無料である"}, {"key": "D", "label": "イベント通知には追加コストが請求される"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>リフレッシュ操作には小額のメンテナンスコスト / イベント通知には追加コスト</strong></p><p>ディレクトリテーブルのメタデータのリフレッシュには、通知経由か手動（ALTER STAGE &lt;stage-name&gt; REFRESH経由）かに関わらず、小額のメンテナンスコストが請求されます。このコストはクラウドサービスコストとして計上されます。さらに、クラウドプラットフォームの通知を使用する場合、請求明細にSnowpipe料金として表示される追加コストが請求されます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-dirtables-intro#billing-for-directory-tables</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 68, "title": "Partner Connectを通じてパートナーに接続するプロセスで作成されるオブジェクトについ...", "multiSelect": true, "stemHtml": "<p>Partner Connectを通じてパートナーに接続するプロセスで作成されるオブジェクトについて正しいものはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "PC_<partner>_DBデータベースはシステムに他のデータベースがない場合にのみ作成される"}, {"key": "B", "label": "パートナーはPC_<partner>_USERを使用してSnowflakeインスタンスに接続する"}, {"key": "C", "label": "PC_<partner>_ROLEにより、パートナーアプリケーションはPUBLICロールに付与されたオブジェクトにアクセスできる"}, {"key": "D", "label": "PC_<partner>_DBデータベースは空で、データのロードまたは保存に使用できる"}, {"key": "E", "label": "PC_<partner>_WH仮想ウェアハウスはシステムに他の仮想ウェアハウスがない場合にのみ作成される"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>PC_&lt;partner&gt;_USERで接続 / PC_&lt;partner&gt;_ROLEはPUBLICロール権限を継承 / PC_&lt;partner&gt;_DBは空で使用可能</strong></p><p>PC_&lt;partner&gt;_DBは空の状態で作成されます。ただし、必要に応じて既存のデータベースを使用するように設定できます。PC_&lt;partner&gt;_ROLEはPUBLICロールの権限を継承します。パートナーアプリケーションがシステム内のオブジェクトにアクセスできるように追加権限を付与できます。このロールはSYSADMINにも付与されます。</p><p>https://docs.snowflake.com/en/user-guide/ecosystem-partner-connect#connecting-with-a-snowflake-partner</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パートナー", "originalCorrect": null, "reviewPoint": ""}}, {"order": 69, "title": "以下のマルチクラスター仮想ウェアハウス設定のうち、オートスケールモードで実行されているものはどれ...", "multiSelect": true, "stemHtml": "<p>以下のマルチクラスター仮想ウェアハウス設定のうち、オートスケールモードで実行されているものはどれですか？</p>", "options": [{"key": "A", "label": "MIN_CLUSTER_COUNT = 1 / MAX_CLUSTER_COUNT = 5"}, {"key": "B", "label": "MIN_CLUSTER_COUNT = 3 / MAX_CLUSTER_COUNT = 3"}, {"key": "C", "label": "MIN_CLUSTER_COUNT = 1 / MAX_CLUSTER_COUNT = 1"}, {"key": "D", "label": "MIN_CLUSTER_COUNT = 2 / MAX_CLUSTER_COUNT = 4"}, {"key": "E", "label": "MIN_CLUSTER_COUNT = 0 / MAX_CLUSTER_COUNT = 0"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>MIN=1,MAX=5 / MIN=2,MAX=4</strong></p><p>マルチクラスター仮想ウェアハウスは最大化モードまたはオートスケールモードで作成できます。オートスケールモードはマルチクラスターの最小クラスターと最大ウェアハウス数に異なる値を選択することで有効になります。最大化モードはマルチクラスターの最小と最大ウェアハウス数を同じ値に設定することで有効になります。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-multicluster#setting-the-scaling-policy-for-a-multi-cluster-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 70, "title": "Snowflakeで継続的に到着するデータをロードするために使用できるものはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeで継続的に到着するデータをロードするために使用できるものはどれですか？</p>", "options": [{"key": "A", "label": "SnowStorm"}, {"key": "B", "label": "Snowpipe"}, {"key": "C", "label": "SnowFast"}, {"key": "D", "label": "SnowTrickle"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>Snowpipe</strong></p><p>SnowflakeはサーバーレスサービスであるSnowpipeを使用して継続的なデータロードを可能にします。Snowpipeはマイクロバッチ方式でデータをロードでき、各実行で少量のデータをロードします。Snowpipeはサーバーレスであり独自のコンピューティング能力を持つため、処理に仮想ウェアハウスを必要としません。Snowpipeのコストは仮想ウェアハウス費用とは別に請求されます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-snowpipe-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 71, "title": "Snowsightのワークシートビューで、クエリが実行されるコンテキストを設定するために選択でき...", "multiSelect": true, "stemHtml": "<p>Snowsightのワークシートビューで、クエリが実行されるコンテキストを設定するために選択できるものはどれですか？</p>", "options": [{"key": "A", "label": "テーブル（Table）"}, {"key": "B", "label": "ユーザー（User）"}, {"key": "C", "label": "スキーマ（Schema）"}, {"key": "D", "label": "仮想ウェアハウス（Virtual Warehouse）"}, {"key": "E", "label": "ロール（Role）"}, {"key": "F", "label": "データベース（Database）"}], "correctAnswers": ["C", "D", "E", "F"], "explanationHtml": "<p>✅ <strong>スキーマ / 仮想ウェアハウス / ロール / データベース</strong></p><p>クエリが実行されるプライマリロールと、クエリの実行に使用する仮想ウェアハウスを選択できます。また、デフォルトのデータベースとスキーマも選択でき、指定したデータベースとスキーマのテーブルにプレフィックスを付ける必要がなくなります。</p><p>https://docs.snowflake.com/en/user-guide/ui-snowsight</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 72, "title": "Snowflakeが動作変更リリースを行う頻度はどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeが動作変更リリースを行う頻度はどれですか？</p>", "options": [{"key": "A", "label": "2週間に1回"}, {"key": "B", "label": "週に1回"}, {"key": "C", "label": "月に1回"}, {"key": "D", "label": "年に1回"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>月に1回</strong></p><p>月に1回、Snowflakeは「動作変更リリース」もリリースします。これらの既存の動作への変更は、既にサービスを使用している顧客に影響を与える可能性があります。2ヶ月にわたって、新しい動作は全員に採用されます。最初の月は、顧客がオプトインしない限り新しい動作は有効になりません。2番目の月では、新しい動作は自動的に有効になりますが、顧客は必要に応じてオプトアウトできます。</p><p>https://docs.snowflake.com/en/user-guide/intro-releases</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント", "originalCorrect": null, "reviewPoint": ""}}, {"order": 73, "title": "Snowflakeへのプライベート接続をサポートするSnowflakeの最低エディションはどれで...", "multiSelect": false, "stemHtml": "<p>Snowflakeへのプライベート接続をサポートするSnowflakeの最低エディションはどれですか？</p>", "options": [{"key": "A", "label": "Enterprise"}, {"key": "B", "label": "Standard"}, {"key": "C", "label": "Virtual Private Snowflake"}, {"key": "D", "label": "Business Critical"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>Business Critical</strong></p><p>プライベート接続により、Snowflakeインスタンスへのアクセスがセキュアな接続を経由することを確保し、インターネットベースのアクセスを完全にブロックすることも可能です。SnowflakeへのプライベートはBusiness Criticalエディション以上が必要です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 74, "title": "以下のコマンドを正常に実行するにはどのロールが必要ですか？ SHOW ORGANIZATION ...", "multiSelect": false, "stemHtml": "<p>以下のコマンドを正常に実行するにはどのロールが必要ですか？ SHOW ORGANIZATION ACCOUNTS;</p>", "options": [{"key": "A", "label": "ORGADMIN"}, {"key": "B", "label": "ACCOUNTADMIN"}, {"key": "C", "label": "SYSADMIN"}, {"key": "D", "label": "SECURITYADMIN"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>ORGADMIN</strong></p><p>&quot;SHOW ORGANIZATION ACCOUNTS&quot;コマンドを実行できるのはORGADMINロールを持つユーザーのみです。</p><p>https://docs.snowflake.com/en/sql-reference/sql/show-organization-accounts</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 75, "title": "Snowflakeのロール階層で権限はどのように継承されますか？", "multiSelect": false, "stemHtml": "<p>Snowflakeのロール階層で権限はどのように継承されますか？</p>", "options": [{"key": "A", "label": "階層の同じレベルのロールのみが権限を継承する"}, {"key": "B", "label": "ロールの権限は階層内のそのロールより上の全てのロールに継承される"}, {"key": "C", "label": "直接の親ロールのみが権限を継承する"}, {"key": "D", "label": "直接の子ロールのみが権限を継承する"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>階層内の上位全ロールに継承される</strong></p><p>ロールは他のロールに付与されてロール階層を作成することもできます。ロールに関連付けられた権限は、そのロールより上の階層内の全てのロールに継承されます。</p><p>https://docs.snowflake.com/en/user-guide/security-access-control-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 76, "title": "Snowflakeの権限とロールについて正しいものはどれですか？該当するものを全て選択してくださ...", "multiSelect": true, "stemHtml": "<p>Snowflakeの権限とロールについて正しいものはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "権限はロールに割り当てられる"}, {"key": "B", "label": "権限はユーザーに直接割り当てられる"}, {"key": "C", "label": "新しいカスタムロールは作成できない"}, {"key": "D", "label": "ロールはユーザーに割り当てられる"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>権限はロールに割り当て / ロールはユーザーに割り当て</strong></p><p>Snowflakeのアクセス制御は、ロールに権限を割り当て、ユーザーにロールを割り当てるロールベースアクセス制御（RBAC）アプローチに基づいています。ロールに付与された権限は、そのロールの全ユーザーに継承されます。</p><p>https://docs.snowflake.com/en/user-guide/security-access-control-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 77, "title": "マイクロパーティションを正しく説明しているステートメントはどれですか？", "multiSelect": true, "stemHtml": "<p>マイクロパーティションを正しく説明しているステートメントはどれですか？</p>", "options": [{"key": "A", "label": "マイクロパーティションのデータは行ストレージ形式で整理されている"}, {"key": "B", "label": "マイクロパーティションは可変で更新できる"}, {"key": "C", "label": "マイクロパーティションのデータは列形式で整理されている"}, {"key": "D", "label": "マイクロパーティションは不変である"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>列形式で整理 / 不変</strong></p><p>Snowflakeパーティションは不変であり、一度作成されると変更できません。テーブルデータは個別のマイクロパーティションにマッピングされ、さらに列形式で整理されます。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 78, "title": "MARKETINGデータベースのPUBLICスキーマのCUSTOMERテーブルのオーナーです。A...", "multiSelect": true, "stemHtml": "<p>MARKETINGデータベースのPUBLICスキーマのCUSTOMERテーブルのオーナーです。ANALYSTというロールにCUSTOMERテーブルへのSELECTアクセスを付与するには、どのオブジェクトにどの権限を提供する必要がありますか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "grant SELECT on database MARKETING to role ANALYST;"}, {"key": "B", "label": "grant READ on schema PUBLIC to role ANALYST;"}, {"key": "C", "label": "grant SELECT on table CUSTOMER to role ANALYST;"}, {"key": "D", "label": "grant USAGE on schema PUBLIC to role ANALYST;"}, {"key": "E", "label": "grant SELECT on schema PUBLIC to role ANALYST;"}, {"key": "F", "label": "grant USAGE on database MARKETING to role ANALYST;"}], "correctAnswers": ["C", "D", "F"], "explanationHtml": "<p>✅ <strong>SELECT on table CUSTOMER / USAGE on schema PUBLIC / USAGE on database MARKETING</strong></p><p>ANALYSTロールがテーブルからデータを読み取るにはテーブルへのSELECT権限が必要です。ただし、ANALYSTロールにテーブルを含むスキーマとデータベースを使用する権限がなければクエリを実行できません。USAGE権限により、USE DATABASEまたはUSE SCHEMAコマンドの実行、またはフルネームスペース（MARKETING.PUBLIC.CUSTOMER）でテーブルにアクセスできます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 79, "title": "Snowflakeの顧客がデータを最初にロードせずにクエリできるメカニズムはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeの顧客がデータを最初にロードせずにクエリできるメカニズムはどれですか？</p>", "options": [{"key": "A", "label": "外部テーブル（External Table）"}, {"key": "B", "label": "COPY"}, {"key": "C", "label": "Snowpipe"}, {"key": "D", "label": "仮想テーブル（Virtual Table）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>外部テーブル（External Table）</strong></p><p>Snowflakeは外部テーブルと呼ばれるテーブルの代替アプローチを提供しており、外部クラウドストレージにデータを保存したままテーブルを作成できます。外部テーブルはデータをSnowflakeにロードする必要をなくします。外部テーブルの場合、テーブルの定義はSnowflakeのメタデータに保存されますが、テーブルのデータはSnowflake外に保存されます。</p><p>https://docs.snowflake.com/en/user-guide/tables-external-intro</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 80, "title": "SnowflakeがSaaS（Software-as-a-Service）製品と見なされる理由は...", "multiSelect": true, "stemHtml": "<p>SnowflakeがSaaS（Software-as-a-Service）製品と見なされる理由はどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "Snowflakeはクラウドで実行され、インターネット経由で利用可能である"}, {"key": "B", "label": "顧客はハードウェアを調達、インストール、管理する必要がない"}, {"key": "C", "label": "従量課金ライセンスを提供し、使用したリソースと機能のみを支払う"}, {"key": "D", "label": "Snowflakeは定期的にソフトウェアを更新し、全てのアカウントがこれらの更新を自動的に受け取るため、手動インストール、メンテナンス、パッチは不要"}], "correctAnswers": ["A", "B", "C", "D"], "explanationHtml": "<p>✅ <strong>クラウドでインターネット経由利用 / ハードウェア管理不要 / 従量課金 / 自動更新</strong></p><p>これらは全てSoftware-as-a-Service製品の特徴です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 81, "title": "多要素認証（MFA）はどれに対して有効にできますか？該当するものを全て選択してください。", "multiSelect": true, "stemHtml": "<p>多要素認証（MFA）はどれに対して有効にできますか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "ODBC"}, {"key": "B", "label": "Python"}, {"key": "C", "label": "Snowpipe"}, {"key": "D", "label": "Snowflake WebUI"}], "correctAnswers": ["A", "B", "D"], "explanationHtml": "<p>✅ <strong>ODBC / Python / Snowflake WebUI</strong></p><p>MFAは全てのSnowflakeアカウントでデフォルトで有効になっており、全てのSnowflakeエディションで利用可能です。Webインターフェース、SnowSQL、各種コネクターとドライバーを含む全てのSnowflakeクライアントツールがMFAをサポートします。SnowpipeはSnowflakeが管理するサーバーレスサービスであり、ユーザーがログインできないためMFAは必要ありません。</p><p>https://docs.snowflake.com/en/user-guide/security-mfa</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 82, "title": "真か偽か：Snowflakeの大きなテーブルには数百万または数億のマイクロパーティションが含まれ...", "multiSelect": false, "stemHtml": "<p>真か偽か：Snowflakeの大きなテーブルには数百万または数億のマイクロパーティションが含まれる可能性がある。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>特定のテーブルのマイクロパーティション数は主にそのテーブルのデータ量に依存します。非常に大きなテーブルでは、マイクロパーティション数は数百万または数億に達する可能性があります。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-micropartitions</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 83, "title": "フェイルセーフストレージからデータを取得できるのはどれですか？", "multiSelect": false, "stemHtml": "<p>フェイルセーフストレージからデータを取得できるのはどれですか？</p>", "options": [{"key": "A", "label": "Snowflakeサポート"}, {"key": "B", "label": "顧客"}, {"key": "C", "label": "誰でも"}, {"key": "D", "label": "クラウドプロバイダー"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>Snowflakeサポート</strong></p><p>データがフェイルセーフストレージに入ると、Snowflakeサポートのみがデータの取得を支援できます。顧客はフェイルセーフストレージにアクセスできません。クラウドプロバイダーはフェイルセーフストレージかどうかにかかわらず、Snowflakeが保存するデータにアクセスできません。</p><p>https://docs.snowflake.com/en/user-guide/data-failsafe</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "フェイルセーフ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 84, "title": "Snowflakeはどのアクセス制御方法を許可していますか？該当するものを全て選択してください。", "multiSelect": true, "stemHtml": "<p>Snowflakeはどのアクセス制御方法を許可していますか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "管理アクセス制御（Management access control / MAC）"}, {"key": "B", "label": "グローバルアクセス制御（Global access control / GAC）"}, {"key": "C", "label": "裁量アクセス制御（Discretionary access control / DAC）"}, {"key": "D", "label": "ロールベースアクセス制御（Role-based access control / RBAC）"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>裁量アクセス制御（DAC） / ロールベースアクセス制御（RBAC）</strong></p><p>Snowflakeのアクセス制御システムはRBACのアイデアに基づいており、ロールに権限を付与し、ユーザーにロールを付与します。Snowflakeはまた裁量アクセス制御（DAC）もサポートしており、オブジェクトを作成したロールがそのオブジェクトを所有し、他のロールにアクセスを提供できることを意味します。</p><p>https://docs.snowflake.com/en/user-guide/security-access-control-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 85, "title": "真か偽か：ストアドプロシージャを作成して実行するには、最低でもEnterpriseエディションが...", "multiSelect": false, "stemHtml": "<p>真か偽か：ストアドプロシージャを作成して実行するには、最低でもEnterpriseエディションが必要である。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>False</strong></p><p>全てのSnowflakeエディションがストアドプロシージャをサポートするため、ストアドプロシージャを作成・実行するために必要な最低エディションはStandardエディションです。</p><p>https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 86, "title": "真か偽か：Snowflake Scriptingはストアドプロシージャの作成に使用できる。", "multiSelect": false, "stemHtml": "<p>真か偽か：Snowflake Scriptingはストアドプロシージャの作成に使用できる。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>Snowflake Scriptingは通常ストアドプロシージャの作成に使用されますが、ストアドプロシージャ外の手続き型コードの作成にも使用できます。</p><p>https://docs.snowflake.com/en/sql-reference/stored-procedures-snowflake-scripting</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 87, "title": "Snowflakeの内部ステージについて正しいものはどれですか？2つ選択してください。", "multiSelect": true, "stemHtml": "<p>Snowflakeの内部ステージについて正しいものはどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "名前付き内部ステージは新しいファイルのために自動的に作成される"}, {"key": "B", "label": "ファイルはデフォルトの名前付き内部ステージに自動的にアップロードされる"}, {"key": "C", "label": "テーブルには自動的に内部ステージが割り当てられる"}, {"key": "D", "label": "ユーザーには自動的に内部ステージが割り当てられる"}], "correctAnswers": ["C", "D"], "explanationHtml": "<p>✅ <strong>テーブルには自動的に内部ステージが割り当てられる / ユーザーには自動的に内部ステージが割り当てられる</strong></p><p>テーブルステージは各テーブルに自動的に作成される内部ステージであり、そのテーブルへのデータロードに使用できます。各ユーザーもユーザー作成時に自動的に内部ステージオブジェクトが作成されます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-local-file-system-create-stage#types-of-internal-stages</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データのロードとアンロード", "originalCorrect": null, "reviewPoint": ""}}, {"order": 88, "title": "ディレクトリテーブルをクエリしたときの結果セットに含まれる列はどれですか？該当するものを全て選択...", "multiSelect": true, "stemHtml": "<p>ディレクトリテーブルをクエリしたときの結果セットに含まれる列はどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "IS_ENCRYPTED"}, {"key": "B", "label": "ETAG"}, {"key": "C", "label": "LAST_MODIFIED"}, {"key": "D", "label": "MD5"}, {"key": "E", "label": "IS_DELETED"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>ETAG / LAST_MODIFIED / MD5</strong></p><p>ディレクトリテーブルをクエリすると、結果セットにはステージオブジェクト内の各ファイルのFILE_URLが含まれます。また、ファイルのサイズ（バイト単位）、最終更新タイムスタンプ、MD5チェックサム、およびファイルの内容が変更された場合に変わるETAGファイルなどの追加メタデータも含まれます。</p><p>https://docs.snowflake.com/en/user-guide/data-load-dirtables-manage#output</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ変換", "originalCorrect": null, "reviewPoint": ""}}, {"order": 89, "title": "Snowflakeアカウント間でデータが共有される場合、コンシューマー側で共有データを使用するた...", "multiSelect": false, "stemHtml": "<p>Snowflakeアカウント間でデータが共有される場合、コンシューマー側で共有データを使用するためにどのタイプのデータベースが作成されますか？</p>", "options": [{"key": "A", "label": "Permanent（永続）"}, {"key": "B", "label": "Temporary（一時）"}, {"key": "C", "label": "Open Access（オープンアクセス）"}, {"key": "D", "label": "Writable（書き込み可能）"}, {"key": "E", "label": "Read-only（読み取り専用）"}], "correctAnswers": ["E"], "explanationHtml": "<p>✅ <strong>Read-only（読み取り専用）</strong></p><p>コンシューマーはSharedオブジェクトから読み取り専用データベースを作成します。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-intro#how-does-secure-data-sharing-work</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 90, "title": "複数のアカウントのレプリケーションを有効にするために必要なロールはどれですか？", "multiSelect": false, "stemHtml": "<p>複数のアカウントのレプリケーションを有効にするために必要なロールはどれですか？</p>", "options": [{"key": "A", "label": "SECURITYADMIN"}, {"key": "B", "label": "ORGADMIN"}, {"key": "C", "label": "ACCOUNTADMIN"}, {"key": "D", "label": "SYSADMIN"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>ORGADMIN</strong></p><p>ソースとターゲットデータベースのレプリケーションを有効にするにはORGADMINを使用する必要があります。</p><p>https://docs.snowflake.com/en/user-guide/database-replication-config#prerequisite-enable-replication-for-accounts-in-the-organization</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 91, "title": "真か偽か：シェアには少なくとも1つのコンシューマーが追加されている必要がある。", "multiSelect": false, "stemHtml": "<p>真か偽か：シェアには少なくとも1つのコンシューマーが追加されている必要がある。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>False</strong></p><p>Snowflakeシェアはコンシューマーを追加せずに定義できます。シェアには後から1つ以上のコンシューマーを追加できます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 92, "title": "クエリプロファイルに表示される「Bytes spilled to local storage」（...", "multiSelect": false, "stemHtml": "<p>クエリプロファイルに表示される「Bytes spilled to local storage」（ローカルストレージへのバイトスピル）を最もよく説明しているのはどれですか？</p>", "options": [{"key": "A", "label": "「Bytes spilled to local storage」はクエリ実行中に剪定されたマイクロパーティションの数である"}, {"key": "B", "label": "「Bytes spilled to local storage」はGETコマンドを使用してダウンロードされたデータの量を示す"}, {"key": "C", "label": "「Bytes spilled to local storage」はメモリに収まらず仮想ウェアハウスの一時ストレージにスピルされなければならなかったデータ量を示す"}, {"key": "D", "label": "「Bytes spilled to local storage」はSnowsightを使用してダウンロードされたデータ量を示す"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>メモリに収まらず仮想ウェアハウスの一時ストレージにスピルされたデータ量</strong></p><p>Snowflakeは操作がメモリに収まらない場合、ウェアハウスのローカルディスクにデータを保存します。データスピルはより多くのIO操作を必要とし、ディスクアクセスはメモリアクセスより遅いため、クエリを遅くします。ローカルディスクがいっぱいになると、Snowflakeはリモートクラウドストレージにデータをスピルします。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile#queries-too-large-to-fit-in-memory</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 93, "title": "完了したクエリのクエリプロファイルのスニペットを考えてください。ハイライトされた統計を正確に説明...", "multiSelect": true, "stemHtml": "<p>完了したクエリのクエリプロファイルのスニペットを考えてください。ハイライトされた統計を正確に説明しているものはどれですか？</p>", "options": [{"key": "A", "label": "クエリプロファイルは非効果的なパーティション剪定を示している"}, {"key": "B", "label": "クエリプロファイルは効果的なパーティション剪定を示している"}, {"key": "C", "label": "クエリプロファイルはクエリに対して仮想ウェアハウスが小さすぎることを示している"}, {"key": "D", "label": "クエリプロファイルは仮想ウェアハウスキャッシュが使用されたことを示している"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>効果的なパーティション剪定 / 仮想ウェアハウスが小さすぎる</strong></p><p>パーティション剪定は、スキャンされたパーティション数が合計パーティション数よりはるかに少ない場合に発生します。Snowflakeは操作がメモリに収まらない場合、ウェアハウスのローカルディスクにデータを保存します。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 94, "title": "大きなテーブルのクラスタリングキーを定義する際に考慮すべき点はどれですか？", "multiSelect": true, "stemHtml": "<p>大きなテーブルのクラスタリングキーを定義する際に考慮すべき点はどれですか？</p>", "options": [{"key": "A", "label": "JOIN文で頻繁に使用される列をクラスタリングする"}, {"key": "B", "label": "WHERE句で頻繁に使用される列をクラスタリングする"}, {"key": "C", "label": "全ての数値列をクラスタリングする"}, {"key": "D", "label": "全ての文字列列をクラスタリングする"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>JOIN文で頻繁に使用される列 / WHERE句で頻繁に使用される列</strong></p><p>クラスタリングキーを定義する際の最初の候補クラスタリング列は、WHERE句またはその他の選択的フィルターで頻繁に使用される列です。また、結合に使用される列も考慮できます。さらに、列のカーディナリティ（個別値の数）も重要です。効果的なパーティション剪定を可能にするために十分に高いカーディナリティを持つ列を選択しつつ、Snowflakeがデータをマイクロパーティションに効率的にグループ化できるほど低いカーディナリティである必要があります。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 95, "title": "真か偽か：パフォーマンスの問題を防ぐために、INFORMATION_SCHEMAを使用するクエリ...", "multiSelect": false, "stemHtml": "<p>真か偽か：パフォーマンスの問題を防ぐために、INFORMATION_SCHEMAを使用するクエリが十分に選択的でない場合はエラーが返される。</p>", "options": [{"key": "A", "label": "False"}, {"key": "B", "label": "True"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>INFORMATION SCHEMAクエリで指定されたフィルターが十分に選択的でない場合、次のエラーが返されます：「Information schema query returned too much data. Please repeat the query with more selective predicates.」（情報スキーマクエリが多すぎるデータを返しました。より選択的な述語でクエリを繰り返してください。）</p><p>https://docs.snowflake.com/en/sql-reference/info-schema#general-usage-notes</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 96, "title": "クラスタリングキーを定義することがクエリパフォーマンス向上にどのように役立ちますか？", "multiSelect": false, "stemHtml": "<p>クラスタリングキーを定義することがクエリパフォーマンス向上にどのように役立ちますか？</p>", "options": [{"key": "A", "label": "クラスタリングキーを定義すると、Snowflakeがクエリ結果を事前計算する"}, {"key": "B", "label": "クラスタリングキーの一部である列にクエリが述語を使用する場合、最適なパーティション剪定が発生する"}, {"key": "C", "label": "クラスタリングキーが定義されると、Snowflakeが異なるコンピュートクラスターにデータを分散する"}], "correctAnswers": ["B"], "explanationHtml": "<p>✅ <strong>クラスタリングキーの列に述語を使用する場合に最適なパーティション剪定が発生する</strong></p><p>特定の列でテーブルをクラスタリングすることで、クエリ処理から不要なパーティションを排除してクエリを最適化できます。クラスタリングキーを定義してテーブルを再クラスタリングすることで、クラスタリングキーに従ってデータをマイクロパーティションに効果的に再分配し、クラスタリングされた列で述語または結合するクエリへの最適なアクセスを確保します。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 97, "title": "他のSnowflakeアカウントとデータを共有するために必要なSnowflakeの最低エディショ...", "multiSelect": false, "stemHtml": "<p>他のSnowflakeアカウントとデータを共有するために必要なSnowflakeの最低エディションはどれですか？</p>", "options": [{"key": "A", "label": "Enterprise"}, {"key": "B", "label": "Business Critical"}, {"key": "C", "label": "Standard"}, {"key": "D", "label": "Virtual Private Snowflake"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>Standard</strong></p><p>データ共有は全てのSnowflakeエディションでサポートされているため、それをサポートする最低エディションはStandardエディションです。</p><p>https://docs.snowflake.com/en/user-guide/intro-editions.html</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 98, "title": "Snowflakeでのスケールアウトを正確に説明している文章はどれですか？該当するものを全て選択...", "multiSelect": true, "stemHtml": "<p>Snowflakeでのスケールアウトを正確に説明している文章はどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "スケールアウトはマルチクラスター仮想ウェアハウスの使用によって達成される"}, {"key": "B", "label": "スケールアウトはクエリのキューイングを減らすのに役立つ"}, {"key": "C", "label": "スケールアウトは仮想ウェアハウスのサイズを増減することによって達成される"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>マルチクラスター仮想ウェアハウスによって達成 / クエリキューイングの削減に役立つ</strong></p><p>仮想ウェアハウスには定義されたコンピューティングリソースセットがあります。キューの問題を解決するために、Snowflakeはマルチクラスター仮想ウェアハウスを提供します。マルチクラスター仮想ウェアハウスは需要に基づいて動的に追加クラスターを追加します。需要が減少すると、追加クラスターは廃止されます。このプロセスはスケールアウト（またはスケールバック）またはオートスケーリングとも呼ばれます。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 99, "title": "データ共有をサポートしないSnowflakeエディションはどれですか？", "multiSelect": false, "stemHtml": "<p>データ共有をサポートしないSnowflakeエディションはどれですか？</p>", "options": [{"key": "A", "label": "Virtual Private Snowflake (VPS)"}, {"key": "B", "label": "Enterprise"}, {"key": "C", "label": "Business Critical"}, {"key": "D", "label": "Standard"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>Virtual Private Snowflake (VPS)</strong></p><p>Virtual Private Snowflake (VPS)は分離されたメタデータ、コンピュート、ストレージを持つため、セキュアデータ共有、Marketplaceなどを使用できません。VPSアカウントには共有機能がありません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 100, "title": "Snowflakeのリーダーアカウントを正しく説明しているものはどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeのリーダーアカウントを正しく説明しているものはどれですか？</p>", "options": [{"key": "A", "label": "リーダーアカウントは外部テーブルにアクセスするために必要である"}, {"key": "B", "label": "リーダーアカウントは部門間でクエリコストを分配するために使用される"}, {"key": "C", "label": "リーダーアカウントはテスト目的のみに使用される"}, {"key": "D", "label": "リーダーアカウントはSnowflakeを使用していないユーザーとデータを共有するために使用できる"}], "correctAnswers": ["D"], "explanationHtml": "<p>✅ <strong>Snowflakeを使用していないユーザーとデータを共有するために使用できる</strong></p><p>リーダーアカウントを作成することで、Snowflakeを使用していないユーザーや組織とデータを共有できます。このリーダーアカウントはデータプロバイダーが共有目的のみのために作成します。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-reader-create</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 101, "title": "Snowsightがサポートするチャートタイプはどれですか？該当するものを全て選択してください。", "multiSelect": true, "stemHtml": "<p>Snowsightがサポートするチャートタイプはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "スコアカード（Scorecards）"}, {"key": "B", "label": "棒グラフ（Bar Charts）"}, {"key": "C", "label": "パレート図（Pareto Charts）"}, {"key": "D", "label": "円グラフ（Pie Charts）"}, {"key": "E", "label": "エリアチャート（Area charts）"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>スコアカード / 棒グラフ</strong></p><p>Snowsightは以下をサポートします：棒グラフ（Bar charts）、折れ線グラフ（Line charts）、散布図（Scatterplots）、ヒートグリッド（Heat grids）、スコアカード（Scorecards）。</p><p>https://docs.snowflake.com/en/user-guide/ui-snowsight-visualizations</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ツールとインターフェース", "originalCorrect": null, "reviewPoint": ""}}, {"order": 102, "title": "Snowflakeのリーダーアカウントについてのどのステートメントが正しいですか？該当するものを...", "multiSelect": true, "stemHtml": "<p>Snowflakeのリーダーアカウントについてのどのステートメントが正しいですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "単一のリーダーアカウントは異なるプロバイダーが共有するデータにアクセスできる"}, {"key": "B", "label": "リーダーアカウントのサポートリクエストはプロバイダーアカウントを通じて提出する必要がある"}, {"key": "C", "label": "リーダーアカウントはリーダーアカウントを作成したプロバイダーアカウントが共有するデータのみにアクセスできる"}, {"key": "D", "label": "リーダーアカウントはサポートリクエストを提出できる"}], "correctAnswers": ["B", "C"], "explanationHtml": "<p>✅ <strong>サポートリクエストはプロバイダーアカウント経由 / 作成したプロバイダーのデータのみアクセス可能</strong></p><p>リーダーアカウントはSnowflakeのライセンス契約を持たないため、サポートにアクセスできません。代わりに、リーダーアカウントを作成したプロバイダーアカウントがサポートリクエストを管理します。リーダーアカウントを作成したプロバイダーアカウントのデータのみをリーダーアカウントが使用できます。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-reader-create</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 103, "title": "Snowflakeはテーブルデータをどの形式で保存しますか？", "multiSelect": false, "stemHtml": "<p>Snowflakeはテーブルデータをどの形式で保存しますか？</p>", "options": [{"key": "A", "label": "独自形式（A proprietary format）"}, {"key": "B", "label": "JSON"}, {"key": "C", "label": "CSVおよびTSVファイル"}, {"key": "D", "label": "Parquet形式"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>独自形式（A proprietary format）</strong></p><p>Snowflakeは、AWS S3、Azure Blob Storage、Google Cloud StorageなどのクラウドオブジェクトストレージのSnowflake独自形式でデータを保存します。ユーザーは実際のファイルを見たり、データの保存方法を確認したり、ファイルに直接アクセスしたりすることはできません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 104, "title": "マルチクラスター仮想ウェアハウスが最小クラスター数1、最大クラスター数3で設定されているとします...", "multiSelect": false, "stemHtml": "<p>マルチクラスター仮想ウェアハウスが最小クラスター数1、最大クラスター数3で設定されているとします。この仮想ウェアハウスは最大化モードですか？</p>", "options": [{"key": "A", "label": "No（いいえ）"}, {"key": "B", "label": "Yes（はい）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>No（いいえ）</strong></p><p>マルチクラスター仮想ウェアハウスは最大化モードまたはオートスケールモードで作成できます。最大化モードはマルチクラスターの最小と最大ウェアハウス数を同じ値に設定することで有効になります。この設定（最小1、最大3）は異なる値のためオートスケールモードです。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-multicluster#setting-the-scaling-policy-for-a-multi-cluster-warehouse</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 105, "title": "SnowflakeでUDFを作成するためにサポートされている言語はどれですか？", "multiSelect": true, "stemHtml": "<p>SnowflakeでUDFを作成するためにサポートされている言語はどれですか？</p>", "options": [{"key": "A", "label": "JavaScript"}, {"key": "B", "label": "Python"}, {"key": "C", "label": "Java"}, {"key": "D", "label": "C#"}, {"key": "E", "label": "SQL"}, {"key": "F", "label": "C++"}], "correctAnswers": ["A", "B", "C", "E"], "explanationHtml": "<p>✅ <strong>JavaScript / Python / Java / SQL</strong></p><p>SQL、Java、JavaScript、PythonはSnowflakeでUDFを作成するために使用できます。</p><p>https://docs.snowflake.com/en/sql-reference/udf-overview#supported-languages</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 106, "title": "Snowflakeアーキテクチャで同じレイヤーを指す用語はどれですか？該当するものを全て選択して...", "multiSelect": true, "stemHtml": "<p>Snowflakeアーキテクチャで同じレイヤーを指す用語はどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "サービスレイヤー（Services Layer）"}, {"key": "B", "label": "ストレージレイヤー（Storage Layer）"}, {"key": "C", "label": "仮想ウェアハウス（Virtual Warehouses）"}, {"key": "D", "label": "クラウドサービスレイヤー（Cloud Services Layer）"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>サービスレイヤー / クラウドサービスレイヤー</strong></p><p>クラウドサービスレイヤーとサービスレイヤーという用語は同義語として使用されます。</p><p>https://docs.snowflake.com/en/user-guide/intro-key-concepts#cloud-services</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 107, "title": "クエリプロファイルについて正しいものはどれですか？該当するものを全て選択してください。", "multiSelect": true, "stemHtml": "<p>クエリプロファイルについて正しいものはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "クエリプロファイルは完了していないクエリには利用できない"}, {"key": "B", "label": "クエリのクエリプランを表示する"}, {"key": "C", "label": "全ステップのグラフィカル表現を表示する"}, {"key": "D", "label": "クエリプロファイルは実行中、完了、または失敗した全クエリで利用可能"}], "correctAnswers": ["B", "C", "D"], "explanationHtml": "<p>✅ <strong>クエリプランを表示 / グラフィカル表現を表示 / 全クエリで利用可能</strong></p><p>クエリプロファイルはクエリ実行の詳細を提供します。指定されたクエリの処理プランの主要コンポーネントのグラフィカル表現と各コンポーネントの統計、全体的なクエリ情報と統計を表示します。クエリプロファイルは実行中、完了、または失敗した全クエリで利用可能です。</p><p>https://docs.snowflake.com/en/user-guide/ui-query-profile</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 108, "title": "Snowflakeのアーキテクチャについて正しいステートメントはどれですか？該当するものを全て選...", "multiSelect": true, "stemHtml": "<p>Snowflakeのアーキテクチャについて正しいステートメントはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "Snowflakeはコンピュートとストレージが密結合したモノリシックアーキテクチャを使用する"}, {"key": "B", "label": "Snowflakeではストレージを変更せずにコンピュートリソースを増減できる"}, {"key": "C", "label": "Snowflakeではストレージが増加するたびにコンピュートも増加する必要がある"}, {"key": "D", "label": "Snowflakeのストレージとコンピュートは互いに独立している"}], "correctAnswers": ["B", "D"], "explanationHtml": "<p>✅ <strong>ストレージ変更なしにコンピュートを増減可能 / ストレージとコンピュートは独立</strong></p><p>Snowflakeはコンピュートとストレージを分離する新しいハイブリッドアーキテクチャを実装しています。このハイブリッドアーキテクチャにより、ストレージの変更なしにコンピュートを増減でき、逆も同様です。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 109, "title": "仮想ウェアハウスをリサイズするために必要な権限はどれですか？", "multiSelect": false, "stemHtml": "<p>仮想ウェアハウスをリサイズするために必要な権限はどれですか？</p>", "options": [{"key": "A", "label": "MODIFY"}, {"key": "B", "label": "USAGE"}, {"key": "C", "label": "ALTER"}, {"key": "D", "label": "MONITOR"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>MODIFY</strong></p><p>MODIFY権限はロールが仮想ウェアハウスのサイズを変更できるようにします。</p><p>https://docs.snowflake.com/en/sql-reference/sql/alter-warehouse#access-control-requirements</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 110, "title": "データベース管理者として、大きなテーブルに新しいクラスタリングキーを定義しました。Snowfla...", "multiSelect": true, "stemHtml": "<p>データベース管理者として、大きなテーブルに新しいクラスタリングキーを定義しました。Snowflakeがデータを再クラスタリングする間、何が起きると予想されますか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "Snowflakeがマイクロパーティションでデータを再分配している間も、SELECTクエリは通常通り実行される"}, {"key": "B", "label": "Snowflakeがマイクロパーティションでデータを再分配している間、SELECTクエリは実行がブロックされる"}, {"key": "C", "label": "Snowflakeがマイクロパーティションでデータを再分配している間、DMLクエリは許可されない"}, {"key": "D", "label": "Snowflakeがマイクロパーティションでデータを再分配している間も、DMLクエリは通常通り実行される"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>SELECTクエリは通常通り実行 / DMLクエリも通常通り実行</strong></p><p>Snowflakeの再クラスタリング操作はユーザーに透過的であり、DMLまたはSELECTクエリをブロックしません。再クラスタリング中のテーブルは、クエリ、更新、変更される際に他のテーブルとまったく同じように動作します。</p><p>https://docs.snowflake.com/en/user-guide/tables-auto-reclustering#non-blocking-dml</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 111, "title": "Tri-Secret Secure暗号化で組み合わされるキーはどれですか？2つ選択してください。", "multiSelect": true, "stemHtml": "<p>Tri-Secret Secure暗号化で組み合わされるキーはどれですか？2つ選択してください。</p>", "options": [{"key": "A", "label": "Snowflakeが管理するキー（Snowflake-managed）"}, {"key": "B", "label": "公開鍵（Public key）"}, {"key": "C", "label": "ハッシュキー（Hash key）"}, {"key": "D", "label": "顧客が管理するキー（Customer-managed）"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>Snowflakeが管理するキー / 顧客が管理するキー</strong></p><p>Tri-Secret SecureはSnowflakeが管理するキーと顧客が管理するキーの組み合わせを指し、データを保護するための複合マスターキーを作成します。Tri-Secret SecureはBusiness Criticalエディション以上が必要で、Snowflakeサポートに連絡することで有効化できます。</p><p>https://docs.snowflake.com/en/user-guide/security-encryption-manage</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 112, "title": "Snowflakeの顧客が実行する必要がない活動はどれですか？該当するものを全て選択してください...", "multiSelect": true, "stemHtml": "<p>Snowflakeの顧客が実行する必要がない活動はどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "データセンターレベルでのハードウェアの高可用性の設定とテスト"}, {"key": "B", "label": "ユーザーアクセスと権限の管理"}, {"key": "C", "label": "Snowflakeデータベースをインストールするためのハードウェアのプロビジョニング"}, {"key": "D", "label": "Snowflakeデータベースソフトウェアのインストール"}, {"key": "E", "label": "データセンターの物理的セキュリティの確保"}], "correctAnswers": ["A", "C", "D", "E"], "explanationHtml": "<p>✅ <strong>ハードウェア高可用性の設定・テスト / ハードウェアプロビジョニング / ソフトウェアインストール / 物理セキュリティの確保</strong></p><p>SaaSとしてのSnowflakeは、顧客がデータセンターとその物理的セキュリティを管理したり、ハードウェアやソフトウェアをインストールしたり、高可用性を管理したりする必要がありません。</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "ライセンスと機能", "originalCorrect": null, "reviewPoint": ""}}, {"order": 113, "title": "データベースまたはスキーマがクローンされた場合、そのデータベース内のSnowpipeに関して正し...", "multiSelect": true, "stemHtml": "<p>データベースまたはスキーマがクローンされた場合、そのデータベース内のSnowpipeに関して正しいステートメントはどれですか？</p>", "options": [{"key": "A", "label": "内部ステージを参照するSnowpipeはクローンされない"}, {"key": "B", "label": "外部ステージを参照するSnowpipeはクローンされない"}, {"key": "C", "label": "内部ステージを参照するSnowpipeはクローンされる"}, {"key": "D", "label": "外部ステージを参照するSnowpipeはクローンされる"}], "correctAnswers": ["A", "D"], "explanationHtml": "<p>✅ <strong>内部ステージを参照するSnowpipeはクローンされない / 外部ステージを参照するSnowpipeはクローンされる</strong></p><p>データベースまたはスキーマがクローンされた場合、名前付き内部ステージを指すSnowpipeはクローンされません。外部ステージを参照するSnowpipeはクローンされます。</p><p>https://docs.snowflake.com/en/user-guide/object-clone#cloning-and-pipes</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "クローニング", "originalCorrect": null, "reviewPoint": ""}}, {"order": 114, "title": "シェアを作成できるのはどれですか？該当するものを全て選択してください。", "multiSelect": true, "stemHtml": "<p>シェアを作成できるのはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "CREATE SHARE権限を持つロール"}, {"key": "B", "label": "ACCOUNTADMINロール"}, {"key": "C", "label": "SECURITYADMINロール"}, {"key": "D", "label": "SYSADMINロール"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>CREATE SHARE権限を持つロール / ACCOUNTADMINロール</strong></p><p>シェアはACCOUNTADMINロールまたは明示的にCREATE SHARE権限が付与されたロールのみが作成できます。</p><p>https://docs.snowflake.com/en/user-guide/data-sharing-gs</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ共有", "originalCorrect": null, "reviewPoint": ""}}, {"order": 115, "title": "真か偽か：一時テーブルのタイムトラベル保持期間が終了すると、一時テーブルの履歴データはSnowf...", "multiSelect": false, "stemHtml": "<p>真か偽か：一時テーブルのタイムトラベル保持期間が終了すると、一時テーブルの履歴データはSnowflakeサポートでも復元できない。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>過渡テーブルと一時テーブルにはフェイルセーフ機能がないため、これらのテーブルのデータはゼロ日のフェイルセーフストレージを通過します。また、過渡テーブルと一時テーブルの最大タイムトラベルは1日です。したがって、これらのテーブルのタイムトラベル期間が完了すると、履歴データを復元する方法はありません。</p><p>https://docs.snowflake.com/en/user-guide/tables-temp-transient</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "データ保護", "originalCorrect": null, "reviewPoint": ""}}, {"order": 116, "title": "Snowflake Webインターフェースのクエリ履歴は何日間保持されますか？", "multiSelect": false, "stemHtml": "<p>Snowflake Webインターフェースのクエリ履歴は何日間保持されますか？</p>", "options": [{"key": "A", "label": "14日"}, {"key": "B", "label": "365日"}, {"key": "C", "label": "30日"}, {"key": "D", "label": "6ヶ月"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>14日</strong></p><p>クエリ履歴ページでは、実行済みおよび現在実行中のクエリの履歴を表示できます。クエリ履歴ページは過去14日間に実行されたクエリの履歴を表示できます。</p><p>https://docs.snowflake.com/en/user-guide/ui-snowsight-activity#query-history</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アカウント使用量と監視", "originalCorrect": null, "reviewPoint": ""}}, {"order": 117, "title": "真か偽か：必要に応じて仮想ウェアハウスのサイズを増減できる。", "multiSelect": false, "stemHtml": "<p>真か偽か：必要に応じて仮想ウェアハウスのサイズを増減できる。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>仮想ウェアハウスはクエリの複雑さが増した場合に十分なパフォーマンスを確保するためにスケールアップできます。スケールダウンは一般的にクエリの複雑さが減少したことに応じて行われます。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-considerations</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 118, "title": "Snowflakeでクエリパフォーマンスを向上させる方法はどれですか？", "multiSelect": false, "stemHtml": "<p>Snowflakeでクエリパフォーマンスを向上させる方法はどれですか？</p>", "options": [{"key": "A", "label": "クラスタリングキー（Clustering Keys）"}, {"key": "B", "label": "結合インデックス（Join Indices）"}, {"key": "C", "label": "セカンダリインデックス（Secondary Indices）"}, {"key": "D", "label": "クエリヒント（Query Hints）"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>クラスタリングキー（Clustering Keys）</strong></p><p>特定の列でテーブルをクラスタリングすることで、クエリ処理から不要なパーティションを排除してクエリを最適化できます。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 119, "title": "SELECTクエリ仕様から取得した事前計算済みデータセットを格納して将来の使用のために保存するも...", "multiSelect": false, "stemHtml": "<p>SELECTクエリ仕様から取得した事前計算済みデータセットを格納して将来の使用のために保存するものを表す用語はどれですか？</p>", "options": [{"key": "A", "label": "ビュー（View）"}, {"key": "B", "label": "セキュアビュー（Secure View）"}, {"key": "C", "label": "マテリアライズドビュー（Materialized View）"}, {"key": "D", "label": "出力ビュー（Output View）"}], "correctAnswers": ["C"], "explanationHtml": "<p>✅ <strong>マテリアライズドビュー（Materialized View）</strong></p><p>マテリアライズドビューはSELECTクエリに基づいてデータを事前計算するビューです。クエリの結果は事前計算され、将来同様のクエリのパフォーマンスを向上させるために物理的に保存されます。基礎テーブルが更新されると、マテリアライズドビューは自動的にリフレッシュされます。</p><p>https://docs.snowflake.com/en/user-guide/views-materialized</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 120, "title": "仮想ウェアハウスのスケールアップ/ダウンとスケールアウトについて正しいステートメントはどれですか...", "multiSelect": true, "stemHtml": "<p>仮想ウェアハウスのスケールアップ/ダウンとスケールアウトについて正しいステートメントはどれですか？該当するものを全て選択してください。</p>", "options": [{"key": "A", "label": "仮想ウェアハウスのスケールアウトとスケールバックはSnowflakeによって自動的に行われる"}, {"key": "B", "label": "仮想ウェアハウスのスケールアップとスケールダウンは手動プロセスである"}, {"key": "C", "label": "仮想ウェアハウスのスケールアップとスケールダウンはSnowflakeによって自動的に管理される"}, {"key": "D", "label": "仮想ウェアハウスのスケールアウトとスケールバックは手動プロセスである"}], "correctAnswers": ["A", "B"], "explanationHtml": "<p>✅ <strong>スケールアウト・スケールバックは自動 / スケールアップ・スケールダウンは手動</strong></p><p>マルチクラスター仮想ウェアハウスはキューの問題を解決するために需要に基づいて動的（かつ自動的）に追加クラスターを追加します。スケールアップとスケールダウンは手動プロセスです。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-multicluster</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}, {"order": 121, "title": "ストアドプロシージャを作成する良い理由とならない要件はどれですか？", "multiSelect": false, "stemHtml": "<p>ストアドプロシージャを作成する良い理由とならない要件はどれですか？</p>", "options": [{"key": "A", "label": "2つの値の平均を計算する"}, {"key": "B", "label": "長期間使用されていないテーブルを見つけてドロップする"}, {"key": "C", "label": "共有された一時データを毎日クリーンアップするための一連のSQLを実行する"}, {"key": "D", "label": "新しいユーザーとそのユーザーの新しいデータベースを作成するための一連のSQLステートメントを実行する"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>2つの値の平均を計算する</strong></p><p>ストアドプロシージャとUDFは似ているように見えますが、異なる目的に役立ちます。UDFの役割は入力を受け取り、計算を行い、値を返すことであり、ストアドプロシージャの役割は1つ以上のSQLクエリを実行することです。したがって、2つの値の平均を計算することはUDFで最もよく処理されます。</p><p>https://docs.snowflake.com/en/sql-reference/stored-procedures-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "Snowflake機能の拡張", "originalCorrect": null, "reviewPoint": ""}}, {"order": 122, "title": "プロキシまたはファイアウォールを通じたアクセスのためにSnowsightを設定する際に、Snow...", "multiSelect": false, "stemHtml": "<p>プロキシまたはファイアウォールを通じたアクセスのためにSnowsightを設定する際に、Snowsightの完全修飾URLとポートを決定するために使用される関数はどれですか？</p>", "options": [{"key": "A", "label": "SYSTEM$ALLOWLIST"}, {"key": "B", "label": "SYSTEM$REFERENCE"}, {"key": "C", "label": "SYSTEM$GET_TAG"}, {"key": "D", "label": "SYSTEM$GENERATE_SAML_CSR"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>SYSTEM$ALLOWLIST</strong></p><p>プロキシやファイアウォールを使用してSnowsightに接続するには、完全修飾URLとポート値をプロキシサーバーまたはファイアウォール設定に追加する必要があります。SYSTEM$ALLOWLIST関数の戻り値のSNOWSIGHT_DEPLOYMENTアイテムを使用して、完全修飾SnowsightのURLとポートを確認します。</p><p>https://docs.snowflake.com/en/user-guide/ui-snowsight-gs#accessing-sf-web-interface-through-a-proxy-or-firewall</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "セキュリティ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 123, "title": "仮想ウェアハウスサイズの例として正しいものはどれですか？", "multiSelect": true, "stemHtml": "<p>仮想ウェアハウスサイズの例として正しいものはどれですか？</p>", "options": [{"key": "A", "label": "Low"}, {"key": "B", "label": "X-Small"}, {"key": "C", "label": "Medium"}, {"key": "D", "label": "High"}, {"key": "E", "label": "6X-Large"}], "correctAnswers": ["B", "C", "E"], "explanationHtml": "<p>✅ <strong>X-Small / Medium / 6X-Large</strong></p><p>SnowflakeはX-Small、Small、Medium、Largeなどのようなサイズのラベルを使用して仮想ウェアハウスの選択を簡単にしています。</p><p>https://docs.snowflake.com/en/user-guide/warehouses-overview</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "アーキテクチャ", "originalCorrect": null, "reviewPoint": ""}}, {"order": 124, "title": "真か偽か：Snowflakeはクラスタリングキーに最大3〜4列を推奨している。", "multiSelect": false, "stemHtml": "<p>真か偽か：Snowflakeはクラスタリングキーに最大3〜4列を推奨している。</p>", "options": [{"key": "A", "label": "True"}, {"key": "B", "label": "False"}], "correctAnswers": ["A"], "explanationHtml": "<p>✅ <strong>True</strong></p><p>Snowflakeはクラスタリングキーに最大3〜4列を使用することを推奨しています。クラスタリングキーの列数が増えるとメンテナンスコストが高くなり、クラスタリングコストを正当化するほどの十分な利益が得られません。</p><p>https://docs.snowflake.com/en/user-guide/tables-clustering-keys</p><p>---</p>", "practiceHtml": "", "sourceAnswer": {"selected": [], "memo": "パフォーマンスの概念", "originalCorrect": null, "reviewPoint": ""}}]}]};
